insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1314, '10', '잠을 자기 전에 대상자의 의치를 빼 주는 이유는?', '["침 분비 촉진", "잇몸 압박 예방", "의치 변형 방지", "의치 유연성 유지", "턱뼈의 골밀도 유지"]'::jsonb, 2, NULL, NULL, '{"1": "침 분비 촉진: 의치를 빼는 것과 직접적인 관련이 없습니다.\n[정답]", "2": "잇몸 압박 예방: 의치를 착용하고 자면 잇몸에 지속적인 압력이 가해져 통증이나 손상을 초래할 수 있습니다.", "3": "의치 변형 방지: 의치가 변형되는 것은 착용 상태와 관련이 있으며, 빼는 것과는 관계가 적습니다.", "4": "의치 유연성 유지: 의치는 일반적으로 고정되어 있어 유연성과 관계가 없습니다.", "5": "턱뼈의 골밀도 유지: 턱뼈와 의치의 관계는 복잡하며, 의치를 빼는 것이 골밀도와 직접적으로 연결되지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1313, '10', '누워 있는 대상자의 구강청결 방법으로 옳은 것은?', '["치아 안쪽은 칫솔질을 삼간다.", "구토를 막기 위해 혀는 닦지 않는다.", "양치물을 삼기지 않도록 상체를 올려준다.", "입안을 헹구기 어려운 경우에는 거즈로 닦아낸다.", "칫솔질은 매 식사 전에 3분간 세심하게 닦는다."]'::jsonb, 3, NULL, NULL, '{"1": "구강청결 시, 치아 안쪽도 소홀히 하지 않아야 합니다.", "2": "구토를 막기 위해서는 혀를 닦는 것이 중요합니다.\n[정답]", "3": "양치물을 삼기지 않도록 상체를 올리는 것이 필요합니다.", "4": "입안을 헹구기 어려운 경우에는 거즈로 닦아내는 것이 좋은 방법입니다.", "5": "칫솔질은 매 식사 후에 하는 것이 바람직합니다."}'::jsonb, '[{"term_ko": "구강청결", "term_vi": "Vệ sinh miệng", "def_ko": "입 안을 깨끗하게 하는 것", "def_vi": "Làm sạch bên trong miệng"}, {"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "환자 또는 돌봐줄 필요가 있는 사람", "def_vi": "Bệnh nhân hoặc người cần chăm sóc"}, {"term_ko": "상체", "term_vi": "Thân trên", "def_ko": "몸의 윗부분", "def_vi": "Phần trên của cơ thể"}, {"term_ko": "헹구다", "term_vi": "Súc", "def_ko": "입안을 씻다", "def_vi": "Rửa miệng"}, {"term_ko": "거즈", "term_vi": "Gạc", "def_ko": "의료용 천", "def_vi": "Vải y tế"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1312, '10', '대상자의 칫솔질 돕기 방법으로 옳은 것은?', '["많은 양의 치약을 칫솔모 위에 눌러 짠다.", "칫솔을 90도 각도로 치아에 대고 닦는다.", "머리를 뒤로 젖히게 하고 칫솔질을 한다.", "컵 사용이 어려울 경우 빨대 달린 컵을 사용하게 한다.", "혈액응고장애가 있으면 칫솔 대신 치실을 사용한다/"]'::jsonb, 4, NULL, NULL, '{"1": "많은 양의 치약을 칫솔모 위에 눌러 짜면 치아에 고르게 닿지 않아 효과적인 칫솔질이 어렵다.\n[정답]", "4": "컵 사용이 어려운 경우 빨대 달린 컵을 사용하는 것은 수분 섭취를 용이하게 하는 좋은 방법이다.", "2": "칫솔을 90도 각도로 치아에 대고 닦는 것은 올바른 방법이 아니다. 보통 45도 각도로 기울여 닦아야 한다.", "3": "머리를 뒤로 젖히게 하면 구강 내에서 물이 흘러나와 불편할 수 있다.", "5": "혈액응고장애가 있는 경우 칫솔 대신 치실을 사용하는 것은 위험할 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(병원, 요양시설 등에서 돌보는 사람)", "def_vi": "Người được chăm sóc trong bệnh viện, cơ sở điều dưỡng."}, {"term_ko": "칫솔질", "term_vi": "Đánh răng", "def_ko": "이와 같은 행동(입안의 이와 턱 청소)", "def_vi": "Hành động làm sạch răng miệng."}, {"term_ko": "혈액응고장애", "term_vi": "Rối loạn đông máu", "def_ko": "혈액이 응고되는 데 문제가 있는 상태", "def_vi": "Tình trạng gặp vấn đề trong việc đông máu."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1311, '10', '대상자의 칫솔질 돕기 방법으로 옳은 것은?', '["칫솔 위에 두툼하게 치약을 올린다.", "잇몸에서부터 치아 쪽 방향으로 닦는다.", "칫솔질을 할 때는 치아만 닦는다.", "칫솔을 옆으로 강하게 문지른다.", "치약의 청량감이 오래가도록 입안을 물로 한번만 헹군다."]'::jsonb, 2, NULL, NULL, '{"1": "칫솔에 치약을 두툼하게 올리는 것은 비효율적입니다.\n[정답]", "2": "잇몸에서부터 치아 쪽 방향으로 닦는 것이 올바른 방법입니다.", "3": "칫솔질을 할 때는 치아 외에도 잇몸을 함께 닦아야 합니다.", "4": "칫솔을 옆으로 강하게 문지르는 것은 잇몸에 손상을 줄 수 있습니다.", "5": "치약의 청량감을 오래 유지하기 위해서는 여러 번 헹궈 주는 것이 좋습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봐야 할 사람", "def_vi": "Người bệnh hoặc người cần chăm sóc"}, {"term_ko": "칫솔질", "term_vi": "Đánh răng", "def_ko": "이빨을 닦는 행위", "def_vi": "Hành động làm sạch răng"}, {"term_ko": "치약", "term_vi": "Kem đánh răng", "def_ko": "이빨을 닦을 때 사용하는 제품", "def_vi": "Sản phẩm sử dụng khi đánh răng"}, {"term_ko": "잇몸", "term_vi": "Nướu", "def_ko": "치아를 둘러싼 부드러운 조직", "def_vi": "Tổ chức mềm bao quanh răng"}, {"term_ko": "헹구다", "term_vi": "Súc miệng", "def_ko": "입안을 물로 씻어내다", "def_vi": "Rửa miệng bằng nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1310, '10', '혈액응고장애가 있는 대상자의 칫솔질을 돕는 방법은?', '["칫솔모가 단단한 칫솔에 치약을 두툼하게 올린다.", "치아에서 잇몸 방향으로 회전하면서 칫솔질하게 한다.", "칫솔로 치아뿐 아니라 혀의 깊숙한 곳까지 닦게 한다.", "치실로 음식물 찌꺼기를 제거한 후 칫솔질하게 한다.", "매 식사 후 30분 이내와 잠자기 전에 칫솔질하게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "칫솔모가 단단한 칫솔은 잇몸에 상처를 유발할 수 있어 부적절하다.\n[정답]", "5": "매 식사 후 30분 이내와 잠자기 전에 칫솔질하는 것이 가장 안전하고 중요하다.", "3": "혀의 깊숙한 곳까지 닦는 것은 필요하지만 혈액응고장애가 있는 경우에는 조심해야 한다.", "2": "치아에서 잇몸 방향으로 회전하는 방법은 잘못된 방법이 아니나, 혈액응고장애가 있는 경우 신중해야 한다.", "4": "치실로 제거한 후 칫솔질하는 것은 좋으나, 칫솔질의 타이밍이 더 중요하다."}'::jsonb, '[{"term_ko": "혈액응고장애", "term_vi": "Rối loạn đông máu", "def_ko": "혈액이 제대로 응고되지 않는 질병", "def_vi": "Bệnh khiến máu không đông đúng cách"}, {"term_ko": "칫솔질", "term_vi": "Đánh răng", "def_ko": "이가 닦이는 행동", "def_vi": "Hành động chải răng"}, {"term_ko": "자주", "term_vi": "Thường xuyên", "def_ko": "빈도가 높은", "def_vi": "Tần suất cao"}, {"term_ko": "잇몸", "term_vi": "Nướu", "def_ko": "치아를 둘러싼 부위", "def_vi": "Vùng xung quanh răng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1309, '10', '의식이 없는 대상자의 구강 청결을 돕는 방법으로 옳은 것은?', '["구강에 상처가 있으면 소독해준다.", "똑바로 누운 자세로 상반신을 낮춘다.", "생리식염수로 입안을 헹구어 준다.", "물에 적신 일회용 스펀지 브러시로 닦는다.", "건조해지지 않도록 입 주변의 물기는 닦지 않는다."]'::jsonb, 4, NULL, NULL, '{"1": "구강에 상처가 있을 경우 소독을 하는 것은 중요하지만, 의식이 없는 환자에게는 즉각적으로 할 수 있는 조치가 아닙니다.\n[정답]", "4": "물에 적신 일회용 스펀지 브러시로 닦는 것은 안전하고 효과적인 방법입니다.", "3": "생리식염수로 입안을 헹구는 것은 의식이 있는 환자에게 적용할 수 있으며, 의식이 없는 환자에게는 적합하지 않습니다.", "2": "똑바로 누운 자세로 상반신을 낮추는 것은 안전하지 않으며, 청결을 돕는 데 비효율적입니다.", "5": "입 주변의 물기를 닦지 않는 것은 오히려 구강 건강에 장애가 될 수 있습니다."}'::jsonb, '[{"term_ko": "구강", "term_vi": "Khóe miệng", "def_ko": "입안(한국어)", "def_vi": "Vùng xung quanh miệng"}, {"term_ko": "청결", "term_vi": "Sự sạch sẽ", "def_ko": "청결함(한국어)", "def_vi": "Sự sạch sẽ"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "자각(한국어)", "def_vi": "Ý thức"}, {"term_ko": "상반신", "term_vi": "Thân trên", "def_ko": "상체(한국어)", "def_vi": "Thân trên"}, {"term_ko": "스펀지", "term_vi": "Bọt biển", "def_ko": "스폰지(한국어)", "def_vi": "Bọt biển"}, {"term_ko": "일회용", "term_vi": "Dùng một lần", "def_ko": "한 번 사용(한국어)", "def_vi": "Dùng một lần"}, {"term_ko": "브러시", "term_vi": "Bàn chải", "def_ko": "솔(한국어)", "def_vi": "Bàn chải"}, {"term_ko": "헹구다", "term_vi": "Súc", "def_ko": "헹구다(한국어)", "def_vi": "Súc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1308, '10', '의식이 없는 대상자의 입안을 닦을 때 순서로 옳은 것은?가. 윗니와 잇몸 나. 아래쪽 이와 잇몸 다. 입청장 라. 혀 마. 볼 안쪽', '["가-나-다-라-마", "가-다-나-라-마", "나-라-가-마-다", "나-가-다-라-마", "다-나-가-마-라"]'::jsonb, 1, NULL, NULL, '{"1": "윗니와 잇몸을 닦은 후 아래쪽 이와 잇몸을 닦고, 입청장, 혀, 볼 안쪽 순서로 닦는 것이 올바른 방법입니다.\n[정답]", "2": "윗니와 잇몸을 먼저 닦고, 입청장 다음에 아래쪽 이와 잇몸을 닦아야 하므로 잘못된 순서입니다.", "3": "아래쪽 이와 잇몸을 먼저 닦는 것은 올바른 순서가 아닙니다.", "4": "입청장을 먼저 닦는 것은 올바르지 않습니다.", "5": "입청장을 먼저 닦는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "입안", "term_vi": "Miệng", "def_ko": "구강(입의 내부)", "def_vi": "Khoang miệng (phần bên trong miệng)"}, {"term_ko": "의식", "term_vi": "Nhận thức", "def_ko": "의식(상태)", "def_vi": "Tình trạng nhận thức"}, {"term_ko": "이", "term_vi": "Răng", "def_ko": "치아(이빨)", "def_vi": "Răng (a tooth)"}, {"term_ko": "잇몸", "term_vi": "Nướu", "def_ko": "잇몸(치아에 연결된 조직)", "def_vi": "Nướu (gums)"}, {"term_ko": "혀", "term_vi": "Lưỡi", "def_ko": "혀(말하는 기관)", "def_vi": "Lưỡi (tongue)"}, {"term_ko": "볼", "term_vi": "Má", "def_ko": "뺨(얼굴의 옆 부분)", "def_vi": "Má (cheek)"}, {"term_ko": "청장", "term_vi": "Màu", "def_ko": "구강 쪽의 구조물", "def_vi": "Cấu trúc trong miệng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1307, '10', '치아가 없거나 연하장애가 있는 대상자에게 제공하는 구강청결 방법은?', '["칫솔질하기", "입안닦아내기", "입안 헹구기", "의치 손질하기", "치실하기"]'::jsonb, 2, NULL, NULL, '{"1": "칫솔질은 치아가 있는 대상자에게 적합한 방법입니다.\n[정답]", "2": "입안닦아내기는 치아가 없거나 연하장애가 있는 대상자에게 적합한 방법입니다.", "3": "입안 헹구기는 물을 사용하는 방법으로 연하장애가 있는 경우 적합하지 않습니다.", "4": "의치 손질은 의치를 사용하는 대상자에게 해당되지만 입안청결에는 적용되지 않습니다.", "5": "치실 사용은 치아가 있는 경우에 적합한 방법입니다."}'::jsonb, '[{"term_ko": "구강청결", "term_vi": "Vệ sinh miệng", "def_ko": "입이나 구강을 청결하게 하는 것", "def_vi": "Làm sạch miệng hoặc khoang miệng"}, {"term_ko": "연하장애", "term_vi": "Khó nuốt", "def_ko": "음식을 삼키기 어려운 장애", "def_vi": "Khó khăn trong việc nuốt thức ăn"}, {"term_ko": "입안", "term_vi": "Trong miệng", "def_ko": "구강의 내부", "def_vi": "Bên trong khoang miệng"}, {"term_ko": "의치", "term_vi": "Hàm giả", "def_ko": "인공 치아", "def_vi": "Răng giả"}, {"term_ko": "치실", "term_vi": "Chỉ nha khoa", "def_ko": "치아 사이의 이물질을 제거하는 도구", "def_vi": "Dụng cụ làm sạch giữa các răng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1306, '10', '식사 전에 입안을 헹구는 이유로 옳은 것은?', '["식욕을 억제하기 위해", "식도 역류를 예방하기 위해", "타액 분비를 줄이기 위해", "위액 분비를 줄이기 위해", "구강건조를 막기 위해"]'::jsonb, 5, NULL, NULL, '{"1": "식욕을 억제하기 위해: 입안을 헹구는 것이 직접적으로 식욕을 억제하지는 않습니다.\n[정답]", "5": "구강건조를 막기 위해: 입안을 헹구면 구강 내 수분을 유지하여 구강건조를 예방할 수 있습니다.", "2": "식도 역류를 예방하기 위해: 입안을 헹구는 것이 식도 역류와 직접적인 연관이 없습니다.", "3": "타액 분비를 줄이기 위해: 헹구는 것은 타액 분비를 줄이지 않습니다.", "4": "위액 분비를 줄이기 위해: 입안을 헹구는 것이 위액 분비와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "식사", "term_vi": "입안", "def_ko": "식사(식사)", "def_vi": "입(miệng)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1305, '10', '대상자의 구강 청결을 돕는 방법으로 옳은 것은?', '["혀 안쪽과 목젖 안까지 깊숙이 닦는다.", "입안에 상처나 염증이 있는지 확인한다.", "냄새가 심하면 구취제거 스프레이를 뿌린다.", "의식이 없는 대상자는 일주일에 한 번 닦는다.", "거부하는 치매 대상자는 두 손가락으로 입을 벌린 후 닦는다."]'::jsonb, 2, NULL, NULL, '{"1": "혀와 목젖까지 깊숙이 닦는 것은 안전하지 않으며, 손상이나 질병을 유발할 수 있습니다.\n[정답]", "2": "입안의 상처나 염증이 있는지 확인하는 것은 구강 청결을 도우는 데 중요합니다.", "3": "구취제거 스프레이 사용은 근본적인 문제를 해결하지 않으므로 권장되지 않습니다.", "4": "의식이 없는 대상자는 일주일에 한 번 구강 청결을 하는 것이 아니라 전문가의 조치가 필요합니다.", "5": "치매 대상자를 강제로 입을 벌리는 것은 부상을 초래할 수 있으므로 피해야 합니다."}'::jsonb, '[{"term_ko": "구강", "term_vi": "Miệng", "def_ko": "입 안", "def_vi": "bên trong của miệng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1304, '10', '장루를 착용하고 있는 대상자를 돕는 방법으로 옳은 것은?', '["주머니 교환하는 날에는 목욕을 금한다.", "복통을 호소하면 장루주머니를 떼어준다.", "장운동의 부담을 덜기 위해 식사량을 줄인다.", "배설물이 1/3~1/2 정도 채워지면 주머니를 비운다.", "숭일간 배설물이 차지 않으면 주머니를 교체한다."]'::jsonb, 4, NULL, NULL, '{"1": "주머니 교환하는 날에는 목욕을 금하는 것은 옳지 않습니다. 목욕은 필요시 할 수 있습니다.", "2": "복통을 호소할 때 장루 주머니를 떼어주는 것은 적절한 조치가 아닙니다.\n[정답]", "3": "장운동의 부담을 덜기 위해 식사량을 줄이는 것은 일반적으로 권장되지 않습니다. 적절한 영양 섭취가 필요합니다.", "4": "배설물이 1/3~1/2 정도 채워지면 주머니를 비우는 것이 올바른 방법입니다.", "5": "특정 기간 동안 배설물이 차지 않더라도, 주머니를 교체할 필요는 없습니다."}'::jsonb, '[{"term_ko": "장루", "term_vi": "Đường hầm", "def_ko": "인체의 장기를 외부로 연결하기 위한 수술적 조치", "def_vi": "Phương pháp phẫu thuật kết nối các cơ quan trong cơ thể với bên ngoài"}, {"term_ko": "배설물", "term_vi": "Chất bài tiết", "def_ko": "소화 후 몸에서 나오는 찌꺼기", "def_vi": "Chất thải trong cơ thể sau khi tiêu hóa"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "배설물을 담는 용기", "def_vi": "Bình chứa chất bài tiết"}, {"term_ko": "복통", "term_vi": "Đau bụng", "def_ko": "배가 아픈 증상", "def_vi": "Triệu chứng đau ở bụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1303, '10', '장루관리에 대한 설명으로 옳은 것은?', '["수분 섭취를 제한한다.", "통목욕 시에는 주머니를 떼고 한다.", "배설 주머니가 가득 차면 비워준다.", "장루주머니는 주 1회 주기로 교환한다.", "복벽을 통하여 체외로 소변을 배출시키기 위해 만든 구멍이다."]'::jsonb, 4, NULL, NULL, '{"1": "장루 관리 시 수분 섭취는 중요하며, 제한하지 않습니다.\n[정답]", "2": "통목욕 시에는 장루주머니를 떼지 않고 그대로 유지해야 합니다.", "3": "배설 주머니가 가득 차면 비워주지만, 이는 필요에 따라 다를 수 있습니다.", "4": "장루주머니는 주 1회 주기로 교환해야 합니다.", "5": "복벽을 통해 소변을 배출하는 것은 장루가 아닌 신루입니다."}'::jsonb, '[{"term_ko": "장루", "term_vi": "Rò đại tràng", "def_ko": "대변을 체외로 배출하기 위해 복부에 만들어진 구멍", "def_vi": "Lỗ được tạo ra ở bụng để bài tiết phân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1302, '10', '대상자의 요루관리 방법으로 옳은 것은?', '["요루는 좌측하복부에 위치하고 있다.", "요루 주머니는 매일 교환한다.", "통목욕 시에는 소변을 비우고 주머니를 착용한다.", "샤워 시에는 반드시 요루 주머니를 착용한다.", "소변이 요루 주머니에 배출될 때마다 비워낸다."]'::jsonb, 3, NULL, NULL, '{"1": "요루는 대개 우측하복부에 위치한다. 따라서 이 정보는 틀리다.\n[정답]", "3": "통목욕 시 소변을 비우고 주머니를 착용하는 것이 올바른 방법이다.", "2": "요루 주머니는 일반적으로 매일 교환할 필요는 없고, 필요한 경우에만 교환한다.", "4": "샤워 시에는 요루 주머니를 착용하되, 반드시 착용해야 하는 것은 아니다. 개인의 상태에 따라 다르다.", "5": "소변이 요루 주머니에 배출될 때마다 비울 필요는 없고, 주머니의 용량이 충분할 때까지 기다린다."}'::jsonb, '[{"term_ko": "요루", "term_vi": "Yoru", "def_ko": "장기를 외부로 연결하는 인공적인 구멍", "def_vi": "Lỗ mở nhân tạo kết nối cơ quan bên ngoài"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "요루에서 배출된 것을 저장하는 기구", "def_vi": "Thiết bị lưu trữ chất thải từ ostomy"}, {"term_ko": "통목욕", "term_vi": "Tắm chung", "def_ko": "여러 사람이 함께 하는 목욕", "def_vi": "Tắm với nhiều người"}, {"term_ko": "비우다", "term_vi": "Xả", "def_ko": "차서 쌓인 것을 빼내다", "def_vi": "Lấy ra chất lỏng đã chứa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1301, '10', '요루관리에 대한 설명으로 옳은 것은?', '["요루 주머니에 소변이 가득 차면 버린다.", "요루 주머니는 주 2~3회 교환한다.", "통목욕 시에는 요루 주머니를 떼고 한다.", "요루에 출혈이 있으면 알코올로 소독한다.", "복벽에 만든 구멍에 주머니를 연결하여 대변을 배출한다."]'::jsonb, 2, NULL, NULL, '{"1": "요루 주머니는 소변이 가득 차면 버리는 것이 아니라, 정해진 주기에 맞추어 교환해야 합니다.\n[정답]", "2": "요루 주머니는 일반적으로 주 2~3회 교환하는 것이 적절합니다.", "3": "통목욕 시에는 요루 주머니를 떼지 않고도 목욕이 가능하게 관리합니다.", "4": "요루에 출혈이 있어도 알코올로 소독하는 것은 적절하지 않으며, 전문적인 처치가 필요합니다.", "5": "복벽에 만든 구멍은 대변을 배출하는 것이 아니라, 요루를 통해 소변을 배출하는 방식입니다."}'::jsonb, '[{"term_ko": "요루", "term_vi": "Yoru", "def_ko": "인체에 인위적으로 생성한 구멍", "def_vi": "Lỗ được tạo ra nhân tạo trên cơ thể"}, {"term_ko": "주머니", "term_vi": "Túi", "def_ko": "물건을 담는 가방", "def_vi": "Bao đựng đồ"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "대사 후 남은 배설물", "def_vi": "Chất thải sau chuyển hóa"}, {"term_ko": "출혈", "term_vi": "Chảy máu", "def_ko": "혈액이 외부로 나오는 현상", "def_vi": "Hiện tượng máu chảy ra ngoài"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "세균을 죽이는 것", "def_vi": "Giết chết vi khuẩn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1300, '10', '대상자가 유치도뇨관을 사용할 때 간호사에게 보고하지 않아도 되는 것은?', '["소변량이 적어진 경우", "소변색이 탁해진 경우", "도뇨관이 빠지는 경우", "소변이 많이 나오는 경우", "체온 상승이 있는 경우"]'::jsonb, 4, NULL, NULL, '{"1": "소변량이 적어진 경우에는 문제가 발생할 수 있으므로 보고해야 한다.", "2": "소변색이 탁해진 경우는 감염 등의 문제가 있을 수 있으니 보고해야 한다.", "3": "도뇨관이 빠지는 경우는 즉시 보고해야 한다.\n[정답]", "4": "소변이 많이 나오는 경우는 일반적으로 이상이 아닐 수 있으므로 보고하지 않아도 된다.", "5": "체온 상승이 있는 경우는 감염의 징후일 수 있으므로 보고해야 한다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "체내에서 소변을 배출하기 위해 삽입된 관", "def_vi": "Ống được đặt vào cơ thể để thải nước tiểu"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "배출되는 소변의 양", "def_vi": "Khối lượng nước tiểu được thải ra"}, {"term_ko": "소변색", "term_vi": "Màu nước tiểu", "def_ko": "소변의 색깔", "def_vi": "Màu sắc của nước tiểu"}, {"term_ko": "체온", "term_vi": "Nhiệt độ cơ thể", "def_ko": "신체의 온도", "def_vi": "Nhiệt độ của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1299, '10', '대상자가 유치도뇨관 사용 시 간호사에게 긴급히 보고해야 할 상황은?', '["연결관이 꺾여 있을 때", "소변주머니가 가득 차 있을 때", "소변주머니를 들고 걸어 다닐 때", "소변주머니의 배출구가 잠겨 있을 때", "도뇨관 밖으로 소변이 샐 때"]'::jsonb, 5, NULL, NULL, '{"1": "연결관이 꺾여 있을 때: 끼었다고 해서 긴급한 상황이 아님.\n[정답]", "5": "도뇨관 밖으로 소변이 샐 때: 이는 즉각적인 조치가 필요한 심각한 상황입니다.", "2": "소변주머니가 가득 차 있을 때: 호출하여 비우는 것이 필요하지만 긴급한 상황은 아님.", "3": "소변주머니를 들고 걸어 다닐 때: 적절하지 않지만 긴급 상황은 아님.", "4": "소변주머니의 배출구가 잠겨 있을 때: 배출이 필요하나 긴급 상황으로 보긴 어려움."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "방광에 카테터를 삽입하는 방법", "def_vi": "Phương pháp đặt catheter vào bàng quang"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 담는 주머니", "def_vi": "Túi chứa nước tiểu"}, {"term_ko": "배출구", "term_vi": "Cửa thoát", "def_ko": "배출의 부분", "def_vi": "Phần thoát nước"}, {"term_ko": "긴급", "term_vi": "Khẩn cấp", "def_ko": "신속한 조치가 필요한 상황", "def_vi": "Tình huống cần phải hành động ngay lập tức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1298, '10', '유치도뇨관을 강제로 빼낼 경우 발생할 수 있는 문제는?', '["방광감염", "요로파열", "요로감염", "체온상승", "요도점막 손상"]'::jsonb, 5, NULL, NULL, '{"1": "방광감염: 유치도뇨관을 제거했을 때 방광에 감염이 올 수 있지만, 이는 주된 문제가 아니다.\n[정답]", "5": "요도점막 손상: 강제로 빼낼 경우 점막이 손상되어 출혈이나 염증이 발생할 수 있다.", "2": "요로파열: 주로 외부 힘에 의해 발생하며, 유치도뇨관 제거로 인한 일반적인 문제는 아니다.", "3": "요로감염: 유치도뇨관을 제거하면서 감염 위험이 증가할 수 있지만, 가장 흔한 상황은 아니다.", "4": "체온상승: 체온은 여러 요인에 의해 영향을 받을 수 있으며, 유치도뇨관과의 직접적인 연관성이 적다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống dẫn nước tiểu", "def_ko": "환자의 방광에서 소변을 배출하기 위해 설치하는 관", "def_vi": "Ống đặt vào bàng quang để thoát nước tiểu của bệnh nhân"}, {"term_ko": "요도점막", "term_vi": "Niêm mạc niệu đạo", "def_ko": "요도 내벽의 점막", "def_vi": "Niêm mạc bên trong niệu đạo"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변을 저장하는 기관", "def_vi": "Cơ quan chứa nước tiểu"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "세균이나 바이러스에 의해 발생하는 병", "def_vi": "Bệnh do vi khuẩn hoặc virus gây ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1297, '10', '유치도뇨관을 삽입하고 있는 대상자르 돕는 방법으로 옳은 것은?', '["수면 중에는 연결관을 잠가둔다.", "소변색이 탁하면 방광을 세척한다.", "금기사항이 없는 한 수분 섭취를 권장한다.", "소변이 새면 유치도뇨관을 즉시 제거한다.", "소변이 배출되지 않으면 유치도뇨관을 교체한다."]'::jsonb, 3, NULL, NULL, '{"1": "수면 중에는 연결관을 잠가두는 것은 소변 배출에 문제가 생길 수 있어 부적절합니다.\n[정답]", "3": "금기사항이 없는 한 수분 섭취를 권장하는 것은 환자의 건강 상태에 따라 중요합니다.", "2": "소변색이 탁하면 방광을 세척하는 것은 꼭 필요한 조치가 아닙니다.", "4": "소변이 새면 유치도뇨관을 즉시 제거하는 것은 상황에 따라 다르며, 먼저 의사와 상담해야 합니다.", "5": "소변이 배출되지 않으면 유치도뇨관을 교체하는 대신 적절한 평가 후 조치를 취해야 합니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 밖으로 배출하기 위해 방광에 삽입하는 튜브", "def_vi": "Ống được chèn vào bàng quang để thoát nước tiểu"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "배설된 액체 형태의 노폐물", "def_vi": "Chất thải ở dạng lỏng được thải ra"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "청소하거나 씻어내는 것", "def_vi": "Làm sạch hoặc gột rửa"}, {"term_ko": "금기사항", "term_vi": "Chống chỉ định", "def_ko": "어떤 행동을 해서는 안 되는 사항", "def_vi": "Các điều không được thực hiện"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1296, '10', '유치도뇨관을 삽입한 대상자를 돕는 방법으로 옳은 것은?', '["산책하는 동안에는 유치도뇨관을 제거한다.", "소변량이 적은 경우 연결관의 꼬임 여부를 확인한다.", "소변주머니를 비운 후 배출구를 비눗물로 세척한다.", "유치도뇨관이 고정되어 있는지 수시로 당겨 본다.", "하복부가 불편하다고 할 때 소변주머니를 비워 준다."]'::jsonb, 2, NULL, NULL, '{"1": "유치도뇨관은 필요시 언제든지 제거할 수 없으며, 산책 중에도 신중히 관리해야 합니다.\n[정답]", "2": "소변량이 적은 경우 연결관의 꼬임 여부를 확인하는 것이 중요합니다.", "3": "소변주머니의 배출구는 비워도 세척할 필요가 없습니다.", "4": "유치도뇨관이 고정되어 있는지 수시로 당기는 것은 권장되지 않습니다.", "5": "하복부 불편 시에는 우선 원인을 파악하고 소변주머니를 비워야 합니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "배뇨를 돕기 위해 삽입하는 카테터", "def_vi": "Ống được lắp đặt để hỗ trợ việc tiểu tiện"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "소변의 양", "def_vi": "Số lượng nước tiểu"}, {"term_ko": "연결관", "term_vi": "Ống nối", "def_ko": "유치도뇨관과 소변주머니를 연결하는 관", "def_vi": "Ống kết nối giữa ống thông tiểu và túi nước tiểu"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 저장하기 위한 주머니", "def_vi": "Túi để lưu trữ nước tiểu"}, {"term_ko": "배출구", "term_vi": "Cửa xả", "def_ko": "소변주머니의 밝힐 수 있는 구멍", "def_vi": "Lỗ có thể xả nước tiểu từ túi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1295, '10', '유치도뇨관을 삽입하고 있는 대상자가 방광이 팽창하여 불편함을 호소할 때 올바른 돕기 방법은?', '["아랫배를 따뜻하게 해준다.", "소변주머니를 비워준다.", "연결관이 꺾여 있는지 확인한다.", "소변 줄을 팽팽하게 당겨 위치를 조정한다.", "수분 섭취량을 제한하고 금식하게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "아랫배를 따뜻하게 해주면 불편함을 완화할 수 있지만, 문제의 근본적인 해결책이 아니다.\n[정답]", "2": "소변주머니를 비워주는 것은 방광의 압력을 줄이고 불편함을 완화시킬 수 있는 적절한 방법이다.", "3": "연결관이 꺾여 있는지를 확인하는 것은 불편함의 원인이 될 수 있는 요소를 점검하는 것이므로 중요하다.", "4": "소변 줄을 팽팽하게 당기는 것은 오히려 불편할 수 있으며, 잘못된 조치일 수 있다.", "5": "수분 섭취량을 제한하고 금식하게 하는 것은 불필요한 방법이며, 오히려 방광의 상태를 악화시킬 수 있다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "방광에 소변을 배출하는 튜브", "def_vi": "Ống dẫn nước tiểu đến bàng quang"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변을 저장하는 기관", "def_vi": "Cơ quan chứa nước tiểu"}, {"term_ko": "소변주머니", "term_vi": "Túi tiểu", "def_ko": "수집 용기", "def_vi": "Bình chứa nước tiểu"}, {"term_ko": "압력", "term_vi": "Áp lực", "def_ko": "힘, 압박", "def_vi": "Lực, sự áp bức"}, {"term_ko": "불편함", "term_vi": "Khó chịu", "def_ko": "괴로움, 고통", "def_vi": "Sự khó chịu, nỗi đau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1294, '10', '유치도뇨관을 삽입하고 있는 대상자의 소변주머니를 관리하는 방법은?', '["소변주머니는 정해진 시간에만 비운다.", "소변주머니는 1일 1회 세척한다.", "소변주머니를 비운 후 배출구를 잠근다.", "소변주머니의 배출구가 바닥에 닿게 놓는다.", "도뇨관과 소변주머니의 연결 부위를 분리하여 소변을 버린다."]'::jsonb, 3, NULL, NULL, '{"1": "소변주머니는 정해진 시간에만 비우는 것은 적절하지 않습니다. 수시로 비워야 합니다.\n[정답]", "3": "소변주머니를 비운 후 배출구를 잠그는 것이 중요합니다. 감염 예방을 위해 배출구를 잠가야 합니다.", "2": "소변주머니는 1일 1회 세척하는 것은 부족합니다. 주기적으로 세척해야 합니다.", "4": "소변주머니의 배출구가 바닥에 닿게 놓는 것은 위생적이지 않으며, 감염의 위험을 높입니다.", "5": "도뇨관과 소변주머니의 연결 부위를 분리하여 소변을 버리는 것은 부적절합니다. 연결 부위를 항상 유지해야 합니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 체외로 배출하기 위해 삽입되는 관", "def_vi": "Ống dùng để thoát nước tiểu ra ngoài cơ thể"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 모으는 주머니", "def_vi": "Túi đựng nước tiểu"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "깨끗이 씻어 내는 것", "def_vi": "Làm sạch"}, {"term_ko": "배출구", "term_vi": "Cửa xả", "def_ko": "소변을 배출하는 부분", "def_vi": "Phần thoát nước"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "바이러스나 세균에 의해 발생하는 질병", "def_vi": "Bệnh do virus hoặc vi khuẩn gây ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1293, '10', '대상자가 유치돈관을 사용할 때 돕는 방법으로 옳은 것은?', '["하루에 한 번 소변량과 색깔을 확인한다.", "소변주머니를 비운 후 배출구는 알코올 솜으로 닦는다.", "요도관이 빠진 경우 신속하게 끼워 넣는다.", "수분 섭취를 제한하여 배뇨량을 조절한다.", "소변을 보고 싶다고 하면 화장실을 이용하도록 돕는다."]'::jsonb, 2, NULL, NULL, '{"1": "하루에 한 번 소변량과 색깔을 확인하는 것은 필요하지만, 유치돈관 관리의 핵심 항목은 아니다.\n[정답]", "2": "소변주머니를 비운 후 배출구는 알코올 솜으로 닦는 것이 옳은 방법이다. 이는 감염 예방을 위한 중요한 절차이다.", "3": "요도관이 빠진 경우 신속하게 끼워 넣는 것은 위험한 행동이다. 전문적인 도움을 받아야 한다.", "4": "수분 섭취를 제한하여 배뇨량을 조절하는 것은 권장되지 않는다. 오히려 충분한 수분 섭취가 필요하다.", "5": "소변을 보고 싶다고 하면 화장실을 이용하도록 돕는 것이 좋지만, 유치돈관을 사용하는 목적에 따라 소변주머니를 이용하도록 해야 한다."}'::jsonb, '[{"term_ko": "유치돈관", "term_vi": "Ống thông tiểu", "def_ko": "배뇨를 돕기 위해 삽입하는 관", "def_vi": "Ống được đưa vào để hỗ trợ việc tiểu tiện"}, {"term_ko": "소변", "term_vi": "Nước tiểu", "def_ko": "배출된 액체", "def_vi": "Chất lỏng thải ra"}, {"term_ko": "소변주머니", "term_vi": "Túi đựng nước tiểu", "def_ko": "소변을 모으는 기구", "def_vi": "Thiết bị thu gom nước tiểu"}, {"term_ko": "알코올 솜", "term_vi": "Bông cồn", "def_ko": "세균을 제거하는 데 사용하는 물체", "def_vi": "Đối tượng được sử dụng để loại bỏ vi khuẩn"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원균에 의해 신체가 영향을 받는 상태", "def_vi": "Tình trạng cơ thể bị ảnh hưởng bởi vi khuẩn"}, {"term_ko": "배뇨", "term_vi": "Tiểu tiện", "def_ko": "소변을 보는 행위", "def_vi": "Hành động đi tiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1292, '10', '유치도뇨관을 삽입하고 있는 대상자를 돕는 방법은?', '["자유로이 움직일 수 있다고 알려 준다.", "소변주머니는 매 식사 전에 비워준다.", "도뇨관이 막힌 경우 즉시 교체한다.", "프로그램에 참여하는 동안에는 연결관을 잠근다.", "소변주머니에서 냄새가 나면 주머니를 세척한다."]'::jsonb, 1, NULL, NULL, '{"1": "유치도뇨관을 사용하는 대상자는 약간의 이동이 가능하므로 자유롭게 움직일 수 있다고 알려주는 것이 중요합니다.\n[정답]", "2": "소변주머니는 매 식사 전에 비워주는 것이 아니라 필요에 따라 비워야 합니다.", "3": "도뇨관이 막힌 경우, 즉시 교체하는 것이 아니라 의료진에게 보고하여 적절한 처치를 받도록 해야 합니다.", "4": "프로그램에 참여하는 동안 연결관을 잠그면 소변이 제대로 흐르지 않을 수 있으므로, 이 방법은 잘못된 접근입니다.", "5": "소변주머니에서 냄새가 나면 주머니를 세척하는 것이 아니라, 소변주머니를 청결하게 유지해야 하며, 필요시 교체해야 합니다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Đường ống dẫn tiểu", "def_ko": "체내에 넣어 소변을 배출하는 관", "def_vi": "Ống được đưa vào cơ thể để dẫn nước tiểu ra ngoài"}, {"term_ko": "소변주머니", "term_vi": "Túi đựng nước tiểu", "def_ko": "소변을 담는 주머니", "def_vi": "Túi chứa nước tiểu"}, {"term_ko": "교체", "term_vi": "Thay thế", "def_ko": "바꾸다", "def_vi": "Thay đổi"}, {"term_ko": "냄새", "term_vi": "Mùi", "def_ko": "특정한 기운", "def_vi": "Một mùi nhất định"}, {"term_ko": "막히다", "term_vi": "Bị tắc", "def_ko": "통과가 막히다", "def_vi": "Bị chặn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1291, '10', '유치도뇨관을 사용하는 대상자를 돕는 방법으로 옳은 것은??', '["소변량, 색깔을 매 2~3시간 마다 확인한다.", "걸을 때는 소변주머니를 아랫배보다 높이 든다.", "도뇨관 밖으로 소변이 새는 경우 즉시 교체한다.", "소변주머니는 가득 찰 때까지 기다렸다가 비운다.", "소변색이 이상하거나 탁해진 경우 즉시 버린다."]'::jsonb, 1, NULL, NULL, '{"1": "소변량과 색깔을 정기적으로 확인하는 것은 필수적이며, 건강 상태를 모니터링하는 데 중요한 방법이다.\n[정답]", "2": "걸을 때는 소변주머니를 아랫배보다 낮게 두어야 소변 흐름을 원활히 한다.", "3": "도뇨관 밖으로 소변이 새는 경우는 즉시 교체하기 보다는 원인을 확인해야 한다.", "4": "소변주머니는 가득 찰 때까지 기다리지 말고, 정기적으로 비워야 감염 예방에 도움이 된다.", "5": "소변색이 이상할 경우 즉시 버리기보다는 의사의 진료를 받는 것이 적절하다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 배출하기 위해 체내에 삽입하는 관", "def_vi": "Ống được đưa vào cơ thể để thoát nước tiểu"}, {"term_ko": "소변량", "term_vi": "Lượng nước tiểu", "def_ko": "배출되는 소변의 양", "def_vi": "Số lượng nước tiểu được thải"}, {"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 모으는 용기", "def_vi": "Bình chứa nước tiểu"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병균이나 바이러스에 의해 일어나는 질병", "def_vi": "Bệnh do vi khuẩn hoặc virus gây ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1290, '10', '소변주머니를 방광의 위치보다 낮게 두어야 하는 이유는?', '["역류성 감염을 예방하기 위해", "보행의 편의를 위해", "유치도뇨관이 빠지지 않게 하기 위해", "냄새의 유출을 방지하기 위해", "연결관이 꺾이지 않게 하기 위해"]'::jsonb, 1, NULL, NULL, '{"1": "소변주머니를 방광보다 낮게 두어야 하여 역류하는 소변으로 인해 감염이 발생하지 않도록 예방해야 합니다.\n[정답]", "2": "보행의 편의를 위해 소변주머니를 낮게 두는 것은 주 목적이 아닙니다.", "3": "유치도뇨관이 빠지지 않게 하기 위해서는 주의가 필요하지만, 위치와는 큰 관련이 없습니다.", "4": "냄새의 유출을 방지하는 것도 고려해야 할 사항이나, 주된 이유는 아닙니다.", "5": "연결관이 꺾이지 않게 하는 것은 편의성을 위한 것이나, 감염 예방이 우선입니다."}'::jsonb, '[{"term_ko": "소변주머니", "term_vi": "Túi nước tiểu", "def_ko": "소변을 모으는 주머니", "def_vi": "Túi để chứa nước tiểu"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변이 저장되는 기관", "def_vi": "Cơ quan lưu trữ nước tiểu"}, {"term_ko": "역류", "term_vi": "Trào ngược", "def_ko": "물이 거꾸로 흐르는 현상", "def_vi": "Hiện tượng nước chảy ngược"}, {"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 계속 뽑아내는 도관", "def_vi": "Đường ống để dẫn nước tiểu ra ngoài"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "세균이나 바이러스로 인해 병이 생기는 것", "def_vi": "Bệnh do vi khuẩn hoặc virus gây ra"}, {"term_ko": "냄새", "term_vi": "Mùi hôi", "def_ko": "불쾌한 향기", "def_vi": "Mùi khó chịu"}, {"term_ko": "연결관", "term_vi": "Ống nối", "def_ko": "두 개의 기구를 연결하는 관", "def_vi": "Ống dùng để kết nối hai thiết bị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1289, '10', '대상자가 유치도뇨관을 사용할 때 돕는 방법으로 옳은 것은?', '["소변주머니는 매일 교체한다.", "소변주머니는 방광의 위치보다 낮게 둔다.", "방광에 통증이 오면 즉시 유치도뇨관을 빼준다.", "연결관이 빠지지 않도록 침상에 누워 있게 한다.", "소변주머니에 소변이 고이지 않을 경우 하복부를 눌러준다."]'::jsonb, 2, NULL, NULL, '{"1": "소변주머니는 하루에 한 번 이상 정기적으로 교체해야 하지만, 매일 교체하는 것은 필요하지 않다. \n[정답]", "2": "소변주머니는 방광의 위치보다 낮게 두어야 하여 소변이 자연스럽게 흐를 수 있도록 해야 한다.", "3": "방광에 통증이 올 경우에는 우선적으로 의료진과 상담해야 하며, 즉시 제거하는 것은 바람직하지 않다.", "4": "연결관이 빠지지 않도록 침상에서 안정적으로 지내는 것도 중요하지만, 눕는 것만으로는 부족하다.", "5": "소변주머니에 소변이 고이지 않을 경우 하복부를 눌러주는 것은 부적절한 방법이며, 다른 방안으로 문제를 해결해야 한다."}'::jsonb, '[{"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "방광에 소변을 배출하기 위해 삽입되는 관", "def_vi": "Ống được đưa vào bàng quang để thoát nước tiểu"}, {"term_ko": "소변주머니", "term_vi": "Túi đựng nước tiểu", "def_ko": "소변을 수집하는 주머니", "def_vi": "Túi để thu thập nước tiểu"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "소변이 저장되는 기관", "def_vi": "Cơ quan lưu trữ nước tiểu"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "신체의 고통이나 불편함", "def_vi": "Cơn đau hoặc khó chịu trên cơ thể"}, {"term_ko": "침상", "term_vi": "Giường", "def_ko": "누워 있는 장소", "def_vi": "Nơi để nằm"}, {"term_ko": "하복부", "term_vi": "Hạ bụng", "def_ko": "복부의 아랫부분", "def_vi": "Phần bụng dưới"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1288, '10', '침상에 누워있는 대상자의 기저귀 사용을 돕는 방법은?', '["대상자가 거부하면 교체하지 않는다.", "기저귀를 교환할 때마다 시설장에게 보고한다.", "피부가 붉어진 경우 더운 물주머니를 대어 준다.", "기저귀가 뭉치지 않도록 잘 펴서 둔부를 감싸준다.", "엉덩이에 발적이 있으면 도넛 모양의 베개를 대어 준다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자가 거부하면 기저귀를 교체하지 않으면 안됩니다. 환자의 편안함과 위생을 위해서는 필요한 경우 반드시 교체해야 합니다.\n[정답]", "4": "기저귀를 교환할 때는 누워 있는 대상자의 엉덩이가 아프지 않도록 잘 펴서 감싸주는 것이 매우 중요합니다.", "2": "기저귀 교환 시 시설장에게 보고하는 것은 일반적이지 않으며, 필요할 경우 보호자나 다른 간호 인력에게 보고합니다.", "3": "피부가 붉어진 경우에는 더운 물주머니를 사용하여 마사지할 것이 아니라 적절한 피부 간호를 해야 합니다.", "5": "엉덩이에 발적이 있다고 해서 도넛 모양의 베개를 즉각 대주는 것은 필요한 조치가 아닙니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã lót"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Người nhận điều trị"}, {"term_ko": "엉덩이", "term_vi": "Mông", "def_ko": "엉덩이(한국어)", "def_vi": "Mông"}, {"term_ko": "발적", "term_vi": "Đỏ da", "def_ko": "발적(한국어)", "def_vi": "Đỏ da"}, {"term_ko": "교체", "term_vi": "Thay", "def_ko": "교체하다(한국어)", "def_vi": "Thay thế"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1287, '10', '침상에서 대상자의 기저귀를 교환하는 방법으로 옳은 것은?', '["윗옷을 가슴까지 올리고 바지를 벗긴다.", "무릎을 편 상태에서 허리를 들어 올린다.", "둔부 밑에 새 기저귀의 바깥면이 보이도록 한다.", "기저귀를 교환하는 동안 창문을 열어 환기한다.", "꼬리뼈 부위에 피부 발적이 있는지 살펴본다."]'::jsonb, 5, NULL, NULL, '{"1": "윗옷을 가슴까지 올리고 바지를 벗기는 것은 환자의 편안함을 고려하지 않은 방법입니다.\n[정답]", "5": "꼬리뼈 부위에 피부 발적이 있는지 살펴보는 것은 기저귀 교환 시 중요한 피부 상태 확인 방법입니다.", "2": "무릎을 편 상태에서 허리를 들어 올리는 것은 수동적인 방법이며 환자에게 부담을 줄 수 있습니다.", "3": "둔부 밑에 새 기저귀의 바깥면이 보이도록 한다는 것은 올바른 교환 방법이 아닌 장비 배치의 의미가 아닙니다.", "4": "기저귀를 교환하는 동안 창문을 열어 환기하는 것은 필요할 수도 있으나 안전이나 프라이버시와 관련된 문제를 고려해야 합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã"}, {"term_ko": "꼬리뼈", "term_vi": "Xương cụt", "def_ko": "xương cụt(한국어)", "def_vi": "xương cụt"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "피부(한국어)", "def_vi": "Da"}, {"term_ko": "환기", "term_vi": "Thông gió", "def_ko": "환기(한국어)", "def_vi": "thông gió"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1286, '10', '대상자의 기저귀를 교환하는 방법으로 옳은 것은?', '["기저귀는 정해진 시간에 교환한다.", "이불을 다리 아래로 내린 후에 면덮개를 덮는다.", "기저귀를 교환하는 동안에 문을 열어 환기한다.", "허리를 들 수 있는 대상자는 옆으로 돌려 눕혀 교환한다.", "오염된 기저귀는 바깥 면이 보이도록 말아서 버린다."]'::jsonb, 5, NULL, NULL, '{"1": "기저귀는 주기적으로 교환해야 하지만, 정해진 시간에만 교환하는 것은 적절하지 않습니다.\n[정답]", "5": "오염된 기저귀는 항상 바깥 면이 보이도록 말아서 버려야 합니다. 이는 위생상의 이유로 매우 중요합니다.", "2": "이불을 다리 아래로 내린 후에 면덮개를 덮는 것은 일반적으로 권장하지 않는 방법입니다.", "3": "기저귀를 교환하는 동안 문을 열어 두는 것은 환기를 위해 좋지 않으며, 개인 정보 보호 측면에서도 문제가 됩니다.", "4": "허리를 들 수 있는 대상자는 옆으로 돌려 눕혀 교환하는 것이 올바른 방법입니다. 그러나 이 방식은 대상자의 상태에 따라 다르게 적용될 수 있습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1285, '10', '기저귀를 교환할 때 대상자의 둔부를 가볍게 두드려 마사지하는 이유는?', '["변의 자극", "근육 이완", "욕창 예방", "장운동 촉진", "호르몬 분비 촉진"]'::jsonb, 3, NULL, NULL, '{"1": "변의 자극: 변의 자극을 위한 것이 아니다. \n[정답]", "3": "욕창 예방: 마사지가 둔부의 혈액순환을 도와 욕창을 예방하는 효과가 있다.", "2": "근육 이완: 마사지가 근육 이완의 목적이 아니므로 정답이 아니다.", "4": "장운동 촉진: 장운동 촉진과는 관련이 없다.", "5": "호르몬 분비 촉진: 호르몬 분비와는 관련이 없다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1284, '10', '허리를 들 수 없는 대상자의 기저귀를 교환하는 방법은?', '["둔부는 수시로 알코올 소독 한다.", "둔부를 들어 방수포를 깔아 준다.", "대상자를 옆으로 돌려 눕혀 기저귀를 갈아준다.", "무릎을 세우고 똑바로 누운 상태에서 갈아준다.", "냄새가 나지 않도록 기저귀를 단단히 조인다."]'::jsonb, 3, NULL, NULL, '{"1": "둔부는 수시로 알코올 소독 한다. - 소독은 필요하지만, 허리를 들 수 없는 환자에 대한 적절한 방법이 아닙니다.\n[정답]", "2": "대상자를 옆으로 돌려 눕혀 기저귀를 갈아준다. - 허리를 들 수 없는 경우, 옆으로 눕혀서 기저귀를 교환하는 것이 가장 안전하고 효율적인 방법입니다.", "3": "무릎을 세우고 똑바로 누운 상태에서 갈아준다. - 허리가 불편한 환자에게는 적합하지 않은 방법입니다.", "4": "둔부를 들어 방수포를 깔아 준다. - 둔부를 들어주는 방법은 허리를 들 수 없는 대상자에게 적합하지 않습니다.", "5": "냄새가 나지 않도록 기저귀를 단단히 조인다. - 기저귀의 새는 것을 방지하는 방법은 필요하지만, 이 질문의 주제와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã"}, {"term_ko": "듬부", "term_vi": "Mông", "def_ko": "둔부(한국어)", "def_vi": "mông"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "소독(한국어)", "def_vi": "Khử trùng"}, {"term_ko": "상태", "term_vi": "Tình trạng", "def_ko": "상태(한국어)", "def_vi": "tình trạng"}, {"term_ko": "세우다", "term_vi": "Đứng", "def_ko": "세우다(한국어)", "def_vi": "đứng"}, {"term_ko": "눕다", "term_vi": "Nằm", "def_ko": "눕다(한국어)", "def_vi": "nằm"}, {"term_ko": "방수포", "term_vi": "Tấm trải chống thấm", "def_ko": "방수포(한국어)", "def_vi": "tấm trải chống thấm"}, {"term_ko": "조인다", "term_vi": "Cài", "def_ko": "조인다(한국어)", "def_vi": "cài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1283, '10', '기저귀를 사용하는 대상자를 돕는 방법으로 옳은 것은?', '["둔부에 발적이 있으면 연고를 발라준다.", "둔부주변을 강한 압력으로 마사지해 준다.", "기저귀에 소변이 조금 묻은 경우 말려서 재사용 한다.", "허리를 들 수 없으면 엎드린 채로 기저귀를 교환한다.", "교환 전에 면덮개를 이불 위에 덮은 후 이불만 다리 아래로 내린다."]'::jsonb, 5, NULL, NULL, '{"1": "둔부에 발적이 있을 경우 연고를 발라주는 것은 필요하지만, 대상자를 돕는 방법으로는 적절하지 않습니다.\n[정답]", "5": "면덮개를 이불 위에 덮고 이불만 다리 아래로 내리는 방법은 기저귀 교환 시 안전하고 위생적인 접근법입니다.", "3": "기저귀에 소변이 묻은 경우, 재사용하는 것은 위생적이지 않으므로 옳지 않습니다.", "2": "강한 압력으로 마사지를 하는 것은 피부 손상을 유발할 수 있으므로 바람직하지 않습니다.", "4": "허리를 들 수 없는 경우에는 엎드린 채 기저귀를 교환하는 것은 안전하지 않으며 권장되지 않습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1282, '10', '기저귀를 사용하는 대상자를 돕는 방법은?', '["기저귀를 사용해도 변기 사용을 시도한다.", "회음부는 뒤에서 앞으로 닦아준다.", "물티슈로 닦아내고 바로 기저귀를 채운다.", "하루에 세 번 규칙적으로 기저귀를 갈아준다.", "피부 발적이 보이면 문지르며 마사지해준다."]'::jsonb, 1, NULL, NULL, '{"1": "기저귀를 사용하더라도 변기 사용을 시도할 수 있는 환경을 조성하는 것이 좋습니다.\n[정답]", "2": "회음부는 앞에서 뒤로 닦아야 감염 예방에 도움이 됩니다.", "3": "물티슈로 닦은 후 기저귀를 바로 채우는 것은 올바르지 않으며, 피부 건조가 필요합니다.", "4": "기저귀를 하루에 세 번 갈기보다는 피부 상태에 따라 유동적으로 갈아야 합니다.", "5": "피부 발적이 있을 때는 문지르지 않고, 피부에 적절한 크림을 사용하여 진정시키는 것이 필요합니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "bỉm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1281, '10', '대상자가 몇 번 실금을 했어도 기저귀를 바로 사용하면 안 되는 이유는?', '["욕창이 발생하기 때문에", "움직임이 제한되기 때문에", "기저귀 구입 비용이 부담되기 때문에", "비뇨기계 감염 발생이 우려되기 때문에", "스스로 배설하는 습관이 약화될 수 있기 때문에"]'::jsonb, 5, NULL, NULL, '{"1": "욕창이 발생하기 때문에\n욕창은 기저귀 사용으로 인한 압력이 원인이 될 수 있지만, 실금 여부와 직접적인 관계는 없습니다.\n[정답]", "5": "스스로 배설하는 습관이 약화될 수 있기 때문에\n기저귀를 자주 사용하게 되면 배설의 자연스러운 패턴이 무너질 수 있습니다.", "2": "움직임이 제한되기 때문에\n기저귀 사용이 운동능력을 제한하는 것은 아니므로 해당 이유는 아닙니다.", "3": "기저귀 구입 비용이 부담되기 때문에\n비용 문제는 의학적 결정에 영향을 미치는 주된 요소가 아닙니다.", "4": "비뇨기계 감염 발생이 우려되기 때문에\n비뇨기계 감염은 기저귀 사용의 결과일 수 있지만, 직접적인 실금 상황에서의 이유는 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 자제하지 못하는 상태", "def_vi": "Trạng thái không kiểm soát được việc tiểu tiện"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기용 기저귀", "def_vi": "Tã lót trẻ em"}, {"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부 손상 상태", "def_vi": "Tổn thương da"}, {"term_ko": "배설", "term_vi": "Đi tiểu", "def_ko": "소변 또는 대변을 배출하는 행동", "def_vi": "Hành động đi tiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1280, '10', '대상자가 몇 번 실금을 했어도 기저귀를 바로 사용하면 안 되는 이유는?', '["욕창이 발생하기 때문에", "움직임이 제한되기 때문에", "기저귀 구입 비용이 부담되기 때문에", "비뇨기계 감염 발생이 우려되기 때문에", "스스로 배설하는 습관이 약화될 수 있기 때문에"]'::jsonb, 5, NULL, NULL, '{"1": "욕창이 발생하기 때문에\n기저귀를 사용한다고 해서 바로 욕창이 발생하지는 않는다. 따라서 이 보기는 적절하지 않다.\n[정답]", "5": "스스로 배설하는 습관이 약화될 수 있기 때문에\n기저귀를 자주 사용하면 스스로 배설하는 습관이 약화될 수 있어 정답이다.", "2": "움직임이 제한되기 때문에\n기저귀 사용은 움직임과는 직접적인 관련이 없다.", "3": "기저귀 구입 비용이 부담되기 때문에\n비용 문제는 직접적인 이유가 아니다.", "4": "비뇨기계 감염 발생이 우려되기 때문에\n기저귀 사용이 꼭 비뇨기계 감염을 유발한다고 할 수 없다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Bỉm", "def_ko": "기저귀(한국어)", "def_vi": "Bỉm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1279, '10', '기저귀가 젖었을 때 속히 갈아주어야 하는 이유는?', '["혈액순환을 촉진하기 위해", "요실금 횟수를 줄이기 위해", "피부 손상을 예방하기 위해", "기저귀 의존성을 줄이기 위해", "체온이 떨어지는 것을 막기 위해"]'::jsonb, 3, NULL, NULL, '{"1": "혈액순환을 촉진하기 위해: 기저귀 갈기는 혈액순환과 직접적으로 관련이 없습니다.\n[정답]", "3": "피부 손상을 예방하기 위해: 기저귀가 젖으면 피부에 자극이 되고 손상을 줄 수 있으므로, 이로 인해 빠른 교체가 필요합니다.", "2": "요실금 횟수를 줄이기 위해: 기저귀 교체는 요실금 관리를 위한 것이 아닙니다.", "4": "기저귀 의존성을 줄이기 위해: 기저귀 교체는 의존성과는 관련이 없습니다.", "5": "체온이 떨어지는 것을 막기 위해: 기저귀 교체는 체온 유지와 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1278, '10', '기저귀를 장시간 교체하지 않을 경우 대상자에게 발생할 수 있는 질환은?', '["건선", "대상포진", "피부발적", "건조증", "아토피 피부염"]'::jsonb, 3, NULL, NULL, '{"1": "건선: 만성 염증성 피부 질환으로, 기저귀와는 관련이 없다.\n[정답]", "3": "피부발적: 장시간 기저귀를 착용하면 피부가 자극을 받아 발적이 발생할 수 있다.", "2": "대상포진: 바이러스성 질환으로 기저귀와는 관련이 없다.", "4": "건조증: 주로 수분 부족으로 발생하며, 기저귀 사용과 직접적인 연관은 없다.", "5": "아토피 피부염: 알레르기성 피부 질환이지만 기저귀 사용으로 인해 직접적으로 발생하지 않는다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "tã(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1277, '10', '대상자가 장기적으로 기저귀를 사용할 때 돕는 방법으로 옳은 것은?', '["오염된 둔부는 마른 수건으로 닦고 건조시킨다.", "피부발적, 상처, 통증을 호소하는지 살핀다.", "환기를 위해 창문을 열고 교체한다.", "하루 세 번 정해진 시간에 갈아준다.", "피부 상태를 확인하기 위해 하의를 벗겨둔다."]'::jsonb, 2, NULL, NULL, '{"1": "오염된 둔부는 마른 수건으로 닦고 건조시킨다는 것은 부적절한 방법입니다. 적절한 세정이 필요합니다.\n[정답]", "2": "피부발적, 상처, 통증을 호소하는지를 살핀다는 것은 매우 중요한 관리 방법입니다.", "3": "환기를 위해 창문을 열고 교체하는 것은 상황에 따라 필요할 수 있지만, 직접적인 기저귀 교체 방법은 아닙니다.", "4": "하루 세 번 정해진 시간에 갈아주는 것은 각 대상자의 상태에 따라 다를 수 있습니다.", "5": "피부 상태를 확인하기 위해 하의를 벗겨둔다면 불필요한 노출이 될 수 있어 주의해야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1276, '10', '누워있는 대상자의 기저귀 사용을 돕는 방법으로 옳은 것은?', '["대상자가 실금하면 바로 기저귀를 채운다.", "기저귀를 한 번 사용하면 계속 채운다.", "젖은 기저귀 안에 속 기저귀를 덧대어 준다.", "배뇨, 배변 시간에 맞추어 기저귀를 자주 살펴본다.", "기저귀를 깨끗이 갈아주기 위해서 최대한 신체노출을 한다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자가 실금하면 즉시 기저귀를 채우는 것은 맞지 않으며, 우선 청결과 안전을 고려해야 합니다.\n[정답]", "4": "배뇨, 배변 시간에 맞추어 기저귀를 자주 살펴보는 것이 올바른 방법입니다.", "2": "한 번 사용한 기저귀를 계속 사용하는 것은 위생적으로 바람직하지 않습니다.", "3": "젖은 기저귀 안에 속 기저귀를 덧대어 주는 것은 불쾌감을 초래할 수 있으며, 권장되지 않습니다.", "5": "기저귀를 갈아주기 위해 최대한 신체노출을 하는 것은 대상자의 사생활을 존중하지 않는 행동입니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "속옷(한국어)", "def_vi": "Tã của người dùng"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Người bệnh"}, {"term_ko": "실금", "term_vi": "Tiểu không kiểm soát", "def_ko": "소변 누출(한국어)", "def_vi": "Sự mất kiểm soát khi tiểu tiện"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 행위(한국어)", "def_vi": "Hành động đi tiểu"}, {"term_ko": "청결", "term_vi": "Sạch sẽ", "def_ko": "깨끗한 상태(한국어)", "def_vi": "Trạng thái sạch sẽ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1275, '10', '기저귀 사용 돕기 중 기저귀를 채우는 시점으로 옳은 것은?', '["배설욕구를 전혀 느끼지 못하는 경우", "화장실에 가기 싫어하는 경우", "실금이 가끔씩 나타나는 경우", "약간의 도움으로 이동이 가능한 경우", "다리부상으로 허리를 들 수 있는 경우"]'::jsonb, 1, NULL, NULL, '{"1": "기저귀를 채우는 핵심 조건으로, 배설욕구를 전혀 느끼지 못하는 경우에는 기저귀 사용이 필수적입니다.\n[정답]", "2": "화장실에 가기 싫어하는 경우는 기저귀 사용을 정당화하지 않는 상황입니다.", "3": "실금이 가끔씩 나타나는 경우는 기저귀 사용을 고려해야 하나, 항상 필요한 것은 아닙니다.", "4": "약간의 도움으로 이동이 가능한 경우는 화장실 이용이 가능할 수 있어 기저귀 사용의 필요성이 낮아집니다.", "5": "다리부상으로 허리를 들 수 있는 경우도 화장실에 갈 수 있는지의 여부에 따라 기저귀 필요성이 달라질 수 있습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1274, '10', '편마비 대상자의 이동변기 사용을 돕는 순서로 옳은 것은?가. 배설 중에 하반신을 수건이나 무릎덮개로 덮어준다. 나. 커튼이나 스크린으로 가려준다. 다. 이동변기를 대상자의 건강한 쪽에 붙인다. 라. 침대 높이와 이동변기의 높이가 같도록 맞춘다.', '["가 - 나 - 다 - 라", "나- 라 - 다 - 가", "나 - 다 - 라 - 가", "다 - 가 - 라 - 나", "라 - 나 - 다 - 가"]'::jsonb, 2, NULL, NULL, '{"1": "배설 중 개인의 사생활을 존중하기 위해 하반신을 덮어주는 것은 중요하다.\n[정답]", "2": "배설을 할 때 커튼이나 스크린으로 가려서 사생활을 보호하는 것이 우선이다.", "3": "건강한 쪽에 이동변기를 붙이는 것은 대상자의 편안함과 안정성을 증가시킨다.", "4": "침대 높이와 이동변기의 높이를 맞추는 것은 물리적 이동을 용이하게 하여 안전성을 높인다.", "5": "순서대로 진행되는 것이 아니라, 상황별로 적절한 조치를 취해야 한다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1273, '10', '오른쪽 편마비 대상자의 이동변기 사용을 돕는 방법은?', '["대상자의 오른쪽에 이동변기를 놓는다.", "이동변기 밑에 작은 수건을 깔아준다.", "변기 손잡이를 오른손으로 잡게 한다.", "이동변기를 조절하여 두 발이 바닥에 닿게 한다.", "배설 중에는 몸이 기울지 않도록 왼쪽을 지지해준다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 오른쪽에 이동변기를 놓는 것은 편마비 환자에게 오히려 불편을 줄 수 있습니다.\n[정답]", "4": "이동변기를 조절하여 두 발이 바닥에 닿게 하는 것은 안정적인 자세를 유지하도록 도와주는 중요한 방법입니다.", "2": "이동변기 밑에 작은 수건을 깔아주는 것은 청결을 유지하는 방법일 수 있지만, 이동변기 사용을 직접 도와주기 위한 방법은 아닙니다.", "3": "변기 손잡이를 오른손으로 잡게 하는 것은 오른쪽 편마비 대상자에게는 도움이 되지 않습니다.", "5": "배설 중 몸이 기울지 않도록 왼쪽을 지지해주는 것은 좋지만, 이동변기를 올바로 조정하는 것이 더 중요합니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔과 다리에 힘이 없고 움직이지 못하는 상태", "def_vi": "Tình trạng không có sức và không thể di chuyển một bên cánh tay và chân"}, {"term_ko": "이동변기", "term_vi": "Bồn cầu di động", "def_ko": "이동식 화장실", "def_vi": "Cái bồn cầu có thể di chuyển"}, {"term_ko": "손잡이", "term_vi": "Tay nắm", "def_ko": "잡을 수 있는 부분", "def_vi": "Phần để có thể cầm"}, {"term_ko": "배설", "term_vi": "Đại tiện", "def_ko": "소변 또는 대변을 보는 행위", "def_vi": "Hành động đi vệ sinh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1272, '10', '대상자의 이동변기 사용을 돕는 방법으로 옳은 것은?', '["이동변기는 하루에 한번 세척한다.", "수치심을 일으키지 않도록 스크린을 설치해준다.", "배변 중 환기를 위해 창문을 열어 둔다.", "대상자의 두 발이 바닥에 닿지 않게 한다.", "배설 시 조용한 환경을 만들어 준다."]'::jsonb, 2, NULL, NULL, '{"1": "이동변기는 청결 유지를 위해 필요한 빈도에 따라 세척해야 합니다. 하루에 한 번만 세척하는 것은 부족할 수 있습니다.\n[정답]", "2": "수치심을 줄이기 위해 스크린을 설치하는 것은 매우 중요합니다. 이는 대상자가 보다 편안하게 배변할 수 있도록 도와줍니다.", "3": "배변 중 환기를 위해 창문을 여는 것은 허용될 수 있지만, 환자의 안전과 사생활을 고려해야 합니다.", "4": "대상자의 두 발이 바닥에 닿지 않도록 하려면 안전한 자세를 유지하기 어려울 수 있으므로, 바닥에 닿게 하는 것이 바람직합니다.", "5": "배설 시 조용한 환경을 제공하는 것도 중요하지만, 이 문제에서 가장 핵심적인 지원 방법은 아닌 것으로 보입니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bô di động", "def_ko": "이동 가능한 화장실", "def_vi": "Nhà vệ sinh di động"}, {"term_ko": "수치심", "term_vi": "Cảm giác xấu hổ", "def_ko": "부끄러움, 창피함", "def_vi": "Sự xấu hổ"}, {"term_ko": "스크린", "term_vi": "Màn chắn", "def_ko": "분리막", "def_vi": "Màn ngăn"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "환경", "def_vi": "Môi trường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1271, '10', '편마비 대상자의 이동변기 사용을 돕는 방법으로 옳은 것은?', '["변기는 불편한 쪽으로 45도 각도로 놓는다.", "이동변기 앞에 미끄럼방지 매트를 깔아 둔다.", "침대와 변기의 높이가 같도록 맞춰준다.", "차가운 물을 끼얹어 변의를 자극한다.", "배설 후에는 물티슈로 손을 닦게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "변기를 불편한 쪽으로 45도 각도로 놓는 것은 오히려 안전하지 않을 수 있다.\n[정답]", "2": "이동변기 앞에 미끄럼방지 매트를 깔아 두는 것은 안전을 위해 중요하지만 정답이 아니다.", "3": "침대와 변기의 높이가 같도록 맞춰주는 것이 편마비 대상자가 이동변기를 사용할 때 가장 안전하고 편리하다.", "4": "차가운 물을 끼얹어 변의를 자극하는 것은 비인간적이며 건강에 해로울 수 있다.", "5": "배설 후에는 물티슈로 손을 닦는 것은 위생적이지 않으며, 손 씻기가 더 바람직하다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "반쪽 몸이 마비된 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}, {"term_ko": "이동변기", "term_vi": "Bồn vệ sinh di động", "def_ko": "이동용 화장실", "def_vi": "Nhà vệ sinh di động"}, {"term_ko": "미끄럼방지 매트", "term_vi": "Thảm chống trượt", "def_ko": "미끄럼 방지를 위한 매트", "def_vi": "Thảm chống trượt"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "소변과 대변의 배출", "def_vi": "Sự bài tiết"}, {"term_ko": "물티슈", "term_vi": "Khăn ướt", "def_ko": "물로 적신 티슈", "def_vi": "Khăn thấm nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1270, '10', '이동변기 사용 돕기의 방법으로 옳은 것은?', '["배변하는 동안 계속 말을 건다.", "이동변기 밑에 미끄럼방지 매트를 깐다.", "이동변기는 침대와 90도가 되도록 놓는다.", "배설 중에는 하반신을 노출시킨다.", "배설 후 냄새가 나지 않도록 뚜껑을 닫아 둔다."]'::jsonb, 2, NULL, NULL, '{"1": "배변하는 동안 말을 건 것은 오히려 환자의 집중을 방해할 수 있습니다.\n[정답]", "2": "이동변기 밑에 미끄럼방지 매트를 깔면 안전성을 높이고 사고를 예방할 수 있습니다.", "3": "이동변기는 침대와 90도가 아닌 가까운 위치에 두어야 안전합니다.", "4": "배설 중 하반신을 노출시키는 것은 프라이버시를 침해할 수 있습니다.", "5": "배설 후 냄새를 줄이기 위해 뚜껑을 닫는 것은 좋지만, 이동변기의 적절한 사용을 돕기 위한 방법이 아닙니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bồn vệ sinh di động", "def_ko": "이동에 용이한 변기", "def_vi": "Bồn vệ sinh dễ di chuyển"}, {"term_ko": "미끄럼방지", "term_vi": "Chống trượt", "def_ko": "미끄럽지 않도록 하는 것", "def_vi": "Làm không trơn trượt"}, {"term_ko": "배설", "term_vi": "Đi vệ sinh", "def_ko": "대변을 보는 것", "def_vi": "Đi đại tiện"}, {"term_ko": "프라이버시", "term_vi": "Quyền riêng tư", "def_ko": "개인적인 공간", "def_vi": "Không gian cá nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1269, '10', '배설이 어려울 때 미지근한 물을 항문이나 요도에 흘려주는 이유는?', '["청결하게 하기 위해서", "냄새를 제거하기 위해서", "수치심을 줄이기 위해서", "배변 후 닦기 쉽게 하기 위해서", "괄약근을 이완시켜 변의를 자극하기 위해서"]'::jsonb, 5, NULL, NULL, '{"1": "청결하게 하기 위해서: 미지근한 물을 흘려주는 주된 이유는 아니다.\n[정답]", "5": "괄약근을 이완시켜 변의를 자극하기 위해서: 이 경우가 가장 적절한 이유이다.", "2": "냄새를 제거하기 위해서: 냄새 제거는 미지근한 물을 사용하는 주요 목적이 아니다.", "3": "수치심을 줄이기 위해서: 수치심 경감도 직접적인 목적이 아니다.", "4": "배변 후 닦기 쉽게 하기 위해서: 배변 후의 청결과는 관련이 있지만, 이 질문의 목적과는 다르다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "대소변을 배출하는 것", "def_vi": "Việc thải chất thải ra ngoài cơ thể"}, {"term_ko": "미지근한", "term_vi": "Ấm áp", "def_ko": "약간 따뜻한", "def_vi": "Hơi ấm"}, {"term_ko": "항문", "term_vi": "Hậu môn", "def_ko": "대변이 나오는 구멍", "def_vi": "Lỗ ra của phân"}, {"term_ko": "요도", "term_vi": "Niệu đạo", "def_ko": "소변이 나오는 구멍", "def_vi": "Lỗ ra của nước tiểu"}, {"term_ko": "괄약근", "term_vi": "Cơ vòng", "def_ko": "배변과 배뇨를 조절하는 근육", "def_vi": "Cơ điều tiết việc đi vệ sinh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1268, '10', '다음과 같은 대상자에게 가장 좋은 배설 돕기 방법은?서서나 앉는 것은 가능하지만 화장실까지 걷기 어려운 대상자', '["화장실 사용 돕기", "기저귀 사용 돕기", "침상배설 돕기", "이동 변기 사용 돕기", "유치도뇨관 사용 돕기"]'::jsonb, 4, NULL, NULL, NULL, NULL) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1267, '10', '이동변기를 사용하는 대상자를 돕는 방법으로 옳은 것은?', '["침대높이보다 이동변기를 낮게 한다.", "변기를 차가운 수건으로 닦아준다.", "배설물은 모아서 한꺼번에 버린다.", "요의를 호소할 때 즉시 배설할 수 있도록 돕는다.", "배설이 끝날 때까지 옆에서 지켜본다."]'::jsonb, 4, NULL, NULL, '{"1": "이동변기를 침대보다 낮게 설정하면 대상자가 안전하게 사용할 수 없습니다.\n[정답]", "4": "요의를 호소할 때 즉시 배설할 수 있도록 돕는 것이 가장 올바른 방법입니다.", "2": "차가운 수건으로 변기를 닦는 것은 위생적으로 좋지 않습니다.", "3": "배설물을 한꺼번에 버리는 것은 위생상 좋지 않습니다.", "5": "배설이 끝날 때까지 옆에서 지켜보는 것은 개인의 사생활을 침해할 수 있습니다."}'::jsonb, '[{"term_ko": "이동변기", "term_vi": "Bồn vệ sinh di động", "def_ko": "이동 가능한 변기", "def_vi": "Bồn vệ sinh có thể di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1266, '10', '대상자의 배설 도움 시 비뇨기계 감염이 발생할 우려가 있는 상황은?', '["매일 수분을 충분히 섭취하게 한다.", "소변주머니를 방광보다 낮은 위치에 둔다.", "항문을 닦을 때에는 앞에서 뒤로 닦아 준다.", "배설물을 처리하기 전과 후에는 손을 씻는다.", "소변이 자주 마려워도 하루에 세 번 규칙적으로 보게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "매일 수분을 충분히 섭취하게 하는 것은 오히려 비뇨기계 감염 예방에 도움이 된다.", "2": "소변주머니를 방광보다 낮은 위치에 두는 것은 감염 예방을 위한 올바른 방법이다.", "3": "항문을 닦을 때에는 앞에서 뒤로 닦아 주는 것이 감염 예방에 중요하다.", "4": "배설물을 처리하기 전과 후에는 손을 씻는 것은 기본적인 위생 수칙이다.\n[정답]", "5": "소변이 자주 마려워도 하루에 세 번 규칙적으로 보게 하는 것은 사실, 잦은 배뇨는 감염의 위험을 높일 수 있다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "배뇨 혹은 대변을 배출하는 행위", "def_vi": "Hành động bài tiết nước tiểu hoặc phân"}, {"term_ko": "비뇨기계", "term_vi": "Hệ tiết niệu", "def_ko": "소변을 형성하고 배설하는 기관의 시스템", "def_vi": "Hệ thống cơ quan hình thành và bài tiết nước tiểu"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "병원체가 체내에 침입하여 발생하는 질병 상태", "def_vi": "Tình trạng bệnh tật do mầm bệnh xâm nhập vào cơ thể"}, {"term_ko": "위생", "term_vi": "Vệ sinh", "def_ko": "청결을 유지하여 질병을 예방하는 방법", "def_vi": "Phương pháp giữ gìn sạch sẽ để ngăn ngừa bệnh tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1265, '10', '배설물의 특이사항으로 간호사에게 보고해야 할 사항은?가. 점액질이 섞인 대변 나. 거품이 있는 소변 다. 냄새가 심한 소변 라. 황금색의 굵은 대변', '["가,나,라", "가,다,라", "가,나,다", "나,다,라", "가,나,다,라"]'::jsonb, 3, NULL, NULL, '{"1": "점액질이 섞인 대변은 소화기관의 이상을 나타낼 수 있으므로 보고할 필요가 있습니다.\n[정답]", "3": "거품이 있는 소변은 신장 또는 대사적 문제가 있을 수 있으므로 반드시 보고해야 합니다.\n냄새가 심한 소변은 탈수나 감염 등의 가능성이 있으나 긴급하게 보고할 상황은 아닙니다.\n황금색의 굵은 대변은 정상적인 소화 상태를 나타내므로 보고할 필요가 없습니다."}'::jsonb, '[{"term_ko": "배설물", "term_vi": "Chất thải", "def_ko": "배설된 물질(한국어)", "def_vi": "Vật chất được đưa ra khỏi cơ thể"}, {"term_ko": "특이사항", "term_vi": "Đặc điểm đặc biệt", "def_ko": "다른 것과 다른 특성(한국어)", "def_vi": "Tính chất khác với những cái khác"}, {"term_ko": "거품", "term_vi": "Bọt", "def_ko": "둥글고 공기 방울이 있는 것(한국어)", "def_vi": "Vật tròn có bọt khí bên trong"}, {"term_ko": "황금색", "term_vi": "Màu vàng kim", "def_ko": "금빛의 색 (한국어)", "def_vi": "Màu sắc của vàng"}, {"term_ko": "굵은", "term_vi": "Dày", "def_ko": "두껍고 튼튼한 것(한국어)", "def_vi": "Dày và chắc"}, {"term_ko": "냄새", "term_vi": "Mùi", "def_ko": "물체가 발산하는 기체의 특성(한국어)", "def_vi": "Tính chất của khí tỏa ra từ vật thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1264, '10', '침상 배설을 돕는 방법 중 옳은 것은?', '["잦은 배변 시에는 식사량을 줄인다.", "변기를 찬 수건으로 닦은 후 대준다.", "배변 중 창문을 열어둔다.", "배변이 끝나면 침대 머리를 높인다.", "배변 후 대상자의 손을 씻게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "잦은 배변 시 식사량을 줄이는 것은 잘못된 접근입니다. 배변에 영향을 주기보다는 적절한 식사량이 중요합니다.", "2": "변기를 찬 수건으로 닦는 것은 위생적이지 않으며, 매번 깨끗하게 소독해야 합니다.", "3": "배변 중 창문을 열어두는 것은 사생활 보호를 해치고 대상자에게 불편을 줄 수 있습니다.", "4": "배변이 끝난 후 침대 머리를 높인다는 것은 일반적인 방법이 아니며, 오히려 불편할 수 있습니다.\n[정답]", "5": "배변 후 대상자의 손을 씻게 하는 것은 위생을 고려한 올바른 방법입니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대", "def_vi": "Giường ngủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1263, '10', '편마비 대상자의 침상 배설을 돕는 방법은?', '["소변을 참지 못하고 실금하면 기저귀를 채운다.", "배설하지 못했으면 변의가 생길 때 다시 대어 준다.", "변의가 생기도록 찬 수건으로 항문 주위를 자극한다.", "건강한 쪽으로 돌려 눕혀 힘주기 쉬운 자세를 취하게 한다.", "점액질이 섞인 배설물은대상자에게 확인시킨 후 버린다."]'::jsonb, 2, NULL, NULL, '{"1": "소변을 참지 못하고 실금하면 기저귀를 채우는 것은 필요할 수 있지만, 배설을 돕는 방법으로는 부적절합니다.\n[정답]", "2": "배설하지 못했으면 변의가 생길 때 다시 대어 주는 것은 올바른 행동입니다.", "3": "변의가 생기도록 찬 수건으로 항문 주위를 자극하는 것은 부적절한 방법입니다.", "4": "건강한 쪽으로 돌려 눕혀 힘주기 쉬운 자세를 취하게 하는 것은 도움이 될 수 있지만, 변의가 생길 때를 고려해야 합니다.", "5": "점액질이 섞인 배설물은 대상자에게 확인시킨 후 버리는 것은 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 팔과 다리에 힘이 없거나 마비된 상태", "def_vi": "Trạng thái không có sức mạnh hoặc bị liệt ở một bên tay và chân"}, {"term_ko": "배설", "term_vi": "Đi vệ sinh", "def_ko": "신체의 노폐물을 내보내는 행위", "def_vi": "Hành động thải chất thải ra khỏi cơ thể"}, {"term_ko": "변의", "term_vi": "Cảm giác đi vệ sinh", "def_ko": "대변을 보고싶은 느낌", "def_vi": "Cảm giác muốn đi vệ sinh"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "배설할 때 사용하는 일회용 또는 세탁 가능한 보호 용품", "def_vi": "Đồ bảo vệ dùng khi đi vệ sinh, có thể là một lần hoặc giặt lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1262, '10', '침상에서 배설하는 대상자를 돕는 방법으로 옳은 것은?', '["대상자가 스스로 변기 위에 앉게 한다.", "침상머리를 올려 좌위를 취하게 한다.", "변기 놓을 자리에 젖은 수건을 깔아 준다.", "변의가 확실하지 않으면 변기를 장시간 대어 준다.", "협조할 수 없는 대상자는 무릎을 세우고 엉덩이를 들게 하여 변기를 대준다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자가 스스로 변기 위에 앉는 것은 자립성을 돕는 방법이지만, 현재 상황에서는 적절하지 않습니다.\n[정답]", "2": "침상머리를 올려 좌위를 취하게 하는 것은 배변을 용이하게 도와주며 올바른 방법입니다.", "3": "변기 놓을 자리에 젖은 수건을 깔아주는 것은 위생적이지 않으며 바람직하지 않습니다.", "4": "변의가 확실하지 않으면 변기를 장시간 대어 주는 것은 불편함을 초래할 수 있습니다.", "5": "협조할 수 없는 대상자를 위해 무릎을 세우고 엉덩이를 들게 하는 방법은 오히려 위험할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 환자와 돌봄 대상", "def_vi": "bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1261, '10', '간이변기를 사용하여 침상 배설하는 대상자를 돕는 방법은?', '["간이변기는 세척하여 침상 위에 놓아둔다.", "간이변기 옆에 미끄럼방지 매트를 깔아 준다.", "엉덩이 밑에 방수포를 깔고 간이변기를 대어 준다.", "변기를 침대 난간과 90도가 되게 놓은 후 대상자를 앉힌다.", "협조할 수 없는 대상자는 옆으로 누운 상태로 변기를 사용한다."]'::jsonb, 3, NULL, NULL, '{"1": "간이변기를 세척하여 침상 위에 놓아두는 것은 비위생적이며 바람직하지 않다.\n[정답]", "2": "엉덩이 밑에 방수포를 깔고 간이변기를 대어 주는 것은 환자의 편안함과 청결을 유지하는 방법이다.", "3": "변기를 침대 난간과 90도가 되게 놓은 후 대상자를 앉히는 것은 불안정할 수 있어 위험하다.", "4": "협조할 수 없는 대상자는 옆으로 누운 상태로 변기를 사용하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "간이변기", "term_vi": "Bệ ngồi toilet di động", "def_ko": "임시 사용을 위한 변기", "def_vi": "Bồn cầu tạm thời"}, {"term_ko": "방수포", "term_vi": "Tấm nhựa chống thấm", "def_ko": "물이 스며들지 않는 포", "def_vi": "Vật liệu không thấm nước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1260, '10', '대상자의 침상 배설을 돕기 위한 방법으로 옳은 것은?', '["대사앚가 협조할 수 없으면 기저귀를 채운다.", "차가운 변기를 대주어 변의를 자극한다.", "찬물을 항문에 끼얹어 배설을 빨리하게 한다.", "침대를 올려주어 배에 힘을 주기 쉬운 자세를 취해준다.", "스크린을 치운 후 옷을 입혀준다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자가 협조할 수 없으면 기저귀를 채운다.", "2": "차가운 변기를 대주어 변의를 자극한다.", "3": "찬물을 항문에 끼얹어 배설을 빨리하게 한다.\n[정답]", "4": "침대를 올려주어 배에 힘을 주기 쉬운 자세를 취해준다.", "5": "스크린을 치운 후 옷을 입혀준다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 고객", "def_vi": "Bệnh nhân, khách hàng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1259, '10', '침상 배설을 돕는 방법으로 옳은 것은?', '["힘을 주기 쉽게 침대 머리를 낮춰준다.", "비언어적 표현에는 대응하지 않는다.", "소변이 튀지 않도록 회음부에 화장지를 댄다.", "항문부위를 물수건으로 닦은 후 바지를 입힌다.", "편안한 배설을 위해 최대한 노출을 한다."]'::jsonb, 3, NULL, NULL, '{"1": "힘을 주기 쉽게 침대 머리를 낮추는 방법은 일반적으로 옳지 않다.\n[정답]", "3": "소변이 튀지 않도록 회음부에 화장지를 대는 것은 적절한 배설 보조 방법이다.", "2": "비언어적 표현에는 대응하지 않는 것은 올바른 접근이 아니다.", "4": "항문부위를 물수건으로 닦는 것보다 더 신중하고 위생적인 방법이 필요하다.", "5": "편안한 배설을 위해 최대한 노출을 하는 것은 오히려 환자를 불편하게 할 수 있다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1258, '10', '침상 배설을 돕는 방법으로 옳은 것은?', '["무릎 아래에 방수포를 깐다.", "소리 나는 것을 방지하기 위해 변기에 물을 채운다.", "대상자가 협조할 수 없는 경우 방수포를 깔지 않는다.", "바지를 내린 후 허리 아래쪽에 무릎덮개를 덮어준다.", "변기 중앙에 항문이 오도록 변기를 밀어 넣는다."]'::jsonb, 5, NULL, NULL, '{"1": "무릎 아래에 방수포를 깔면 불필요한 오염을 줄일 수 있으나, 상황에 따라 다를 수 있다.\n[정답]", "5": "변기 중앙에 항문이 오도록 변기를 밀어 넣는 것이 적절한 방법이다.", "2": "소리 나는 것을 방지하기 위해 변기에 물을 채우는 것은 잘못된 방법이다.", "3": "대상자가 협조할 수 없는 경우에도 방수포를 깔아야 한다.", "4": "바지를 내린 후 허리 아래쪽에 무릎덮개를 덮어주는 것은 잘못된 처치 방법이다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대 위", "def_vi": "trên giường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1257, '10', '여성 대상자가 침상 배뇨를 할 때 소리로 인한 수치심을 덜 느끼도록 돕는 방법은?', '["변기에 물을 채운다.", "음악을 틀어준다.", "무릎에 담요를 덮어준다.", "변기 아래에 방수포를 깔아준다.", "수건을 말아 허리 밑에 대준다."]'::jsonb, 2, NULL, NULL, '{"1": "변기에 물을 채우면 소리가 줄어들지만 수치심을 덜 느끼게 하는 방법이 아님.\n[정답]", "2": "음악을 틀어주면 소음으로 인해 수치심을 덜 느끼게 할 수 있다.", "3": "무릎에 담요를 덮어주는 것은 체온 유지에는 도움이 되지만 수치심 해소와는 관련이 없다.", "4": "변기 아래에 방수포를 깔아주는 것은 안전성을 높일 수 있지만 수치심과는 무관하다.", "5": "수건을 말아 허리 밑에 대주는 것은 편안함을 주겠지만 수치심 해소에는 기여하지 않는다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대 위", "def_vi": "trên giường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1256, '10', '변기를 따뜻하게 데워주는 이유는?', '["피부발진을 예방하기 위해", "항문 괄약근을 이완시키기 위해", "요실금을 예방하기 위해", "수치심을 줄이기 위해", "치질을 예방하기 위해"]'::jsonb, 2, NULL, NULL, '{"1": "피부발진을 예방하기 위해: 온도가 피부 발진 예방과 직접적인 연관이 없습니다.\n[정답]", "2": "항문 괄약근을 이완시키기 위해: 따뜻한 온도가 항문 괄약근을 이완시켜 배변을 용이하게 합니다.", "3": "요실금을 예방하기 위해: 요실금 예방과는 관련이 없습니다.", "4": "수치심을 줄이기 위해: 온도가 수치심에 영향을 미치지 않습니다.", "5": "치질을 예방하기 위해: 치질 예방과 연관된 효과는 없습니다."}'::jsonb, '[{"term_ko": "변기", "term_vi": "Bệ ngồi", "def_ko": "화장실에서 사용하는 기구", "def_vi": "Thiết bị sử dụng trong nhà vệ sinh"}, {"term_ko": "따뜻하게", "term_vi": "Làm ấm", "def_ko": "따뜻한 상태로 만들다", "def_vi": "Tạo ra trạng thái ấm"}, {"term_ko": "항문", "term_vi": "Hậu môn", "def_ko": "대변을 배출하는 곳", "def_vi": "Nơi bài tiết phân"}, {"term_ko": "괄약근", "term_vi": "Cơ vòng", "def_ko": "근육으로 이루어진 고리 구조", "def_vi": "Cấu trúc vòng được tạo thành từ cơ"}, {"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "소변을 조절하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được tiểu tiện"}, {"term_ko": "치질", "term_vi": "Trĩ", "def_ko": "항문 주위의 정맥이 부풀어 올라 아픈 상태", "def_vi": "Tình trạng tĩnh mạch quanh hậu môn phình ra và gây đau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1255, '10', '누워있는 대상자의 침상 배설을 돕는 방법으로 옳은 것은?', '["간이변기 사용 직후에 기저귀를 채워준다.", "조용한 환경에서 배설할 수 있게 한다.", "상태를 살피기 위해 스크린을 열어둔다.", "변기는 따뜻하게 데워서 사용한다.", "배설 후 뒤에서 앞으로 닦는다."]'::jsonb, 4, NULL, NULL, '{"1": "간이변기 사용 직후에 기저귀를 채워주는 것은 바람직하지 않습니다.\n[정답]", "2": "조용한 환경에서 배설할 수 있게 하는 것은 중요하고 옳은 방법입니다.", "3": "상태를 살피기 위해 스크린을 열어두는 것은 사생활 보호에 반하는 행동입니다.", "4": "변기는 따뜻하게 데워서 사용해야 대하죠. 이는 대비세를 감소시킬 수 있습니다.", "5": "배설 후 닦는 방향은 앞에서 뒤로가 아니라, 뒤에서 앞으로가 올바릅니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 응급환자, 간병 대상자", "def_vi": "Bệnh nhân, Người được chăm sóc, Người bệnh khẩn cấp"}, {"term_ko": "침상", "term_vi": "Giường bệnh", "def_ko": "병상의 침대", "def_vi": "Giường nằm"}, {"term_ko": "배설", "term_vi": "Tiểu tiện", "def_ko": "대변과 소변을 배출하다.", "def_vi": "Đáh bài tiểu"}, {"term_ko": "변기", "term_vi": "Bồn cầu", "def_ko": "화장실의 설비", "def_vi": "Thiết bị trong nhà vệ sinh"}, {"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "아기가 사용하는 기저귀", "def_vi": "Tã cho trẻ em"}, {"term_ko": "환경", "term_vi": "Môi trường", "def_ko": "주변의 상태", "def_vi": "Tình trạng xung quanh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1254, '10', '침상 배설을 도울 때 제일 먼저 해야 하는 것은?', '["TV를 켜거나 음악을 틀어놓는다.", "커튼이나 스크린으로 가린다.", "대상자를 확인하고 절차를 설명한다.", "일회용 장갑을 착용한다.", "따뜻한 물로 변기를 데워놓는다."]'::jsonb, 3, NULL, NULL, '{"1": "TV를 켜거나 음악을 틀어놓는 것은 집중이 필요한 상황에서 부적절한 행동입니다.\n[정답]", "3": "대상자를 확인하고 절차를 설명하는 것이 가장 우선되어야 합니다.", "2": "커튼이나 스크린으로 가리는 것은 사생활 보호를 위한 단계입니다.", "4": "일회용 장갑을 착용하는 것은 위생을 위해 필요하지만, 사전에 대상자를 확인하는 것이 먼저입니다.", "5": "따뜻한 물로 변기를 데워놓는 것은 편안함을 위한 조치이지만, 가장 먼저 할 일은 아닙니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대 위", "def_vi": "Trên giường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1253, '10', '나도 모르게 오줌이 나와 속옷이 자꾸 젖어요라고 호소하는 대상자를 돕는 방법으로 옳은 것은?', '["기저귀를 채운다.", "배뇨 훈련에 참여하도록 격려한다.", "수분 섭취량을 줄인다.", "변기에 오랫동안 앉아있게 한다.", "복부에 얼음주머니를 대준다."]'::jsonb, 2, NULL, NULL, '{"1": "기저귀를 채우는 것은 일시적인 해결책일 뿐, 근본적인 문제 해결이 아닙니다.\n[정답]", "2": "배뇨 훈련에 참여하도록 격려하는 것은 장기적으로 도움이 되는 방법입니다.", "3": "수분 섭취량을 줄이는 것은 건강에 해로울 수 있으며, 문제가 해결되지 않을 수 있습니다.", "4": "변기에 오랫동안 앉게 하는 것은 불편함을 증가시킬 수 있습니다.", "5": "복부에 얼음주머니를 대는 것은 통증 완화에 도움이 될 수 있지만, 문제 해결에는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "오줌", "term_vi": "Nước tiểu", "def_ko": "소변(한국어)", "def_vi": "nước tiểu(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1252, '10', '침상에서 배변하는 대상자를 돕는 방법은?', '["요의나 변의를 호소할 때 참도록 유도한다.", "오염을 예방하기 위해 옷을 모두 벗긴다.", "복부를 시계방향으로 마사지 한다.", "배변하는 동안 피부 상태를 살펴본다.", "참지 못하고 실수하는 경우 주의를 준다."]'::jsonb, 3, NULL, NULL, '{"1": "요의나 변의를 호소할 때 참도록 유도하는 것은 일반적인 방법이지만, 실상 배변이 필요한 시점에서는 그러한 유도가 도움이 되지 않을 수 있습니다.\n[정답]", "3": "복부를 시계방향으로 마사지하는 것은 장운동을 촉진할 수 있어 도움이 되는 방법입니다.", "2": "오염을 예방하기 위해 옷을 모두 벗기는 것은 필요하지 않으며, 최소한의 의복만 제거하는 것이 바람직합니다.", "4": "배변하는 동안 피부 상태를 살펴보는 것은 중요하지만, 이는 배변을 도와주는 방법이라고 볼 수는 없습니다.", "5": "참지 못하고 실수하는 경우 주의를 주는 것은 부정적인 경험을 초래할 수 있으므로 주의가 필요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 집중환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1251, '10', '편마비 대상자가 휠체어로 이동하여 화장실을 사용할 때 돕는 방법은?', '["대상자의 불편한 쪽에 휠체어를 둔다.", "휠체어 의자 끝에 걸터앉게 하여 이동한다.", "휠체얼르 타고 내릴 때는 잠금장치를 해제한다.", "대상자의 겨드랑이를 감싸 일으킨 후 몸을 90도 회전시켜 변기에 앉힌다.", "배설이 끝나 대상자가 호출하기 전까지 다른 업무를 본다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 불편한 쪽에 휠체어를 두는 것은 이동 시 불편함을 초래할 수 있습니다.\n[정답]", "2": "휠체어 의자 끝에 걸터앉게 하여 이동하는 방법은 안전하지 않으며, 대상자의 불편함을 증가시킬 수 있습니다.", "3": "휠체어를 타고 내릴 때는 잠금장치를 해제해야 안전하므로 올바른 방법이 아닙니다.", "4": "대상자의 겨드랑이를 감싸 일으킨 후 몸을 90도 회전시켜 변기에 앉히는 것은 올바른 지원 방법입니다.", "5": "배설이 끝나기 전까지 다른 업무를 보는 것은 대상자의 안전을 보장하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "일방의 팔과 다리가 마비된 상태", "def_vi": "Tình trạng tê liệt một bên tay và chân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1250, '10', '배설 돕기 시 대상자가 부끄러우니 밖에서 기다려 달라고 할 때, 올바른 대처방법은?', '["즉시 자리를 피해준다.", "낙상 위험이 있으므로 옆에 있기를 고집한다.", "커튼으로 가려주고 가끔 들여다본다.", "호출기를 쥐어주고 밖에서 기다린다.", "문을 활짝 열어놓고 밖에서 지켜본다."]'::jsonb, 4, NULL, NULL, '{"1": "즉시 자리를 피해주는 것은 대상자의 안전을 위협할 수 있습니다.\n[정답]", "4": "호출기를 쥐어주고 밖에서 기다리는 것은 대상자가 편안하게 배설할 수 있게 도와주면서도 안전을 확보하는 좋은 방법입니다.", "2": "낙상 위험이 있으므로 옆에 있기를 고집하는 것은 대상자의 의사를 무시하는 것입니다.", "3": "커튼으로 가려주고 가끔 들여다보는 것은 오히려 대상자를 불편하게 할 수 있습니다.", "5": "문을 활짝 열어놓고 밖에서 지켜보는 것은 프라이버시를 침해하는 행동입니다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Đi vệ sinh", "def_ko": "배변(한국어)", "def_vi": "Đi tiêu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1249, '10', '화장실에 가기 위해 누워 있는 대상자를 일으킨 후 잠시 앉아 있게 해야 하는 이유는?', '["땀이 날 수 있으므로", "숨이 찰 수 있으므로", "혈압 저하로 어지러울 수 있으므로", "맥박 저하로 가슴 통증이 있으므로", "소변을 참도록 연습시키기 위해서"]'::jsonb, 3, NULL, NULL, '{"1": "땀은 운동이나 긴장으로 인해 발생할 수 있지만, 앉아 있는 것과 직접적인 관계는 적습니다.\n[정답]", "2": "숨이 찰 수 있지만, 주로 이동 직후가 아니라 앉아있는 동안 발생하는 경우가 많습니다.", "3": "혈압 저하로 인해 대상자가 어지러움을 느낄 수 있으므로, 움직임에 대한 준비가 필요합니다.", "4": "맥박 저하로 인한 가슴 통증은 대부분 심각한 상태에서 나타나며, 이 문제와의 연관성이 적습니다.", "5": "소변을 참도록 연습하는 것은 대상자의 필요가 아닙니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1248, '10', '침대에 누워 있는 편마비 대상자가 휠체어를 이용하여 화장실을 갈 때 돕는 방법은?', '["마비된 쪽에 휠체어를 놓는다.", "침대에 일으켜 앉혔을 때 어지러움을 호소하는지 살핀다.", "침대에서 최대한 멀리 휠체어를 놓는다.", "휠체어에 앉을 때 잠금장치를 풀어둔다.", "옷을 입고 벗기 쉽게 속옷을 입히지 않는다."]'::jsonb, 2, NULL, NULL, '{"1": "마비 측에 휠체어를 놓는 것은 환자가 안전하게 이동할 수 없게 할 수 있다.\n[정답]", "2": "어지러움 여부를 확인하는 것은 중요한 안전 절차이다.", "3": "휠체어를 멀리 놓는 것은 환자의 이동을 더 어렵게 만든다.", "4": "휠체어의 잠금장치를 푸는 것은 위험할 수 있다.", "5": "속옷을 입히지 않는 것은 환자의 위생에 좋지 않다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng cơ thể bị liệt một nửa"}, {"term_ko": "휠체어", "term_vi": "Xe lăn", "def_ko": "이동을 돕는 의자", "def_vi": "Ghế hỗ trợ di chuyển"}, {"term_ko": "어지러움", "term_vi": "Chóng mặt", "def_ko": "비틀거리거나 머리가 아픈 증상", "def_vi": "Triệu chứng choáng váng hoặc đau đầu"}, {"term_ko": "잠금장치", "term_vi": "Thiết bị khóa", "def_ko": "고정하는 장치", "def_vi": "Công cụ giữ cố định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1247, '10', '대상자가 화장실을 안전하게 이용할 수 있도록 돕는 방법은?', '["화장실 이동 시 재촉한다.", "배뇨하는 동안 바로 옆에서 지켜본다.", "배설할 때는 옷을 최대한 벗긴다.", "바닥에 흐트러진 물건들을 정리한다.", "편안하게 배설하도록 조명을 어둡게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "화장실 이동 시 재촉한다. - 이는 대상자의 안전을 위협할 수 있습니다.\n[정답]", "4": "바닥에 흐트러진 물건들을 정리한다. - 이는 안전성을 높이는 중요한 방법입니다.", "2": "배뇨하는 동안 바로 옆에서 지켜본다. - 대인적인 사생활을 침해할 수 있습니다.", "3": "배설할 때는 옷을 최대한 벗긴다. - 이는 불편함을 초래할 수 있습니다.", "5": "편안하게 배설하도록 조명을 어둡게 한다. - 이는 범죄나 사고 위험을 증가시킬 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(병원이나 요양시설에서 돌봄을 받는 사람)", "def_vi": "Người nhận sự chăm sóc tại bệnh viện hoặc cơ sở chăm sóc."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1246, '10', '거동이 불편한 대상자가 화장실을 이용할 때 낙상위험을 줄이는 방법으로 옳은 것은?', '["이동하는 동안 슬리퍼를 신긴다.", "화장실 가는 중간에 의자를 둔다.", "화장실 문 앞에 작은 매트를 깔아준다.", "변기 옆에 손잡이를 설치하여 필요 시 잡도록 한다.", "화장실 문밖에 응급벨을 설치한다."]'::jsonb, 4, NULL, NULL, '{"1": "이동하는 동안 슬리퍼를 신기는 하여 불편함을 증가시킬 수 있습니다.\n[정답]", "4": "변기 옆에 손잡이를 설치하여 필요 시 잡도록 하면 안정성을 높일 수 있습니다.", "2": "화장실 가는 중간에 의자를 두는 것은 오히려 불편할 수 있습니다.", "3": "화장실 문 앞에 작은 매트를 깔면 미끄러짐의 위험을 증가시킬 수 있습니다.", "5": "화장실 문밖에 응급벨을 설치하는 것도 중요하지만, 직접적인 낙상 예방과는 관련이 적습니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "대상자", "def_ko": "행동, di chuyển", "def_vi": "환자, người dùng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1245, '10', '대상자가 휠체어 사용 시 화장실 이용을 돕는 방법으로 옳은 것은?', '["처음부터 끝까지 도와준다.", "휠체어를 타고 내릴 때는 잠금장치를 풀어놓는다.", "대상자를 변기로 옮기는 동안 발 받침대는 내려놓는다.", "건조하지 않도록 화장실 바닥에 물을 뿌린다.", "배뇨 후 도움이 필요한 부분을 도와준다."]'::jsonb, 5, NULL, NULL, '{"1": "처음부터 끝까지 도와주는 것은 대상자의 자율성을 영어.\n[정답]", "5": "배뇨 후 도움이 필요한 부분만 도와주는 것이 올바른 방법이다.", "3": "변기로 옮길 때 발 받침대를 내려놓는 것은 안전상 문제를 야기할 수 있다.", "2": "휠체어를 타고 내릴 때 잠금장치를 풀어놓으면 사고의 위험이 있다.", "4": "화장실 바닥에 물을 뿌리는 것은 미끄러짐의 원인이 될 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1244, '10', '대상자의 배설요구 표현으로 볼 수 있는 것은?', '["웃옷을 벗는 행위", "물을 마시지 않는 행위", "머리를 자주 긁는 행위", "안절부절 못하며 허리를 들썩이는 행위", "손을 자꾸 입으로 가져가는 행위"]'::jsonb, 4, NULL, NULL, '{"1": "웃옷을 벗는 행위는 배설과 연관되지 않음.\n[정답]", "4": "안절부절 못하며 허리를 들썩이는 행위는 배설의 요구를 나타낼 수 있음.", "2": "물을 마시지 않는 행위는 배설 요구와 무관함.", "3": "머리를 자주 긁는 행위는 불편함 표시일 수 있으나 배설 요구와는 관련이 없음.", "5": "손을 자꾸 입으로 가져가는 행위는 다른 심리적 불안을 의미할 수 있음."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "특정 환자나 사람", "def_vi": "Người bệnh hoặc cá nhân cụ thể"}, {"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "소변이나 대변을 배출하는 행위", "def_vi": "Hành động thải nước tiểu hoặc phân"}, {"term_ko": "행위", "term_vi": "Hành động", "def_ko": "특정한 행동 또는 동작", "def_vi": "Hành vi cụ thể hoặc động tác"}, {"term_ko": "불편함", "term_vi": "Sự không thoải mái", "def_ko": "편안하지 않음", "def_vi": "Không thoải mái"}, {"term_ko": "신호", "term_vi": "Tín hiệu", "def_ko": "특정한 정보나 경고를 전달하는 방법", "def_vi": "Phương thức truyền đạt thông tin hoặc cảnh báo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1243, '10', '대상자가 소변이 마려워라고 말할 때 돕는 방법으로 옳은 것은?', '["걸을 수 있는 대상자는 혼자 가게 한다.", "신체적, 심리적 상태를 파악하여 보조한다.", "화장실 문을 열어 놓고 배설하게 한다.", "낙상 예방을 위해 이동변기 사용을 적극 권유한다.", "배설물처리 시 냄새가 난다며 솔직히 말한다."]'::jsonb, 2, NULL, NULL, '{"1": "걸을 수 있는 대상자는 혼자 가게 한다: 혼자 가게 하는 것은 안전하지 않을 수 있습니다.\n[정답]", "2": "신체적, 심리적 상태를 파악하여 보조한다: 대상자의 상태를 제대로 파악하고 돕는 것이 가장 적절한 방법입니다.", "3": "화장실 문을 열어 놓고 배설하게 한다: 사생활을 존중하지 않는 행동입니다.", "4": "낙상 예방을 위해 이동변기 사용을 적극 권유한다: 이동변기는 필요할 때에만 사용해야 하며, 이동하기 어려운 경우에 적절합니다.", "5": "배설물처리 시 냄새가 난다며 솔직히 말한다: 대상자의 자존심에 상처를 줄 수 있는 부적절한 대화입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자, 수혜자", "def_vi": "Bệnh nhân, người thụ hưởng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1242, '10', '베설 요양보호의 일반적 원칙으로 옳은 것은?', '["대상자의 요구사항을 무시한다.", "대상자가 편안하게 배설하도록 배려한다.", "배설을 하면 모아서 한꺼번에 치운다.", "요양보호사가 전적으로 도와준다.", "항문은 뒤에서 앞으로 닦는다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자의 요구사항을 무시하는 것은 요양보호의 원칙에 반합니다.\n[정답]", "2": "대상자가 편안하게 배설하도록 배려하는 것은 중요한 원칙입니다.", "3": "배설물을 모아서 한꺼번에 치우는 것은 바람직하지 않습니다.", "4": "요양보호사가 전적으로 도와주는 것이 아니라, 대상자의 자율성을 존중해야 합니다.", "5": "항문을 닦는 방향은 뒤에서 앞으로가 아니라 앞으로 뒤로입니다."}'::jsonb, '[{"term_ko": "배설", "term_vi": "Bài tiết", "def_ko": "배변 또는 소변을 보는 것", "def_vi": "việc đi tiểu hoặc đại tiện"}, {"term_ko": "요양보호", "term_vi": "Chăm sóc người cao tuổi", "def_ko": "노인을 돌보는 일", "def_vi": "công việc chăm sóc cho người lớn tuổi"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 혹은 돌봐야 할 사람", "def_vi": "bệnh nhân hoặc người cần được chăm sóc"}, {"term_ko": "편안하다", "term_vi": "Thoải mái", "def_ko": "안락하고 불편함이 없다", "def_vi": "không khó chịu và dễ chịu"}, {"term_ko": "자율성", "term_vi": "Tự chủ", "def_ko": "스스로 결정할 수 있는 능력", "def_vi": "khả năng tự quyết định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1241, '10', '약의 변질을 먹기 위한 올바른 방법은?', '["안약, 귀약은 상온의 그늘진 곳에서 보관한다.", "알약은 습기가 많은 상온에서 보관한다.", "가루약을 먹일 때 물기가 있는 숟가락을 사용한다.", "시럽제는 약 용기 째 빨아 먹는다.", "꺼낸 시럽은 다시 병에 넣어 보관한다."]'::jsonb, 1, NULL, NULL, '{"1": "안약, 귀약은 상온의 그늘진 곳에서 보관한다.\n[정답]", "2": "알약은 습기가 많은 상온에서 보관한다. 이는 약의 변질을 유발할 수 있다.", "3": "가루약을 먹일 때 물기가 있는 숟가락을 사용한다. 이는 약의 변질을 일으킬 수 있다.", "4": "시럽제는 약 용기 째 빨아 먹는다. 이는 오염의 위험이 있다.", "5": "꺼낸 시럽은 다시 병에 넣어 보관한다. 이는 약의 변질을 초래할 수 있다."}'::jsonb, '[{"term_ko": "약", "term_vi": "Thuốc", "def_ko": "약물(한국어)", "def_vi": "Dược phẩm(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1240, '10', '대상자의 약품을 보관하는 방법으로 옳은 것은?', '["가루약은 물에 녹여 냉장 보관한다.", "시럽제는 햇빛이 잘 드는 곳에 보관한다.", "알약은 건조한 곳에 보관한다.", "안약은 냉장고에 보관한다.", "치매 대상자의 약은 침상 옆에 보관한다."]'::jsonb, 3, NULL, NULL, '{"1": "가루약은 물에 녹여 냉장 보관하는 것이 아니라, 건조하고 서늘한 곳에 보관해야 합니다.\n[정답]", "3": "알약은 반드시 건조한 곳에 보관해야 하며, 습기와 열을 피해야 합니다.", "2": "시럽제는 햇빛이 잘 드는 곳에 보관하는 것이 아니라, 직사광선을 피해야 합니다.", "4": "안약은 냉장고에 보관할 수 있지만, 사용 전에는 실온으로 두어야 하며, 제조사의 지침을 따라야 합니다.", "5": "치매 대상자의 약은 침상 옆에 보관하는 것이 아니라, 안전한 곳에 보관하여 잘못된 사용을 방지해야 합니다."}'::jsonb, '[{"term_ko": "약품", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "보관", "term_vi": "Lưu trữ", "def_ko": "저장(한국어)", "def_vi": "Lưu trữ"}, {"term_ko": "가루약", "term_vi": "Thuốc bột", "def_ko": "분말 약(한국어)", "def_vi": "Thuốc dạng bột"}, {"term_ko": "알약", "term_vi": "Viên thuốc", "def_ko": "알약(한국어)", "def_vi": "Viên thuốc"}, {"term_ko": "시럽제", "term_vi": "Sirop", "def_ko": "시럽 형태의 약(한국어)", "def_vi": "Sirop"}, {"term_ko": "안약", "term_vi": "Thuốc nhỏ mắt", "def_ko": "안구 치료제(한국어)", "def_vi": "Thuốc nhỏ cho mắt"}, {"term_ko": "치매", "term_vi": "Lú lẫn", "def_ko": "치매(한국어)", "def_vi": "Giai đoạn lơ đãng"}, {"term_ko": "대상자", "term_vi": "Bệnh nhân", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1239, '10', '정맥주사 주입 중 대상자가 주사부위의 토증을 호소할 때 올바른 대처방법은?', '["주사바늘을 즉시 제거한다.", "주사주입 속도를 줄인다.", "통증 부위를 냉찜질 한다.", "수액병을 심장보다 아래로 내려준다.", "조저릭를 잠근 후 즉시 간호사에게 보고한다."]'::jsonb, 5, NULL, NULL, '{"1": "주사바늘을 제거하는 것은 불필요한 조치이며, 상태를 확인하기 전에 시행하면 상황을 악화시킬 수 있다.\n[정답]", "5": "조저릭을 잠근 후 즉시 간호사에게 보고하는 것이 안전한 조치이며, 상황을 관리하는 데 필요하다.", "2": "주사주입 속도를 줄이는 것은 즉각적인 대처 방법으로 적절하지 않으며, 증상이 심각할 수 있다.", "3": "통증 부위를 냉찜질 하는 것은 일시적인 완화일 수 있으나, 근본 원인을 해결하지 않는다.", "4": "수액병을 심장보다 아래로 내려주는 것은 혈류에 영향을 미치지 않으며, 적절한 대처 방법이 아니다."}'::jsonb, '[{"term_ko": "정맥주사", "term_vi": "Tiêm tĩnh mạch", "def_ko": "정맥으로 하는 주사", "def_vi": "Tiêm vào tĩnh mạch"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자", "def_vi": "Bệnh nhân"}, {"term_ko": "토증", "term_vi": "Buồn nôn", "def_ko": "메스꺼움", "def_vi": "Cảm giác buồn nôn"}, {"term_ko": "조저릭", "term_vi": "Van điều chỉnh", "def_ko": "주입 속도 조절 장치", "def_vi": "Thiết bị điều chỉnh tốc độ truyền"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1238, '10', '대상자에게 주사주입 시 수액 병의 높이로 옳은 것은?', '["심장 위", "심장 아래", "방광 아래", "허리 아래", "허리에서 심장 사이"]'::jsonb, 1, NULL, NULL, '{"1": "주사 주입 시 수액 병은 심장보다 높아야만 적절한 압력으로 수액이 주입됩니다.\n[정답]", "2": "심장 아래에 위치하면 수액 주입이 어려워집니다.", "3": "방광 아래는 적합하지 않습니다.", "4": "허리 아래는 수액 주입의 원리에 맞지 않습니다.", "5": "허리에서 심장 사이도 주입 원리에 맞지 않습니다."}'::jsonb, '[{"term_ko": "주사", "term_vi": "주입", "def_ko": "주사(tiêm)", "def_vi": "주입(cho vào)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1237, '10', '대상자에게 주사주입 시 돕기 방법으로 옳은 것은?', '["수액세트가 팽팽하게 당겨지도록 한다.", "의복을 갈아입었을 때 주사바늘을 빼둔다.", "주사부위에 부종이 생기면 주사바늘을 제거한다.", "정맥주입 속도가 일정하게 유지되는지 수시로 확인한다.", "주사바늘을 제거한 후 알코올 솜을 비벼준다."]'::jsonb, 4, NULL, NULL, '{"1": "수액세트를 팽팽하게 당겨지는 것은 불필요하며, 이로 인해 혈관에 압력이 가해질 수 있습니다.\n[정답]", "4": "정맥주입 속도를 수시로 확인하는 것은 주사 시 매우 중요한 절차입니다.", "3": "주사부위에 부종이 생겼을 때는 주사바늘을 제거하는 것이 맞지만, 제거하지 않은 경우에도 이유가 있을 수 있으므로 신중해야 합니다.", "2": "의복을 갈아입었을 때 주사바늘을 빼둬서는 안 되며, 주사 주입을 진행해야 합니다.", "5": "주사바늘을 제거한 후 알코올 솜을 비비는 것은 올바르지 않습니다."}'::jsonb, '[{"term_ko": "주사", "term_vi": "Tiêm", "def_ko": "주사기나 바늘로 약물을 체내에 넣는 것", "def_vi": "Sử dụng ống tiêm hoặc kim để đưa thuốc vào cơ thể"}, {"term_ko": "주입", "term_vi": "Truyền", "def_ko": "체내에 약액을 넣는 행위", "def_vi": "Hành động đưa chất lỏng vào cơ thể"}, {"term_ko": "부위", "term_vi": "Vị trí", "def_ko": "신체의 특정 장소", "def_vi": "Một địa điểm cụ thể trên cơ thể"}, {"term_ko": "주사부위", "term_vi": "Vị trí tiêm", "def_ko": "주사가 시행되는 구역", "def_vi": "Khu vực được tiêm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1236, '10', '왼쪽 귀에 염증이 있는 대상자에게 귀약을 투여할 때 올바른 방법은?', '["왼쪽 귀를 위쪽으로 하여 편안한 자세를 취하도록 한다.", "귓바퀴를 후하방으로 잡아당겨 약물투여가 쉽도록 한다.", "약물이 잘 흡수되도록 귀입구를 문질러 준다.", "투여 직후 왼쪽 귀를 아래로 하여 5분간 누워있게 한다.", "투여 후 하루동안 귓구멍에 작은 솜을 끼워 놓는다."]'::jsonb, 1, NULL, NULL, '{"1": "올바른 자세를 유지하여 귀약이 효과적으로 투여될 수 있도록 돕는다.\n[정답]", "2": "귓바퀴를 후하방으로 잡아당기는 것은 귀약이 더 잘 투여되도록 하기 위한 올바른 방법이지만, 1번이 보다 좋은 방법이다.", "3": "귀입구를 문질러 주는 것은 보통 권장되지 않는 방법이다. 약물이 귀에 직접적으로 침투할 수 있도록 하는 관리가 필요하다.", "4": "투여 직후 누워 있는 것이 도움이 될 수 있으나, 5분간 누워 있을 필요는 없다.", "5": "투여 후 솜을 끼워 놓는 것은 권장되지 않는다. 이는 귀약에 따라 달라질 수 있으나, 일반적으로는 필요하지 않다."}'::jsonb, '[{"term_ko": "귀약", "term_vi": "Thuốc nhỏ tai", "def_ko": "약물 치료를 위해 귀에 넣는 약", "def_vi": "thuốc dùng để điều trị cho tai"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1235, '10', '한쪽 귀에 통증이 있는 대상자에게 귀약을 투여할 때 옳은 방법은?', '["똑바로 누운 자세에서 투여한다.", "약을 넣기 전에 면봉으로 귓속을 깨끗이 닦아 준다.", "점적 후 솜을 이관 내에 꼭 끼워 눌러 준다.", "이도 중앙에 정확한 방울 수의 약물을 점적한다.", "점적 후 귀입구를 부드럽게 눌러주고 5분간 누워있게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "똑바로 누운 자세는 귀약 투여에 적합하지 않습니다.", "2": "약을 넣기 전에 면봉으로 귓속을 깨끗이 닦는 것은 권장되지 않습니다.\n[정답]", "5": "점적 후 귀입구를 부드럽게 눌러주고 5분간 누워있게 하는 것이 올바른 방법입니다.", "3": "점적 후 솜을 이관 내에 꼭 끼워 눌러 주는 것은 잘못된 방법입니다.", "4": "이도 중앙에 정확한 방울 수의 약물을 점적하는 것은 중요하지만, 다른 방법과 함께 시행해야 합니다."}'::jsonb, '[{"term_ko": "귀약", "term_vi": "Thuốc nhỏ tai", "def_ko": "귀에 사용하는 약물", "def_vi": "Thuốc dùng cho tai"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1234, '10', '귀약을 투여하는 방법으로 옳은 것은?', '["냉장고에서 꺼내 바로 사용한다.", "점적 전에 면봉으로 귓바퀴와 외이도를 닦는다.", "치료할 귀를 아래쪽으로 향하게 한다.", "점적 후 귓바퀴를 후하방으로 잡아당긴다.", "작은 솜을 안쪽 깊이 끼워넣는다."]'::jsonb, 2, NULL, NULL, '{"1": "냉장고에서 보관된 약물은 사용 전에 실온에 두어야 합니다.\n[정답]", "2": "점적 전에 면봉으로 귓바퀴와 외이도를 닦는 것이 중요합니다.", "3": "치료할 귀를 아래쪽으로 향하는 것이 꼭 필요한 것은 아닙니다.", "4": "점적 후 귓바퀴를 후하방으로 잡아당겨야 약물이 잘 들어갑니다.", "5": "작은 솜을 깊이 끼워넣는 것은 금지되어 있습니다."}'::jsonb, '[{"term_ko": "귀약", "term_vi": "Thuốc nhỏ tai", "def_ko": "귀에 사용하는 약", "def_vi": "Thuốc sử dụng cho tai"}, {"term_ko": "점적", "term_vi": "Nhỏ giọt", "def_ko": "떨어뜨리다", "def_vi": "Hành động làm nhỏ giọt"}, {"term_ko": "귓바퀴", "term_vi": "Vành tai", "def_ko": "귓속에서 겉으로 보이는 부분", "def_vi": "Phần bên ngoài của tai"}, {"term_ko": "외이도", "term_vi": "Ống tai ngoài", "def_ko": "귀의 바깥쪽 통로", "def_vi": "Đường dẫn bên ngoài của tai"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1233, '10', '냉장고에 보관 중인 약물을 귀에 투여할 때 옳은 방법은?', '["전자레인지에 넣고 데운다.", "햇볕이 잘 드는 창가에 둔다.", "끓는 물에 담가 데운다.", "차가운 상태로 바로 복용한다.", "손으로 따뜻하게 하여 사용한다."]'::jsonb, 5, NULL, NULL, '{"1": "전자레인지에 넣고 데우는 것은 약물의 효과를 저하시킬 수 있으므로 잘못된 방법입니다.\n[정답]", "5": "손으로 따뜻하게 하여 사용하는 방법은 귀에 투여하기 전에 약물을 적정 온도로 맞춰주는 올바른 방법입니다.", "3": "끓는 물에 담가 데우는 것은 약물의 성분을 변질시킬 수 있어 위험합니다.", "4": "차가운 상태로 바로 복용하는 것은 약물의 효과를 감소시킬 수 있습니다.", "2": "햇볕이 잘 드는 창가에 두는 것은 온도 조절이 제대로 이루어지지 않아 문제가 될 수 있습니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1232, '10', '안연고를 투여하는 방법으로 옳은 것은?', '["처음 나온 연고는 거즈로 닦아 버린다.", "동공에 직접 대고 짜 넣는다.", "약을 넣은 후 눈을 감고 안구를 고정시킨다.", "눈꺼풀 밖으로 나온 연고는 멸균 솜으로 밀어 넣는다.", "눈 바깥쪽에서 안쪽으로 짜 넣는다."]'::jsonb, 1, NULL, NULL, '{"1": "처음 나온 연고는 거즈로 닦아 버린다.\n[정답]", "2": "동공에 직접 대고 짜 넣는다.", "3": "약을 넣은 후 눈을 감고 안구를 고정시킨다.", "4": "눈꺼풀 밖으로 나온 연고는 멸균 솜으로 밀어 넣는다.", "5": "눈 바깥쪽에서 안쪽으로 짜 넣는다."}'::jsonb, '[{"term_ko": "안연고", "term_vi": "Thuốc mỡ mắt", "def_ko": "눈에 사용하는 약물", "def_vi": "Thuốc dùng cho mắt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1231, '10', '대상자에게 안약을 투여하는 방법으로 옳은 것은?', '["위 눈꺼풀에 멸균솜을 대어 준다.", "대상자에게 아래를 보게 한다.", "안약을 각막에 점적한다.", "안약을 점적한 후 비루관을 눌러 준다.", "멸균솜으로 눈 바깥쪽에서 안쪽으로 닦는다."]'::jsonb, 4, NULL, NULL, '{"1": "위 눈꺼풀에 멸균솜을 대는 것은 안약 투여 방법이 아닙니다.\n[정답]", "2": "대상자에게 아래를 보게 하는 것은 부적절하며, 각막이 아닌 아래쪽을 향하게 됩니다.", "3": "안약을 각막에 점적하는 것은 맞지만, 추가 조치가 필요합니다.", "4": "안약을 점적한 후 비루관을 눌러주는 것은 약물의 흡수율을 높이기 위한 올바른 방법입니다.", "5": "멸균솜으로 닦는 것은 필요 없는 조치입니다."}'::jsonb, '[{"term_ko": "안약", "term_vi": "Thuốc nhỏ mắt", "def_ko": "눈에 사용하는 약물", "def_vi": "thuốc dùng cho mắt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1230, '10', '한쪽 눈에만 감염이 있을 때, 반대편 눈에 전염되지 않도록 멸균 솜을 이용하여 닦아내는 방향은?', '["어느 방향이든 상관없다.", "눈 바깥쪽에서 안쪽으로 닦는다.", "눈 안쪽에서 바깥쪽으로 닦는다.", "눈 주위를 둥근 원을 그리며 닦는다.", "눈 주위를 위에서 아래로 닦는다."]'::jsonb, 3, NULL, NULL, '{"1": "어느 방향이든 상관없다. - 잘못된 정보로, 감염 예방을 위한 정확한 방법이 아닙니다.\n[정답]", "3": "눈 안쪽에서 바깥쪽으로 닦는다. - 이 방법이 감염 전파를 예방하는데 가장 안전한 방법입니다.", "2": "눈 바깥쪽에서 안쪽으로 닦는다. - 잘못된 방법으로 감염이 확산될 수 있습니다.", "4": "눈 주위를 둥근 원을 그리며 닦는다. - 효과적인 방법이 아니며, 감염 위험이 있습니다.", "5": "눈 주위를 위에서 아래로 닦는다. - 이 방법도 감염 확산의 위험이 있습니다."}'::jsonb, '[{"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "감염(한국어)", "def_vi": "nhiễm trùng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1229, '10', '물약을 따르기 전에 흔들어서 섞는 이유는?', '["변질을 막기 위해", "냄새를 없애기 위해", "약의 흡수를 위해", "쓴맛을 없애기 위해", "농도를 맞추기 위해"]'::jsonb, 5, NULL, NULL, '{"1": "변질을 막기 위해\n약물이 변질되지 않도록 흔드는 것은 중요하지만, 주요 목적은 아닙니다.\n[정답]", "5": "농도를 맞추기 위해\n물약의 성분이 고르게 섞여 농도가 일정하게 유지되도록 하기 위해 흔듭니다.", "3": "약의 흡수를 위해\n흔드는 것이 약물의 흡수에 직접적인 영향을 주지는 않습니다.", "4": "쓴맛을 없애기 위해\n쓴맛은 흔드는 것과는 별개로, 맛을 조절하는 과정이 필요합니다.", "2": "냄새를 없애기 위해\n냄새를 줄이는 것은 흔드는 것과 관련이 없습니다."}'::jsonb, '[{"term_ko": "물약", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1228, '10', '대상자에게 물약을 투여할 때 돕기 방법으로 옳은 것은?', '["계량컵이 없을 때에는 종이컵을 이용한다.", "라벨이 붙은 쪽 방향으로 용액을 따른다.", "용량을 초과해서 따른 약은 약병에 다시 넣는다.", "병 뚜껑을 씌우기 전에 복용량을 확인한다.", "약의 용량이 적을 때는 바늘을 제거한 주사기를 이용하여 투여한다."]'::jsonb, 5, NULL, NULL, '{"1": "계량컵이 없을 경우 종이컵은 일반적인 계량 도구가 아니므로 정확성을 보장할 수 없습니다.\n[정답]", "2": "라벨이 붙은 쪽 방향으로 용액을 따르면 혼동을 방지할 수 있어 옳은 방법입니다.", "3": "용량을 초과한 약은 재사용하면 안 되므로 잘못된 방법입니다.", "4": "병 뚜껑을 씌우기 전에 복용량을 확인하는 것은 중요하지만, 복용 전 확인이 필요합니다.", "5": "약의 용량이 적은 경우 바늘을 제거한 주사기를 이용하여 투여하는 것이 적절한 방법입니다."}'::jsonb, '[{"term_ko": "물약", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1227, '10', '대상자의 약 복용을 돕는 방법으로 옳은 것은?', '["삼키기 어려운 알약은 갈아서 먹인다.", "약을 먹인 후 물은 조금만 준다.", "알약이 많을 경우에도 한번에 먹인다.", "약을 떨어뜨릴 우려가 있는 대상자는 직접 입안에 넣어준다.", "남은 알약은 다른 용기에 담아 냉장 보관한다."]'::jsonb, 4, NULL, NULL, '{"1": "삼키기 어려운 알약은 갈아서 먹인다. 이는 약의 성분 변화를 초래할 수 있어 위험하다.\n[정답]", "4": "약을 떨어뜨릴 우려가 있는 대상자는 직접 입안에 넣어준다. 이는 안전한 방법이다.", "2": "약을 먹인 후 물은 조금만 준다. 충분한 물을 제공해야 약의 효과가 제대로 나타난다.", "3": "알약이 많을 경우에도 한번에 먹인다. 여러 번에 나눠서 먹이는 것이 안전하다.", "5": "남은 알약은 다른 용기에 담아 냉장 보관한다. 약의 보관 방법을 준수해야 한다."}'::jsonb, '[{"term_ko": "약", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "복용", "term_vi": "Uống thuốc", "def_ko": "복용(한국어)", "def_vi": "Uống thuốc"}, {"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Người bệnh"}, {"term_ko": "알약", "term_vi": "Viên thuốc", "def_ko": "알약(한국어)", "def_vi": "Viên thuốc"}, {"term_ko": "보관", "term_vi": "Bảo quản", "def_ko": "보관(한국어)", "def_vi": "Bảo quản"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1226, '10', '물약 복용 돕기 방법으로 옳은 것은?', '["햇볕이 잘 드는 곳에 약을 보관한다.", "병뚜껑 안쪽이 바닥을 향하도록 놓는다.", "계량컵을 눈높이로 들고 따른다.", "남은 약은 다시 부어 넣는다.", "주사기에 1회분씩 나누어 보관한다."]'::jsonb, 3, NULL, NULL, '{"1": "햇볕이 잘 드는 곳에 약을 보관하면 약의 효능이 떨어질 수 있어 올바른 방법이 아닙니다.\n[정답]", "3": "계량컵을 눈높이로 들고 따르는 것은 정확한 양을 측정하는 데 도움이 됩니다.", "2": "병뚜껑 안쪽이 바닥을 향하도록 놓으면 보관하기 어려우며, 사용하기 불편합니다.", "4": "남은 약은 다시 부어 넣는 것은 오염의 위험이 있기 때문에 바람직하지 않습니다.", "5": "주사기에 1회분씩 나누어 보관하는 것은 부적절한 방법으로, 약물의 효능을 저하시킬 수 있습니다."}'::jsonb, '[{"term_ko": "물약", "term_vi": "Thuốc", "def_ko": "약물(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1225, '10', '대상자의 경구 약 복용 방법으로 옳은 것은?', '["알약은 병에 손가락을 넣어 꺼낸다.", "물약은 라벨이 없는 쪽을 잡고 용액을 따른다.", "색이 변하거나 혼탁한 약물은 잘 흔들어 먹인다.", "물약은 뚜껑 안쪽이 위로 가도록 놓는다.", "병뚜껑을 씌우기 전에 손으로 입구를 닦는다."]'::jsonb, 4, NULL, NULL, '{"1": "알약은 병에 손가락을 넣어 꺼내는 것은 위생적이지 않으므로 잘못된 방법입니다.\n[정답]", "2": "물약은 라벨이 없는 쪽을 잡고 용액을 따르는 것은 라벨이 있는 쪽을 잡아야 하므로 잘못된 방법입니다.", "3": "색이 변하거나 혼탁한 약물은 잘 흔들어 먹이는 것이 아니라, 사용하지 않아야 하는 약물입니다.", "4": "물약은 뚜껑 안쪽이 위로 가도록 놓는 것이 올바른 방법입니다.", "5": "병뚜껑을 씌우기 전에 손으로 입구를 닦는 것은 위생적인 방법입니다."}'::jsonb, '[{"term_ko": "경구", "term_vi": "Đường uống", "def_ko": "입을 통해 복용하는 것", "def_vi": "Sử dụng qua miệng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1224, '10', '자주 사레들리는 대상자의 가루약 복용을 돕는 방법은?', '["가루약을 입안에 넣은 후 물을 먹인다.", "음식이나 우유에 섞어서 먹인다.", "물약에 섞어 빨대로 천천히 먹인다.", "입 안에 물을 먼저 넣고 가루약을 털어 넣는다.", "숟가락에 약을 담아 물로 녹여 먹인다."]'::jsonb, 5, NULL, NULL, '{"1": "가루약을 입안에 넣은 후 물을 먹인다: 입안의 가루약이 불편하게 느껴질 수 있어 권장되지 않습니다.\n[정답]", "2": "음식이나 우유에 섞어서 먹인다: 가루약을 섞어 복용하는 것은 좋은 방법이지만, 약의 종류에 따라 효과가 떨어질 수 있습니다.", "3": "물약에 섞어 빨대로 천천히 먹인다: 물약과 섞이는 과정에서 약효가 감소할 수 있습니다.", "4": "입 안에 물을 먼저 넣고 가루약을 털어 넣는다: 두 가지가 동시에 들어가 불편할 수 있습니다.", "5": "숟가락에 약을 담아 물로 녹여 먹인다: 올바른 방법으로, 약을 잘 섭취할 수 있는 방법입니다."}'::jsonb, '[{"term_ko": "사레", "term_vi": "Sare", "def_ko": "기침이나 숨막힘", "def_vi": "ho hoặc khó thở"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "치료를 받는 사람", "def_vi": "người nhận điều trị"}, {"term_ko": "가루약", "term_vi": "Thuốc bột", "def_ko": "분말 형태의 약", "def_vi": "thuốc ở dạng bột"}, {"term_ko": "복용", "term_vi": "Sử dụng", "def_ko": "약을 먹는 과정", "def_vi": "quá trình uống thuốc"}, {"term_ko": "물", "term_vi": "Nước", "def_ko": "액체, 음료", "def_vi": "chất lỏng, đồ uống"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "식사", "def_vi": "bữa ăn"}, {"term_ko": "우유", "term_vi": "Sữa", "def_ko": "유제품", "def_vi": "sản phẩm từ sữa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1223, '10', '대상자의 약 복용을 돕는 방법으로 옳은 것은?', '["처방된 이외의 약은 섞어준다.", "용량이 많은 물약은 주사기를 이용하여 복용한다.", "잘못 복용했을 경우 토하게 한다.", "개수가 많은 알약은 2~3번에 나누어 투약한다.", "계량컵을 눈높이 보다 위로 들고 따른다."]'::jsonb, 4, NULL, NULL, '{"1": "처방된 이외의 약은 섞어주면 안 되므로 잘못된 방법입니다.\n[정답]", "2": "용량이 많은 물약은 주사기로 정확히 측정하여 복용하는 것이 좋습니다.", "3": "잘못 복용했을 경우 안전한 방법은 의료진에게 연락하는 것이지 토하게 하는 것은 위험할 수 있습니다.", "4": "개수가 많은 알약은 2~3번에 나누어 투약하는 것이 올바른 방법입니다.", "5": "계량컵은 눈높이와 일치하게 들고 따라야 정확한 양을 측정할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1222, '10', '경구약 복용으로 돕는 방법으로 옳은 것은?', '["알약은 손바닥에 따른다.", "알약은 가루로 만들어 복용하게 한다.", "가급적 물은 소량만 먹인다.", "스스로 먹을 수 있도록 대상자 손에 직접준다.", "질문을 하여 입안에 약이 남아 있는지 확인한다."]'::jsonb, 5, NULL, NULL, '{"1": "알약이 손바닥에 따라서는 안 됩니다. 복용 시 안정성이 중요합니다.\n[정답]", "5": "질문을 통해 입안에 약이 남아 있는지 확인하는 것은 중요합니다.", "2": "알약을 가루로 만들어 복용하게 하는 것은 환자에게 혼란을 줄 수 있습니다.", "3": "물은 충분히 먹여야 약물이 제대로 작용할 수 있습니다.", "4": "스스로 복용 할 수 있도록 돕는 것은 중요하지만, 항상 직접 넘겨주는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "경구약", "term_vi": "Thuốc uống", "def_ko": "입으로 복용하는 약", "def_vi": "Thuốc được uống qua miệng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1221, '10', '약물 복용 시 치아착색을 방지하기 위해 사용하는 도구는?', '["빨대", "유리컵", "약병뚜껑", "플라스틱 스푼", "플라스틱 컵"]'::jsonb, 1, NULL, NULL, '{"1": "빨대를 사용하면 약물이 치아에 직접 닿지 않아 착색을 예방할 수 있습니다.\n[정답]", "2": "유리컵은 약물을 담는 용도로 사용되지만, 치아 착색을 방지하는 데는 도움이 되지 않습니다.", "3": "약병뚜껑은 약물을 따르는 용도로 불편하며 착색을 방지하지 못합니다.", "4": "플라스틱 스푼은 약물을 복용하는 방법일 뿐 치아 착색에는 영향이 없습니다.", "5": "플라스틱 컵도 치아에 직접적인 영향을 미치는 것이 아니므로 착색을 방지하지 않습니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1220, '10', '대상자의 복약을 돕는 방법으로 옳은 것은?', '["금식 중이라도 혈압약은 투약한다.", "유효기간이 지난 약은 냉장보관 한다.", "잘못 복용했을 경우 물을 많이 마시게 한다.", "캡슐약은 캡슐을 벗기고 투약한다.", "약을 삼키지 못할 경우 갈거나 쪼갠다."]'::jsonb, 1, NULL, NULL, '{"1": "금식 중에도 혈압약은 생명 유지와 연관되어 반드시 투약해야 한다.\n[정답]", "2": "유효기간이 지난 약은 효과가 없으므로 냉장 보관해서는 안 된다.", "3": "잘못 복용했을 경우 물을 많이 마시게 하는 것은 권장되지 않는다.", "4": "캡슐약은 그대로 복용해야 하며 벗기면 약효가 달라질 수 있다.", "5": "약을 삼키지 못할 경우에는 의사와 상담 후 적절한 방법을 결정해야 한다."}'::jsonb, '[{"term_ko": "복약", "term_vi": "Dùng thuốc", "def_ko": "약을 복용하는 것", "def_vi": "Uống thuốc"}, {"term_ko": "혈압약", "term_vi": "Thuốc huyết áp", "def_ko": "혈압 조절을 위한 약", "def_vi": "Thuốc điều chỉnh huyết áp"}, {"term_ko": "유효기간", "term_vi": "Thời hạn sử dụng", "def_ko": "약의 사용이 가능한 기간", "def_vi": "Thời gian thuốc có thể sử dụng"}, {"term_ko": "잘못", "term_vi": "Sai", "def_ko": "잘못된 것", "def_vi": "Điều không đúng"}, {"term_ko": "삼키다", "term_vi": "Nuốt", "def_ko": "입으로 넘기는 것", "def_vi": "Đưa vào trong cơ thể qua miệng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1219, '10', '경관 영양액 주입 중 시설장, 간호사에게 즉시 보고해야 할 사항은?', '["입 안의 건조", "갈증", "다뇨", "변비", "구토"]'::jsonb, 5, NULL, NULL, '{"1": "입 안의 건조는 일반적인 증상이나 즉시 보고할 정도는 아닙니다.", "2": "갈증은 느낄 수 있지만, 긴급한 상황은 아닙니다.", "3": "다뇨는 지켜봐야 하는 증상이나 즉각적인 위험은 아닙니다.", "4": "변비는 흔한 문제이나 긴급한 사항에 포함되지 않습니다.\n[정답]", "5": "구토는 경관 영양 시 즉각적으로 보고해야 할 심각한 증상입니다."}'::jsonb, '[{"term_ko": "경관", "term_vi": "Dinh dưỡng ống", "def_ko": "위장관으로 음식을 공급하는 방식", "def_vi": "Phương thức cung cấp thức ăn qua ống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1218, '10', '스스로 식사할 수 없는 대상자의 경관영양을 돕는 방법은?', '["구강간호는 하지 않아도 된다.", "비위관이 빠졌을 경우 신속히 밀어 넣는다.", "고농도의 영양액을빠르게 주입한다.", "비위관이 잘 고정되어 있는지 확인한다.", "영양 주머니에 영양액을 가득 채운다."]'::jsonb, 4, NULL, NULL, '{"1": "구강간호는 경관영양을 받는 환자에게도 필요하다. 따라서 하지 않아도 된다는 것은 잘못된 정보이다.\n[정답]", "2": "비위관이 빠졌을 경우 즉시 재삽입해야 하지만, 밀어 넣는 것은 위험하다.", "3": "고농도의 영양액을 빠르게 주입하는 것은 환자에게 부담이 될 수 있으므로 적절하지 않다.", "4": "비위관이 잘 고정되어 있는지 확인하는 것은 매우 중요하다.", "5": "영양 주머니에 영양액을 가득 채우는 것은 필요하지만, 과다 추입은 피해야 한다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống thông", "def_ko": "위에 튜브를 통해 영양을 공급하는 것", "def_vi": "Cung cấp dinh dưỡng thông qua ống vào dạ dày"}, {"term_ko": "비위관", "term_vi": "Ống thông dạ dày", "def_ko": "위에 넣는 관", "def_vi": "Ống được đưa vào dạ dày"}, {"term_ko": "영양액", "term_vi": "Dung dịch dinh dưỡng", "def_ko": "영양이 포함된 액체", "def_vi": "Chất lỏng chứa dinh dưỡng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1217, '10', '침상에 누워있는 경관영양액 주입 대상자를 오른쪽으로 눕혀서 제공하는 이유는?', '["비위관이 새지 않게 하기 위해서", "영양액 속도를 조절하기 위해서", "비위관을 빼지 못하게 하기 위해서", "편안한 자세 유지를 위해서", "기도로의 역류 가능성을 줄이기 위해서"]'::jsonb, 5, NULL, NULL, '{"1": "비위관이 새지 않게 하기 위해서\n비위관이 새지 않도록 하는 것은 중요하지만, 주로 코 위치나 관의 상태에 따라 결정되므로 오른쪽으로 눕히는 주된 이유는 아닙니다.", "2": "영양액 속도를 조절하기 위해서\n영양액 속도 조절은 주입 관리와 관련된 사항이며, 자세 변경과는 큰 관련이 없습니다.", "3": "비위관을 빼지 못하게 하기 위해서\n비위관을 제자리에 두는 것도 중요하지만, 이는 환자의 자세와 직접적인 관련이 없습니다.", "4": "편안한 자세 유지를 위해서\n편안한 자세 유지도 고려 사항이지만, 오른쪽으로 눕히는 주된 이유는 기도로의 역류 가능성을 줄이기 위함입니다.\n[정답]", "5": "기도로의 역류 가능성을 줄이기 위해서\n경관영양을 주입하는 환자를 오른쪽으로 눕히면 기도로의 영양액 역류를 방지하여 흡인 위험을 줄일 수 있습니다."}'::jsonb, '[{"term_ko": "침상", "term_vi": "Giường", "def_ko": "침대(한국어)", "def_vi": "Giường ngủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1216, '10', '경관영양 대상자를 돕는 방법으로 옳은 것은?', '["침상머리를 올려 대상자를 앉게 한다.", "의식이 없는 경우에만 경관영양을 한다.", "영양액 주머니는 침대 난간 아래에 건다.", "영양액이 역류하면 영양주머니를 높여준다.", "비위관이 막히거나 혼탁할 경우 세척을 위해 빼낸다."]'::jsonb, 1, NULL, NULL, '{"1": "경관영양을 실시할 때 환자의 안전을 위해 침상머리를 올려 앉히는 것이 올바른 방법입니다.\n[정답]", "2": "의식이 있는 환자도 필요시 경관영양을 할 수 있으며, 의식이 없는 경우만 해당되지 않습니다.", "3": "영양액 주머니는 침대 난간 위에 걸어야 하며, 아래에 걸면 역류의 위험이 있습니다.", "4": "영양액이 역류하면 영양주머니를 낮춰야 하며, 높이면 더욱 악화될 수 있습니다.", "5": "비위관이 막히거나 혼탁할 경우에는 세척을 하지만, 반드시 빼내는 것은 아닙니다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống dẫn", "def_ko": "인공적으로 음식을 공급하는 방법", "def_vi": "Phương pháp cung cấp thức ăn một cách nhân tạo"}, {"term_ko": "침상", "term_vi": "Giường bệnh", "def_ko": "병상", "def_vi": "Giường của bệnh nhân"}, {"term_ko": "역류", "term_vi": "Trào ngược", "def_ko": "되돌아오는 현상", "def_vi": "Hiện tượng quay trở lại"}, {"term_ko": "비위관", "term_vi": "Ống thông dạ dày", "def_ko": "위장관의 일종", "def_vi": "Một loại ống dẫn trong dạ dày"}, {"term_ko": "세척", "term_vi": "Rửa", "def_ko": "씻어내는 것", "def_vi": "Việc rửa sạch"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1215, '10', '경관영양을 하는 대상자를 돕는 방법으로 옳은 것은?', '["고농도의 진한 영양액을 준비한다.", "청색증이 나타나면 천천히 주입한다.", "영양액 주입 후 알코올 솜으로 입안을 닦아준다.", "비위관 삽입 부위에 윤활제를 바른다.", "영양액 주머니는 매번 소독하여 사용한다."]'::jsonb, 4, NULL, NULL, '{"1": "고농도의 진한 영양액을 준비하는 것은 위험할 수 있으며, 일반적으로 권장되지 않는다.\n[정답]", "2": "청색증이 나타날 경우에는 주입 속도를 줄여야 하나 무조건 천천히 주입하는 것은 아니라서 틀리다.", "3": "영양액 주입 후 입안을 닦는 것은 일반적이지 않으며 필요하지 않다.", "4": "비위관 삽입 부위에 윤활제를 바르는 것은 올바른 방법이다.", "5": "영양액 주머니는 매번 소독할 필요 없이 청결하게 관리하면 된다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống thông", "def_ko": "위나 장을 통해 영양을 공급하는 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng qua dạ dày hoặc ruột"}, {"term_ko": "청색증", "term_vi": "Xanh tím", "def_ko": "피부와 점막이 파랗게 변하는 상태", "def_vi": "Tình trạng da và niêm mạc chuyển sang màu xanh"}, {"term_ko": "비위관", "term_vi": "Ống thông dạ dày", "def_ko": "위에 삽입하는 관", "def_vi": "Ống được đặt vào dạ dày"}, {"term_ko": "윤활제", "term_vi": "Chất bôi trơn", "def_ko": "마찰을 줄이고 부드럽게 하는 물질", "def_vi": "Chất làm giảm ma sát và làm cho bề mặt trơn tru"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1214, '10', '영양액의 주입이 빠르거나 고농도의 영양을 주입할 때 나타날 수 있는 증상은?', '["혈변", "변비", "설사", "혈뇨", "단백뇨"]'::jsonb, 3, NULL, NULL, '{"1": "혈변: 소화관에서 출혈이 발생할 경우 나타날 수 있는 증상으로, 영양액 주입과는 관련이 적다.", "2": "변비: 배변이 어려운 상태로, 영양액 주입과 직접적인 연결이 없다.\n[정답]", "3": "설사: 빠르거나 고농도의 영양액 주입 시 장에 자극을 줄 수 있어 설사가 발생할 수 있다.", "4": "혈뇨: 비뇨기계의 출혈로 인한 증상으로, 영양액과 관련이 없다.", "5": "단백뇨: 신장 문제에 의한 증상으로, 직접적인 연관성은 적다."}'::jsonb, '[{"term_ko": "영양액", "term_vi": "Dịch dinh dưỡng", "def_ko": "영양 chất이 포함된 액체(한국어)", "def_vi": "chất lỏng chứa dinh dưỡng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1213, '10', '경관영양을 받고 있는 대상자가 설사를 계속할 때 주의해서 관찰해야 하는것은?', '["탈수", "구토", "오심", "부종", "다뇨"]'::jsonb, 1, NULL, NULL, '{"1": "설사를 지속할 경우 탈수가 발생할 수 있으므로 주의 깊게 관찰해야 합니다.\n[정답]", "2": "구토는 탈수와 관련성 있지만 우선적으로 관찰해야 하는 것은 아닙니다.", "3": "오심은 불편감을 초래하나 탈수와 직접적인 연관이 없습니다.", "4": "부종은 경관영양과 관련이 적고, 주의해야 할 사항이 아닙니다.", "5": "다뇨는 다른 건강문제를 시사할 수 있지만, 설사와의 직접적인 연관은 적습니다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "위나 장을 통해 영양을 공급하는 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng qua dạ dày hoặc ruột"}, {"term_ko": "탈수", "term_vi": "Mất nước", "def_ko": "체내 수분이 부족한 상태", "def_vi": "Tình trạng thiếu nước trong cơ thể"}, {"term_ko": "구토", "term_vi": "Nôn", "def_ko": "입이나 코를 통해 위 내용물이 나오는 것", "def_vi": "Sự thoát ra của thức ăn từ dạ dày qua miệng hoặc mũi"}, {"term_ko": "오심", "term_vi": "Buồn nôn", "def_ko": "메스꺼움과 구토를 유발하는 불쾌한 감정", "def_vi": "Cảm giác khó chịu gây nôn mửa"}, {"term_ko": "부종", "term_vi": "Phù", "def_ko": "체내에 수분이 축적되어 부풀어 오르는 상태", "def_vi": "Tình trạng tích tụ nước trong cơ thể gây sưng"}, {"term_ko": "다뇨", "term_vi": "Tiểu nhiều", "def_ko": "소변의 양이 비정상적으로 많아지는 현상", "def_vi": "Hiện tượng lượng nước tiểu bất thường tăng lên"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1212, '10', '경관영양 돕기 시 시설장, 간호사에게 반드시 보고해야 할 사항은?', '["비위관이 눌려 있을 때", "비위관이 새고 있을 때", "영양액이 천천히 들어가고 있을 때", "대상자가 무의식적으로 빼려고 할 때", "비위관이 꺾여 있을 때"]'::jsonb, 2, NULL, NULL, '{"1": "비위관이 눌려 있을 때는 보고할 필요가 있다. 하지만 긴급히 보고해야 할 상황은 아니다.\n[정답]", "2": "비위관이 새고 있을 때는 즉시 보고해야 하는 중요한 사항이다.", "3": "영양액이 천천히 들어가고 있을 때는 문제의 소지가 있으나, 보고해야 할 사항은 아니다.", "4": "대상자가 무의식적으로 빼려고 할 때는 주의가 필요하나, 보고해야 할 사항으로 보기는 어렵다.", "5": "비위관이 꺾여 있을 때는 상황을 점검해야하나, 즉각 보고할 사항은 아니다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "인공적으로 영양을 공급하는 방법(비위관)", "def_vi": "Phương pháp cung cấp dinh dưỡng một cách nhân tạo (ống dẫn dinh dưỡng)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1211, '10', '경관영양 돕기의 기본원칙으로 옳은 것은?', '["유효기간이 지난 영양액은 끓여서 주입한다.", "영양주머니는 하루에 한 번 세척하여 건조시킨다.", "대상자가 의식이 없어도 식사 시작과 끝을 알린다.", "비위관이 새거나 영양액이 역류되면 비위관을 즉시 뺀다.", "관이 막히지 않도록 영양액을 빠르게 주입한다."]'::jsonb, 3, NULL, NULL, '{"1": "유효기간이 지난 영양액은 끓여서 주입하면 안 된다. 이는 안전과 효과를 보장하지 못하기 때문이다.\n[정답]", "3": "대상자가 의식이 없어도 식사 시작과 끝을 알리는 것은 의사소통을 통한 안정감을 제공할 수 있기 때문이다.", "2": "영양주머니는 매일 세척할 필요는 없으며, 제조사 지침에 따라 관리해야 한다.", "4": "비위관이 새거나 영양액이 역류될 경우에는 확인 후 조치를 취해야 하며, 즉시 제거하는 것은 상황에 따라 달라질 수 있다.", "5": "영양액은 천천히 주입해야 관과 대상자의 안전을 보장할 수 있다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua ống", "def_ko": "비경구적 방법으로 영양을 공급하는 것", "def_vi": "Phương pháp cung cấp dinh dưỡng không qua đường miệng"}, {"term_ko": "영양액", "term_vi": "Dung dịch dinh dưỡng", "def_ko": "체내에 공급되는 영양소가 포함된 액체", "def_vi": "Chất lỏng chứa các chất dinh dưỡng được cung cấp cho cơ thể"}, {"term_ko": "비위관", "term_vi": "Ống thông dạ dày", "def_ko": "위에 영양액을 공급하기 위한 관", "def_vi": "Ống được sử dụng để cung cấp dung dịch dinh dưỡng vào dạ dày"}, {"term_ko": "역류", "term_vi": "Trào ngược", "def_ko": "액체가 원래 있던 위치로 되돌아가는 현상", "def_vi": "Hiện tượng chất lỏng trở lại vị trí ban đầu"}, {"term_ko": "유효기간", "term_vi": "Thời hạn sử dụng", "def_ko": "제품이 안전하고 효과적으로 사용될 수 있는 기간", "def_vi": "Khoảng thời gian sản phẩm có thể được sử dụng một cách an toàn và hiệu quả"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1210, '10', '경관영양을 해야 하는 대상자는?', '["편식하는 대상자", "영양공급이 충분한 대상자", "식사를 거부하는 대상자", "의식이 없거나 혼수에 빠진 대상자", "의치를 착용하고 있는 대상자"]'::jsonb, 4, NULL, NULL, '{"1": "편식하는 대상자는 경관영양이 필요하지 않다.\n[정답]", "3": "의식이 없거나 혼수에 빠진 대상자는 경관영양이 반드시 필요하다.", "2": "영양공급이 충분한 대상자는 경관영양이 필요하지 않다.", "4": "의치를 착용하고 있는 대상자는 경관영양이 필요하지 않다.", "5": "식사를 거부하는 대상자는 경관영양이 필요할 수 있으나, 의식이 없거나 혼수에 빠진 경우가 더 명확하다."}'::jsonb, '[{"term_ko": "경관영양", "term_vi": "Dinh dưỡng qua đường dẫn", "def_ko": "위장관에 직접 영양을 공급하는 방법", "def_vi": "Phương pháp cung cấp dinh dưỡng trực tiếp vào đường tiêu hóa"}, {"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "도움이나 지원이 필요한 사람", "def_vi": "Người cần sự trợ giúp hoặc hỗ trợ"}, {"term_ko": "편식", "term_vi": "Kén ăn", "def_ko": "특정 음식만 고집하는 것", "def_vi": "Chỉ ăn một số loại thực phẩm nhất định"}, {"term_ko": "혼수", "term_vi": "Hôn mê", "def_ko": "의식이 없는 상태", "def_vi": "Trạng thái không có ý thức"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "스스로 알고 느끼는 상태", "def_vi": "Trạng thái tự nhận thức và cảm nhận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1209, '10', '왼쪽 편마비 대상자에게 침상에서 식사를 제공하는 방법으로 옳은 것은?', '["대상자의 왼쪽에서 식사를 돕는다.", "입안의 왼쪽에 음식을 넣어준다.", "오른쪽 상체를 베개로 지지해준다.", "오른손에 식사보조도구를 끼워준다.", "식후 왼쪽의 입안에 음식 찌꺼기가 남아 있는지 확인한다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자의 왼쪽에서 식사를 돕는 것은 편마비 환자에게 불편할 수 있습니다.\n[정답]", "5": "식후 왼쪽의 입안에 음식 찌꺼기가 남아 있는지 확인하는 것은 안전을 위해 매우 중요합니다.", "2": "입안의 왼쪽에 음식을 넣어주는 것은 잘못된 방법입니다.", "3": "오른쪽 상체를 베개로 지지해주는 것은 도움이 될 수 있지만 기준이 아닙니다.", "4": "오른손에 식사보조도구를 끼우는 것은 편마비 환자에게 적절하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "편측 마비(사람의 한 쪽의 신체가 마비됨을 의미함)", "def_vi": "Tình trạng cơ thể bị liệt ở một bên"}, {"term_ko": "입안", "term_vi": "Miệng", "def_ko": "입의 안쪽", "def_vi": "Bên trong miệng"}, {"term_ko": "음식 찌꺼기", "term_vi": "Thức ăn thừa", "def_ko": "음식을 먹은 뒤 남은 것", "def_vi": "Phần thức ăn còn lại sau khi ăn"}, {"term_ko": "식사 보조 도구", "term_vi": "Dụng cụ hỗ trợ ăn uống", "def_ko": "식사할 때 사용하는 전문 도구", "def_vi": "Dụng cụ chuyên dụng để ăn uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1208, '10', '연하곤란이 있는 대상자에게 식사를 제공할 때 사레를 예방하는 방법은?', '["대화하면서 식사를 제공한다.", "국물이 많은 음식을 제공한다.", "식사 전에 입안을 물로 헹궈 목을 축이게 한다.", "다양한 향신료를 넣은 음식을 제공한다.", "음식을 완전히 삼키기 전에 더 넣어 준다."]'::jsonb, 3, NULL, NULL, '{"1": "대화하면서 식사를 제공하면 집중력이 떨어져 사레가 발생할 수 있습니다.\n[정답]", "3": "식사 전에 입안을 물로 헹궈 목을 축이면 삼키는 데 도움이 됩니다.", "2": "국물이 많은 음식을 제공하면 삼키기 어려운 경우가 있어 위험합니다.", "4": "다양한 향신료를 넣은 음식은 자극적일 수 있어 사레를 유발할 수 있습니다.", "5": "음식을 완전히 삼키기 전에 더 넣어 주면 기도가 막힐 위험이 있습니다."}'::jsonb, '[{"term_ko": "연하곤란", "term_vi": "Khó khăn trong việc nuốt", "def_ko": "삼키기 어려운 증상", "def_vi": "Triệu chứng khó nuốt"}, {"term_ko": "사레", "term_vi": "Sặc", "def_ko": "기도가 막혀서 발생하는 현상", "def_vi": "Hiện tượng tắc nghẽn đường thở"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "입안", "term_vi": "Miệng", "def_ko": "입의 안쪽", "def_vi": "Phần bên trong của miệng"}, {"term_ko": "헹구다", "term_vi": "Rửa", "def_ko": "헹구거나 씻어내는 행위", "def_vi": "Hành động rửa hoặc làm sạch"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1207, '10', '편마비 대상자의 식사 돕기 방법으로 옳은 것은?', '["시력이 저하된 대상자는 음식을 한꺼번에 섞어서 제공한다.", "식사 중 연하곤란이 있는지 주의 깊게 관찰한다.", "마비된 쪽의 입가에 흐르는 음식물은 그대로 둔다.", "식사 중에도 수시로 질문하여 상태를 확인한다.", "식사 후 바로 누워 쉬게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "시력이 저하된 대상자에게 음식물을 섞어서 제공하는 것은 혼란을 줄 수 있으며, 이는 옳지 않은 방법입니다.\n[정답]", "2": "식사 중 연하곤란 여부를 주의 깊게 관찰하는 것은 매우 중요합니다. 대상자의 안전을 위해 반드시 체크해야 합니다.", "3": "마비된 쪽의 입가에 흐르는 음식물은 즉시 제거해야 하며, 방치하는 것은 위험합니다.", "4": "식사 중에 질문하여 상태를 확인하는 것은 필요하지만, 너무 자주 질문하는 것은 대상자에게 스트레스를 줄 수 있습니다.", "5": "식사 후 바로 누워 쉬게 하는 것은 소화에 좋지 않으며, 바른 자세로 앉아 있게 하는 것이 좋습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸이 마비된 상태", "def_vi": "Tình trạng mất khả năng vận động một bên cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1206, '10', '대상자에게 숟가락을 사용하여 음식을 제공할 때 올바른 방법은?', '["숟가락으로 음식을 가득 떠서 넣어준다.", "숟가락 끝부분으로 입술 옆쪽에 대고 먹인다.", "숟가락을 입속 중앙으로 넣어 먹인다.", "대상자가 오른손잡이라면 왼쪽에서 먹인다.", "편마비 대상자는 불편한 쪽에서 넣어준다."]'::jsonb, 2, NULL, NULL, '{"1": "숟가락으로 음식을 가득 떠서 넣어주는 것은 적절하지 않다. 너무 많은 양을 한 번에 넣는 것은 위험할 수 있다.\n[정답]", "2": "숟가락 끝부분으로 입술 옆쪽에 대고 먹이는 것은 대상자가 편안하게 음식을 먹을 수 있도록 돕는 바른 방법이다.", "3": "숟가락을 입속 중앙으로 넣어 먹이는 것은 대상자의 안전을 고려할 때 좋지 않은 방법이다.", "4": "대상자가 오른손잡이라면 왼쪽에서 먹이는 것은 바람직하지 않다; 일반적으로 오른손잡이는 오른쪽에서 음식을 서빙받는 것이 편하다.", "5": "편마비 대상자는 불편한 쪽에서 넣어주는 것은 도움이 되지 않으므로, 편한 쪽에서 접근할 필요가 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자 또는 수혜자", "def_vi": "Bệnh nhân hoặc người thụ hưởng"}, {"term_ko": "숟가락", "term_vi": "Muỗng", "def_ko": "음식 제공 도구", "def_vi": "Công cụ để cung cấp thực phẩm"}, {"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 몸의 마비 상태", "def_vi": "Tình trạng bị liệt một bên cơ thể"}, {"term_ko": "입술", "term_vi": "Môi", "def_ko": "입 주위의 부위", "def_vi": "Vùng xung quanh miệng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1205, '10', '편마비 대상자의 식사를 돕는 방법으로 옳은 것은?', '["똑바로 누운 자세를 취한다.", "대상자의 상체를 낮춘다.", "국을 한 숟가락 먹인 후 밥을 준다.", "마비된 쪽의 입가로 음식을 넣어준다.", "국물은 가는 빨대를 이용하여 마시게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "똑바로 누운 자세는 식사 시 안전하지 않아 권장되지 않습니다.\n[정답]", "3": "국을 한 숟가락 먹인 후 밥을 주는 방법은 식사를 안전하고 효율적으로 돕는 방식입니다.", "2": "대상자의 상체를 낮추는 것은 식사에 적절하지 않습니다.", "4": "마비된 쪽의 입가로 음식을 넣는 것은 위험할 수 있습니다.", "5": "가는 빨대를 사용하는 것은 식사 방법으로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nửa người", "def_ko": "한쪽 신체가 마비된 상태", "def_vi": "Tình trạng một bên cơ thể bị liệt"}, {"term_ko": "식사", "term_vi": "Ăn uống", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1204, '10', '대상자의 식사 돕기를 할 때 가장 먼저 해야 하는 것은?', '["배설여부를 확인한다.", "구강을 청결하게 한다.", "침대 머리를 올려 상체를 높인다.", "주변을 편안하고 깨끗하게 정리한다.", "어떤 음식이 나왔는지 대상자에게 알려준다."]'::jsonb, 1, NULL, NULL, '{"1": "배설여부를 확인한다. 대상자의 식사가 이루어지기 전에 배설 여부를 확인하는 것이 중요합니다.\n[정답]", "2": "구강을 청결하게 한다. 식사 전에 구강 위생을 유지하는 것도 중요하지만, 먼저 배설 여부를 확인해야 합니다.", "3": "침대 머리를 올려 상체를 높인다. 이 단계는 식사 상황에서 구체적인 행동이지만, 배설 여부 확인이 먼저입니다.", "4": "주변을 편안하고 깨끗하게 정리한다. 환경 정리는 중요하지만, 우선적으로 대상자의 생리적 상태를 확인해야 합니다.", "5": "어떤 음식이 나왔는지 대상자에게 알려준다. 음식에 대한 안내는 식사 준비의 일부이지만, 배설 여부 확인이 선행되어야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "식사", "def_ko": "환자, người bệnh", "def_vi": "ăn uống, bữa ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1203, '10', '다음 중 사레 들리기 쉬운 대상자가 주의해야 하는 과일은?', '["배", "수박", "바나나", "홍시", "자몽"]'::jsonb, 5, NULL, NULL, '{"1": "배는 비교적 안전한 과일입니다.\n[정답]", "2": "자몽은 사레 들리기 쉬운 과일로, 특히 주의가 필요합니다.", "3": "바나나도 주의가 필요하지만 자몽보다 덜 위험합니다.", "4": "홍시는 일반적으로 안전하지만 개인 차가 있을 수 있습니다.", "5": "수박은 대체로 안전한 과일입니다."}'::jsonb, '[{"term_ko": "사레", "term_vi": "사́u", "def_ko": "목에 걸린 것(한국어)", "def_vi": "điều khiển nào đó (베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1202, '10', '대ㅐ상자에게 신맛이 나는 음식을 제한하는 이유는?', '["입맛이 떨어진다.", "설사를 유발한다.", "메스꺼움이 심해진다.", "사레 들릴 수 있다.", "입안이 건조해진다."]'::jsonb, 4, NULL, NULL, '{"1": "신맛이 나는 음식이 입맛을 떨어트릴 수 있지만, 주된 이유는 아닙니다.\n[정답]", "2": "신맛이 나는 음식은 메스꺼움을 유발하기 때문에 사레에 들릴 위험이 있습니다.", "3": "신맛이 나는 음식이 설사를 유발하는 경우는 있으나, 이는 일반적이지 않습니다.", "4": "신맛이 나는 음식은 메스꺼움을 심화시킬 수 있는 요소입니다.", "5": "신맛이 나는 음식은 입안을 건조하게 할 수 있으나, 다른 영향보다 덜 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được phục vụ", "def_ko": "치료를 받거나 도움을 필요로 하는 사람", "def_vi": "Người cần điều trị hoặc trợ giúp"}, {"term_ko": "신맛", "term_vi": "Vị chua", "def_ko": "신맛을 느끼는 맛", "def_vi": "Vị cảm nhận chua"}, {"term_ko": "설사", "term_vi": "Tiêu chảy", "def_ko": "변이 묽어지는 증상", "def_vi": "Triệu chứng phân lỏng"}, {"term_ko": "메스꺼움", "term_vi": "Buồn nôn", "def_ko": "구역질을 느끼는 증상", "def_vi": "Triệu chứng cảm thấy buồn nôn"}, {"term_ko": "사레", "term_vi": "Nghẹn", "def_ko": "기도가 막히거나 걸리는 현상", "def_vi": "Hiện tượng bị tắc nghẽn khí quản"}, {"term_ko": "입안", "term_vi": "Miệng", "def_ko": "구강 내부", "def_vi": "Phần bên trong của miệng"}, {"term_ko": "건조", "term_vi": "Khô", "def_ko": "수분이 부족함", "def_vi": "Thiếu độ ẩm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1201, '10', '연하곤란이 있는 대상자에게 식사를 제공 시 옳은 것은?', '["기침을 하면 쉬었다 먹인다.", "음식을 빨리 먹도록 재촉한다.", "사레가 들리면 식사를 중단하고 즉시 시설장에게 보고한다.", "사레 위험이 있으므로 식사 전에 물을 먹이지 않는다.", "배 부위와 가슴을 압박하는 옷으로 등을 펴게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "기침을 하면 잠시 쉬도록 하는 것이 필요하지만, 오래 쉬게 하는 것은 좋지 않다.\n[정답]", "3": "사레가 들리면 즉시 식사를 중단하고 필요한 조치를 취해야 한다.", "2": "음식을 재촉하는 것은 위험할 수 있다.", "4": "식사 전에 물을 먼저 주는 것은 오히려 위험을 증가시킬 수 있다.", "5": "압박 옷은 호흡을 어렵게 할 수 있어 주의해야 한다."}'::jsonb, '[{"term_ko": "연하곤란", "term_vi": "Khó khăn trong việc nuốt", "def_ko": "삼키는 것이 어려운 상태", "def_vi": "Tình trạng khó nuốt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1200, '10', '사레들리기 쉬운 대상자가 바나나를 먹고 싶어 할 때 대처방법은?', '["불에 익혀서 준다.", "통째로 준다.", "얼음으로 얼려서 준다.", "숟가락으로 긁어서 준다.", "한 입에 들어갈 크기로 잘라서 준다."]'::jsonb, 4, NULL, NULL, '{"1": "불에 익혀서 준다: 바나나를 익히는 것은 식감이나 영양소에 영향을 줄 수 있다.\n[정답]", "4": "숟가락으로 긁어서 준다: 식사가 어려운 대상자에게 적합한 방법이다.", "2": "통째로 준다: 통째로 주는 것은 대상자가 삼키기 어려울 수 있다.", "3": "얼음으로 얼려서 준다: 얼음으로 제공하면 효과적인 식사가 어려울 수 있다.", "5": "한 입에 들어갈 크기로 잘라서 준다: 잘라서는 방법이지만, 대상자의 상황에 따라 적합하지 않을 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1199, '10', '연하곤란이 있는 대상자에게 식사를 제공하는 방법으로 옳은 것은?', '["많은 양의 음식을 한꺼번에 준다.", "딱딱한 음식을 제공한다.", "레몬 소스를 곁들인 샐러드를 제공한다.", "똑바로 누운 상태에서 천천히 제공한다.", "충분히 삼킬 수 있는 적은 양을 입에 넣어준다."]'::jsonb, 5, NULL, NULL, '{"1": "많은 양의 음식을 한꺼번에 준다. - 연하곤란이 있는 경우, 많은 양을 한꺼번에 주는 것은 위험합니다.\n[정답]", "2": "충분히 삼킬 수 있는 적은 양을 입에 넣어준다. - 적은 양을 천천히 제공하는 것이 안전하며, 삼킬 수 있는 양을 고려해야 합니다.", "3": "레몬 소스를 곁들인 샐러드를 제공한다. - 산성이 강한 음식은 연하곤란 환자에게 적합하지 않습니다.", "4": "똑바로 누운 상태에서 천천히 제공한다. - 눕힌 상태에서 식사를 제공하면 기도막힘 등이 발생할 수 있습니다.", "5": "딱딱한 음식을 제공한다. - 딱딱한 음식은 연하곤란 환자에게 적합하지 않습니다."}'::jsonb, '[{"term_ko": "연하곤란", "term_vi": "Khó khăn trong việc nuốt", "def_ko": "삼키는 데 어려움이 있는 상태", "def_vi": "Tình trạng khó khăn trong việc nuốt"}, {"term_ko": "대상자", "term_vi": "Người nhận sự chăm sóc", "def_ko": "돌봄을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "제공하다", "term_vi": "Cung cấp", "def_ko": "제공하다, 주다", "def_vi": "Cung cấp, cho"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1198, '10', '대상자의 식욕을 증진시키는 방법으로 옳은 것은?', '["식사 전에 수면을 취하게 한다.", "식사 전에 몸을 움직이지 못하게 한다.", "조명을 어둡고 차분하게 한다.", "식사 전에 간식을 제공한다.", "식사 전에 밖으로 나가 맑은 공기를 마시게 한다."]'::jsonb, 5, NULL, NULL, '{"1": "식사 전에 수면을 취하게 하는 것은 식욕을 증진시키지 않음.\n[정답]", "5": "식사 전에 밖으로 나가 맑은 공기를 마시게 하는 것은 식욕을 증진시킬 수 있음.", "3": "조명을 어둡고 차분하게 하는 것은 식욕에 도움을 주지 않음.", "2": "식사 전에 몸을 움직이지 못하게 하는 것은 식욕을 오히려 저하시킬 수 있음.", "4": "간식을 제공하는 것은 식사를 대신할 수 있어 식욕에 부정적 영향을 줄 수 있음."}'::jsonb, '[{"term_ko": "식욕", "term_vi": "Thèm ăn", "def_ko": "식사를 하고 싶은 마음", "def_vi": "Ý muốn ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1197, '10', '의자에 앉아 있는 대상자가 등이 구부정한 상태에서 식사할 경우 발생할 수 있는 합병증은?', '["식도염", "천식", "폐결핵", "폐렴", "후두염"]'::jsonb, 4, NULL, NULL, '{"1": "식도염은 주로 위산의 역류와 관련된 질환입니다.\n[정답]", "4": "폐렴은 구부정한 자세로 식사할 경우 음식물이 기도로 잘 들어가면서 발생할 수 있는 합병증입니다.", "2": "천식은 주로 알레르기와 관련이 깊고 식사 자세와는 관계가 없습니다.", "3": "폐결핵은 전염성 질환으로 자세와는 직접적인 연관이 없습니다.", "5": "후두염은 주로 바이러스 감염이나 사용을 과도하게 한 경우에 발생하는 질환입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1196, '10', '음식물을 삼키기 힘들어 하는 대상자를 돕는 방법으로 옳은 것은?', '["삼키기 쉽도록 턱을 위로 들게 하여 식사를 제공한다.", "대상자가 원하는 만큼의 양을 입에 넣어준다.", "완전히 삼켰는지 확인한 후 음식을 제공한다.", "천천히 식사하도록 자주 질문을 한다.", "대상자 스스로 식사할 수 있으면 자리를 비켜준다."]'::jsonb, 3, NULL, NULL, '{"1": "삼키기 쉽도록 턱을 위로 들게 하여 식사를 제공하는 것은 오히려 삼키기 어려운 자세가 될 수 있다.\n[정답]", "3": "완전히 삼켰는지 확인한 후 음식을 제공하는 것이 안전한 방법이다.", "2": "대상자가 원하는 만큼의 양을 입에 넣어주는 것은 과다 섭취로 이어질 수 있어 위험하다.", "4": "천천히 식사하도록 자주 질문하는 것은 대상자가 불안해할 수 있어 권장되지 않는다.", "5": "대상자 스스로 식사할 수 있으면 자리를 비켜주는 것은 안전 문제를 고려해야 하므로 조심해야 한다."}'::jsonb, '[{"term_ko": "삼키다", "term_vi": "Nuốt", "def_ko": "목구멍으로 음식을 통과시키다(한국어)", "def_vi": "Làm cho thức ăn đi qua cổ họng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1195, '10', '왼쪽 편마비 대상자가 침상에서 편안하게 식사하도록 돕는 방법은?', '["오른쪽을 밑으로 하여 약간 옆으로 누운 자세를 취한다.", "상체를 세운 후 얼굴을 왼쪽으로 돌린다.", "침상 식탁에 왼팔을 올려 주고 똑바로 앉힌다.", "사례가 들리면 침대 머리를 최대한 올려준다.", "식후 오른쪽 뺨 부위에 음식물이 남아 있는지 확인한다."]'::jsonb, 1, NULL, NULL, '{"1": "오른쪽을 밑으로 하여 약간 옆으로 누운 자세를 취하면 왼쪽 편마비가 있는 환자가 식사하기에 더 편안해질 수 있습니다.\n[정답]", "2": "상체를 세운 후 얼굴을 왼쪽으로 돌린다면 편마비 쪽으로 음식이 들어가기 어려워 식사에 도움이 되지 않습니다.", "3": "왼팔을 올려주고 똑바로 앉히는 것은 편안한 식사를 도와주지 않습니다.", "4": "침대 머리를 올리는 것은 식사 시 도움이 될 수 있지만, 정답이 아닙니다.", "5": "식후 오른쪽 뺨에 음식물이 남아 있는지 확인하는 것은 중요하지만, 식사 방법이 아닙니다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Bệnh liệt nửa người", "def_ko": "한쪽 신체의 마비(한국어)", "def_vi": "Tình trạng liệt một bên cơ thể"}, {"term_ko": "침상", "term_vi": "Giường bệnh", "def_ko": "침대(한국어)", "def_vi": "Giường dùng trong bệnh viện"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식 먹기(한국어)", "def_vi": "Thời gian ăn uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1194, '10', '오른쪽 편마비가 있는 대상자가 누워있는 상태에서 식사를 할 때 돕기 방법은?', '["침대에 똑바로 누운 상태에서 천천히 음식을 제공한다.", "왼쪽을 밑으로 하여 약간 옆으로 누운 자세에서 음식을 제공한다.", "오른쪽을 밑으로 하여 약간 옆으로 누운 자세에서 음식을 제공한다.", "왼쪽을 베개나 쿠션으로 지지하여 안정감을 준다.", "오른쪽 입에 빨대를 고정시켜 국물을 제공한다."]'::jsonb, 2, NULL, NULL, '{"1": "침대에 똑바로 누운 상태에서는 오른쪽 편마비로 인해 음식물이 잘 넘어갈 수 없고, 안전하지 않다.\n[정답]", "2": "왼쪽을 밑으로 하여 약간 옆으로 누운 자세는 오른쪽 편마비 환자가 안정적으로 식사를 할 수 있도록 도와준다.", "3": "오른쪽을 밑으로 하여 누운 자세는 편마비된 쪽에 대한 식사가 불리할 수 있다.", "4": "왼쪽을 베개나 쿠션으로 지지하는 것은 필요한 지원이지만, 측면 자세로 음식을 제공하는 것이 효과적이다.", "5": "오른쪽 입에 빨대를 고정시키는 것은 비효율적이며, 잘못된 방법이다."}'::jsonb, '[{"term_ko": "편마비", "term_vi": "Liệt nữa người", "def_ko": "한쪽 몸에 힘이 없거나 마비된 상태", "def_vi": "Trạng thái mất sức hoặc liệt một bên cơ thể"}, {"term_ko": "지지", "term_vi": "Hỗ trợ", "def_ko": "물체를 받쳐서 안정감을 주는 것", "def_vi": "Đặt vật gì đó để tạo sự ổn định"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "어떤 방식으로 몸을 두는 것", "def_vi": "Cách cơ thể được đặt"}, {"term_ko": "안정감", "term_vi": "Cảm giác an toàn", "def_ko": "편안함과 안전함을 느끼는 감정", "def_vi": "Cảm giác thoải mái và an toàn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1193, '10', '침상에 누워 있는 대상자에게 식사를 제공할 때 사례를 예방하는 방법으로 옳은 것은?', '["물기가 없는 음식을 제공한다.", "상체를 높이고 턱을 든 자세를 취하게 한다.", "입맛을 돋우기 위해 신맛 나는 음식을 먼저 준다.", "음식을 먹고 있는 도중에 말을 시킨다.", "침상 머리를 30~60도 높인 후 음식을 제공한다."]'::jsonb, 5, NULL, NULL, '{"1": "물기가 없는 음식을 제공한다는 것은 식사를 더 안전하게 만드는 방법은 아닙니다.\n[정답]", "5": "침상 머리를 30~60도 높인 후 음식을 제공하는 것이 가장 안전한 방법입니다.", "3": "신맛 나는 음식을 먼저 주는 것은 입맛을 돋우는 데 도움이 될 수 있으나, 안전과는 관련이 없습니다.", "4": "음식을 먹고 있는 도중에 말하는 것은 위험할 수 있습니다.", "2": "상체를 높이고 턱을 든 자세는 도움이 되나, 충분한 각도를 유지하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자, 또는 돌봄이 필요한 사람", "def_vi": "Bệnh nhân hoặc người cần chăm sóc"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식 먹는 것", "def_vi": "Việc ăn uống"}, {"term_ko": "사례", "term_vi": "Trường hợp", "def_ko": "사고나 문제가 발생하는 경우", "def_vi": "Khi có sự cố hoặc vấn đề xảy ra"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "미리 방지하다", "def_vi": "Phòng ngừa trước"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1192, '10', '대상자가 식탁에서 식사할 때 올바른 자세는?', '["의자에 깊숙이 앉고 식탁 위에 팔꿈치를 올린다.", "음식을 먹는 경우 머리를 뒤로 젖힌다.", "의자의 앞쪽 끝부분에 걸터 앉게 한다.", "발가락 끝이 바닥에 닿게 의자 높이를 조절한다.", "등받이에 등이 닿지 않게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "의자에 깊숙이 앉고 식탁 위에 팔꿈치를 올리는 것은 올바른 자세이다.\n[정답]", "2": "음식을 먹는 경우 머리를 뒤로 젖히는 것은 올바르지 않다.", "3": "의자의 앞쪽 끝부분에 걸터 앉게 하는 것은 올바르지 않다.", "4": "발가락 끝이 바닥에 닿게 의자 높이를 조절해야 하는 것은 올바르지 않다.", "5": "등받이에 등이 닿지 않게 하는 것은 올바르지 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1191, '10', '거동이 불편한 대상자의 식사를 돕는 방법으로 옳은 것은?', '["바퀴가 달린 의자에 앉게 한다.", "팔 받침이 없는 의자에 앉게 한다.", "발바닥이 바닥에 닿도록 의자 높이를 조절한다.", "식탁 상판의 높이를 대상자의 가슴 위치로 조절한다.", "휠체어에 안장서 식사할 때는 식탁과 충분한 간격을 둔다."]'::jsonb, 3, NULL, NULL, '{"1": "바퀴가 달린 의자에 앉게 하는 것은 이동에 편리할 수 있으나, 안정성을 고려할 때 식사 시 적합하지 않습니다.\n[정답]", "3": "발바닥이 바닥에 닿도록 의자 높이를 조절하는 것은 안정성을 제공하며 올바른 자세를 유지할 수 있도록 도와줍니다.", "2": "팔 받침이 없는 의자에 앉게 하는 것은 팔의 지지 없이 불편함을 초래할 수 있습니다.", "4": "식탁 상판의 높이를 대상자의 가슴 위치로 조절하는 것은 식사 시 편리하지 않을 수 있습니다.", "5": "휠체어에 안장서 식사할 때는 식탁과의 간격이 너무 멀면 불편할 수 있습니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "거 động", "def_ko": "움직임(한국어)", "def_vi": "sự di chuyển(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1190, '10', '대상자가 식탁에서 식사할 때 식탁의 높이로 옳은 것은?', '["턱 밑", "가슴 위", "배 아래", "가슴과 배꼽 사이", "최대한 높게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "턱 밑: 식사가 불편하고 잘 보이지 않을 수 있음.", "2": "가슴 위: 불편함을 초래할 수 있음.\n[정답]", "3": "배 아래: 식탁이 너무 낮아 편안하지 않을 수 있음.", "4": "가슴과 배꼽 사이: 적절한 높이로 식사 시 편안함을 제공함.", "5": "최대한 높게 한다: 지나치게 높으면 불편하게 될 수 있음."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "환자, 이용자", "def_vi": "Bệnh nhân, người sử dụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1189, '10', '대상자가 삼키는 능력이 없고 의식장애가 있을 때 비위관을 통하여 제공하는 식이의 종류는?', '["일반식", "저작 도움식", "경관 유동식", "경구 유동식", "연하 도움식"]'::jsonb, 3, NULL, NULL, '{"1": "일반식은 삼키는 능력이 있는 자에게 제공하는 식사입니다.", "2": "저작 도움식은 저작이 가능한 대상자에게 적합한 식사입니다.\n[정답]", "3": "경관 유동식은 비위관을 통해 제공할 수 있는 식사로, 삼키는 능력이 없는 대상자에게 적합합니다.", "4": "경구 유동식은 입을 통한 섭취가 가능한 대상자에게 제공됩니다.", "5": "연하 도움식은 연하 문제가 있는 대상자에게 저작이 가능할 때 사용하는 식사입니다."}'::jsonb, '[{"term_ko": "삼키다", "term_vi": "Nuốt", "def_ko": "먹다(한국어)", "def_vi": "ăn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1188, '10', '저작과 연하 능력이 떨어져 씹고 삼키기 어려운 대상자에게 제공하는 식이의 종류는?', '["경관 유동식", "경구 유동식", "연하 도움식", "저작 도움식", "일반식"]'::jsonb, 3, NULL, NULL, '{"1": "경관 유동식: 특정한 경로(예: 비위관 등)로 제공되는 액체 형태의 식사입니다.\n[정답]", "2": "연하 도움식: 연하 장애가 있는 환자를 위해 고안된, 꼭 필요한 영양소를 포함하는 식사입니다.", "3": "경구 유동식: 구강을 통해 유동적으로 섭취할 수 있는 식사입니다.", "4": "저작 도움식: 저작에 도움이 되도록 조리된 식사입니다.", "5": "일반식: 일반인이 섭취할 수 있는 평범한 식사입니다."}'::jsonb, '[{"term_ko": "저작", "term_vi": "Nhai", "def_ko": "씹는 행위", "def_vi": "Hành động nhai"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1187, '10', '저작능력이 떨어져 단단하고 질긴 음식을 먹기 어려운 대상자에게 제공하는 식이의 종류는?', '["저작 도움식", "연하 도움식", "경구 유동식", "일반식", "경관 유동식"]'::jsonb, 1, NULL, NULL, '{"1": "저작에 도움이 되는 음식을 제공하는 식이입니다.\n[정답]", "2": "연하(삼킴)에 어려움을 겪는 대상자를 위한 식이입니다.", "3": "구강을 통해 섭취하는 유동식으로 쉽게 흡수되지만 저작능력 문제와는 직접적인 연관이 없습니다.", "4": "일반적인 식사로 저작능력과 관계없이 제공됩니다.", "5": "경관을 통해 제공되는 유동식으로 저작능력의 문제를 해결하기 위한 것은 아닙니다."}'::jsonb, '[{"term_ko": "저작능력", "term_vi": "Khả năng nhai", "def_ko": "음식을 씹는 능력", "def_vi": "Khả năng nhai thức ăn"}, {"term_ko": "연하", "term_vi": "Nuốt", "def_ko": "음식을 삼키는 능력", "def_vi": "Khả năng nuốt thức ăn"}, {"term_ko": "일반식", "term_vi": "Bữa ăn thông thường", "def_ko": "일반적인 식사", "def_vi": "Bữa ăn bình thường"}, {"term_ko": "경관", "term_vi": "Ống dẫn", "def_ko": "인공적으로 주입하는 방식", "def_vi": "Phương pháp tiêm qua ống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1186, '10', '노인 대상자의 영양부족 상태를 알 수 있는 지표에 해당하는 것은?', '["체중 증가", "인지 수준 변화", "식욕 증가", "신체기능 증진", "안정된 심리상태"]'::jsonb, 2, NULL, NULL, '{"1": "체중 증가: 영양부족 상태와는 반대로 나타나는 징후이다.\n[정답]", "2": "인지 수준 변화: 영양부족으로 인해 인지 능력이 저하될 수 있다.", "3": "식욕 증가: 영양부족 시 식욕이 감소하는 경향이 있다.", "4": "신체기능 증진: 영양부족 상태에서는 신체기능이 저하되는 경우가 많다.", "5": "안정된 심리상태: 영양부족은 심리적 불안감을 초래할 수 있다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1185, '10', '식사를 할 때 영양부족이 발생할 가능성이 있는 대상자는?', '["녹내장 대상자", "언어장애 대상자", "연하장애 대상자", "변비가 있는 대상자", "요실금이 있는 대상자"]'::jsonb, 3, NULL, NULL, '{"1": "녹내장은 시각적 문제로 식사와 직접적 연관성이 적습니다.", "2": "언어장애는 식사와의 연관성은 있으나 영양부족과는 직접적인 관련이 없습니다.\n[정답]", "3": "연하장애는 음식 섭취에 어려움이 있어 영양부족이 발생할 수 있습니다.", "4": "변비는 영양부족과는 직접적인 관련이 없습니다.", "5": "요실금도 영양부족과 관련이 없습니다."}'::jsonb, '[{"term_ko": "영양부족", "term_vi": "대상자", "def_ko": "영양 thiếu hụt", "def_vi": "đối tượng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1184, '10', '노인의 영양부족을 초래하는 위험 요인으로 옳은 것은?', '["체중 증가", "비타민 복용", "인지능력 상승", "약물사용", "규칙적인 식사"]'::jsonb, 4, NULL, NULL, '{"1": "체중 증가: 체중 증가 자체는 영양부족과 관계가 없다.\n[정답]", "4": "약물사용: 약물은 노인의 영양 상태에 영향을 미칠 수 있는 위험 요인이다.", "3": "인지능력 상승: 인지능력의 상승은 일반적으로 영양 부족과 무관하다.", "2": "비타민 복용: 비타민 복용은 영양 보충의 일환으로 볼 수 있다.", "5": "규칙적인 식사: 규칙적인 식사는 영양 부족을 예방하는데 도움이 된다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1183, '10', '노인의 건강상태를 관찰할 때 영양부족이 의심되는 상황은?', '["상처의 회복이 지연된다.", "정상적인 배설을 한다.", "수분을 충분히 섭취한다.", "종합 비타민을 복용하고 있다.", "담배를 하루에 한 갑씩 피우고 있다."]'::jsonb, 1, NULL, NULL, '{"1": "상처의 회복이 지연된다: 영양부족 시 상처 회복이 느려지므로 적절한 선택이다.\n[정답]", "2": "정상적인 배설을 한다: 정상적인 배설은 영양부족과 관계가 없다.", "3": "수분을 충분히 섭취한다: 충분한 수분 섭취는 영양부족과 무관하다.", "4": "종합 비타민을 복용하고 있다: 비타민 복용이 영양부족을 해결하는 것은 아니다.", "5": "담배를 하루에 한 갑씩 피우고 있다: 담배 흡연은 영양상태와 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "영양부족", "term_vi": "상처", "def_ko": "영양 thiếu hụt", "def_vi": "vết thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1182, '10', '연하곤란이 있는 대상자에게 식사를 제공할 때 주의 깊게 관찰해야 하는 것은?', '["탈수", "부종", "청색증", "소양증", "피부 발적"]'::jsonb, 3, NULL, NULL, '{"1": "탈수: 식사 중 수분 섭취 부족으로 인한 증상으로 연관성이 적다.", "2": "부종: 체액 저류로 인한 부풀음으로 연하곤란과 직접적인 연관성이 없다.\n[정답]", "3": "청색증: 산소 부족으로 인해 입술이나 피부가 푸르게 변하는 증상으로, 연하곤란시 가장 주의해야 하는 증상이다.", "4": "소양증: 가려움증으로 연하곤란과 큰 연관이 없다.", "5": "피부 발적: 피부의 염증으로, 연하곤란과 직접적인 연관성이 적다."}'::jsonb, '[{"term_ko": "연하곤란", "term_vi": "Khó nuốt", "def_ko": "삼키기 어려움", "def_vi": "Khó khăn trong việc nuốt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1181, '10', '섭취 요양보호의 일반적 원칙으로 옳은 것은?', '["대상자의 식사습관과 소화능력은 고려하지 않는다.", "식사방법, 속도는 요양보호사에게 맞춘다.", "식사 중에 주변 환경을 청결히 정리한다.", "대상자의 요구를 최대한 반영한다.", "식사 중에만 대상자를 주의 깊게 관찰한다."]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 식사습관과 소화능력은 고려하지 않는다. (옳지 않음: 대상자의 특성을 고려해야 함.)", "2": "식사방법, 속도는 요양보호사에게 맞춘다. (옳지 않음: 대상자에게 맞춰야 함.)\n[정답]", "3": "식사 중에 주변 환경을 청결히 정리한다. (옳음: 청결한 환경을 유지해야 하므로 옳은 원칙임.)", "4": "대상자의 요구를 최대한 반영한다. (옳음: 대상자의 욕구를 반영하는 것이 중요함.)", "5": "식사 중에만 대상자를 주의 깊게 관찰한다. (옳지 않음: 항상 관찰해야 함.)"}'::jsonb, '[{"term_ko": "섭취", "term_vi": "섭 thu", "def_ko": "먹는 것(한국어)", "def_vi": "Đồ ăn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1180, '9', '다음에서 설명하는 주요 내용을 다루는 회의는?• 요양보호사의 업무와 관련된 정보와 업무 준수사항을 전달한다. • 기관운영, 인사, 복리후생에 대해 의견 및 애로사항을 듣는다.', '["사례회의", "점검회의", "검토회의", "월례회의", "평가회의"]'::jsonb, 4, NULL, NULL, '{"1": "사례회의: 특정 사례에 대한 논의가 필요한 회의로, 설명한 내용과는 차이가 있다.\n[정답]", "4": "월례회의: 정기적으로 개최되어 요양보호사의 업무와 기관 운영 관련 사항을 점검하고 의견을 주고받는 회의이다.", "3": "검토회의: 제안된 안건이나 자료를 검토하는 회의로, 일반적으로 정기적이지 않다.", "2": "점검회의: 특정 업무의 진행 상황을 점검하는 회의지만, 요양보호사 업무에 초점을 맞추지 않을 수 있다.", "5": "평가회의: 성과를 평가하는 회의로, 업무 준수 사항을 다루기보다는 결과에 초점을 두고 있다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일(일하는 것)", "def_vi": "Công việc hoặc nhiệm vụ"}, {"term_ko": "기관", "term_vi": "Cơ quan", "def_ko": "시설, 조직", "def_vi": "Tổ chức hoặc cơ sở"}, {"term_ko": "복리후생", "term_vi": "Phúc lợi", "def_ko": "직원의 복지 향상", "def_vi": "Cải thiện phúc lợi cho nhân viên"}, {"term_ko": "회의", "term_vi": "Cuộc họp", "def_ko": "의견을 교환하는 모임", "def_vi": "Cuộc họp để trao đổi ý kiến"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1179, '9', '장기요양기관에서 실시하는 사례회의의 목적은?', '["기관의 신규 사업 홍보", "요양보호사의 업무 평가", "요양보호사의 업무와 관련된 정보 공유", "요양보호사 복리후생에 대한 의견 수렴", "서비스제공 계획의 타당성 검토와 조정"]'::jsonb, 5, NULL, NULL, '{"1": "기관의 신규 사업 홍보는 사례회의의 직접적인 목적이 아니다.\n[정답]", "5": "서비스제공 계획의 타당성 검토와 조정은 사례회의의 주된 목적 중 하나이다.", "2": "요양보호사의 업무 평가 역시 사례회의의 주 목적이 아니다.", "3": "요양보호사의 업무와 관련된 정보 공유는 중요하지만 사례회의의 핵심 목적은 아니다.", "4": "요양보호사 복리후생에 대한 의견 수렴도 사례회의의 목적과는 거리가 있다."}'::jsonb, '[{"term_ko": "장기요양기관", "term_vi": "Cơ sở chăm sóc dài hạn", "def_ko": "장기적인 요양을 제공하는 기관", "def_vi": "Cơ sở cung cấp dịch vụ chăm sóc dài hạn"}, {"term_ko": "사례회의", "term_vi": "Cuộc họp trường hợp", "def_ko": "사례를 논의하기 위한 회의", "def_vi": "Cuộc họp để thảo luận về các trường hợp"}, {"term_ko": "서비스제공 계획", "term_vi": "Kế hoạch cung cấp dịch vụ", "def_ko": "서비스 제공을 위한 계획", "def_vi": "Kế hoạch để cung cấp dịch vụ"}, {"term_ko": "타당성", "term_vi": "Tính hợp lý", "def_ko": "적절하거나 의미가 있는 것", "def_vi": "Điều gì đó phù hợp hoặc có ý nghĩa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1178, '9', '대상자의 상황과 제공되는 서비스를 점검하고 평가하여, 대상자의 욕구에 맞는 서비스를 제공하기 위해 개최하는 회의는?', '["월례회의", "사례회의", "업무보고회의", "동급평가회의", "장기요양회의"]'::jsonb, 2, NULL, NULL, '{"1": "월례회의: 정기적으로 개최되는 회의로, 특정한 상황 평가와는 관련이 적다.\n[정답]", "2": "사례회의: 대상자의 욕구에 맞춰 서비스를 제공하기 위해 개최되는 회의이다.", "3": "업무보고회의: 업무 상황을 보고하는 회의로, 평가와는 거리가 있다.", "4": "동급평가회의: 서로 동등한 위치의 사람들끼리 평가하는 회의로, 대상자 욕구와는 관련이 없다.", "5": "장기요양회의: 장기요양에 관련된 사항을 논의하는 회의지만, 특정 대상자의 욕구에 중점을 두지는 않다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 서비스를 받는 사람", "def_vi": "Bệnh nhân hoặc người nhận dịch vụ"}, {"term_ko": "욕구", "term_vi": "Nhu cầu", "def_ko": "필요나 원하는 것", "def_vi": "điều cần thiết hoặc điều mong muốn"}, {"term_ko": "제공", "term_vi": "Cung cấp", "def_ko": "공급하다", "def_vi": "cung cấp"}, {"term_ko": "회의", "term_vi": "Cuộc họp", "def_ko": "사람들의 모임", "def_vi": "cuộc họp của mọi người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1177, '9', '요양보호사가 업무수행 시 서면보고를 해야 하는 경우로 옳은 것은?', '["긴급을 요할 때", "사안이 가벼울 때", "신속하게 보고해야 할 때", "정확히 보고할 필요가 있을 때", "자료를 보존할 필요가 없을 때"]'::jsonb, 4, NULL, NULL, '{"1": "긴급을 요할 때는 구두보고가 우선될 수 있습니다.", "2": "사안이 가벼울 때는 서면보고가 필요하지 않을 수 있습니다.\n[정답]", "3": "신속하게 보고해야 할 때 서면보고는 오히려 시간 지연을 초래할 수 있습니다.", "4": "정확히 보고할 필요가 있을 때 서면보고는 필수적입니다.", "5": "자료를 보존할 필요가 없을 때는 서면보고의 필요성이 없습니다."}'::jsonb, '[{"term_ko": "업무수행", "term_vi": "Thực hiện công việc", "def_ko": "일을 수행하는 것", "def_vi": "Làm công việc"}, {"term_ko": "서면보고", "term_vi": "Báo cáo bằng văn bản", "def_ko": "서면으로 하는 보고", "def_vi": "Báo cáo bằng văn bản"}, {"term_ko": "긴급", "term_vi": "Khẩn cấp", "def_ko": "급한 상황", "def_vi": "Tình huống khẩn cấp"}, {"term_ko": "신속", "term_vi": "Nhanh chóng", "def_ko": "빠르게", "def_vi": "Nhanh chóng"}, {"term_ko": "정확히", "term_vi": "Chính xác", "def_ko": "틀림없이", "def_vi": "Chính xác"}, {"term_ko": "자료", "term_vi": "Tài liệu", "def_ko": "필요할 수 있는 정보", "def_vi": "Thông tin có thể cần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1175, '9', '신속하게 보고할 수 있다는 장점이 있으나 정확한 기록을 남길 수 없다는 단점이 있는 업무보고 형식은?', '["구두보고", "서면보고", "사건보고", "전산망 보고", "정기 업무보고"]'::jsonb, 1, NULL, NULL, '{"1": "구두보고는 신속하게 전달할 수 있으나 기록이 남지 않아 정확한 확인이 어렵다.\n[정답]", "2": "서면보고는 정확한 기록을 남길 수 있으나 즉시 전달하는 데 시간이 걸린다.", "3": "사건보고는 특정 사건에 대한 기록으로 단순 비교가 어렵다.", "4": "전산망 보고는 디지털 방식으로 정보를 기록하나, 즉각적인 의사소통에는 제약이 있을 수 있다.", "5": "정기 업무보고는 정기적으로 정보를 공유하나, 비정기적인 긴급 상황에는 적합하지 않다."}'::jsonb, '[{"term_ko": "구두보고", "term_vi": "Báo cáo miệng", "def_ko": "말로 전달하는 보고 방식", "def_vi": "Cách báo cáo bằng lời nói"}, {"term_ko": "서면보고", "term_vi": "Báo cáo bằng văn bản", "def_ko": "문서로 기록하는 보고 방식", "def_vi": "Cách báo cáo bằng tài liệu"}, {"term_ko": "사건보고", "term_vi": "Báo cáo sự kiện", "def_ko": "특정 사건에 대한 보고", "def_vi": "Báo cáo về một sự kiện cụ thể"}, {"term_ko": "전산망", "term_vi": "Mạng điện tử", "def_ko": "전자적 정보 시스템", "def_vi": "Hệ thống thông tin điện tử"}, {"term_ko": "정기 업무보고", "term_vi": "Báo cáo công việc định kỳ", "def_ko": "정해진 시간마다 하는 보고", "def_vi": "Báo cáo được thực hiện vào những thời điểm cố định"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1174, '9', '요양보호 업무 수행 시 반드시 기관에 보고를 해야 할 사항은?', '["대상자의 상태가 평상시와 같을 때", "서비스에 변화가 없을 때", "업무를 잘못 수행했을 때", "대상자에게 기저귀를 채울 때", "대상자의 가족이 방문했을 때"]'::jsonb, 3, NULL, NULL, '{"1": "대상자의 상태가 평상시와 같을 때는 보고할 필요가 없다.", "2": "서비스에 변화가 없을 때도 보고할 필요가 없다.\n[정답]", "3": "업무를 잘못 수행했을 때는 반드시 보고해야 한다.", "4": "대상자에게 기저귀를 채울 때는 보고할 사항이 아니다.", "5": "대상자의 가족이 방문했을 때는 보고할 필요가 없다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "Chuyên gia chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1173, '9', '요양보호사가 근무 중 대상자와 관련하여 상황이 급하거나 사안이 가벼울 때 보고하는 형식은?', '["구두보고", "서면보고", "전산망보고", "주간보고", "월간보고"]'::jsonb, 1, NULL, NULL, '{"1": "구두보고는 상황이 급할 때 신속하게 정보를 전달하는 방식입니다.\n[정답]", "2": "서면보고는 공식적인 기록을 남기기 위한 방법이지만 긴급 상황에서는 적절하지 않을 수 있습니다.", "3": "전산망보고는 정보 관리 시스템을 통한 보고 방식으로, 긴급 상황에서는 구두보고가 더 적합합니다.", "4": "주간보고는 주기적으로 이루어지는 보고 형식으로, 긴급 상황에는 해당하지 않습니다.", "5": "월간보고는 월 단위로 작성되므로 긴급 상황에서 빠르게 대처하기 어렵습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌봄 제공자", "def_vi": "Người cung cấp dịch vụ chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1172, '9', '요양보호사의 업무보고 방법으로 옳은 것은?', '["숫자나 표가 포함된 내용을 구두로 보고한다.", "대상자 가족의 개인정보를 수시로 보고한다.", "업무를 잘못 수행했을 때에는 해결한 후 보고한다.", "업무 중 느낀 점을 정확하게 기록하여 보고한다.", "예기치 못한 사고 시 즉시 시설장에게 보고한다."]'::jsonb, 5, NULL, NULL, '{"1": "숫자나 표가 포함된 내용을 구두로 보고하는 것은 비효율적일 수 있다.\n[정답]", "5": "예기치 못한 사고 시 즉시 시설장에게 보고해야 한다.", "3": "업무를 잘못 수행했을 경우에는 즉시 보고해야 한다.", "4": "업무 중 느낀 점을 기록하는 것은 중요하지만, 보고는 후속 조치 후에 이루어져야 한다.", "2": "대상자 가족의 개인정보는 그들의 동의 없이 보고할 수 없다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "업무", "def_ko": "보고 công việc", "def_vi": "công việc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1171, '9', '다음 중 업무보고 시기로 적절하지 않은 것은?', '["대상자의 상태에 변화가 있을 때", "서비스에 변화가 없을 때", "사고가 발생했을 때", "새로운 업무방법을 찾았을 때", "서비스를 추가하거나 변경할 필요가 있을 때"]'::jsonb, 2, NULL, NULL, '{"1": "대상자의 상태에 변화가 있을 때는 반드시 보고해야 한다.\n[정답]", "2": "서비스에 변화가 없을 때는 업무보고가 필요하지 않다.", "3": "사고가 발생했을 때는 즉시 보고해야 한다.", "4": "새로운 업무방법을 찾았을 때는 관련 정보를 보고해야 한다.", "5": "서비스를 추가하거나 변경할 필요가 있을 때는 반드시 보고해야 한다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "Báo cáo công việc", "def_ko": "업무에 대한 임무 및 상태를 알리는 것", "def_vi": "Thông báo về nhiệm vụ và tình trạng công việc"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "서비스의 수혜자", "def_vi": "Người hưởng lợi từ dịch vụ"}, {"term_ko": "변화", "term_vi": "Thay đổi", "def_ko": "상태나 조건이 달라지는 것", "def_vi": "Việc thay đổi trạng thái hoặc điều kiện"}, {"term_ko": "사고", "term_vi": "Tai nạn", "def_ko": "의도치 않은 사건", "def_vi": "Sự cố không mong muốn"}, {"term_ko": "업무방법", "term_vi": "Phương pháp làm việc", "def_ko": "일을 수행하는 방식", "def_vi": "Cách thức thực hiện công việc"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공되는 도움이나 지원", "def_vi": "Giúp đỡ hoặc hỗ trợ được cung cấp"}, {"term_ko": "추가하다", "term_vi": "Thêm vào", "def_ko": "더하다", "def_vi": "Thêm"}, {"term_ko": "변경하다", "term_vi": "Thay đổi", "def_ko": "바꾸다", "def_vi": "Thay đổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1166, '9', '대상자의 아들이 외국으로 나간다고 할 때 요양보호사의 대처방법으로 옳은 것은?', '["서비스를 계속한다.", "다른 시설을 소개해준다.", "외국에 같이 데리고 가라고 한다.", "비용을 할인해 준다.", "시설장에게 보고한다."]'::jsonb, 5, NULL, NULL, '{"1": "서비스를 계속한다. - 서비스의 지속 여부는 아들의 결정에 달려 있으므로 옳지 않다.\n[정답]", "5": "시설장에게 보고한다. - 요양보호사는 대상자의 상태와 요양 상황을 관리하기 위해 시설장에게 보고해야 한다.", "2": "다른 시설을 소개해준다. - 다른 시설로의 전환은 대상자의 의사를 고려해야 하므로 옳지 않다.", "3": "외국에 같이 데리고 가라고 한다. - 이를 요청하는 것은 비현실적이므로 옳지 않다.", "4": "비용을 할인해 준다. - 비용 할인은 계약과 관계되므로 무단으로 결정할 수 없다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자(한국어)", "def_vi": "Bệnh nhân"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "간호사와 비슷한 직업으로 요양 서비스를 제공하는 사람(한국어)", "def_vi": "Người cung cấp dịch vụ chăm sóc"}, {"term_ko": "대처방법", "term_vi": "Cách xử lý", "def_ko": "문제를 해결하는 방법(한국어)", "def_vi": "Phương pháp để giải quyết vấn đề"}, {"term_ko": "시설장", "term_vi": "Quản lý cơ sở", "def_ko": "요양 시설을 관리하는 사람(한국어)", "def_vi": "Người quản lý cơ sở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1165, '9', '방문요양서비스 제공 중 관리책임자에게 보고하지 않아도 되는 상황은?', '["대상자가 넘어져 타박상을 입었을 때", "대상자가 하루 종일 텔레비전을 볼 때", "대사자가 당뇨병 진단받은 것을 알았을 때", "베란다에서 배변 중인 대상자를 처음 발견했을 때", "대상자가 유효기간이 지난 음식을 먹고 복통을 호소할 때"]'::jsonb, 2, NULL, NULL, '{"1": "이 상황은 사고가 발생한 것이므로 관리책임자에게 보고해야 함.\n[정답]", "2": "단순히 텔레비전을 보는 것은 관리책임자에게 보고할 필요가 없음.", "3": "당뇨병 진단은 건강 상태에 변동이 있는 사항이므로 보고해야 함.", "4": "베란다에서 배변 중인 경우는 위생상 문제와 관련하여 보고해야 할 사항임.", "5": "유효기간이 지난 음식을 먹고 복통을 호소하는 경우 건강에 큰 영향을 미칠 수 있어 반드시 보고해야 함."}'::jsonb, '[{"term_ko": "방문요양서비스", "term_vi": "Dịch vụ chăm sóc tại nhà", "def_ko": "가정에서 제공되는 요양 서비스", "def_vi": "Dịch vụ chăm sóc được cung cấp tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1164, '9', '방문요양서비스 제공 시 관리책임자에게 신속하게 보고해야 하는 상황은?', '["체납 고지서를 발견하였다.", "쓰레기를 분리 배출하지 않았다.", "방문을 열 때마다 삐걱 소리가 난다.", "대상자가 현기증과 두통을 호소한다.", "근처에 사는 친척이 방문하였다."]'::jsonb, 4, NULL, NULL, '{"1": "체납 고지서는 서비스 제공과 직접적인 관련이 없습니다.", "2": "쓰레기를 분리 배출하지 않는 것은 관리자의 보고 사항이 아닙니다.", "3": "삐걱 소리는 안전 문제일 수 있으나 긴급한 상황은 아닙니다.\n[정답]", "4": "대상자가 현기증과 두통을 호소하는 경우 즉각적인 조치가 필요하므로 관리책임자에게 보고해야 합니다.", "5": "친척의 방문은 특별히 보고할 필요가 없습니다."}'::jsonb, '[{"term_ko": "방문요양서비스", "term_vi": "Dịch vụ chăm sóc tại nhà", "def_ko": "집에서 요양서비스를 제공하는 것", "def_vi": "Cung cấp dịch vụ chăm sóc tại nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1163, '9', '다음 중 업무보고의 방법으로 옳은 것은?', '["모든 보고는 문서로 한다.", "사고 발생 시 요양보호사의 판단으로 처리한다.", "보고내용이 중복되지 않도록 한다.", "대상자의 건강상태에 변화가 생겼을 때에만 보고한다.", "추가적인 서비스를 요청 시 보호자와 상의한다."]'::jsonb, 3, NULL, NULL, '{"1": "모든 보고는 문서로 해야 한다는 것은 잘못된 내용으로, 구두 보고도 허용된다.\n[정답]", "3": "보고내용이 중복되지 않도록 하는 것은 중요하며, 업무의 효율성을 높인다.", "2": "사고 발생 시 요양보호사의 판단만으로 처리하는 것은 적절하지 않다.", "4": "건강상태 변화가 있을 때만 보고하는 것은 보고의 필요성을 제한하는 문제이다.", "5": "추가적인 서비스 요청 시 보호자와 상의해야 하지만, 항상 보호자와의 협의가 필요한 것은 아니다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "Báo cáo công việc", "def_ko": "임무에 대한 정보를 제공하는 것", "def_vi": "Cung cấp thông tin về nhiệm vụ"}, {"term_ko": "보고내용", "term_vi": "Nội dung báo cáo", "def_ko": "전달하는 정보나 데이터", "def_vi": "Thông tin hoặc dữ liệu được truyền đạt"}, {"term_ko": "중복되지 않다", "term_vi": "Không bị trùng lặp", "def_ko": "같은 내용이 두 번 이상 존재하지 않다", "def_vi": "Không tồn tại cùng một nội dung nhiều hơn một lần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1162, '9', '요양보호사가 일일업무 보고를 할 때 옳은 것은?', '["구두로만 보고한다.", "중요한 사항만 보고한다.", "보고내용은 사실과 다름이 없이 정확하게 보고한다.", "공식화된 용어보다 쉬운 용어를 사용한다.", "자신의 생각을 중심으로 보고한다."]'::jsonb, 3, NULL, NULL, '{"1": "구두로만 보고하는 것은 불완전할 수 있습니다.", "2": "중요한 사항만 보고하는 것은 전체적인 내용을 놓칠 수 있습니다.\n[정답]", "3": "보고내용은 사실과 다름이 없이 정확하게 보고해야 합니다.", "4": "공식화된 용어보다 쉬운 용어를 사용하는 것은 필요하지만, 전문 용어를 적절히 사용하는 것이 중요합니다.", "5": "자신의 생각을 중심으로 보고하는 것은 객관성을 해칠 수 있습니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 요양하는 사람", "def_vi": "Người chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1161, '9', '요양보호사의 업무보고 원칙으로 옳은 것은?', '["주관적인 사실을 보고한다.", "육하원칙에 따라 보고한다.", "근무종료 후 보고한다.", "중요한 내용은 반복해서 보고한다.", "일주일 단위로 모아서 보고한다."]'::jsonb, 2, NULL, NULL, '{"1": "주관적인 사실을 보고하면 신뢰성이 떨어질 수 있으므로 옳지 않습니다.\n[정답]", "2": "육하원칙에 따라 보고하는 것이 업무 보고의 기본 원칙입니다.", "3": "근무종료 후 보고하는 것은 업무의 연속성을 해칠 수 있어 적절하지 않습니다.", "4": "중요한 내용은 반복해서 보고할 필요가 없고, 명확히 보고해야 합니다.", "5": "일주일 단위로 모아서 보고하는 것은 즉각적인 정보 전달을 방해할 수 있습니다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "Báo cáo công việc", "def_ko": "질의, 정보 제공을 위한 단계", "def_vi": "Giai đoạn để truy vấn và cung cấp thông tin"}, {"term_ko": "원칙", "term_vi": "Nguyên tắc", "def_ko": "기본적인 규칙", "def_vi": "Quy tắc cơ bản"}, {"term_ko": "주관적", "term_vi": "Chủ quan", "def_ko": "개인적인 판단", "def_vi": "Đánh giá cá nhân"}, {"term_ko": "육하원칙", "term_vi": "Nguyên tắc 5W1H", "def_ko": "5W1H의 원칙", "def_vi": "Quy tắc 5W1H"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1160, '9', '업무보고의 중요성으로 옳은 것은?', '["대상자의 단점을 파악할 수 있다.", "보호자와 관계가 돈독해진다.", "사고대응을 신속하게 할 수 있다.", "대사자의 질병치료를 할 수 있다.", "업무성과를 평가 받을 수 있다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자의 단점 파악은 업무보고의 직접적인 목적이 아니다.\n[정답]", "3": "사고대응을 신속하게 할 수 있다는 것은 업무보고의 중요한 효과 중 하나이다.", "2": "보호자와의 관계는 중요하지만 업무보고의 직접적인 결과는 아니다.", "4": "대사자의 질병치료는 업무보고의 결과가 아니다.", "5": "업무성과 평가에 대한 것은 결과적으로 영향을 미칠 수 있지만 주요 목적이 아니다."}'::jsonb, '[{"term_ko": "업무보고", "term_vi": "Báo cáo công việc", "def_ko": "일의 진행 상황을 정리해서 보고하는 것", "def_vi": "Việc tổng hợp và báo cáo tiến độ công việc"}, {"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "보살핌을 받는 사람", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "보호자", "term_vi": "Người chăm sóc", "def_ko": "환자의 가족이나 대리인", "def_vi": "Gia đình hoặc đại diện của bệnh nhân"}, {"term_ko": "사고대응", "term_vi": "Phản ứng sự cố", "def_ko": "사고 발생 시의 대처 방안", "def_vi": "Phương án ứng phó khi xảy ra sự cố"}, {"term_ko": "질병치료", "term_vi": "Điều trị bệnh", "def_ko": "질병을 치료하는 행동", "def_vi": "Hành động điều trị bệnh"}, {"term_ko": "업무성과", "term_vi": "Kết quả công việc", "def_ko": "일의 결과와 성과", "def_vi": "Kết quả và thành tích của công việc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1159, '9', '장기요양급여 제공기록지 작성 시 올바른 방법은?', '["방문요양서비스는 서비스 제공 시작과 종료 시간을 기록한다.", "방문요양서비스는 세부 서비스별 제공시간을 ''시간'' 단위로 기재한다.", "방문목욕서비스의 경우 장기요양요원 1명의 성명을 기재한다.", "주 야간 보호 서비스는 세부 서비스별 제공시간을 기재하지 않는다.", "시설급여서비스의 경우 특이사항은 기재하지 않는다."]'::jsonb, 1, NULL, NULL, '{"1": "방문요양서비스는 서비스 제공 시작과 종료 시간을 기록한다.\n[정답]", "2": "방문요양서비스는 세부 서비스별 제공시간을 ''시간'' 단위로 기재한다.", "3": "방문목욕서비스의 경우 장기요양요원 1명의 성명을 기재한다.", "4": "주 야간 보호 서비스는 세부 서비스별 제공시간을 기재하지 않는다.", "5": "시설급여서비스의 경우 특이사항은 기재하지 않는다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Chăm sóc dài hạn", "def_ko": "장기사용을 위한 요양서비스 제공", "def_vi": "Dịch vụ chăm sóc dài hạn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1158, '9', '방문 요양 시 장기요양급여 제공기록지에 기록할 내용으로 옳은 것은?', '["월 급여한도액", "수급자 가족 수", "수급자 희망급여", "총 급여제공시간", "보호자 직업"]'::jsonb, 4, NULL, NULL, '{"1": "월 급여한도액은 기록하지 않음.", "2": "수급자 가족 수는 제공 기록지에 포함되지 않음.\n[정답]", "3": "총 급여제공시간은 반드시 기록해야 하는 내용임.", "4": "보호자 직업은 기록할 필요가 없음."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Trợ cấp chăm sóc dài hạn", "def_ko": "장기 요양을 위한 재정 지원", "def_vi": "Hỗ trợ tài chính cho chăm sóc dài hạn"}, {"term_ko": "제공기록지", "term_vi": "Bảng ghi chép cung cấp", "def_ko": "급여 제공 내용을 기록한 문서", "def_vi": "Tài liệu ghi lại nội dung cung cấp trợ cấp"}, {"term_ko": "수급자", "term_vi": "Người hưởng trợ cấp", "def_ko": "지원 혜택을 받는 사람", "def_vi": "Người nhận hỗ trợ"}, {"term_ko": "총", "term_vi": "Tổng", "def_ko": "전체", "def_vi": "Tổng thể"}, {"term_ko": "희망", "term_vi": "Hy vọng", "def_ko": "원하는", "def_vi": "Mong muốn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1157, '9', '장기요양급여 제공기록지에 기재 되지 않은 것은?', '["장기요양등급", "서비스 제공일자", "장기요양 인정번호", "장기요양 유효기간", "서비스 시작시간 및 종료시간"]'::jsonb, 4, NULL, NULL, '{"1": "장기요양등급은 기록지에 필수로 포함되어야 하는 요소입니다.\n[정답]", "4": "장기요양 유효기간은 제공기록지에 기재되지 않아야 하는 사항입니다.", "2": "서비스 제공일자는 필수 기재 사항입니다.", "3": "장기요양 인정번호 또한 중요한 항목으로 기록되어야 합니다.", "5": "서비스 시작시간 및 종료시간은 제공기록지에 반드시 기재해야 하는 내용입니다."}'::jsonb, '[{"term_ko": "장기요양급여", "term_vi": "Chăm sóc lâu dài", "def_ko": "장기 요양 서비스를 통해 제공되는 혜택", "def_vi": "Sự hỗ trợ từ dịch vụ chăm sóc lâu dài"}, {"term_ko": "기록지", "term_vi": "Sổ ghi chép", "def_ko": "기록을 위한 문서", "def_vi": "Tài liệu để ghi lại"}, {"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "제공하는 돌봄 활동", "def_vi": "Hoạt động chăm sóc cung cấp"}, {"term_ko": "유효기간", "term_vi": "Thời hạn hiệu lực", "def_ko": "사용이 가능한 기간", "def_vi": "Thời gian có thể sử dụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1156, '9', '요양보호 기록 시 주의해야 할 사항으로 옳은 것은?', '["개인정보는 제3자에게 노출시킬 수 있다.", "업무상 알게 된 정보는 외부에 유출할 수 있다.", "대상자의 동의 없이 개인 정보 수집을 할 수 있다.", "기록은 반드시 잠금장치가 되어 있는 장소에 보관한다.", "대상자의 기록은 누구나 열람할 수 있다."]'::jsonb, 4, NULL, NULL, '{"1": "개인정보는 제3자에게 노출시킬 수 없다. 이는 개인 정보 보호의 원칙에 위배됩니다.\n[정답]", "4": "기록은 반드시 잠금장치가 되어 있는 장소에 보관해야 안전하게 보호될 수 있습니다.", "2": "업무상 알게 된 정보는 외부에 유출할 수 없다. 이는 윤리적 문제를 일으킵니다.", "3": "대상자의 동의 없이 개인 정보 수집을 할 수 없다. 이는 법적으로 금지되어 있습니다.", "5": "대상자의 기록은 누구나 열람할 수 없다. 기록은 관련된 사람만 접근할 수 있어야 합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "돌봄과 지원을 제공하는 일", "def_vi": "Công việc cung cấp sự hỗ trợ và chăm sóc"}, {"term_ko": "기록", "term_vi": "Hồ sơ", "def_ko": "정보나 사건을 기록한 자료", "def_vi": "Tài liệu ghi lại thông tin hoặc sự kiện"}, {"term_ko": "개인정보", "term_vi": "Thông tin cá nhân", "def_ko": "개인에 대한 특정 정보", "def_vi": "Thông tin cụ thể về cá nhân"}, {"term_ko": "동의", "term_vi": "Sự đồng ý", "def_ko": "허락, 승인", "def_vi": "Sự chấp thuận, công nhận"}, {"term_ko": "유출", "term_vi": "Rò rỉ", "def_ko": "비밀을 누설하다", "def_vi": "Tiết lộ bí mật"}, {"term_ko": "보관", "term_vi": "Lưu trữ", "def_ko": "안전하게 지키거나 저장하다", "def_vi": "Bảo vệ hoặc lưu giữ an toàn"}, {"term_ko": "잠금장치", "term_vi": "Khóa", "def_ko": "잠금장치가 있는 기계", "def_vi": "Thiết bị có cơ chế khóa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1155, '9', '요양보호사가 관찰한 내용을 기록하는 방법으로 옳은 것은?', '["식탁에 오래된 빵이 있다.", "한참을 산책하였다.", "청소하는데 오래 걸렸다.", "오전 10시에 죽 한 그릇을 드셨다.", "며칠만에 대변을 시원하게 보았다."]'::jsonb, 4, NULL, NULL, '{"1": "식탁에 오래된 빵이 있다. (객관적인 관찰이 아닌 주관적 판단의 요소가 포함됨)\n[정답]", "4": "오전 10시에 죽 한 그릇을 드셨다. (정확한 시간과 행동이 기록되어 있어 객관적으로 관찰된 내용)", "2": "한참을 산책하였다. (정확하지 않은 시간 정보가 부족함)", "3": "청소하는데 오래 걸렸다. (구체적인 시간 정보가 부족하며 주관적 요소가 강함)", "5": "며칠만에 대변을 시원하게 보았다. (숫자 표현과 주관적인 표현이 혼합됨)"}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자나 노인을 돌보는 일을 하는 사람", "def_vi": "Người chăm sóc bệnh nhân hoặc người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1154, '9', '요양보호사의 업무기록 방법으로 옳은 것은?', '["오랜만에 입맛이 좋아 보였다.", "얼마 전부터 식사량이 꽤 늘었다.", "평소보다 낮잠을 많이 잤다.", "오후 3시에 간식으로 나온 수박을 안 드셨다.", "며칠 만에 기분이 좋아 보인다."]'::jsonb, 4, NULL, NULL, '{"1": "오랜만에 입맛이 좋아 보였다는 주관적인 표현으로, 기록으로 적합하지 않습니다.\n[정답]", "4": "오후 3시에 간식으로 나온 수박을 안 드셨다는 구체적인 사실을 기록하여, 요양보호사의 업무 기록으로 적합합니다.", "2": "얼마 전부터 식사량이 꽤 늘었다는 주관적인 기술로서, 구체적인 수치를 포함하지 않아 정확한 기록에 부족합니다.", "3": "평소보다 낮잠을 많이 잤다는 주관적 기술이며, 구체적인 시간 또는 양이 부족합니다.", "5": "며칠 만에 기분이 좋아 보인다는 주관적인 감정 표현으로 정확한 기록으로 적합하지 않습니다."}'::jsonb, '[{"term_ko": "업무기록", "term_vi": "Ghi chép công việc", "def_ko": "작업 기록(한국어)", "def_vi": "Ghi chép công việc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1153, '9', '요양보호사가 기록한 내용 중 올바른 것은?', '["어르신이 평소보다 식사를 많이 함", "피부 발적이 심하게 나타남", "쵝근 들어 체중이 많이 줄었음", "7월 10일, 오후 3시, 방에서 300CC의 소변을 봄", "점심에 경관영양을 400ML 제공 함"]'::jsonb, 4, NULL, NULL, '{"1": "어르신이 평소보다 식사를 많이 했다는 내용은 주관적인 판단이 들어갈 수 있어 기록으로서 적절하지 않습니다.", "2": "피부 발적이 심하게 나타났다는 표현은 상태를 정확히 파악하기 어려워, 구체적인 수치나 조건이 요구됩니다.", "3": "체중 변화에 관한 내용은 정확한 수치가 부족하여 신뢰도가 낮습니다.\n[정답]", "4": "7월 10일, 오후 3시, 방에서 300CC의 소변을 본 내용은 구체적이고 명시적인 숫자를 포함하고 있어 기록으로서 올바른 표현입니다.", "5": "경관영양 제공에 관한 내용은 양이 정해져 있지만, 기록 시 참고가 필요할 수 있는 다른 정보가 부족합니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보고 관리하는 사람", "def_vi": "Người chăm sóc và quản lý bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1152, '9', '요양보호사의 업무기록 방법으로 옳은 것은?', '["주관적인 판단으로 작성한다.", "한꺼번에 모아서 기록한다.", "우회적으로 장황하게 기록한다.", "정정 시 지우거나 덧칠을 한다.", "서비스의 과정과 결과를 정확하게 기록한다."]'::jsonb, 5, NULL, NULL, '{"1": "주관적인 판단으로 작성하는 것은 바람직하지 않습니다.\n[정답]", "5": "서비스의 과정과 결과를 정확하게 기록해야 합니다.", "2": "모든 기록을 한꺼번에 모아서 작성하는 것은 비효율적입니다.", "3": "우회적이고 장황한 기록은 명확성을 저하시킵니다.", "4": "정정 시 지우거나 덧칠하는 것은 기록의 신뢰성을 떨어뜨릴 수 있습니다."}'::jsonb, '[{"term_ko": "업무기록", "term_vi": "Ghi chép công việc", "def_ko": "일에 대한 기록방법", "def_vi": "Phương pháp ghi chép về công việc"}, {"term_ko": "주관적", "term_vi": "Chủ quan", "def_ko": "자신의 판단에 따라", "def_vi": "Dựa trên phán đoán của cá nhân"}, {"term_ko": "정정", "term_vi": "Sửa chữa", "def_ko": "수정 작업", "def_vi": "Thao tác chỉnh sửa"}, {"term_ko": "과정", "term_vi": "Quá trình", "def_ko": "어떤 일이 진행되는 단계", "def_vi": "Giai đoạn diễn ra của một công việc"}, {"term_ko": "결과", "term_vi": "Kết quả", "def_ko": "어떤 결과가 생기는 것", "def_vi": "Kết quả mà một công việc tạo ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1151, '9', '요양보호 기록의 원칙으로 옳은 것은?', '["대상자의 사생활을 기록한다.", "서비스의 결과만 기록한다.", "기록은 한 달에 한번 한다.", "공식화된 용어를 사용한다.", "요양보호사의 생각을 사실대로 기록한다."]'::jsonb, 4, NULL, NULL, '{"1": "대체로 사생활은 보호되어야 하며, 기록에 포함되면 안 되는 경우가 많습니다.\n[정답]", "4": "공식화된 용어를 사용해야 정보를 명확히 전달할 수 있습니다.", "2": "서비스의 결과만 기록하는 것은 불완전한 기록으로, 발생한 모든 사항을 기재해야 합니다.", "3": "기록은 주기적으로 해야 하며, 한 달에 한번으로 제한되지 않습니다.", "5": "요양보호사의 주관적인 생각보다는 사실에 기반한 객관적인 기록이 필요합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "돌봄이 필요한 사람을 도와주는 서비스", "def_vi": "Dịch vụ giúp đỡ người cần chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1150, '9', '요양보호 기록의 원칙으로 옳은 것은?', '["서비스의 제공 과정만 기록한다.", "업무종결 후 한꺼번에 기록한다.", "서비스내용은 간단명료하게 기록한다.", "주관적인 생각과 판단을 토대로 기록한다.", "중요한 내용은 보호자의 동의를 구한 후 기록한다."]'::jsonb, 3, NULL, NULL, '{"1": "서비스 제공의 모든 과정이 아니라 특정한 점들을 기록해야 하는데, 이 항목은 틀린 것이다.\n[정답]", "3": "서비스 내용은 간결하고 명확하게 기록해야 한다. 이는 기록의 원칙 중 하나이다.", "2": "업무 후에 한 번에 기록하는 것은 비효율적이며, 상황이 기억에서 사라질 수 있으므로 올바르지 않다.", "4": "기록은 주관적인 판단이 아니라 사실에 기반해야 하므로 틀린 주장이다.", "5": "중요한 내용을 기록하기 위해서는 보호자의 동의가 필요할 수 있으나, 모든 사항을 해당 원칙으로 기록할 필요는 없다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Ghi chép", "def_ko": "돌봄 제공", "def_vi": "ghi chép"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1149, '9', '요양보호 기록의 원칙으로 옳은 것은?', '["동료와 기록을 공유한다.", "요양보호사의 주관적 생각도 기록한다.", "육하원칙을 바탕으로 기록한다.", "서비스의 결과만 기록한다.", "길고 자세하게 기록한다."]'::jsonb, 3, NULL, NULL, '{"1": "동료와 기록을 공유하는 것은 보안 문제로 옳지 않습니다.\n[정답]", "3": "육하원칙을 바탕으로 기록하는 것이 기본 원칙입니다.", "2": "요양보호사의 주관적 생각은 기록에 포함되지 않아야 합니다.", "4": "서비스의 결과만 기록하는 것이 아니라 과정도 중요합니다.", "5": "길고 자세하게 기록하기 보다는 간결하고 명확한 것이 중요합니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "기록", "def_ko": "돌봄 서비스(서비스 chăm sóc)", "def_vi": "기록(ghi chép)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1148, '9', '요양보호사가 퇴직, 휴직 등으로 인하여 업무를 그만둘 때 직원간의 업무인수인계를 위해 기록하는 것은?', '["방문일지", "사고보고서", "상태기록지", "장기요양급여제공기록지", "인수인계서"]'::jsonb, 5, NULL, NULL, '{"1": "방문일지: 환자의 방문 기록을 남기는 문서로, 인수인계와는 무관합니다.", "2": "사고보고서: 사고가 발생했을 때 작성하는 문서로, 인수인계와는 관련이 없습니다.", "3": "상태기록지: 환자의 상태를 기록하는 문서로, 인수인계의 목적에는 적합하지 않습니다.\n[정답]", "4": "장기요양급여제공기록지: 요양급여 제공 내용을 기록하는 문서이나, 인수인계의 목적으로는 사용되지 않습니다.", "5": "인수인계서: 후임자에게 업무에 대한 정보를 전달하기 위해 작성하는 문서로, 가장 적절한 선택입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc sức khỏe", "def_ko": "환자를 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân"}, {"term_ko": "퇴직", "term_vi": "Nghỉ việc", "def_ko": "그만두는 것", "def_vi": "Nghỉ lại"}, {"term_ko": "휴직", "term_vi": "Nghỉ phép", "def_ko": "일시적으로 업무를 중단하는 것", "def_vi": "Dừng công việc tạm thời"}, {"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일을 하는 것", "def_vi": "Làm việc"}, {"term_ko": "인수인계", "term_vi": "Chuyển giao công việc", "def_ko": "다음 사람에게 업무를 전달하는 것", "def_vi": "Đưa công việc cho người khác"}, {"term_ko": "기록", "term_vi": "Ghi chép", "def_ko": "내용을 적어두는 것", "def_vi": "Ghi nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1147, '9', '식사섭취, 배설, 목욕 등의 상태 및 제공 내용을 기록하는 요양보호 기록지는?', '["욕구사정", "방문일지", "상담일지", "상태기록지", "인수인계서"]'::jsonb, 4, NULL, NULL, '{"1": "욕구사정: 개인의 필요와 욕구를 평가하는 도구로, 기록지는 아닙니다.\n[정답]", "4": "상태기록지: 식사섭취, 배설, 목욕 등의 상태 및 제공 내용을 기록하는 문서입니다.", "2": "방문일지: 방문한 날짜와 시간, 활동 내용을 기록합니다.", "3": "상담일지: 상담 내용과 결과를 기록하는 문서입니다.", "5": "인수인계서: 요양보호사 간의 정보 전달 문서입니다."}'::jsonb, '[{"term_ko": "식사섭취", "term_vi": "Sự tiêu thụ thực phẩm", "def_ko": "음식이나 음료를 섭취하는 것", "def_vi": "Ăn uống hoặc uống đồ uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1146, '9', '요양보호사의 재각급여제공 내용을 국민건강보험공단에 실시간으로 전송하고 이를 급여비용 청구와 자동으로 연계하는 관리체계는?', '["보건복지포털", "사회복지통합관리망", "요양시설관리시스템", "재가급여전자관리시스템", "건강보험급여청구시스템"]'::jsonb, 4, NULL, NULL, '{"1": "보건복지부가 제공하는 정보 시스템으로 전송 기능과는 거리가 있습니다.\n[정답]", "4": "재가급여 전자관리 시스템은 재각급여 제공 내용을 실시간으로 전송하고 급여비용 청구와 연결하는 시스템입니다.", "2": "사회복지통합관리망은 다양한 사회복지 관련 정보를 통합 관리하지만 이 문제와는 연관성이 낮습니다.", "3": "요양시설 관리 시스템은 시설 관리에 중점을 두고 있고, 재각급여와 관련이 없습니다.", "5": "건강보험 급여청구 시스템은 건강보험 관련 청구를 처리하지만 재각급여의 실시간 전송과는 연결되지 않습니다."}'::jsonb, '[{"term_ko": "재각급여", "term_vi": "Trợ cấp lại", "def_ko": "다시 제공되는 요양급여", "def_vi": "Phúc lợi chăm sóc được cung cấp lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1145, '9', '요양보호사가 대상자에게 제공한 서비스의 내용과 시간, 특이사항을 기록하는 것은?', '["상담일지", "상태기록지", "사고보고서", "인수인계서", "장기요양급여 제공기록지"]'::jsonb, 5, NULL, NULL, '{"1": "상담일지: 상담 내용을 기록하는 문서로, 서비스 제공 기록과는 다릅니다.\n[정답]", "5": "장기요양급여 제공기록지: 요양보호사가 제공한 서비스 내용, 시간 및 특이사항을 기록하는 공식 문서입니다.", "2": "상태기록지: 대상자의 건강 상태를 기록하는 문서입니다.", "3": "사고보고서: 사고 발생 시 작성하는 문서로, 서비스 기록과는 차이가 있습니다.", "4": "인수인계서: 서비스 인계 시 작성하는 서류로, 제공 기록과는 목적이 다릅니다."}'::jsonb, '[{"term_ko": "서비스", "term_vi": "Dịch vụ", "def_ko": "서비스(한국어)", "def_vi": "Dịch vụ(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1144, '9', '요양보호사가 제공한 서비스 내용을 기록하는 목적은?', '["동료를 평가하고 감독하기 위해서", "업무에 대한 책임감을 높이기 위해서", "대상자의 비밀을 동료와 공유하기 위해서", "법적 책임을 회피하기 위해서", "서비스를 제한하고 대상자를 평가하기 위해서"]'::jsonb, 2, NULL, NULL, '{"1": "동료를 평가하고 감독하기 위해서는 서비스 내용 기록이 아닌 다른 방법이 필요하다. \n[정답]", "2": "업무에 대한 책임감을 높이기 위한 것이며, 기록은 서비스 제공에 있어 중요한 증거가 된다.", "3": "대상자의 비밀은 다른 동료와 공유해서는 안 된다.", "4": "법적 책임을 회피하기 위한 것이 아니라, 법적 책임을 명확히 하기 위한 기록이라 할 수 있다.", "5": "서비스를 제한하고 대상자를 평가하기 위한 목적이 아니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "돌보미", "def_vi": "Người chăm sóc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1143, '9', '요양보호 기록의 목적으로 옳은 것은?', '["요양보호사의 능력을 평가하기 위해서", "요양보호사의 책임성을 줄이기 위해서", "요양보호사의 단점을 발견하기 위해서", "요양보호서비스의 표준화에 기여하기 위해서", "요양보호사의 근무 태도를 비교하기 위해서"]'::jsonb, 4, NULL, NULL, '{"1": "요양보호사의 능력을 평가하기 위해서", "2": "요양보호사의 책임성을 줄이기 위해서", "3": "요양보호사의 단점을 발견하기 위해서\n[정답]", "4": "요양보호서비스의 표준화에 기여하기 위해서", "5": "요양보호사의 근무 태도를 비교하기 위해서"}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc người già", "def_ko": "노인을 돌보는 활동", "def_vi": "Hoạt động chăm sóc cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1142, '9', '요양보호 업무기록의 중요성으로 옳은 것은?', '["기록하는 습관을 유지할 수 있다.", "대상자의 사생활을 관리할 수 있다.", "보호자와의 유대관계를 형성한다.", "관련 전문가에게 중요한 정보를 제공한다.", "대상자에 대한 주관적인 판단에 도움이 된다."]'::jsonb, 4, NULL, NULL, '{"1": "기록하는 습관을 유지할 수 있지만, 이는 중요성의 핵심이 아닙니다.\n[정답]", "4": "관련 전문가에게 중요한 정보를 제공하는 것이 요양보호 업무기록의 가장 중요한 역할 중 하나입니다.", "2": "대상자의 사생활 관리와 연관이 있지만, 주로 업무기록의 중요성과 관련되지 않습니다.", "3": "보호자와의 유대관계 형성은 중요하지만, 업무기록의 중요한 목적은 아닙니다.", "5": "대상자에 대한 주관적인 판단은 업무기록의 목적이 아닙니다."}'::jsonb, '[{"term_ko": "요양보호", "term_vi": "Chăm sóc người cao tuổi", "def_ko": "노인을 돌보는 일", "def_vi": "Công việc chăm sóc cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1141, '9', '요양보호 기록의 목적으로 옳은 것은?', '["시설장에게 잘 보이기 위해서", "주관적인 의견을 기록하기 위해서", "대상자의 건강을 진단하기 위해서", "서비스의 연속성을 유지하기 위해서", "근무 평가에 따른 수당을 더 받기 위해서"]'::jsonb, 4, NULL, NULL, '{"1": "시설장에게 잘 보이기 위해서는 기록의 목적이 아니다.\n[정답]", "4": "서비스의 연속성을 유지하기 위해서 기록은 필수적이다.", "3": "건강 진단은 전문 의료인이 수행해야 한다.", "2": "주관적인 의견은 표기하지 않아야 한다.", "5": "근무 평가에 따른 수당은 기록과 직접적 연관이 없다."}'::jsonb, '[{"term_ko": "요양보호 기록", "term_vi": "Ghi chép chăm sóc người cao tuổi", "def_ko": "노인 돌봄과 관련된 문서 작성", "def_vi": "Việc viết tài liệu liên quan đến chăm sóc người cao tuổi"}, {"term_ko": "시설장", "term_vi": "Giám đốc cơ sở", "def_ko": "시설의 책임자", "def_vi": "Người chịu trách nhiệm về cơ sở"}, {"term_ko": "주관적", "term_vi": "Chủ quan", "def_ko": "개인의 의견이나 느낌", "def_vi": "Ý kiến hoặc cảm nhận cá nhân"}, {"term_ko": "서비스 연속성", "term_vi": "Tính liên tục của dịch vụ", "def_ko": "서비스의 지속적인 제공", "def_vi": "Việc cung cấp dịch vụ liên tục"}, {"term_ko": "건강 진단", "term_vi": "Chẩn đoán sức khỏe", "def_ko": "건강 상태를 평가하는 과정", "def_vi": "Quá trình đánh giá tình trạng sức khỏe"}, {"term_ko": "근무 평가", "term_vi": "Đánh giá công việc", "def_ko": "업무 수행에 대한 평가", "def_vi": "Đánh giá về việc thực hiện công việc"}, {"term_ko": "수당", "term_vi": "Phụ cấp", "def_ko": "추가 보상", "def_vi": "Thưởng thêm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1140, '8', '거동이 불편하거나 인지기능이 저하된 시설 대상자의 여가활동을 돕기 위한 방법으로 옳은 것은?', '["어렵지 않고 흥미로운 프로그램으로 배정한다.", "가족의 의견을 중심으로 여가활동을 지원한다.", "요양보호사의 상황에 따라 프로그램을 배정한다.", "움직임이 빠르고 신속한 프로그램을 배정한다.", "대상자의 경제적 수준을 고려하여 집단 프로그램으로 배정한다."]'::jsonb, 1, NULL, NULL, '{"1": "어렵지 않고 흥미로운 프로그램으로 배정한다. - 대상자가 참여하기 쉽고 기분이 좋아지는 활동을 제공하는 것이 중요하다.\n[정답]", "2": "가족의 의견을 중심으로 여가활동을 지원한다. - 가족의 의견이 중요하지만, 항상 개별 대상자의 선호가 우선되어야 한다.", "3": "요양보호사의 상황에 따라 프로그램을 배정한다. - 요양보호사의 상황보다는 대상자의 특성을 우선적으로 고려해야 한다.", "4": "움직임이 빠르고 신속한 프로그램을 배정한다. - 거동이 불편한 대상자에게는 부적합한 선택이다.", "5": "대상자의 경제적 수준을 고려하여 집단 프로그램으로 배정한다. - 경제적 수준은 고려해야 하지만, 대상자의 선호와 신체적 한계를 더 중요하게 생각해야 한다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Di chuyển", "def_ko": "움직임(행동)", "def_vi": "di chuyển"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1139, '8', '다음 대화 중 요양보호사가 대상자에게 추천한 여가활동 유형은?대상자: 건강했을 때 농사를 지었는데 힘들어도 보람이 있어서 좋았는데 지금은 심심해. 요양보호사: 그러셨어요! 상추를 가꾸어 보시는 건 어떠세요.', '["소일 활동", "운동 활동", "가족 중심 활동", "사교 오락 활동", "자기계발 활동"]'::jsonb, 1, NULL, NULL, '{"1": "상추를 가꾸는 것은 흙을 다루는 활동이며, 흙과의 접촉을 통해 심리적 안정감을 제공한다. 이는 소일 활동에 해당한다.\n[정답]", "2": "운동 활동은 신체 단련이 목표인데, 농사를 지으면서 그 자체가 운동으로 배치되기 어렵다.", "3": "가족 중심 활동은 가족과의 시간을 중시하는 활동을 의미하여 관련이 없다.", "4": "사교 오락 활동은 친구나 타인과의 교류가 중심인 여가 활동이다.", "5": "자기계발 활동은 개인적인 성장이나 학습에 중점을 두는 활동으로, 농사를 한다는 것과는 무관하다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 수행하는 활동", "def_vi": "Hoạt động thực hiện trong thời gian rảnh rỗi"}, {"term_ko": "소일 활동", "term_vi": "Hoạt động liên quan đến đất", "def_ko": "자연과 함께하는 활동", "def_vi": "Hoạt động như tiếp xúc với đất"}, {"term_ko": "운동", "term_vi": "Thể dục", "def_ko": "신체를 사용하는 활동", "def_vi": "Hoạt động sử dụng cơ thể"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "친척", "def_vi": "Người thân"}, {"term_ko": "사교", "term_vi": "Xã hội", "def_ko": "친구나 지인과의 교류", "def_vi": "Giao lưu với bạn bè"}, {"term_ko": "자기계발", "term_vi": "Phát triển bản thân", "def_ko": "개인의 성장 활동", "def_vi": "Hoạt động liên quan đến sự phát triển cá nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1138, '8', '대상자의 신진대사 촉진에 도움이 되는 산책에 해당하는 여가활동 유형은?', '["자기계발 활동", "사교 오락 활동", "가족 중심 활동", "운동 활동", "소일 활동"]'::jsonb, 4, NULL, NULL, '{"1": "자기계발 활동: 개인의 능력 개발과 관련된 활동으로 신진대사 촉진과는 직접적인 연관이 없습니다.\n[정답]", "4": "운동 활동: 신진대사를 촉진하는 중요한 방법으로 산책은 운동의 일종입니다.", "2": "사교 오락 활동: 사람들과의 사회적 상호작용을 포함하지만 신진대사와의 연관성은 낮습니다.", "3": "가족 중심 활동: 가족 간의 유대감을 강화하는 활동이나 신진대사 촉진과는 다소 거리가 있습니다.", "5": "소일 활동: 시간을 보내기 위한 활동으로 신진대사와 크게 관련이 없습니다."}'::jsonb, '[{"term_ko": "신진대사", "term_vi": "Chuyển hóa", "def_ko": "생명체의 물질대사 과정", "def_vi": "Quá trình trao đổi chất"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1137, '8', '김씨 할아버지는 아내와 사별 후 1년 동안 다른 사람 만나는 것을 꺼리고 있다. 이때 추천할 수 있는 여가활동은?', '["신문 보기", "그림 그리기", "친목 활동", "책 읽기", "텔레비전 시청하기"]'::jsonb, 3, NULL, NULL, '{"1": "신문 보기는 정보 습득은 가능하지만 외부와의 상호작용이 적습니다.", "2": "그림 그리기는 개인적인 취미 활동으로 사회적 상호작용이 부족합니다.\n[정답]", "3": "친목 활동은 타인과의 관계를 형성하고 정서적 지지를 받을 수 있는 좋은 방법입니다.", "4": "책 읽기는 개인적인 활동으로 외부와의 소통이 없습니다.", "5": "텔레비전 시청하기는 수동적인 활동으로 사회적 상호작용을 제공하지 않습니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동(한국어)", "def_vi": "Hoạt động trong thời gian rảnh rỗi(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1136, '8', '김씨 할아버지는 아내와 사별 후 1년 동안 다른 사람 만나는 것을 꺼리고 있다. 이때 추천할 수 있는 여가활동은?', '["신문 보기", "그림 그리기", "친목 활동", "책 읽기", "텔레비전 시청하기"]'::jsonb, 3, NULL, NULL, '{"1": "신문 보기는 개인적인 활동으로 고립감을 느낄 수 있습니다.\n[정답]", "3": "친목 활동은 사람들과의 교류를 통해 정서적 지지를 받을 수 있는 좋은 방법입니다.", "2": "그림 그리기는 개인적인 취미로 사회적 교류가 적습니다.", "4": "책 읽기는 개인적인 활동으로, 다른 사람과의 상호작용을 유도하지 않습니다.", "5": "텔레비전 시청은 소극적인 활동으로 대인관계 형성이 어렵습니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간을 활용한 활동", "def_vi": "Hoạt động trong thời gian rảnh rỗi"}, {"term_ko": "사별", "term_vi": "Mất mát", "def_ko": "사랑하는 사람을 잃다", "def_vi": "Mất người thân"}, {"term_ko": "추천", "term_vi": "Gợi ý", "def_ko": "제안하다", "def_vi": "Đề xuất"}, {"term_ko": "친목", "term_vi": "Giao lưu", "def_ko": "사람들과의 교류", "def_vi": "Sự tương tác với mọi người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1135, '8', '은퇴를 한 노부부가 친목회 회원들과 가끔 음악회나 전시회를 가곤한다. 해당하는 여가활동 유형은?', '["종교 참여 활동", "사교 오락 활동", "운동 활동", "소일 활동", "자기계발 활동"]'::jsonb, 2, NULL, NULL, '{"1": "종교 참여 활동: 종교적인 모임이나 의식에 참여하는 활동입니다.\n[정답]", "2": "사교 오락 활동: 사람들이 모여 즐겁게 대화하고 오락을 즐기는 활동입니다.", "3": "운동 활동: 신체 활동을 통해 건강을 유지하거나 증진하는 활동입니다.", "4": "소일 활동: 여가시간을 보내는 간단한 활동입니다.", "5": "자기계발 활동: 개인의 기술이나 지식을 향상시키기 위한 활동입니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "사교", "def_ko": "여가시간에 하는 활동(활동 giải trí)", "def_vi": "사람들과의 친목과 교류(quan hệ xã hội)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1134, '8', '다음 대화에서 요양보호사가 제안한 여가활동 유형은?대상자: 옛날에는 사물놀이에서 장구도 배우고 재밌었는데, 지금은 나이가 들어 아무것도 안 하니까 재미가 없어. 요양보호사: 그러면 다시 한번 장구를 배워보시면 어떨가요?', '["소일 활동", "자기계발 활동", "운동 활동", "가족중심 활동", "사교오락 활동"]'::jsonb, 2, NULL, NULL, '{"1": "소일 활동: 일상적인 일을 하며 시간을 보내는 활동입니다. 이 문제에서는 해당되지 않습니다.\n[정답]", "2": "자기계발 활동: 장구를 배우는 것은 개인의 기술을 향상시키는 활동으로 자기계발 활동에 해당합니다.", "3": "운동 활동: 신체적인 활동을 포함하지만, 장구 배우기는 운동의 범주에 포함되지 않습니다.", "4": "가족중심 활동: 가족과 함께하는 활동은 아니므로 해당되지 않습니다.", "5": "사교오락 활동: 친구들과의 여가활동에 해당하지만, 이 경우 특정 기술을 배우는 것이므로 주제와 다릅니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동(한국어)", "def_vi": "Hoạt động trong thời gian rảnh(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1133, '8', '보행이 불편한 대상자의 자기계발을 위한 여가활동으로 적합한 것은?', '["텃밭 가꾸기", "손자녀 돌보기", "산책 하기", "외식나들이", "서예교실"]'::jsonb, 5, NULL, NULL, '{"1": "텃밭 가꾸기는 신체적인 활동이 많이 필요하여 보행이 불편한 대상자에게는 적합하지 않습니다.\n[정답]", "5": "서예교실은 정적인 활동으로 보행이 불편한 대상자도 참여할 수 있어 자기계발에 적합합니다.", "2": "손자녀 돌보기는 신체적 부담이 클 수 있어 적합하지 않습니다.", "3": "산책하기는 보행이 불편한 대상자에게 힘든 활동입니다.", "4": "외식나들이는 보행이 불편한 상황에서 어려움이 있을 수 있습니다."}'::jsonb, '[{"term_ko": "보행", "term_vi": "Đi bộ", "def_ko": "걷기(한국어)", "def_vi": "Đi lại(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1132, '8', '서예. 책 읽기를 좋아하는 노인대상자의 여가활동 유형은?', '["운동 활동", "자기계발 활동", "사교오락 활동", "종교참여 활동", "가족중심 활동"]'::jsonb, 2, NULL, NULL, '{"1": "운동 활동: 신체적 건강을 위한 활동이나 운동은 노인이 선호하지 않을 수 있습니다.\n[정답]", "2": "자기계발 활동: 책 읽기는 지식과 능력을 개발할 수 있는 활동으로, 노인이 선호할 수 있는 여가활동입니다.", "3": "사교오락 활동: 타인과의 관계를 중요시하지만, 개인적인 독서와는 거리가 있습니다.", "4": "종교참여 활동: 종교적 활동은 개인적일 수 있지만 일반적으로 책 읽기에 해당하지 않습니다.", "5": "가족중심 활동: 가족과의 시간도 중요하지만 책 읽기와는 관련이 적습니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가 시간에 하는 활동(한국어)", "def_vi": "Hoạt động trong thời gian rảnh(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1131, '8', '노인의 여가활동 중 사교오락 활동에 해당하는 것은?', '["TV 보기", "책 읽기", "음악회", "텃밭 가꾸기", "악기연주"]'::jsonb, 3, NULL, NULL, '{"1": "TV 보기는 혼자서 즐기는 활동으로 사교오락 활동이 아닙니다.", "2": "책 읽기는 개인적인 활동으로 사교오락 활동이 아닙니다.\n[정답]", "3": "음악회는 타인과의 교류가 있는 사교오락 활동입니다.", "4": "텃밭 가꾸기는 개인적인 취미 활동으로 사교오락 활동이 아닙니다.", "5": "악기연주는 개인적으로 할 수도 있지만, 타인과 함께 할 경우 사교오락이 될 수 있습니다."}'::jsonb, '[{"term_ko": "여가활동", "term_vi": "Hoạt động giải trí", "def_ko": "여가에 사용하는 활동(한국어)", "def_vi": "Các hoạt động sử dụng thời gian rảnh"}, {"term_ko": "사교오락", "term_vi": "Giải trí xã hội", "def_ko": "사람들과의 교류가 있는 오락 활동(한국어)", "def_vi": "Hoạt động giải trí có sự giao lưu với người khác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1130, '8', '다음과 같은 방법으로 의사소통을 해야 하는 치매 대상자의 상황은?• 휴지를 주워와서 모을 때는 본인이 하고 싶어 하는 대로 두기 • 주워 온 물건에 대해 다시 이야기하지 않기 • 대상자가 할 수 있는 일로 주의 전환하기', '["수집증", "무감동", "불안", "섭식장애", "초조행동"]'::jsonb, 1, NULL, NULL, '{"1": "수집증은 물건을 모으는 행동으로, 해당 상황에 부합합니다.\n[정답]", "2": "무감동은 감정 표현이 없는 상태지만, 주어진 상황과는 관련이 없습니다.", "3": "불안은 불안감을 느끼는 상태로, 제시된 방법과 연관성이 떨어집니다.", "4": "섭식장애는 식습관의 문제가 초점이므로 상황에 적합하지 않습니다.", "5": "초조행동은 불안정한 감정을 나타내지만, 특정한 수집과 관련성은 부족합니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 사고에 영향을 미치는 신경퇴행성 질환", "def_vi": "Bệnh thoái hoá thần kinh ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1129, '8', '치매 대상자가 우울한 상황에서 의사소통 방법으로 옳은 것은?', '["활동에 참여하도록 강요한다.", "잘못은 직접적으로지적한다.", "우울한 생각을 계속하면 모른 척 외면한다.", "좋아하고 즐거워하는 활동을 하게 한다.", "어ㅕ운 일을 맡겨 성취감을 맛보게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "활동에 참여하도록 강요한다. - 강요는 환자의 기분을 더 우울하게 만들 수 있습니다.\n[정답]", "4": "좋아하고 즐거워하는 활동을 하게 한다. - 환자의 기분을 좋게 하는 긍정적인 접근입니다.", "2": "잘못은 직접적으로 지적한다. - 부정적인 피드백은 우울감을 증대시킬 수 있습니다.", "3": "우울한 생각을 계속하면 모른 척 외면한다. - 외면은 환자의 감정을 무시하는 행동입니다.", "5": "어려운 일을 맡겨 성취감을 맛보게 한다. - 지나치게 어려운 일은 부담을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억 및 인지 기능의 지속적인 저하", "def_vi": "Sự suy giảm liên tục của trí nhớ và chức năng nhận thức"}, {"term_ko": "우울", "term_vi": "Trầm cảm", "def_ko": "슬픔과 절망의 감정", "def_vi": "Cảm xúc buồn và tuyệt vọng"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보나 감정을 주고받는 과정", "def_vi": "Quá trình trao đổi thông tin hoặc cảm xúc"}, {"term_ko": "활동", "term_vi": "Hoạt động", "def_ko": "어떤 행동이나 일", "def_vi": "Một hành động hoặc công việc"}, {"term_ko": "성취감", "term_vi": "Cảm giác thành công", "def_ko": "달성의 기쁨", "def_vi": "Niềm vui khi đạt được"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1128, '8', '인지능력 저하, 우울증, 무관심 등이 원인이 되어 나타나는 치매대상자의 상황으로 다음과 같은 방법으로 의사소통해야 하는 경우는?• 대답하지 않더라도 이름을 부르거나 화를 내지 않기 • 좋아하는 활동 확인하기 • 사소한 말과 행동에도 관심 기울이기', '["무감동", "불안", "배회", "공격성", "초조행동"]'::jsonb, 1, NULL, NULL, '{"1": "무감동: 감정 표현이 결여되어 있는 상태를 의미하며, 해당 상황에서 의사소통 방법이 적합합니다.\n[정답]", "2": "불안: 불안은 다른 문제와 연관되어 있으며, 이 경우 적절한 의사소통 방법과는 거리가 있습니다.", "3": "배회: 치매 환자에게서 흔히 나타나는 행동이나, 의사소통에 대한 질문과는 관련이 적습니다.", "4": "공격성: 공격성은 의사소통의 방식이 아닌 행동상의 문제로, 의사소통 방법과 무관합니다.", "5": "초조행동: 초조행동 역시 의사소통과 관련이 적습니다."}'::jsonb, '[{"term_ko": "인지능력", "term_vi": "Năng lực nhận thức", "def_ko": "능력을 이해하고 판단하는 힘", "def_vi": "Khả năng hiểu và phán đoán"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1127, '8', '치매 대상자가 눈이 내리는 창밖을 보면서 다음과 같이 말한다. 이때 대상자의 지남력 증진에 도움이 되는 요양보호사의 반응으로 적절한 것은?대상자: 빨리 도토리 주우러 가자. 남들이 다 줍기 전에.. 요양보호사: ( )', '["\"밖에 나가고 싶으세요?\"", "\"미끄러워 위험하니 다음에 가요.\"", "\"배고프신가 봐요. 맛있는 거 드릴게요.\"", "\"아무도 주워가지 않으니 걱정마세요.\"", "\"지금은 한겨울이에요. 도토리는 강르에 줍잖아요.\""]'::jsonb, 5, NULL, NULL, '{"1": "''밖에 나가고 싶으세요?''는 대상자의 말을 단순히 반영할 뿐, 지남력 증진에는 도움이 되지 않습니다.\n[정답]", "5": "''지금은 한겨울이에요. 도토리는 강르에 줍잖아요.''는 계절적 정보를 제공하여 대상자의 지남력 증진에 기여합니다.", "2": "''미끄러워 위험하니 다음에 가요.''는 부정적인 반응으로 지남력 증진에 도움이 되지 않습니다.", "3": "''배고프신가 봐요. 맛있는 거 드릴게요.''는 대상자의 표현과 관련이 없어 지남력 증진에 기여하지 않습니다.", "4": "''아무도 주워가지 않으니 걱정마세요.''는 대상자를 안심시키지만, 지남력 증진에는 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 사고 기능의 감소로 인한 질병", "def_vi": "Bệnh giảm chức năng trí nhớ và tư duy"}, {"term_ko": "지남력", "term_vi": null, "def_ko": "시간, 장소, 사람에 대한 인식 능력", "def_vi": null}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "노인이나 환자를 돕고 케어하는 직업", "def_vi": "Nghề giúp đỡ và chăm sóc người cao niên hoặc bệnh nhân"}, {"term_ko": "도토리", "term_vi": "Quả sồi", "def_ko": "나무에서 떨어지는 열매", "def_vi": "Quả rơi từ cây"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1126, '8', '치매로 인한 장애 대상자와 의사소통하는 방법은?', '["주변사람들에게 치매로 인한 장애를 비밀로 한다.", "상식에 어긋나는 말을 할 경우 지적한다.", "시간, 장소, 사람 등을 인식시킨다.", "한 번에 많은 내용의 이야기를 한다.", "요양보호사의 속도에 맞추어 대화한다."]'::jsonb, 3, NULL, NULL, '{"1": "주변사람들에게 치매로 인한 장애를 비밀로 하여도 대상자의 의사소통에는 도움이 되지 않으므로 부적절하다.", "2": "상식에 어긋나는 말을 지적하는 것은 대상자의 자존감을 해칠 수 있으므로 좋은 방법이 아니다.\n[정답]", "3": "시간, 장소, 사람 등을 인식시킴으로써 대상자가 상황을 이해할 수 있도록 돕는 것은 효과적인 의사소통 방법이다.", "4": "한 번에 많은 내용을 이야기하는 것은 오히려 혼란을 줄 수 있으므로 지양해야 한다.", "5": "요양보호사의 속도에 맞추어 대화하는 것은 대상자의 이해 능력을 고려하지 않은 방법이다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí", "def_ko": "기억을 잃는 질병", "def_vi": "Bệnh mất trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1125, '8', '치매로 인한 장애가 있는 대상자와 의사소통 방법으로 옳은 것은?', '["환경적 자극을 위해 변화를 자주 준다.", "대상자의 뒤에서 천천히 다가가 말을 건넨다.", "자신감을 느끼도록 매번 새로운 정보를 준다.", "대상자의 언어적 표현보다 심적 안정에 맞춘다.", "대상자의 사소한 말과 행동은 그냥 넘긴다."]'::jsonb, 4, NULL, NULL, '{"1": "환경적 자극을 변화에 주는 것은 치매 환자에게 혼란을 줄 수 있다.\n[정답]", "2": "대상자의 뒤에서 다가가는 것은 오히려 불안감을 줄 수 있어 좋은 방법이 아니다.", "3": "매번 새로운 정보를 주는 것은 오히려 환자의 혼란을 가중시킬 수 있다.", "4": "대상자의 언어적 표현보다 심적 안정에 맞추는 것이 중요하다.", "5": "사소한 말과 행동을 무시하는 것은 환자의 자존감을 해칠 수 있다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고능력이 저하되는 뇌의 질병", "def_vi": "Bệnh liên quan đến việc giảm khả năng nhớ và tư duy của não"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "사람들 간에 정보를 교환하는 과정", "def_vi": "Quá trình trao đổi thông tin giữa mọi người"}, {"term_ko": "심적 안정", "term_vi": "An toàn tâm lý", "def_ko": "정서적으로 안정된 상태", "def_vi": "Trạng thái tâm lý ổn định"}, {"term_ko": "자존감", "term_vi": "Lòng tự trọng", "def_ko": "자신의 가치나 중요성을 느끼는 것", "def_vi": "Cảm giác về giá trị hoặc tầm quan trọng của bản thân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1124, '8', '치매로 인한 장애 대상자와 의사소통 하는 방법으로 옳은 것은?', '["''할 수 없는 것''을 집중적으로 찾아 준다.", "대상자의 뒤에서 천천히 다가가 말을 건넨다.", "자신감을 느끼도록 매번 새로운 정보를 준다.", "대상자의 언어적 표현보다 심적 안정에 맞춘다.", "대상자의 사소한 말과 행동은 그냥 넘긴다."]'::jsonb, 2, NULL, NULL, '{"1": "''할 수 없는 것''을 집중적으로 찾아 주는 것은 부정적인 언어로 의사소통을 하게 되어 대상자의 자존감을 떨어뜨릴 수 있습니다.\n[정답]", "2": "대상자의 뒤에서 천천히 다가가 말을 건네는 방법은 상대방에게 안전하고 편안한 느낌을 주며 의사소통을 원활하게 합니다.", "3": "매번 새로운 정보를 주는 것은 혼란을 초래할 수 있으며, 대상자의 이해력을 고려하는 것이 중요합니다.", "4": "언어적 표현보다 심적 안정을 우선시하는 것은 의사소통의 중요한 요소지만, 대상자의 의사 표현도 존중해야 합니다.", "5": "대상자의 사소한 말과 행동을 그냥 넘기는 것은 대상자의 감정을 무시하는 행동이 될 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng sa sút trí tuệ", "def_ko": "기억력과 사고능력의 저하", "def_vi": "Sự giảm sút trí nhớ và khả năng tư duy"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "사람들 간의 정보를 주고받는 행위", "def_vi": "Hành vi trao đổi thông tin giữa mọi người"}, {"term_ko": "자존감", "term_vi": "Lòng tự trọng", "def_ko": "자신에 대한 믿음", "def_vi": "Niềm tin về bản thân"}, {"term_ko": "혼란", "term_vi": "Sự hỗn loạn", "def_ko": "명확하지 않은 상태", "def_vi": "Tình trạng không rõ ràng"}, {"term_ko": "안정", "term_vi": "Ổn định", "def_ko": "위험이 없고 편안한 상태", "def_vi": "Tình trạng không có nguy cơ và thoải mái"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1123, '8', '뇌졸중으로 알아듣기는 하나 말이 어눌한 대상자와의 의사소통 방법으로 옳은 것은?', '["대상자 옆에 앉아서 대화한다.", "사람이 많은 곳에서 대화한다.", "대상자의 말에 짐작하여 대답한다.", "답변이 끝나기 전에 다음 질문을 한다.", "대상자가 의사표현을 잘했을 경우 긍정적 공감을 표현해준다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자 옆에 앉아서 대화하는 것은 좋은 의사소통 방법입니다. 그러나 반드시 올바른 방법은 아닙니다.\n[정답]", "5": "대상자가 의사표현을 잘했을 경우 긍정적 공감을 표현해 주는 것은 환자의 자존감을 높이고 의사소통을 원활하게 해줄 수 있는 방법입니다.", "3": "대상자의 말을 짐작하여 대답하는 것은 잘못된 의사소통 방법입니다.", "4": "답변이 끝나기 전에 다음 질문을 하는 것은 상대방의 말을 듣지 않는 태도로 비춰질 수 있습니다.", "2": "사람이 많은 곳에서 대화하는 것은 집중을 방해할 수 있으므로 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 중단되어 생기는 질환", "def_vi": "Bệnh xảy ra khi cung cấp máu cho não bị ngừng lại"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "서로 정보를 주고받는 과정", "def_vi": "Quá trình trao đổi thông tin giữa hai hoặc nhiều người"}, {"term_ko": "긍정적", "term_vi": "Tích cực", "def_ko": "좋거나 긍정적인 반응을 보이는 것", "def_vi": "Biểu hiện phản ứng tốt hoặc tích cực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1122, '8', '알아듣기는 해도 말로 표현이 어려운 대상자와 의사소통 하는 방법은?', '["음악을 틀어 편안하게 해준다.", "귀에 대고 천천히 또박또박 말한다.", "그림판, 문자판을 이용하여 표현하게 한다.", "날짜, 달력, 시계 등을 자주 인식시킨다.", "몸짓, 얼굴표정 등으로 이야기 전달을 돕는다."]'::jsonb, 3, NULL, NULL, '{"1": "음악을 틀어 편안하게 해주는 것은 분위기를 좋게 할 수 있지만, 의사소통을 직접적으로 향상시키지는 않습니다.\n[정답]", "3": "그림판, 문자판을 이용하여 표현하게 하는 것은 비언어적 의사소통에 효과적이며, 상대방이 자신의 생각이나 감정을 전달하는 데 도움을 줍니다.", "2": "귀에 대고 천천히 또박또박 말하는 것은 듣는 데 도움이 될 수 있지만, 말로 표현하기 어려운 경우에는 효과적이지 않습니다.", "4": "날짜, 달력, 시계 등을 자주 인식시키는 것은 인지적 도움을 주지만, 의사소통에는 직접적인 도움이 되지 않습니다.", "5": "몸짓, 얼굴표정 등으로 이야기 전달을 돕는 것은 비언어적 의사소통에 도움을 줄 수 있지만, 직접적으로 표현하게 하는 방법은 아닙니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통(한국어)", "def_vi": "sự thông tin qua lại(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1121, '8', '시각장애 대상자와 이야기하는 방법으로 옳은 것은?', '["대상자와 반걸음 떨어진 뒤에서 이야기한다.", "전달하기 어려운 형태나 사물은 만져보게 한다.", "지시대명사를 사용하여 사물의 위치를 설명한다.", "몸짓과 얼굴표정을 사용하여 대화한다.", "보행 시에는 대상자의 바로 뒤에 서서 돕는다."]'::jsonb, 2, NULL, NULL, '{"1": "대화 시 적정한 거리에서 이야기하는 것이 중요하나 반걸음 떨어진 뒤에서 이야기하는 것은 적절하지 않다.\n[정답]", "2": "전달하기 어려운 형태나 사물은 만져보게 하는 것이 시각장애인에게 더 알기 쉽게 의사소통할 수 있다.", "3": "지시대명사를 사용하여 사물의 위치를 설명하는 것은 시각장애인에게 혼동을 줄 수 있다.", "4": "몸짓과 얼굴표정을 사용하여 대화하는 것은 시각장애인에게 적합하지 않으며, 언어적 소통이 필요하다.", "5": "보행 시에는 대상자의 주변을 항상 확인하며 돕는 것이 중요하지만, 바로 뒤에 서는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "시각장애", "term_vi": "Khuyết tật thị giác", "def_ko": "시력을 잃거나 시력이 제한된 상태", "def_vi": "Tình trạng mất hoặc hạn chế khả năng nhìn"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 행위", "def_vi": "Hành động trao đổi thông tin"}, {"term_ko": "지시대명사", "term_vi": "Đại từ chỉ định", "def_ko": "특정 대상을 지칭하는 대명사", "def_vi": "Đại từ chỉ định đối tượng cụ thể"}, {"term_ko": "전달", "term_vi": "Truyền đạt", "def_ko": "정보를 주는 것", "def_vi": "Việc cung cấp thông tin"}, {"term_ko": "형태", "term_vi": "Hình thức", "def_ko": "형태, 구조", "def_vi": "Hình dạng, cấu trúc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1120, '8', '처음으로 시설에 입소한 시각장애 대상자에게 설명하는 방법으로 옳은 것은?', '["사물의 위치를 시계방향으로 설명한다.", "요양보호사를 중심으로 오른쪽, 왼쪽을 설명한다.", "대상자와 눈이 마주쳤을 때 대화를 시도한다.", "여기, 이쪽 등으로 정확히 방향을 제시해 준다.", "말을 건네기 전에 먼저 신체 접촉을 한다."]'::jsonb, 1, NULL, NULL, '{"1": "사물의 위치를 시계방향으로 설명한다. [정답] 이는 시각장애인이 공간을 이해하는 데 도움을 줄 수 있습니다.", "2": "요양보호사를 중심으로 오른쪽, 왼쪽을 설명한다. 이는 시각장애인에게 방향 감각을 혼동시킬 수 있습니다.", "3": "대상자와 눈이 마주쳤을 때 대화를 시도한다. 시각장애인에게는 눈맞춤이 의미가 없으므로 부적절합니다.", "4": "여기, 이쪽 등으로 정확히 방향을 제시해 준다. 이는 불명확한 지시로 대상자의 이해를 방해할 수 있습니다.", "5": "말을 건네기 전에 먼저 신체 접촉을 한다. 이는 개인의 공간을 침해하고 불안감을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "시각장애", "term_vi": "Khiếm thị", "def_ko": "시력에 장애가 있는 상태", "def_vi": "Tình trạng không có khả năng nhìn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1119, '8', '노인성 난청이 있는 대상자와 의사소통하는 방법으로 옳은 것은?', '["신체 접촉을 하지 않는다.", "조명이 어두운 실내에서 대화한다.", "대상자의 등 뒤에서 큰소리로 말한다.", "보청기의 전원 스위치가 작동하는지 확인한다.", "의사소통을 위한 정보제공 시간을 짧게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "신체 접촉을 하지 않는 것은 의사소통 시 비효율적입니다.\n[정답]", "4": "보청기의 전원 스위치가 작동하는지 확인하는 것은 필수 적인 조치입니다.", "2": "조명이 어두운 실내에서 대화하는 것은 부적절합니다.", "3": "대상자의 등 뒤에서 큰소리로 말하는 것은 어려움을 가중시킵니다.", "5": "의사소통을 위한 정보제공 시간을 짧게 하는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Nghe kém ở người lớn tuổi", "def_ko": "노인을 위한 청각 장애", "def_vi": "Khuyết tật thính giác dành cho người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1118, '8', '노인성 난청 대상자와 대화하는 방법으로 옳은 것은?', '["굳은 표정으로 차분하게 말한다.", "보청기 입력은 낮게 출력은 높게 한다.", "정보제공 시간을 짧게 한다.", "말의 의미를 이해할 때까지 반복해서 설명한다.", "대상자의 옆에서 큰 소리로 이야기 한다."]'::jsonb, 4, NULL, NULL, '{"1": "굳은 표정은 대화의 원활함을 방해할 수 있습니다.\n[정답]", "4": "반복해서 설명하면 대상자가 말을 이해하는 데 도움이 됩니다.", "2": "보청기의 사용법에 대해 정확한 정보가 필요합니다. 일반적으로 입력과 출력의 조절은 전문가의 도움이 필요합니다.", "3": "정보 제공 시간은 충분해야 대상자가 내용을 소화할 수 있습니다.", "5": "대상자의 옆에서 큰 소리로 이야기하면 듣는 데 오히려 방해가 됩니다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Mất thính lực tuổi già", "def_ko": "나이가 들어감에 따라 발생하는 청각 장애", "def_vi": "Khiếm thính do tuổi tác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1117, '8', '노인성 난청을 앓고 있는 대상자와 올바른 의사소통 방법은?', '["뒤에서 크게 말한다.", "빠른 속도로 말한다.", "고음으로 정확하게 말한다.", "얼굴표정과 몸짓을 사용하여 말한다.", "입을 작게 벌리며 말한다."]'::jsonb, 4, NULL, NULL, '{"1": "뒤에서 크게 말하는 것은 상대방에게 접촉이 없고 불필요한 소음을 유발할 수 있어 바람직하지 않다.", "2": "빠른 속도로 말하는 것은 이해를 돕기보다는 오히려 혼란을 줄 수 있다.", "3": "고음으로 말하는 것은 난청의 원인인 고주파 소리를 더욱 어렵게 만들 수 있다.\n[정답]", "4": "얼굴표정과 몸짓을 사용하여 말함으로써 비언어적 커뮤니케이션을 통해 의사소통의 효과를 높일 수 있다.", "5": "입을 작게 벌리며 말하는 것은 발음을 듣기 어렵게 만들 수 있다."}'::jsonb, '[{"term_ko": "노인성", "term_vi": "난청", "def_ko": "노인에 관련된, tuổi già", "def_vi": "청력을 잃거나 감소하는 것, mất thính lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1116, '8', '노인성 난청이 있는 대상자와 의사소통으로 옳은 것은?', '["아주 큰 목소리로 말한다.", "말을 되풀이 하지 않는다.", "보청기의 입력은 낮게, 출력은 크게 조절한다.", "말할 때 어깨를 두드리지 않는다.", "눈짓으로 신호를 주면서 말한다."]'::jsonb, 5, NULL, NULL, '{"1": "아주 큰 목소리로 말하는 것은 난청 있는 대상자가 불편해할 수 있다.\n[정답]", "5": "눈짓으로 신호를 주면서 말하는 것은 시각적, 청각적 자극을 동시에 제공해 의사소통을 원활하게 해준다.", "2": "말을 반복하지 않는 것은 대상자가 혼란스러워할 수 있다.", "3": "보청기의 입력과 출력을 조절할 때, 입력은 높이고 출력을 낮추는 것이 일반적이다.", "4": "말할 때 어깨를 두드리지 않는 것이 좋다, 그러나 상황에 따라 다를 수 있다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Điếc tuổi già", "def_ko": "노인에 의해 발생하는 청력 손실", "def_vi": "Mất thính lực do tuổi tác"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "두 사람 이상이 서로의 생각이나 감정을 전달하는 과정", "def_vi": "Quá trình truyền đạt suy nghĩ hoặc cảm xúc giữa hai hoặc nhiều người"}, {"term_ko": "보청기", "term_vi": "Máy trợ thính", "def_ko": "청력을 보완하기 위해 사용하는 장치", "def_vi": "Thiết bị dùng để hỗ trợ thính lực"}, {"term_ko": "눈짓", "term_vi": "Ánh mắt", "def_ko": "눈으로 하는 신호", "def_vi": "Tín hiệu bằng mắt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1115, '8', '대상자 가족과의 의사소통 방법으로 옳은 것은?', '["대상자에 대한 느낌을 솔직하게 전달한다.", "대상자의 이상 상태를 가족에게 알리지 않는다.", "대상자의 부정적인 행동을 직설적으로 말한다.", "의료진으로부터 받은 정보를 가족에게 전달하지 않는다.", "대상자에 대한 정보는 수시로 주고받는다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자에 대한 느낌을 솔직하게 전달하는 것은 중요하지만, 모든 경우에 적절한 방법은 아닙니다.\n[정답]", "5": "대상자에 대한 정보는 수시로 주고받아야 가족이 상황을 잘 이해하고 지원할 수 있습니다.", "2": "대상자의 이상 상태를 알리지 않는 것은 가족의 알 권리를 침해할 수 있습니다.", "3": "대상자의 부정적인 행동을 직설적으로 말하는 것은 가족에게 불필요한 불안을 줄 수 있습니다.", "4": "의료진으로부터 받은 정보를 가족에게 전달하지 않는 것은 비밀보장 원칙과는 관련이 있지만, 가족의 참여와 이해를 높이는 데 방해가 됩니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자, 대상자", "def_vi": "Bệnh nhân"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통, 의사전달", "def_vi": "Truyền đạt thông điệp"}, {"term_ko": "정보", "term_vi": "Thông tin", "def_ko": "알림, 데이터", "def_vi": "Dữ liệu, thông tin"}, {"term_ko": "부정적인", "term_vi": "Tiêu cực", "def_ko": "나쁜, 부정적", "def_vi": "Xấu, tiêu cực"}, {"term_ko": "이상 상태", "term_vi": "Tình trạng bất thường", "def_ko": "문제 있는 상태", "def_vi": "Tình trạng có vấn đề"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1114, '8', '다음 말벗하기에서 밑줄 친 부분에 해당하는 내용은?대상자: 비가 와서 그런지 팔 다리가 쑤시고 아파... 요양보호사: 몸이 많이 무거우시죠? 제가 따뜻한 물로 마사지해 드릴게요.', '["적극적 청취", "증상완화 보조", "정보의 제공", "감정의 제공", "존중과 관심"]'::jsonb, 2, NULL, NULL, '{"1": "적극적 청취: 대상자의 말을 잘 듣고 반응하는 것을 의미하지만, 이 경우 요양보호사 행동은 마사지 제공으로 이어지므로 해당되지 않음.\n[정답]", "2": "증상완화 보조: 요양보호사가 대상자의 팔 다리 통증을 완화하기 위해 마사지하려는 행동은 증상완화 보조에 해당하므로 정답임.", "3": "정보의 제공: 대상자에게 특별한 정보나 지식을 제공하는 것이 아니라 단순히 마사지하겠다는 내용이므로 해당되지 않음.", "4": "감정의 제공: 감정에 대한 언급이 없고, 구체적으로 대처하는 내용이 없으므로 해당되지 않음.", "5": "존중과 관심: 대상자의 말을 듣고 반응하는 것은 맞지만, 마사지 행위로 직접적 행위를 언급하는 것이므로 해당되지 않음."}'::jsonb, '[{"term_ko": "말벗하기", "term_vi": null, "def_ko": "대화하기", "def_vi": null}, {"term_ko": "요양보호사", "term_vi": null, "def_ko": "노인을 돌보는 전문가", "def_vi": null}, {"term_ko": "마사지", "term_vi": "Xoa bóp", "def_ko": "근육 이완을 위한 손으로 하는 치료", "def_vi": "Phương pháp điều trị thư giãn cơ"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 부상의 신호", "def_vi": "Dấu hiệu bệnh tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1113, '8', '대상자와 대화 중 밑줄 친 부분에 해당하는 것은?대상자: 영감이 돌아가시기 전까지 매일 잠자리를 살펴주었는데... 요양보호사: 할아버지를 한번 뵙고 싶어요. 사진을 좀 보여주세요.', '["정보의 제공", "존중과 관심", "적극적 청취", "증상완화 보조", "감정 공감"]'::jsonb, 3, NULL, NULL, '{"1": "정보의 제공: 요양보호사가 정보를 제공한 것이 아니라면 해당되지 않습니다.\n[정답]", "2": "존중과 관심: 요양보호사가 할아버지에 대한 관심을 표현한 것과는 차이가 있습니다.", "3": "적극적 청취: 요양보호사가 대화에 적극적으로 귀 기울이는 모습이 보입니다.", "4": "증상완화 보조: 증상 완화와는 관련이 없습니다.", "5": "감정 공감: 감정을 공감하는 부분이 있지만 이는 대화의 전반적인 맥락으로 보아야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối diện", "def_ko": "환자나 고객", "def_vi": "Bệnh nhân hoặc khách hàng"}, {"term_ko": "영감", "term_vi": "Ông", "def_ko": "할아버지", "def_vi": "Ông ông"}, {"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "요양을 돕는 사람", "def_vi": "Người giúp đỡ trong việc chăm sóc"}, {"term_ko": "적극적", "term_vi": "Tích cực", "def_ko": "능동적인", "def_vi": "Chủ động"}, {"term_ko": "청취", "term_vi": "Nghe", "def_ko": "듣기", "def_vi": "Nghe"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1112, '8', '당ㅁ 말벗하기에서 밑줄 친 부분에 해당하는 대화 내용은?대상자: 영감이 돌아가신 후엔 도둑이 들까 겁도 나고...늘 문단속을 해주었거든... 요양보호사: 할아버지가 자상한 분이셨네요.', '["감정 공감", "적극적 청취", "정보의 제공", "증상완화 보조", "존중과 관심"]'::jsonb, 1, NULL, NULL, '{"1": "감정 공감: 대상자의 감정에 공감하며 대화하는 방식입니다.\n[정답]", "2": "적극적 청취: 대상자가 말하는 내용을 주의 깊게 듣고 반응하는 것입니다.", "3": "정보의 제공: 필요한 정보를 제공하는 것입니다.", "4": "증상완화 보조: 환자의 증상을 완화하는 보조적인 역할입니다.", "5": "존중과 관심: 대상자를 존중하고 그에 대한 관심을 표현하는 것입니다."}'::jsonb, '[{"term_ko": "감정", "term_vi": "Cảm xúc", "def_ko": "감정(한국어)", "def_vi": "Cảm xúc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1111, '8', '다음 대상자와 대화 중 요양보호사의 반응에 해당되는 것은?대상자: 손자 생일 선물을 사 주기로 약속했어요. 나를 마트에 데려가 주세요. 요양보호사: 손자가 아주 좋아하겠어요.', '["적극적 청취", "감정 공감", "수용", "결정", "존중과 관심"]'::jsonb, 2, NULL, NULL, '{"1": "적극적 청취: 상대방의 말을 경청하며 이해하는 것이나, 감정에 대한 공감이 아님.\n[정답]", "2": "감정 공감: 대상자의 감정에 공감하여 반응한 사례.", "3": "수용: 상대방의 생각이나 감정을 있는 그대로 받아들이는 것으로, 예시와는 다름.", "4": "결정: 특정 행동을 선택하는 것, 이번 상황과는 관련이 없음.", "5": "존중과 관심: 대상자에 대한 존중이 필요한 상황이지만, 감정 공감과는 다름."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자 또는 고객", "def_vi": "Bệnh nhân hoặc khách hàng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1110, '8', '김 할아버지는 열이 나는 데도 손자 생일 선물을 사준다고 외출을 고집하신다. 대상자에게 존중과 관심을 표현하는 대답으로 옳은 것은?', '["해열제를 먼저 드세요.", "열이 있으니 외출하시면 안돼요.", "퇴근 후에 아들에게 사오라고 하세요.", "선물보다 용돈으로 주세요.", "열이 좀 있으시네요. 제가 대신 다녀올까요?"]'::jsonb, 5, NULL, NULL, '{"1": "해열제를 먼저 드세요. - 대상자의 상태를 충분히 존중하지 않은 답변이다.", "2": "열이 있으니 외출하시면 안돼요. - 걱정하는 마음은 있지만 비판적인 태도가 포함되어 있다.", "3": "퇴근 후에 아들에게 사오라고 하세요. - 대상자의 욕구를 무시하는 답변이다.", "4": "선물보다 용돈으로 주세요. - 대상자의 선택을 제한하는 대답이다.\n[정답]", "5": "열이 좀 있으시네요. 제가 대신 다녀올까요? - 대상자의 상태를 인식하고, 존중하며 제안하는 올바른 대답이다."}'::jsonb, '[{"term_ko": "열", "term_vi": "Sốt", "def_ko": "열(열)", "def_vi": "Nhiệt độ cao"}, {"term_ko": "손자", "term_vi": "Cháu trai", "def_ko": "손자(아들)", "def_vi": "Con trai của con"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1109, '8', '효과적인 의사소통을 위한 요양보호사의 공감적 반응으로 옳은 것은?대상자: 애들이 왔다 간 지 너무 오래됐어. 다른 사람들은 손주들까지 데리고 자주 오던데... 요양보호사: ( )', '["\"자녀분들이 무심하네요. 제가 전화해 볼게요.\"", "\"연세가 많으시니 이것저것 서운한 게 당연해요.\"", "\"그동안 아무 말씀 없으시더니 왜 그러세요.\"", "\"자녀분들이 많이 보고 싶으신가봐요.\"", "\"가족이 외국에 살아서 아예 안 오시는 분도 있어요.\""]'::jsonb, 4, NULL, NULL, '{"1": "자녀를 비난하는 듯한 표현으로 공감적 반응이 아닙니다.\n[정답]", "4": "대상자의 감정에 공감하고, 그들을 생각해주는 따뜻한 반응입니다.", "2": "나이와 서운함을 연결지어 대상자의 기분을 경시하는 것으로 비공감적입니다.", "3": "질문 형식으로 대상자의 기분을 모르는 듯한 반응입니다.", "5": "다른 상황을 제시하여 상황을 축소하는 느낌을 주므로 공감적이지 않습니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통(한국어)", "def_vi": "sự trao đổi thông tin(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1108, '8', '치매 대상자가 몸에 난 점을 보고 벌레가 나를 문다. 며 소란을 피운다. 요양보호사의 반응으로 옳은 것은?', '["\"어디 벌레가 있어요?\"", "\"잘 보세요. 점이잖아요!\"", "\"벌레는 저도 있어요. 소란피우지 마세요.\"", "\"점이 벌레처럼 보여서 무서우셨군요.\"", "\"어르신, 스스로 잡아보세요.\""]'::jsonb, 4, NULL, NULL, '{"1": "대상자의 불안감을 더욱 부각시키는 부적절한 반응입니다.\n[정답]", "4": "대상자의 감정을 이해하고 안심시킬 수 있는 적절한 반응입니다.", "2": "치매 대상자의 인지를 무시하는 반응으로 올바르지 않습니다.", "3": "치매 대상자가 걱정하는 것을 무시하는 반응입니다.", "5": "대상자의 상태를 더욱 악화시킬 수 있는 반응입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억과 사고에 영향을 미치는 질환", "def_vi": "Bệnh làm ảnh hưởng đến trí nhớ và tư duy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1107, '8', '대상자에게 좋은 ''말벗''이 되기 위한 요양보호사의 태도로 옳은 것은?', '["대상자와 의존관계를 형성한다.", "친해지면 가끔 반말을 한다.", "대상자의 기분이나 감정에 주의를 기울인다.", "대상자의 삶을 옳고 그름으로 판단한다.", "대상자에 대한 좋고 싫은 감정을 솔직하게 표현한다."]'::jsonb, 3, NULL, NULL, '{"1": "대상자와 의존관계를 형성하는 것은 좋지 않은 태도이다.", "2": "친해지더라도 반말을 하는 것은 적절하지 않다.\n[정답]", "3": "대상자의 기분이나 감정에 주의를 기울이는 것은 중요한 태도이다.", "4": "대상자의 삶을 판단하는 것은 비윤리적인 태도이다.", "5": "대상자의 감정을 솔직하게 표현하는 것은 바람직하지 않다."}'::jsonb, '[{"term_ko": "말벗", "term_vi": "Người bạn đồng hành", "def_ko": "대화를 나누고 서로에게 정서적인 지지를 주는 친구", "def_vi": "Người bạn lắng nghe và hỗ trợ tinh thần cho nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1106, '8', '대상자와 효과적인 말벗하기를 위한 방법으로 옳은 것은?', '["대상자와 의존관계를 형성한다.", "사적인 대화를 많이 한다.", "대상자의 삶을 ''옳고 그름''으로 판단한다.", "대상자의 삶을 주관적으로 판단한다.", "대상자의 심리적 상태를 충분히 이해한다."]'::jsonb, 5, NULL, NULL, '{"1": "대상자와 의존관계를 형성하는 것은 부적절한 접근 방법입니다.\n[정답]", "5": "대상자의 심리적 상태를 충분히 이해하는 것이 효과적인 말벗하기를 위한 기본입니다.", "2": "사적인 대화를 많이 하는 것은 개인적 경계를 침범할 수 있습니다.", "3": "대상자의 삶을 ''옳고 그름''으로 판단하는 것은 비판적 사고를 조장할 수 있습니다.", "4": "대상자의 삶을 주관적으로 판단하는 것도 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người nhận chăm sóc hoặc bệnh nhân"}, {"term_ko": "의존관계", "term_vi": "Mối quan hệ phụ thuộc", "def_ko": "누군가에게 의존하는 상태", "def_vi": "Tình trạng phụ thuộc vào ai đó"}, {"term_ko": "사적인 대화", "term_vi": "Cuộc trò chuyện riêng tư", "def_ko": "개인적인 대화", "def_vi": "Cuộc trò chuyện cá nhân"}, {"term_ko": "주관적 판단", "term_vi": "Đánh giá chủ quan", "def_ko": "개인적인 의견에 의거한 판단", "def_vi": "Đánh giá dựa trên ý kiến cá nhân"}, {"term_ko": "심리적 상태", "term_vi": "Tình trạng tâm lý", "def_ko": "감정이나 정신의 상태", "def_vi": "Trạng thái cảm xúc hoặc tâm thần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1105, '8', '의사소통 시 침묵의 긍정적인 효과는?', '["서로의 마음이 통하여 호감과 상호신뢰가 생긴다.", "상대방의 입장에서 이해하고자 노력한다.", "자신의 느낌과 생각을 효과적으로 표현한다.", "요양보호사와 대상자 모두에게 생각을 정리할 시간을 준다.", "상대방의 표현을 있는 그대로 받아들인다."]'::jsonb, 5, NULL, NULL, '{"1": "서로의 마음이 통하여 호감과 상호신뢰가 생길 수 있지만, 침묵과는 직접적인 관련이 없다.", "2": "상대방의 입장에서 이해하고자 노력하는 것은 중요하나, 침묵의 효과라고 보기는 어렵다.", "3": "자신의 느낌과 생각을 효과적으로 표현하는 것은 말이 필요하다.\n[정답]", "4": "요양보호사와 대상자 모두에게 생각을 정리할 시간을 주며, 이는 의사소통의 효과적인 부분이다.", "5": "상대방의 표현을 있는 그대로 받아들이는 것은 침묵의 효과와 관련이 없다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통(한국어)", "def_vi": "Sự trao đổi thông tin giữa các bên."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1104, '8', '대상자가 옷 입기를 거부할 때 나-전달법으로 옳은 것은?', '["\"저한테 불만이 많으신가 봐요.\"", "\"왜 옷을 안 입으세요?\"", "\"어르신이 옷을 갈아입지 않으려고 하니 제가 힘드네요.\"", "\"옷을 입지 않으시면 외출하지 않을거예요.\"", "\"마음에 안 드는 것이 있으면 말씀하세요.\""]'::jsonb, 3, NULL, NULL, '{"1": "''저한테 불만이 많으신가 봐요.'' - 대상자의 감정을 판단하는 발언으로 거부감을 줄 수 있습니다.", "2": "''왜 옷을 안 입으세요?'' - 직접적인 질문이지만, 상대의 기분을 고려하지 않은 방식입니다.\n[정답]", "3": "''어르신이 옷을 갈아입지 않으려고 하니 제가 힘드네요.'' - 나-전달법을 적절히 사용하여 상대의 행동이 자신의 감정에 어떤 영향을 미치는지를 표현하고 있습니다.", "4": "''옷을 입지 않으시면 외출하지 않을거예요.'' - 위협적인 언급으로서 부정적인 반응을 유발할 수 있습니다.", "5": "''마음에 안 드는 것이 있으면 말씀하세요.'' - 상대방의 감정을 존중하는 예의는 있지만, 구체적인 행동의 변화를 유도하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자, 고객", "def_vi": "Bệnh nhân, khách hàng"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "거절하다, 수용하지 않음", "def_vi": "từ chối, không chấp nhận"}, {"term_ko": "옷", "term_vi": "Áo", "def_ko": "의복", "def_vi": "quần áo"}, {"term_ko": "나-전달법", "term_vi": "Phương pháp truyền đạt cảm xúc của bản thân", "def_ko": "자신의 감정을 전달하는 법", "def_vi": "Phương pháp truyền đạt cảm xúc của bản thân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1103, '8', '대상자가 식사를 거부할 때 나-전달법으로 옳은 것은?', '["\"제게 불만이 많으신가요?\"", "\"어르신이 식사를 안 하려고 하니 걱정이 되네요.\"", "\"반찬이 마음에 안 드세요?\"", "\"배가 고파지면 말씀하세요.\"", "\"식사를 안 하면 오후에 간식이 없어요.\""]'::jsonb, 2, NULL, NULL, '{"1": "대상자의 감정을 직접적으로 물어보는 것은 효과적인 접근 방식이 아닙니다.\n[정답]", "2": "대상자의 식사 거부에 대한 걱정을 표현함으로써, 공감을 나타내고 소통의 기회를 마련합니다.", "3": "반찬에 대한 직접적인 질문은 대상자의 심리적 상태를 고려하지 않은 접근입니다.", "4": "행동을 강요하는 메시지는 대상자의 거부감을 더욱 악화시킬 수 있습니다.", "5": "조건부 행동을 제시하는 것은 부정적인 효과를 미칠 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "도움을 받는 사람", "def_vi": "Người nhận sự giúp đỡ"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식을 먹는 행위", "def_vi": "Hành động ăn uống"}, {"term_ko": "거부", "term_vi": "Từ chối", "def_ko": "받아들이지 않음", "def_vi": "Không chấp nhận"}, {"term_ko": "전달법", "term_vi": "Phương pháp giao tiếp", "def_ko": "소통 방법", "def_vi": "Cách thức giao tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1102, '8', '대상자와 요양보화의 대화 중 ''나-전달법''으로 옳은 것은?', '["식사를 안 하시면 어르신만 손해예요.", "입맛이 없어도 억지로라도 드셔야죠.", "점심때까지 배고파도 참으셔야겠네요.", "식사를 안 하시면 제가 더 힘들어요.", "소고기무국 좋아하시는데 식사를 안 하시니 걱정이 돼요."]'::jsonb, 5, NULL, NULL, '{"1": "''어르신만 손해예요.''는 나의 주장을 강조하는 표현입니다.\n[정답]", "5": "''소고기무국 좋아하시는데 식사를 안 하시니 걱정이 돼요.''는 나의 감정과 걱정을 전하는 표현입니다.", "2": "''억지로라도 드셔야죠.''는 상대방의 선택을 제한하는 언급입니다.", "3": "''참으셔야겠네요.''는 상대방의 행동을 강요하는 측면이 있습니다.", "4": "''제가 더 힘들어요.''는 나의 기분을 강조하지만 상대방의 입장을 고려하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "대상자(한국어)", "def_vi": "Người nhận sự chăm sóc"}, {"term_ko": "요양보호", "term_vi": "Chăm sóc", "def_ko": "돌봄(한국어)", "def_vi": "Chăm sóc"}, {"term_ko": "전달법", "term_vi": "Phương pháp truyền đạt", "def_ko": "전달 방법(한국어)", "def_vi": "Phương thức giao tiếp"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "식사(한국어)", "def_vi": "Bữa ăn"}, {"term_ko": "걱정", "term_vi": "Lo lắng", "def_ko": "걱정(한국어)", "def_vi": "Sự lo lắng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1101, '8', '동료 요양보호사가 반복적으로 사적인 부탁을 할 때 ''나-전달법'' 의사소통 방법은?', '["\"그건 규칙에 어긋나는 일이어서 안돼요.\"", "\"미안하지만 다른 분에게 부탁하는 게 좋겠어요.\"", "\"이번에만 해 드릴테니 다음부터는 부탁하지 마세요.\"", "\"한두 번도 아니고 다른 사람을 너무 힘들게 하시네요.\"", "\"자꾸 이러면 내 생활에 지장이 있고 함께 일하기 불편해요.\""]'::jsonb, 5, NULL, NULL, '{"1": "상대방의 행동을 단순히 지적하는 방법으로, ''나-전달법''에 적합하지 않습니다.", "2": "상황을 피하는 방식으로, 보다 효과적인 의사소통 방법이 아닙니다.\n[정답]", "3": "자신의 감정이나 상황을 명확히 전달하는 방법입니다.", "4": "비난하는 방식으로, 건설적인 의사소통이 아닙니다.", "5": "자신의 영향과 감정을 명확히 전달하는 ''나-전달법''에 적합한 방법입니다."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Nhân viên chăm sóc", "def_ko": "환자를 돌보는 전문가", "def_vi": "chuyên gia chăm sóc bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1100, '8', '다음 상황에서 나- 전달법 의사소통으로 옳은 것은?대상자와 관련된 중요한 전화를 기다리고 있는데 동료 요양보호사가 사적인 전화 통화를 계속하고 있다.', '["언제까지 기다려야 하나요.", "사적인 통화는 휴대폰으로 하세요.", "전화 예의가 없으시네요.", "중요한 전화를 받지 못할까 봐 조바심도 나고 걱정이 돼요.", "통화를 할 때는 용건만 간단히 하세요."]'::jsonb, 4, NULL, NULL, '{"1": "언제까지 기다려야 하나요. - 이는 상대방에게 불만을 표출하는 방식으로, 부정적인 인상을 줄 수 있습니다.", "2": "사적인 통화는 휴대폰으로 하세요. - 강압적인 표현으로 해석 될 수 있습니다.\n[정답]", "3": "전화 예의가 없으시네요. - 이는 부정적인 피드백이므로 적절하지 않은 표현입니다.", "4": "중요한 전화를 받지 못할까 봐 조바심도 나고 걱정이 돼요. - 이는 자신의 감정을 솔직하게 표현함으로써 상대방의 이해를 도울 수 있는 올바른 커뮤니케이션입니다.", "5": "통화를 할 때는 용건만 간단히 하세요. - 이를 요청하는 것은 다소 무례하게 들릴 수 있습니다."}'::jsonb, '[{"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통하는 방법", "def_vi": "Phương pháp giao tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1099, '8', '대상자와 효과적으로 말하는 방법으로 옳은 것은?', '["자신의 감정을 숨긴다.", "의사전달을 분명하게 한다.", "부족하고 자신감 없는 태도를 보인다.", "모든 일에 전문가임을 주장한다.", "지나간 나쁜 내용을 상기시킨다."]'::jsonb, 2, NULL, NULL, '{"1": "자신의 감정을 숨기는 것은 신뢰를 구축하는 데 도움이 되지 않습니다.\n[정답]", "2": "의사전달을 분명하게 하는 것은 대상자와의 효과적인 소통에 필수적입니다.", "3": "부족하고 자신감 없는 태도는 상대방에게 부정적인 인식을 줄 수 있습니다.", "4": "모든 일에 전문가임을 주장하는 것은 오히려 상대방을 불편하게 할 수 있습니다.", "5": "지나간 나쁜 내용을 상기시키는 것은 불필요한 긴장을 유발합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người hưởng lợi", "def_ko": "환자 또는 돌봄 받는 사람", "def_vi": "Người bệnh hoặc người được chăm sóc"}, {"term_ko": "효과적", "term_vi": "Hiệu quả", "def_ko": "효과적인, 효과를 내는", "def_vi": "Có tác dụng hoặc hiệu quả"}, {"term_ko": "의사전달", "term_vi": "Truyền đạt thông tin", "def_ko": "정보를 전달하는 것", "def_vi": "Việc truyền đạt thông tin"}, {"term_ko": "신뢰", "term_vi": "Tin tưởng", "def_ko": "믿음", "def_vi": "Lòng tin"}, {"term_ko": "태도", "term_vi": "Thái độ", "def_ko": "행동이나 마음가짐", "def_vi": "Hành vi hoặc thái độ"}, {"term_ko": "전문가", "term_vi": "Chuyên gia", "def_ko": "특정 분야에서 지속적인 연구와 훈련을 받은 사람", "def_vi": "Người đã nghiên cứu và đào tạo liên tục trong một lĩnh vực cụ thể"}, {"term_ko": "상기시키다", "term_vi": "Nhắc lại", "def_ko": "기억나게 하다", "def_vi": "Ghi nhớ hoặc nhớ lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1098, '8', '대상자와 공감적 대화로 옳은 것은?대상자: 어제 밤에 잠을 통 못 잤어. 낮잠을 자지 말아야겠어. 요양보호사: ( )', '["\"오늘 기분이 좋아 보이시네요.\"", "\"낮에 저랑 산책해요.\"", "\"네, 그렇게 해보시겠어요?\"", "\"무슨 고민이 있으세요?\"", "\"나이가 들면 잠이 없어진대요.\""]'::jsonb, 3, NULL, NULL, '{"1": "상대방의 기분에 대한 잘못된 판단으로 공감을 잘못 표현함.\n[정답]", "3": "대상자의 의사를 존중하며 긍정적인 방안을 제시함.", "2": "단순한 제안으로서 감정적 지지 부족.", "4": "대상자의 상태에 대한 불필요한 질문을 던짐.", "5": "일반적인 정보로서 대상자의 감정에 대한 공감 부족."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "환자나 보살핌이 필요한 사람", "def_vi": "Người bệnh hoặc người cần được chăm sóc"}, {"term_ko": "공감적", "term_vi": "Đồng cảm", "def_ko": "감정이나 상황을 이해하고 공유하는 것", "def_vi": "Hiểu và chia sẻ cảm xúc hoặc tình huống"}, {"term_ko": "대화", "term_vi": "Cuộc trò chuyện", "def_ko": "말이나 의사소통의 방식", "def_vi": "Cách giao tiếp hoặc nói chuyện"}, {"term_ko": "제안", "term_vi": "Đề xuất", "def_ko": "어떤 행동이나 결정을 제안하는 것", "def_vi": "Đưa ra một hành động hoặc quyết định"}, {"term_ko": "의사", "term_vi": "Bác sĩ", "def_ko": "전문가로서 진단을 내리거나 치료하는 사람", "def_vi": "Người chuyên môn đưa ra chẩn đoán hoặc điều trị"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1097, '8', '다음 대화 중 요양보호사의 공감적 반응으로 옳은 것은?대상자: 아이고 다리가 너무 아파, 꼼짝을 못하겠어. 갈수록 더 아픈 것 같아. 요양보호사: ( )', '["\"연세가 많으시니 아픈 것은 당연하지요.\"", "\"진통제를 좀 드릴까요.\"", "\"그동안 잘 참으셨잖아요. 조금만 더 참으세요.\"", "\"아프시니까 많이 힘드시죠.\"", "\"옆집 어르신도 많이 아프신가 봐요. 기운내세요.\""]'::jsonb, 4, NULL, NULL, '{"1": "환자의 감정을 무시하고 단순한 사실을 언급하여 공감하지 않음.\n[정답]", "4": "환자의 아픔을 인정하고 힘들다는 점에 공감함.", "3": "애써 환자를 위로하려는 의도는 있으나, 감정을 충분히 이해하지 못한 반응임.", "2": "의학적 제안으로, 감정적 지지를 제공하지 않음.", "5": "다른 사람의 사례를 들어 환자의 감정을 담아내지 않음."}'::jsonb, '[{"term_ko": "공감", "term_vi": "Đồng cảm", "def_ko": "이해하고 느끼는 것", "def_vi": "Hiểu và cảm nhận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1096, '8', '다음 대화 중 요양보호사의 공감적 대화로 옳은 것은?대상자: 전에 요양보호사는 일 그만 두었다요? 그 분이 일을 참 잘했었는데... 요양보호사: ( )', '["그런 식으로 말씀하시지 마세요. 부탁드립니다.", "전에 하시던 분이 참 잘하셨나봐요. 저도 열심히 할게요.", "제가 마음에 안 드시면 다른 분 소개시켜 드릴까요?", "그러게 말씀하시니 기분이 안 좋네요. 서로 적응하면 나아질거예요.", "일 그만 둔 사람을 왜 찾으세요? 섭섭하네요."]'::jsonb, 2, NULL, NULL, '{"1": "그런 식으로 말씀하시지 마세요. 부탁드립니다.", "2": "[정답] 전에 하시던 분이 참 잘하셨나봐요. 저도 열심히 할게요.", "3": "제가 마음에 안 드시면 다른 분 소개시켜 드릴까요?", "4": "그러게 말씀하시니 기분이 안 좋네요. 서로 적응하면 나아질거예요.", "5": "일 그만 둔 사람을 왜 찾으세요? 섭섭하네요."}'::jsonb, '[{"term_ko": "요양보호사", "term_vi": "Người chăm sóc", "def_ko": "환자나 노인 등을 돌보는 사람", "def_vi": "Người chăm sóc bệnh nhân hoặc người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1095, '8', '다음 대화 중 요양보호사의 공감적 반응으로 옳은 것은?대상자: 나를 어린애 취급하는 것 같은데 성인으로 대해주세요. 양치질 해라, 머리 빗어라 명령하고 안하면 신경질 내잖아요. 요양보호사: ( )', '["신경질 낸 적 없거든요.", "그런 식으로 말하지 마세요.", "저도 성인으로 대하고 싶거든요.", "일일이 간섭하고 성가시게 해서 기분이 상하셨군요.", "어르신이 어린애처럼 스스로 못 챙기시잖아요."]'::jsonb, 4, NULL, NULL, '{"1": "신경질 낸 적 없거든요. (대상자의 감정을 무시하고 반박하는 태도입니다.)", "2": "그런 식으로 말하지 마세요. (비난적인 태도로 공감을 하지 못합니다.)", "3": "저도 성인으로 대하고 싶거든요. (자신의 입장을 나타내며 공감을 하지 않습니다.)\n[정답]", "4": "일일이 간섭하고 성가시게 해서 기분이 상하셨군요. (대상자의 기분을 공감하고 이해하는 반응입니다.)", "5": "어르신이 어린애처럼 스스로 못 챙기시잖아요. (부정적인 태도로 공감하지 않습니다.)"}'::jsonb, '[{"term_ko": "공감적 반응", "term_vi": "Phản ứng đồng cảm", "def_ko": "이해하고 동감하는 반응", "def_vi": "Phản ứng thể hiện sự hiểu biết và chia sẻ cảm xúc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1094, '8', '대상자와 대화할 때 경청을 방해하는 경우는?', '["충분히 듣지 않은 상태에서 조언한다.", "흥분하지 않고, 비판적 태도를 버린다.", "상대방이 말하는 의미를 잘 파악하고 이해한다.", "상대방이 말하는 동안 경청하고 있다는 것을 표현한다.", "상대방의 말을 가로채거나 이야기를 가로막지 않는다."]'::jsonb, 1, NULL, NULL, '{"1": "충분히 듣지 않은 상태에서 조언한다. - 경청을 방해하는 대표적인 행동입니다. [정답]", "2": "흥분하지 않고, 비판적 태도를 버린다. - 경청에 도움이 되는 태도입니다.", "3": "상대방이 말하는 의미를 잘 파악하고 이해한다. - 경청의 중요한 요소입니다.", "4": "상대방이 말하는 동안 경청하고 있다는 것을 표현한다. - 경청을 증진시키는 방법입니다.", "5": "상대방의 말을 가로채거나 이야기를 가로막지 않는다. - 올바른 경청 태도입니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Người bệnh hoặc người nhận sự chăm sóc"}, {"term_ko": "경청", "term_vi": "Lắng nghe", "def_ko": "주의 깊게 듣는 것", "def_vi": "Nghe một cách chú ý"}, {"term_ko": "조언", "term_vi": "Lời khuyên", "def_ko": "다른 사람에게 일어날 수 있는 방법이나 해결책을 제시하는 것", "def_vi": "Đưa ra phương pháp hoặc giải pháp cho người khác"}, {"term_ko": "비판적", "term_vi": "Phê bình", "def_ko": "부정적이고 평가하는 태도", "def_vi": "Thái độ tiêu cực và đánh giá"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1093, '8', '대상자와 의사소통 시 효과적인 방법으로 옳은 것은?', '["듣고 싶지 않은 말은 걸러낸다.", "듣는 중간에 계속해서 조언한다.", "원하는 바를 우회적으로 돌려서 이야기한다.", "대상자의 말과 표정이 일치하는지 확인한다.", "요양보호사의 경험을 근거로 문제해결 방법을 조언한다."]'::jsonb, 4, NULL, NULL, '{"1": "듣고 싶지 않은 말을 걸러내는 것은 효과적인 의사소통이 아닙니다.", "2": "듣는 중간에 계속해서 조언을 하는 것은 상대방의 말을 충분히 듣지 못하게 만들 수 있습니다.", "3": "원하는 바를 우회적으로 돌려서 이야기하는 것은 대화의 명확성을 떨어뜨릴 수 있습니다.\n[정답]", "4": "대상자의 말과 표정이 일치하는지 확인하는 것은 의사소통의 정확성을 높이는 좋은 방법입니다.", "5": "요양보호사의 경험을 근거로 문제해결 방법을 조언하는 것은 때로 도움이 될 수 있지만, 대상자가 느끼는 감정이나 요구를 우선적으로 고려해야 합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận chăm sóc", "def_ko": "환자 또는 수혜자", "def_vi": "Bệnh nhân hoặc người thụ hưởng"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통 또는 대화", "def_vi": "Sự giao tiếp hoặc trao đổi"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 감정 표현", "def_vi": "Sự bày tỏ cảm xúc trên khuôn mặt"}, {"term_ko": "조언", "term_vi": "Lời khuyên", "def_ko": "의견이나 제안", "def_vi": "Ý kiến hoặc đề xuất"}, {"term_ko": "우회적", "term_vi": "Gián tiếp", "def_ko": "직접적이지 않은", "def_vi": "Không trực tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1091, '8', '대상자와 효과적으로 의사소통하는 방법은?', '["의견이 맞지 않을 때는 대화 주제를 바꾼다.", "상황에 맞지 않는 말은 지적해 준다.", "대상자의 표정을 관찰하며 듣는다.", "ㄷ대상자가 말하는 동안 미리 대답을 준비한다.", "대상자의 말을 요양보호사의 경험에 비추어 판단한다."]'::jsonb, 3, NULL, NULL, '{"1": "의견이 맞지 않을 때는 대화 주제를 바꾼다: 이는 효과적인 의사소통이 아닌 회피적 행동입니다.\n[정답]", "3": "대상자의 표정을 관찰하며 듣는다: 비언어적 신호를 이해하고 반응하는 것은 의사소통의 핵심입니다.", "2": "상황에 맞지 않는 말은 지적해 준다: 직접적인 지적은 대화의 흐름을 방해할 수 있습니다.", "4": "대상자가 말하는 동안 미리 대답을 준비한다: 이는 상대방의 말을 충분히 듣지 못하는 결과를 초래합니다.", "5": "대상자의 말을 요양보호사의 경험에 비추어 판단한다: 개인적인 경험으로 판단하는 것은 대상자의 고유한 상황을 왜곡할 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자나 클라이언트", "def_vi": "Bệnh nhân hoặc khách hàng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1090, '8', '대상자와 친밀한 관계를 형성하는 데 도움이 되는 의사소통 방법은?', '["듣기 전에 대답할 말을 미리 준비한다.", "논쟁에서는 다른 사람과 비교하면서 설득한다.", "ㅇ요양보호사는 국가자격을 지닌 전문가임을 강조한다.", "의견이 다를 때에는 대상자의 주장을 먼저 들어준다.", "대상자가 침묵할 때에는 요양보호사가 주도적으로 이야기한다."]'::jsonb, 4, NULL, NULL, '{"1": "듣기 전에 대답할 말을 미리 준비하는 것은 상대방의 의견을 존중하지 않는 태도이다.\n[정답]", "4": "의견이 다를 때에는 대상자의 주장을 먼저 들어주는 것이 친밀한 관계를 형성하는 데 도움이 된다.", "2": "논쟁에서는 다른 사람과 비교하면서 설득하는 것은 관계를 악화시킬 수 있다.", "3": "요양보호사가 국가자격을 지닌 전문가임을 강조하는 것은 관계 형성과는 거리가 있다.", "5": "대상자가 침묵할 때 요양보호사가 주도적으로 이야기하는 것은 상대방의 필요를 무시하는 태도이다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người đối tượng", "def_ko": "보호받는 사람", "def_vi": "Người được chăm sóc"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 전달하는 과정", "def_vi": "Quá trình truyền đạt thông tin"}, {"term_ko": "친밀한", "term_vi": "Thân thiết", "def_ko": "가까운, 친근한", "def_vi": "Gần gũi, thân thuộc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1089, '8', '비언어적 의사소통 중 바람직한 태도는?', '["입술을 깨물거나 꼭 다문 입", "대상자보다 높거나 낮은 눈높이", "따뜻하고 배려하는 표정", "손가락으로 지적하기", "큰소리로 말하기"]'::jsonb, 3, NULL, NULL, '{"1": "입술을 깨물거나 꼭 다문 입: 긴장이나 불안감을 나타내는 부정적인 비언어적 신호입니다.\n[정답]", "3": "따뜻하고 배려하는 표정: 상대방에게 긍정적인 감정을 전달하며, 비언어적 의사소통에서 매우 중요한 태도입니다.", "2": "대상자보다 높거나 낮은 눈높이: 눈높이가 맞지 않으면 비언어적 의사소통의 효과가 떨어질 수 있습니다.", "4": "손가락으로 지적하기: 공격적이거나 불쾌감을 줄 수 있는 행동입니다.", "5": "큰소리로 말하기: 비언어적 의사소통의 맥락에서 부적절한 태도로 간주됩니다."}'::jsonb, '[{"term_ko": "비언어적 의사소통", "term_vi": "Giao tiếp không bằng lời nói", "def_ko": "언어가 아닌 방법으로 의사소통하는 것", "def_vi": "Cách giao tiếp không sử dụng ngôn ngữ"}, {"term_ko": "바람직한", "term_vi": "Đáng mong đợi", "def_ko": "좋은 품질이나 상태를 가진", "def_vi": "Có chất lượng hoặc trạng thái tốt"}, {"term_ko": "태도", "term_vi": "Thái độ", "def_ko": "어떤 행동이나 사고방식", "def_vi": "Một hành vi hoặc cách suy nghĩ"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 감정이나 상태", "def_vi": "Cảm xúc hoặc trạng thái của khuôn mặt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1088, '8', '대상자와 의사소통 시 올바른 자세는?', '["팔짱끼기", "잦은 하품", "눈썹 치켜뜨기", "대상자와 같은 눈높이", "지나친 머리 끄덕임"]'::jsonb, 4, NULL, NULL, '{"1": "팔짱끼기는 비협조적인 태도로 해석될 수 있습니다.\n[정답]", "4": "대상자와 같은 눈높이는 신뢰감을 주고 의사소통에 효과적입니다.", "3": "눈썹 치켜뜨기는 놀란 듯한 인상을 줄 수 있습니다.", "2": "잦은 하품은 피로감을 나타내어 적절하지 않습니다.", "5": "지나친 머리 끄덕임은 동의의 의미로 이해되겠지만, 과도할 경우 무례하게 여겨질 수 있습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 돌봄을 받는 사람", "def_vi": "Bệnh nhân hoặc người nhận sự chăm sóc"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통", "def_vi": "Giao tiếp"}, {"term_ko": "눈높이", "term_vi": "Tầm nhìn", "def_ko": "동일한 시선의 높이", "def_vi": "Chiều cao của tầm nhìn"}, {"term_ko": "팔짱", "term_vi": "Khoanh tay", "def_ko": "두 팔을 서로 교차하여 감다", "def_vi": "Bắt chéo hai tay"}, {"term_ko": "하품", "term_vi": "Ngáp", "def_ko": "피로감으로 입을 벌리고 숨을 내쉬는 행위", "def_vi": "Hành động há miệng và thở ra do mệt mỏi"}, {"term_ko": "치켜뜨다", "term_vi": "Nâng mày", "def_ko": "눈썹을 위로 들어 올리다", "def_vi": "Nâng lông mày lên"}, {"term_ko": "지나치다", "term_vi": "Quá mức", "def_ko": "과도하거나 너무 많다", "def_vi": "Quá nhiều hoặc quá mức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1087, '8', '비언어적 의사소통 시 요양보호사의 자세로 옳은 것은?', '["너무 긴 침묵", "희미한 미소", "시선을 한 곳에 고정하기", "습관적인 머리 끄덕임", "대상자를 향해 약간 기울인 자세"]'::jsonb, 5, NULL, NULL, '{"1": "너무 긴 침묵은 대화의 흐름을 방해할 수 있습니다.", "2": "희미한 미소는 상대방에게 비인격적인 인상을 줄 수 있습니다.", "3": "시선을 한 곳에 고정하는 것은 상대방과의 소통을 어렵게 합니다.", "4": "습관적인 머리 끄덕임은 진정한 이해를 나타내지 않을 수 있습니다.\n[정답]", "5": "대상자를 향해 약간 기울인 자세는 관심과 참여를 나타내어 비언어적 소통에 긍정적입니다."}'::jsonb, '[{"term_ko": "비언어적", "term_vi": "Giao tiếp phi ngôn ngữ", "def_ko": "말로 하지 않고 전달되는 의사소통", "def_vi": "Giao tiếp không bằng lời nói"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1086, '8', '다음 중 언어적 의사소통 표현으로 옳은 것은?', '["자세", "말의 내용", "눈맞춤", "옷차림", "얼굴표정"]'::jsonb, 2, NULL, NULL, '{"1": "자세: 비언어적 표현이며 의사소통에 영향을 줄 수 있지만 언어적 의사소통과는 관계없음.\n[정답]", "2": "말의 내용: 언어적 의사소통을 표현하는 가장 직접적인 수단이며, 텍스트나 언어로 전달되는 의미를 담고 있음.", "3": "눈맞춤: 비언어적 의사소통에 해당하며 상대방과의 연결감을 주는 방법입니다.", "4": "옷차림: 개인의 스타일 표현으로, 의사소통을 돕기보다는 주로 비언어적 신호로 작용함.", "5": "얼굴표정: 비언어적 의사소통의 일종으로 감정이나 반응을 전달하는 수단입니다."}'::jsonb, '[{"term_ko": "언어적 의사소통", "term_vi": "Giao tiếp bằng ngôn ngữ", "def_ko": "말이나 글을 통해 의사를 전달하는 과정", "def_vi": "Quá trình truyền đạt ý kiến thông qua lời nói hoặc văn bản"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1085, '8', '대화를 할 때 영향을 미치는 요소 중 가장 중요한 것은?', '["억양", "표현력", "얼굴표정", "말의 내용", "말의 속도"]'::jsonb, 3, NULL, NULL, '{"1": "억양은 대화의 감정을 전달할 수 있지만, 가장 중요한 요소는 아닙니다.\n[정답]", "3": "얼굴표정은 비언어적 의사소통의 중요한 부분으로, 대화에 큰 영향을 미칩니다.", "2": "표현력도 중요하지만, 얼굴표정보다 덜 중요합니다.", "4": "말의 내용은 필수적이지만, 비언어적 요소인 얼굴표정에 비해 중요도가 낮습니다.", "5": "말의 속도도 대화에 영향을 주지만, 얼굴표정이 더 중요합니다."}'::jsonb, '[{"term_ko": "대화", "term_vi": "Cuộc trò chuyện", "def_ko": "대화를 나누는 것", "def_vi": "Hành động giao tiếp với nhau"}, {"term_ko": "영향", "term_vi": "Ảnh hưởng", "def_ko": "어떤 것이 다른 것에 미치는 작용", "def_vi": "Tác động của một cái gì đó lên cái khác"}, {"term_ko": "요소", "term_vi": "Yếu tố", "def_ko": "구성하는 부분", "def_vi": "Phần cấu thành"}, {"term_ko": "얻다", "term_vi": "Đạt được", "def_ko": "어떤 것을 가지게 되다", "def_vi": "Có được điều gì đó"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 모습", "def_vi": "Diện mạo của khuôn mặt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1084, '8', '업무수행 과정에서 요굳회는 의사소통의 필요성으로 옳은 것은?', '["요양보호사의 업무를 평가하기 위해서", "요양보호사의 활동을 입증하기 위해서", "요양보호사의 전문성을 향상하기 위해서", "요양보호사의 책임성을 제고하기 위해서", "신뢰관계를 형성하여 좋은 관계를 유지하기 위해서"]'::jsonb, 5, NULL, NULL, '{"1": "요양보호사의 업무를 평가하기 위해서\n→ 이 선택지는 평가의 필요성을 언급하고 있지만, 의사소통의 필요성과는 다소 관련이 낮습니다.\n[정답]", "5": "신뢰관계를 형성하여 좋은 관계를 유지하기 위해서\n→ 의사소통은 신뢰관계를 구축하고 유지하는 데 필수적인 요소입니다. 따라서 올바른 답변입니다.", "2": "요양보호사의 활동을 입증하기 위해서\n→ 활동의 입증은 의사소통의 필요성과 직접적으로 연결되지 않습니다.", "3": "요양보호사의 전문성을 향상하기 위해서\n→ 전문성 향상은 교육이나 경험을 통해 이루어지며, 의사소통과의 관련성이 떨어집니다.", "4": "요양보호사의 책임성을 제고하기 위해서\n→ 책임성 제고와 의사소통 필요성은 연결될 수 있으나, 신뢰관계 형성의 중요성이 더 크다고 볼 수 있습니다."}'::jsonb, '[{"term_ko": "업무", "term_vi": "Công việc", "def_ko": "일, 작업", "def_vi": "Công việc, nhiệm vụ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1083, '7', '한랭 질환인 저체온증에 대한 설명으로 옳은 것은?', '["젖은 옷을 입은 채 담요로 감싼다.", "피부 및 피하조직이 손ㅅ상되어 무감각해진다.", "손가락, 발가락이 단단해지며 누런 회색으로 변한다.", "의식이 있으면 따뜻한 음료와 초콜릿을 섭취하게 한다.", "따뜻한 장소로 이동 후, 호전이 없으면 119에 신고한다."]'::jsonb, 4, NULL, NULL, '{"1": "젖은 옷을 입은 채 담요로 감싸면 오히려 체온이 떨어질 수 있으므로 잘못된 방법이다.\n[정답]", "4": "의식이 있으면 따뜻한 음료와 초콜릿을 섭취하게 하는 것이 적절한 응급 처치 방법이다.", "2": "피부 및 피하조직이 손상되어 무감각해지는 것은 저체온증의 증상일 수 있으나 직접적인 대처 방법은 아니다.", "3": "손가락, 발가락이 단단해지고 변색되는 것은 저체온증의 증상으로 맞지만, 이를 대처하는 방법으로 적절하지 않다.", "5": "따뜻한 장소로 이동 후, 호전이 없으면 119에 신고하는 것이 좋지만, 이 단계에서 따뜻한 음료를 주는 것이 먼저이다."}'::jsonb, '[{"term_ko": "저체온증", "term_vi": "Hạ thân nhiệt", "def_ko": "기온이 체온보다 낮아져 나타나는 질환", "def_vi": "Bệnh xảy ra khi nhiệt độ cơ thể thấp hơn nhiệt độ bình thường"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "주변 상황을 인식하고 있는 상태", "def_vi": "Trạng thái nhận thức được xung quanh"}, {"term_ko": "온도", "term_vi": "Nhiệt độ", "def_ko": "열의 정도", "def_vi": "Mức độ của nhiệt"}, {"term_ko": "음료", "term_vi": "Đồ uống", "def_ko": "마실 수 있는 액체", "def_vi": "Chất lỏng có thể uống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1082, '7', '한랭관련 질환에 대한 설명으로 옳은 것은?', '["동상은 주로 가슴과 배, 등 부위에 생긴다.", "저체온증인 경우 옷을 벗은 상태로 있는다.", "동상부위는 차가운 물에 담가준다.", "저체온증은 착란, 어눌한 말투, 기억상실 증상이 나타난다.", "겨울에는 혈관이 이완되고 혈압이 저하되어 뇌졸중이 발생한다."]'::jsonb, 4, NULL, NULL, '{"1": "동상은 주로 손, 발, 코와 같은 노출된 부위에 발생합니다, 따라서 잘못된 설명입니다.\n[정답]", "4": "저체온증에서는 착란, 어눌한 말투, 기억상실 등의 증상이 나타나므로 옳은 설명입니다.", "2": "저체온증인 경우 옷을 벗으면 상황이 더욱 악화될 수 있습니다, 잘못된 설명입니다.", "3": "동상 부위는 따뜻한 물에 담가야 하며 차가운 물은 피해야 합니다, 잘못된 설명입니다.", "5": "겨울철에는 혈관이 수축되고 혈압이 상승하여 뇌졸중 위험이 증가합니다, 잘못된 설명입니다."}'::jsonb, '[{"term_ko": "동상", "term_vi": "Bệnh đông lạnh", "def_ko": "동상", "def_vi": "Bệnh đông lạnh"}, {"term_ko": "저체온증", "term_vi": "Hạ thân nhiệt", "def_ko": "저체온증", "def_vi": "Hạ thân nhiệt"}, {"term_ko": "착란", "term_vi": "Rối loạn ý thức", "def_ko": "혼란", "def_vi": "Rối loạn ý thức"}, {"term_ko": "어눌한", "term_vi": "Lời nói khó khăn", "def_ko": "둔한", "def_vi": "Lời nói khó khăn"}, {"term_ko": "기억상실", "term_vi": "Mất trí nhớ", "def_ko": "기억상실", "def_vi": "Mất trí nhớ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1081, '7', '겨울철 뇌졸중 예방을 위한 안전수칙으로 옳은 것은?', '["실내 운동보다 실외 운동을 한다.", "술을 마신 다음 날 아침에 운동을 한다.", "운동시간은 낮보다 새벽 시간을 이용한다.", "따뜻한 곳에서 바로 차가운 곳으로 나간다.", "외출 시 방한복과 모자를 착용한다."]'::jsonb, 5, NULL, NULL, '{"1": "실내 운동보다 실외 운동은 기온에 따라 위험할 수 있기 때문에 옳지 않습니다.\n[정답]", "5": "외출 시 방한복과 모자를 착용하는 것은 체온 유지에 도움이 되어 뇌졸중 예방에 효과적입니다.", "2": "술을 마신 다음 날 아침에 운동은 몸에 무리가 갈 수 있어 적절하지 않습니다.", "3": "운동시간을 새벽에 하는 것은 기온이 낮아 위험할 수 있어 권장되지 않습니다.", "4": "따뜻한 곳에서 바로 차가운 곳으로 나가는 것은 체온 조절에 문제가 생길 수 있습니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌에 혈액이 공급되지 않아 발생하는 질병", "def_vi": "Bệnh xảy ra khi máu không được cung cấp cho não"}, {"term_ko": "안전수칙", "term_vi": "Quy tắc an toàn", "def_ko": "사고를 예방하기 위한 규칙", "def_vi": "Quy tắc để ngăn ngừa tai nạn"}, {"term_ko": "방한복", "term_vi": "Đồ ấm", "def_ko": "겨울철에 체온을 유지하는 옷", "def_vi": "Trang phục giữ nhiệt độ cơ thể vào mùa đông"}, {"term_ko": "모자", "term_vi": "Mũ", "def_ko": "머리를 덮는 의복", "def_vi": "Đồ che đầu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1080, '7', '노인의 겨울철 안전수칙으로 옳은 것은?', '["실내운동과 적절한 영양섭취를 한다.", "심혈관질환 댓상자는 야외활동을 늘린다.", "밖에 나갈 때는 여러 겹의 두꺼운 옷을 입는다.", "동상부위는 헤어드라이어로 열을 가해 녹인다.", "저체온증으로 의식이 없으면 따뜻한 커피를 먹인다."]'::jsonb, 1, NULL, NULL, '{"1": "노인은 실내에서 운동과 영양섭취를 통해 건강을 유지해야 한다. \n[정답]", "2": "심혈관질환 환자는 야외활동을 조심해야 하며, 무리한 활동은 피해야 한다.", "3": "여러 겹의 얇은 옷을 입는 것이 보온에 더 효과적이며, 두꺼운 옷은 동작을 제한할 수 있다.", "4": "동상 부위는 반드시 따뜻한 물에 담그거나 의료진과 상담을 해야 하며, 헤어드라이어는 사용할 수 없다.", "5": "저체온증으로 의식이 없을 경우, 음식을 섭취하는 것이 위험하며 즉시 응급처치를 받아야 한다."}'::jsonb, '[{"term_ko": "겨울철", "term_vi": "안전수칙", "def_ko": "겨울(한국어) - mùa đông(베트남어)", "def_vi": "안전 규칙(한국어) - quy tắc an toàn(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1079, '7', '대상자가 겨울철에 실내에서 차가운 바깥응로 나갈 때 가장 주의해야 할 증상은?', '["맥박 저하", "혈압 상승", "호흡수 감소", "심박동수 저하", "체온 상승"]'::jsonb, 2, NULL, NULL, '{"1": "맥박 저하는 일반적으로 추위와 관련이 적습니다.\n[정답]", "2": "혈압 상승은 차가운 환경에서 발생할 수 있는 주요 증상입니다.", "3": "호흡수 감소는 상황에 따라 다르지만 주된 증상은 아닙니다.", "4": "심박동수 저하는 일반적으로 긴장이나 스트레스 상황에서 발생합니다.", "5": "체온 상승은 차가운 환경에서는 발생하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người nhận", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1078, '7', '열탈진(일사병)이 발생한 경ㅇ우 응급조치로 옳은 것은?', '["119에 즉시 신고한다.", "따뜻한 물로 목욕을 시킨다.", "경련이 일어난 근육을 마사지한다.", "스포츠 음료나 주스 등을 마시게 한다.", "따뜻한 음료와 초콜릿을 제공한다."]'::jsonb, 4, NULL, NULL, '{"1": "119에 신고하는 것은 좋지만 즉시 상황이 위급한 경우가 아니면 우선적인 조치가 아닙니다.\n[정답]", "4": "스포츠 음료나 주스는 수분과 전해질을 보충해 주어 탈진 회복에 도움이 됩니다.", "2": "따뜻한 물로 목욕시키는 것은 오히려 더 위험할 수 있습니다.", "3": "경련이 일어난 근육을 마사지하는 것은 올바른 조치가 아닙니다.", "5": "따뜻한 음료와 초콜릿을 주는 것은 바람직하지 않습니다."}'::jsonb, '[{"term_ko": "열탈진", "term_vi": "Cơn sốc nhiệt", "def_ko": "열에 의해 발생하는 신체의 이상 상태", "def_vi": "Tình trạng bất thường của cơ thể do nhiệt độ cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1077, '7', '다음과 같은 방법으로 응급조치를 시행해야 하는 온열질환은?• 서늘한 곳에서 휴식 • 스포츠 음료나 주스 등을 마심 • 경련이 일어난 근육을 마사지', '["열발진", "열성부종", "열경련", "열사병", "열실신"]'::jsonb, 3, NULL, NULL, '{"1": "열발진: 피부에 발진이 있는 상태로, 주로 발한의 영향을 받아 발생하며 응급조치가 필요하지 않음.\n[정답]", "3": "열경련: 근육이 경련을 일으키고 탈수로 인해 발생하며, 서늘한 곳에서의 휴식과 수분 보충이 필요함.", "2": "열성부종: 부종이 발생하는 온열질환으로, 일반적으로 긴급한 처치가 필요하지 않음.", "4": "열사병: 심각한 온열질환으로, 즉각적인 응급 처치가 필요하지만 본 문제의 응급조치에는 맞지 않음.", "5": "열실신: 기절하는 상태이지만, 문제에서 제시한 조치와는 관련이 없음."}'::jsonb, '[{"term_ko": "응급조치", "term_vi": "Biện pháp khẩn cấp", "def_ko": "긴급한 상황에서 행하는 처치", "def_vi": "Các biện pháp thực hiện trong tình huống khẩn cấp"}, {"term_ko": "온열질환", "term_vi": "Bệnh lý do nhiệt", "def_ko": "열로 인한 질환", "def_vi": "Bệnh vì nhiệt độ cao"}, {"term_ko": "열경련", "term_vi": "Chuột rút nhiệt", "def_ko": "근육 경련이 발생한 상태", "def_vi": "Tình trạng cơ bị co thắt"}, {"term_ko": "탈수", "term_vi": "Mất nước", "def_ko": "체액 결핍 상태", "def_vi": "Tình trạng thiếu nước cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1076, '7', '열사병으로 대상자가 의식이 없을 때 대처 방법으로 옳은 것은?', '["시원한 음료를 마시게 한다.", "이불 등으로 몸을 감싸 땀을 흘리게 한다.", "시원한 장소로 옮긴 후 살포제를 사용한다.", "기다렸다가 의식이 회복되면 병원 진료를 받는다.", "옷을 시원한 물로 적시고 몸에 선풍기 바람을 쇠어준다."]'::jsonb, 5, NULL, NULL, '{"1": "시원한 음료를 마시게 하는 것은 의식이 있는 경우에 가능한 방법입니다. 여기서는 대상자가 의식이 없으므로 부적절합니다.\n[정답]", "5": "옷을 시원한 물로 적시고 몸에 선풍기 바람을 쏴주는 것은 열사병의 주요 응급처치 방법 중 하나로 올바른 대처입니다.", "2": "이불 등으로 몸을 감싸서 땀을 흘리게 하는 것은 열사병을 악화시킬 수 있으므로 적절하지 않습니다.", "3": "시원한 장소로 옮긴 후 살포제를 사용하는 것은 의식이 없는 상태에서 신중하게 접근해야 하며, 부적절할 수 있습니다.", "4": "기다렸다가 의식이 회복되면 병원 진료를 받는 것은 즉각적인 응급처치를 제공하지 않는 것이므로 잘못된 방법입니다."}'::jsonb, '[{"term_ko": "열사병", "term_vi": "Bệnh say nắng", "def_ko": "과도한 더위에 노출되어 발생하는 질환", "def_vi": "căn bệnh xảy ra do phơi nhiễm nhiệt độ quá cao"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "자신이 존재하는 것을 인지하는 상태", "def_vi": "trạng thái nhận thức về sự tồn tại của bản thân"}, {"term_ko": "응급처치", "term_vi": "Sơ cứu", "def_ko": "즉각적인 치료를 제공하는 과정", "def_vi": "quá trình cung cấp sự trợ giúp ngay lập tức"}, {"term_ko": "선풍기", "term_vi": "Quạt", "def_ko": "바람을 발생시키는 기구", "def_vi": "thiết bị tạo ra gió"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1075, '7', '여름철 폭염 대응 안전수칙으로 옳은 것은?', '["야외 활동을 권장한다.", "평소보다 물을 적게 마신다.", "두통이 있을 때는 가볍게 운동을 한다.", "현기증, 메스꺼움이 있을 때는 뜨거운 차를 마신다.", "외출할 때는 챙이 넓은 모자와 물을 휴대한다."]'::jsonb, 5, NULL, NULL, '{"1": "여름철 폭염에선 야외 활동을 피해야 하므로 틀린 선택이다.\n[정답]", "5": "여름철 더위에 대비해 챙이 넓은 모자와 물을 휴대하는 것이 중요하다.", "2": "여름철에는 수분 보충이 필요하므로 물을 적게 마시는 것은 바람직하지 않다.", "3": "두통이 있을 때는 운동하기 보다는 휴식이 권장된다.", "4": "현기증 및 메스꺼움을 느낄 때는 뜨거운 차를 마시는 것 대신 시원한 환경을 유지해야 한다."}'::jsonb, '[{"term_ko": "폭염", "term_vi": "Nóng", "def_ko": "무더위(한국어)", "def_vi": "Nắng nóng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1074, '7', '여름철 폭염 시 대상자가 외출 후 현기증과 매스꺼움, 두통을 호소 할 때 대처방법은?', '["낮잠을 자게 한다.", "따뜻한 물로 목욕 시킨다.", "평소보다 식사를 많이 하게 한다.", "시원한 물이나 음료를 천천히 마시게 한다.", "문을 닫고 선풍기를 틀어준다."]'::jsonb, 4, NULL, NULL, '{"1": "낮잠을 자게 한다: 낮잠은 휴식을 제공할 수 있지만, 현기증과 매스꺼움에는 즉각적인 도움이 되지 않습니다.\n[정답]", "4": "시원한 물이나 음료를 천천히 마시게 한다: 탈수와 열로 인한 증상을 완화시키고, 수분 보충에 효과적입니다.", "2": "따뜻한 물로 목욕 시킨다: 따뜻한 물은 오히려 열을 가중시켜 증상을 악화시킬 수 있습니다.", "3": "평소보다 식사를 많이 하게 한다: 식사는 필요하지만, 매스꺼움을 느낄 때는 과식이 오히려 불편함을 초래할 수 있습니다.", "5": "문을 닫고 선풍기를 틀어준다: 선풍기가 도움이 될 수 있지만, 시원한 음료 섭취가 더욱 중요합니다."}'::jsonb, '[{"term_ko": "폭염", "term_vi": "Nóng bức", "def_ko": "엄청 더움(한국어)", "def_vi": "rất nóng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1072, '7', '파상풍, 디프테리아 예방접종 주기로 옳은 것은?', '["6개월", "1년", "3년", "5년", "10년"]'::jsonb, 5, NULL, NULL, '{"1": "6개월 간격으로 접종하지 않습니다.", "2": "1년 후 접종이 필요하지 않습니다.", "3": "3년 간격으로 접종하지 않습니다.", "4": "5년 간격으로 접종하는 것이 아닙니다.\n[정답]", "5": "10년마다 예방접종을 보강해야 합니다."}'::jsonb, '[{"term_ko": "파상풍", "term_vi": "Bệnh uốn ván", "def_ko": "병의 이름(한국어)", "def_vi": "Tên bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1071, '7', '노인 대상자에게 매년 1회 접종하도록 권유해야 하는 예방접종은?', '["파상풍", "디프테리아", "폐렴구균", "인플루엔자", "유행성 이하선염"]'::jsonb, 4, NULL, NULL, '{"1": "파상풍은 정기적으로 접종해야 하지만 매년 1회 접종 대상은 아닙니다.", "2": "디프테리아도 정기적으로 접종해야 하지만 주기적으로 맞아야 합니다.\n[정답]", "3": "폐렴구균 예방접종은 노인에게 매년 접종이 권장됩니다.", "4": "인플루엔자 예방접종은 매년 1회 접종이 권장됩니다.", "5": "유행성 이하선염은 노인에게 주로 권장되는 예방접종이 아닙니다."}'::jsonb, '[{"term_ko": "예방접종", "term_vi": "대상자", "def_ko": "접종 예방", "def_vi": "người được áp dụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1070, '7', '노인에게 권장되는 예방접종에 대한 설명으로 옳은 것은?', '["결핵 - 10년마다 1회", "인플루엔자 - 3년마다 1회", "파상풍 - 5년마다 1회", "폐렴구균 - 매년 1회", "대상포진 - 60세 이상 1회"]'::jsonb, 5, NULL, NULL, '{"1": "결핵 예방접종은 일반적으로 권장되지 않으며, 10년마다 1회는 잘못된 정보입니다.\n[정답]", "5": "대상포진 예방접종은 60세 이상에게 1회 권장됩니다.", "2": "인플루엔자 예방접종은 매년 1회가 권장되며, 3년마다 1회는 잘못된 정보입니다.", "3": "파상풍 예방접종은 10년마다 1회가 권장되며, 5년마다 1회는 잘못된 정보입니다.", "4": "폐렴구균 예방접종은 고위험군에서 웬만하면 5년마다 1회가 권장됩니다."}'::jsonb, '[{"term_ko": "예방접종", "term_vi": "노인", "def_ko": "예방접종(주사) - tiêm chủng", "def_vi": "노인 - người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1069, '7', '음주를 하고 있는 대상자가 절주 습관을 갖도록 돕는 방법은?', '["공복에 술을 마시게 한다.", "매일 식사와 함게 소량의 술을 마시게 한다.", "절주에 대한 결심을 주변 사람에게 알리게 한다.", "권유받은 경우에만 술을 마시게 한다.", "암 예방을 위해 하루 2잔 이내로 마시게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "공복에 술을 마시게 하면 건강에 해롭고 절주에 도움이 되지 않습니다.", "2": "매일 식사와 함께 소량의 술을 마시는 것은 오히려 음주 습관을 악화시킬 수 있습니다.\n[정답]", "3": "절주에 대한 결심을 주변 사람에게 알리게 하면 사회적 지지가 이루어져 절주를 유지하는 데 도움을 줍니다.", "4": "권유받은 경우에만 술을 마시게 하는 것은 자율적인 절주 습관 형성에 도움이 되지 않습니다.", "5": "암 예방을 위해 하루 2잔 이내로 마시게 하는 것은 절주가 아닌 지침일 뿐입니다."}'::jsonb, '[{"term_ko": "음주", "term_vi": "Uống rượu", "def_ko": "술을 마시는 행동", "def_vi": "Hành động uống rượu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1068, '7', '절주를 돕는 방법으로 옳은 것은?', '["큰 잔에 술을 마시게 한다.", "음주일지를 작성하여 점검하게 한다.", "여러 종류의 술을 섞어 마시게 한다.", "알코올 도수가 높은 술로 마시게 한다.", "집 안의 잘 보이는 곳에 술을 전시하게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "큰 잔에 술을 마시게 한다는 것은 오히려 음주를 장려하는 방법이다.\n[정답]", "2": "음주일지를 작성하여 점검하게 하는 것은 음주 습관을 스스로 인식하게 도와 절주를 돕는 방법이다.", "3": "여러 종류의 술을 섞어 마시게 하는 것은 건강에 해롭고 음주 통제를 어렵게 만든다.", "4": "알코올 도수가 높은 술로 마시게 하는 것은 절주와는 반대되는 행동이다.", "5": "집 안의 잘 보이는 곳에 술을 전시하게 하는 것은 음주를 부추기는 환경을 조성하는 것이다."}'::jsonb, '[{"term_ko": "절주", "term_vi": "Kiểm soát uống rượu", "def_ko": "술을 줄이거나 마시지 않는 것", "def_vi": "Giảm hoặc không uống rượu"}, {"term_ko": "음주일지", "term_vi": "Nhật ký uống rượu", "def_ko": "음주 습관을 기록하는 일지", "def_vi": "Nhật ký ghi lại thói quen uống rượu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1067, '7', '흡연과 금연에 관한 설명으로 옳은 것은?', '["간접흡연 시 폐활량이 증가한다.", "금연 시기를 놓치면 금연 효과가 없다.", "일시적 금연은 폐기능을 악화시킨다.", "간접흡연은 질병을 유발할 수 있다.", "금연 시 혈중 일산화탄소 수치가 증가한다."]'::jsonb, 4, NULL, NULL, '{"1": "간접흡연은 폐활량에 긍정적인 영향을 미치지 않습니다. 오히려 감소할 수 있습니다.\n[정답]", "4": "간접흡연은 다양한 질병을 유발할 수 있습니다. 이는 여러 연구에서도 입증된 바 있습니다.", "2": "금연 시기를 놓치더라도 금연하면 효과는 발생합니다.", "3": "일시적 금연이 폐기능을 악화시키는 것은 아닙니다. 일반적으로 금연은 폐기능 개선에 긍정적입니다.", "5": "금연 시 혈중 일산화탄소 수치는 감소합니다."}'::jsonb, '[{"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 것", "def_vi": "Hút thuốc lá"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1066, '7', '금연 후 나타나는 변화로 옳은 것은?', '["기대수명이 감소한다.", "혈압이 정상으로 돌아온다.", "손상된 폐기능이 악화된다.", "성기능과 정자 수가 감소한다.", "혈중 산소량이 정상보다 감소한다."]'::jsonb, 2, NULL, NULL, '{"1": "기대수명이 감소한다. - 금연은 기대수명을 증가시킵니다.\n[정답]", "2": "혈압이 정상으로 돌아온다. - 금연 후 혈압이 정상적으로 회복됩니다.", "3": "손상된 폐기능이 악화된다. - 금연 후 폐기능이 개선됩니다.", "4": "성기능과 정자 수가 감소한다. - 금연은 성기능 및 정자 수를 증가시킵니다.", "5": "혈중 산소량이 정상보다 감소한다. - 금연 후 혈중 산소량이 증가합니다."}'::jsonb, '[{"term_ko": "금연", "term_vi": "Bỏ thuốc lá", "def_ko": "담배를 끊는 것", "def_vi": "Ngưng hút thuốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1065, '7', '금연으로 기대할 수 있는 변화로 옳은 것은?', '["후각과 미각이 무뎌진다.", "혈압이 정상보다 높아진다.", "심장병 발병 위험이 증가한다.", "폐암으로 사망할 확률이 증가한다.", "혈중 일산화탄소량이 정상으로 회복된다."]'::jsonb, 5, NULL, NULL, '{"1": "후각과 미각이 무뎌진다. 이는 금연 후 개선되는 부분이다.\n[정답]", "5": "혈중 일산화탄소량이 정상으로 회복된다. 금연 후 혈중 수치는 회복된다.", "2": "혈압이 정상보다 높아진다. 금연은 혈압을 정상으로 낮춘다.", "3": "심장병 발병 위험이 증가한다. 금연은 심장병 위험을 감소시킨다.", "4": "폐암으로 사망할 확률이 증가한다. 금연은 폐암 위험을 줄인다."}'::jsonb, '[{"term_ko": "금연", "term_vi": "Bỏ thuốc lá", "def_ko": "담배를 끊는 것", "def_vi": "Ngừng hút thuốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1064, '7', '노인의 흡연에 대한 설명으로 옳은 것은?', '["흡연은 체중감소 효과가 있다.", "흡연은 우울증, 불면증을 개선한다.", "흡연은 혈액순환에 도움이 된다.", "하루 1~2개비가 적정 흡연량이다.", "오랫동안 흡연하였어도 금연하면 건강을 증진할 수 있다."]'::jsonb, 5, NULL, NULL, '{"1": "흡연은 체중감소 효과가 있지만, 이는 건강에 해로운 영향을 미친다.", "2": "흡연은 우울증과 불면증을 악화시킬 수 있다.", "3": "흡연은 혈액순환에 부정적인 영향을 미친다.", "4": "하루 1~2개비는 여전히 건강에 나쁜 영향을 미칠 수 있다.\n[정답]", "5": "오랫동안 흡연하였어도 금연하면 건강을 개선할 수 있는 여러 연구 결과가 있다."}'::jsonb, '[{"term_ko": "흡연", "term_vi": "Hút thuốc", "def_ko": "담배를 피우는 것", "def_vi": "Hút thuốc lá"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1063, '7', '다음 중 약물복용 방법으로 옳은 것은?', '["철분제는 우유와 함께 복용한다.", "고혈압 약은 자몽주스와 함께 복용한다.", "인슐린은 식사 전 입으로 복용한다.", "기관지확장제는 머리를 숙인 채 흡입한다.", "분할선이 있는 약은 쪼개어 복용할 수 있다."]'::jsonb, 5, NULL, NULL, '{"1": "철분제는 우유와 함께 복용 시 흡수에 방해가 됩니다.\n[정답]", "5": "분할선이 있는 약은 쪼개어 복용할 수 있어, 복용량 조절에 도움이 됩니다.", "2": "고혈압 약과 자몽주스는 상호작용이 있어 함께 복용하면 안 됩니다.", "3": "인슐린은 주사제로 사용되며, 식사 전 입으로 복용하지 않습니다.", "4": "기관지확장제는 일반적으로 제대로된 자세로 흡입해야 합니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1062, '7', '노인이 복용한 후 낙상 사고의 부작용이 발생할 수 있는 약물로 옳은 것은?', '["소염진통제", "스테로이드제", "당뇨병 약제", "항응고제", "수면제 등 신경정신계 약물"]'::jsonb, 5, NULL, NULL, '{"1": "소염진통제는 주로 통증 완화를 위해 사용되며 낙상과 직접적인 관련이 없습니다.\n[정답]", "5": "수면제 등 신경정신계 약물은 졸림과 집중력 저하를 유발하여 낙상 사고의 위험을 증가시킵니다.", "2": "스테로이드제는 면역 반응을 억제하지만 낙상과 직접적인 연관성은 낮습니다.", "3": "당뇨병 약제는 혈당 조절을 위해 사용되며 일반적으로 낙상과는 무관합니다.", "4": "항응고제는 출혈 위험을 증가시킬 수 있지만, 낙상 사고를 직접 유발하지는 않습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "나이 많은 사람", "def_vi": "Người lớn tuổi"}, {"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어져서 떨어지는 것", "def_vi": "Ngã xuống"}, {"term_ko": "소염진통제", "term_vi": "Thuốc giảm đau chống viêm", "def_ko": "통증을 줄이는 약물", "def_vi": "Thuốc giảm đau"}, {"term_ko": "스테로이드제", "term_vi": "Thuốc steroid", "def_ko": "면역 반응을 억제하는 약물", "def_vi": "Thuốc ức chế miễn dịch"}, {"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "혈당 조절 장애", "def_vi": "Rối loạn kiểm soát đường huyết"}, {"term_ko": "항응고제", "term_vi": "Thuốc chống đông máu", "def_ko": "출혈 예방 약물", "def_vi": "Thuốc ngăn ngừa chảy máu"}, {"term_ko": "수면제", "term_vi": "Thuốc an thần", "def_ko": "잠을 유도하는 약물", "def_vi": "Thuốc gây buồn ngủ"}, {"term_ko": "신경정신계", "term_vi": "Hệ thần kinh tâm thần", "def_ko": "정신 건강과 관련된 약물", "def_vi": "Liên quan đến sức khỏe tâm thần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1061, '7', '약물과 약물의 흡수를 돕는 식품이 바르게 연결된 것은?', '["칼슘제 - 우유", "와파린 - 시금치", "고혈압약 - 인삼, 홍삼", "철분제 - 오렌지주스", "항생제 - 프로바이오틱스"]'::jsonb, 4, NULL, NULL, '{"1": "칼슘제를 우유와 함께 복용할 경우 흡수에 방해가 될 수 있습니다.\n[정답]", "4": "철분제는 오렌지주스와 함께 복용해야 흡수력이 높아집니다.", "2": "와파린과 시금치는 비타민 K의 영향을 줄 수 있습니다.", "3": "고혈압약과 인삼, 홍삼은 상호작용에 주의해야 합니다.", "5": "항생제와 프로바이오틱스는 보통 함께 복용할 경우 효과가 줄어들 수 있습니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "thuốc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1060, '7', '재가 방문 시 편의점에서 구입 가능한 비상약으로 옳은 것은?', '["수면제", "항생제", "해열진통제", "혈압약", "기관지확장제"]'::jsonb, 3, NULL, NULL, '{"1": "수면제는 일반 약국에서 구입이 가능하지만, 편의점에서는 구입할 수 없다.", "2": "항생제는 의사의 처방이 필요한 약물이다.\n[정답]", "3": "해열진통제는 일반적으로 편의점에서도 쉽게 구입할 수 있는 비상약이다.", "4": "혈압약은 처방이 필요하며 일반 약국에서만 구입할 수 있다.", "5": "기관지확장제도 처방약으로 분류되어 일반적인 접촉에서 구입할 수 없다."}'::jsonb, '[{"term_ko": "재가", "term_vi": "Tại gia", "def_ko": "가정에서의 의미", "def_vi": "Nghĩa là ở nhà"}, {"term_ko": "편의점", "term_vi": "Cửa hàng tiện lợi", "def_ko": "쉽게 접근할 수 있는 상점", "def_vi": "Cửa hàng dễ dàng tiếp cận"}, {"term_ko": "비상약", "term_vi": "Thuốc khẩn cấp", "def_ko": "긴급하게 필요한 약", "def_vi": "Thuốc cần thiết trong trường hợp khẩn cấp"}, {"term_ko": "해열진통제", "term_vi": "Thuốc hạ sốt và giảm đau", "def_ko": "열을 낮추고 통증을 완화하는 약물", "def_vi": "Thuốc giảm nhiệt độ và giảm đau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1059, '7', '올바른 약물복용을 위한 관리방법으로 옳은 것은?', '["전날에 복용하지 않은 경우 2회 분량을 한꺼번에 복용한다.", "효과가 없을 때에는 정해진 양보다 많이 먹는다.", "증상이 좋아지면 처방약 복용을 중단한다.", "약물과 건강기능식품을 함께 복용 시 의사와 상의 없이 먹어도 된다.", "다른 병원이나 약국을 방문할 경우 이전 처방전을 보여준다."]'::jsonb, 5, NULL, NULL, '{"1": "전날에 복용하지 않은 경우 2회 분량을 한꺼번에 복용하는 것은 잘못된 방법입니다. 약물은 정해진 복용량에 따라 복용해야 합니다.\n[정답]", "5": "다른 병원이나 약국을 방문할 경우 이전 처방전을 보여주는 것이 올바른 관리 방법입니다. 이는 안전한 약물 복용을 위해 필요합니다.", "2": "효과가 없을 때 정해진 양보다 많이 먹는 것은 오히려 위험할 수 있습니다.", "3": "증상이 좋아지면 처방약 복용을 중단해서는 안 되며, 의사의 지시를 따라야 합니다.", "4": "약물과 건강기능식품을 함께 복용할 때는 반드시 의사와 상의해야 합니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1058, '7', '노인들의 약물관리 방법으로 옳은 것은?', '["술을 마신 후에도 반드시 약을 복용한다.", "위장 장애가 있을 때에느 약 용량을 줄인다.", "약을 중단하기 전 의사와 먼저 상담한다.", "약을 증상에 맞게 본인이 혼합해서 먹어도 된다.", "새로운 약을 처방받은 경우 이전 약을 먼저 먹는다."]'::jsonb, 3, NULL, NULL, '{"1": "술을 마신 후에 약을 복용하면 상호작용이 발생할 수 있어 위험합니다.\n[정답]", "3": "약을 중단하기 전에는 반드시 의사와 상담해야 안전합니다.", "2": "위장 장애가 있을 때는 즉시 의사와 상담해야 하며, 용량을 조정할 수 있습니다.", "4": "약은 반드시 의사의 처방에 따라서 복용해야 하며, 혼합해서 복용하는 것은 위험합니다.", "5": "새로운 약을 처방받은 경우, 기존 약과의 상호작용을 피하기 위해 반드시 먼저 의사와 상담해야 합니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1057, '7', '대상자가 두통이 있을 때마다 약을 복용하려 할 때 대처방법은?', '["삼키기 힘든 장용 코팅제는 쪼개서 복용하게 한다.", "한번에 많은 양을 사두고 필요 시 복용하게 한다.", "증상에 따라 약 용량을 조절하여 복용하게 한다.", "비처방 약이라도 의사와 사담 후 복용하게 한다.", "증상이 비슷한 다른 대상자의 약을 복용하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "삼키기 힘든 장용 코팅제는 쪼개서 복용하게 한다. 잘못된 방법입니다. 장용 코팅제는 쪼개면 효과가 감소할 수 있습니다.\n[정답]", "2": "한 번에 많은 양을 사두고 필요 시 복용하게 한다. 이는 안전하지 않으며, 과다 복용의 위험이 있습니다.", "3": "증상에 따라 약 용량을 조절하여 복용하게 한다. 이는 의사가 지시한 경우에만 가능합니다.", "4": "비처방 약이라도 의사와 사담 후 복용하게 한다. 의사와 상담 후에 약을 복용하는 것은 안전한 방법입니다.", "5": "증상이 비슷한 다른 대상자의 약을 복용하게 한다. 이는 매우 위험하며, 안전하지 않습니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người tham gia", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1056, '7', '노인에게 약물중독이 많이 발생하는 주된 이유는?', '["약물의 흡수능력 증가", "심장의 수축력 증가", "간의 대사능력 증가", "위장의 위산분비 증가", "신장의 혈류량 감소"]'::jsonb, 5, NULL, NULL, '{"1": "약물의 흡수능력이 증가하면 약물이 더 쉽게 체내에 흡수될 수 있지만, 이것이 주된 원인은 아닙니다.", "2": "심장의 수축력이 증가하는 것은 일반적으로 약물중독의 원인과 관련이 없습니다.", "3": "간의 대사능력이 증가하면 약물이 더 빨리 대사되어야 하지만, 노인의 경우 대사능력이 감소하는 경향이 있습니다.", "4": "위장의 위산분비가 증가하는 것은 약물 흡수에 영향을 미칠 수 있지만, 주된 원인은 아닙니다.\n[정답]", "5": "신장의 혈류량 감소는 노인에서 흔히 발생하며, 신장의 기능 저하로 이어져 약물 배설이 원활하지 않아 약물중독의 위험을 증가시킵니다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "Thuốc", "def_ko": "약(한국어)", "def_vi": "Thuốc"}, {"term_ko": "중독", "term_vi": "Ngộ độc", "def_ko": "해로운 물질이 몸에 들어가 고통을 주는 상태(한국어)", "def_vi": "Tình trạng có chất độc xâm nhập vào cơ thể gây đau đớn"}, {"term_ko": "흡수능력", "term_vi": "Khả năng hấp thụ", "def_ko": "어떤 것이 흡수할 수 있는 능력(한국어)", "def_vi": "Khả năng mà một cái gì đó có thể được hấp thụ"}, {"term_ko": "신장", "term_vi": "Thận", "def_ko": "피가 여과되는 장기(한국어)", "def_vi": "Cơ quan lọc máu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1055, '7', '노인에게 약물중독이 많이 발생하는 주된 이유는?', '["약물의 흡수능력 증가", "심장의 수축력 증가", "간의 대사능력 증가", "위장의 위산분비 증가", "신장의 혈류량 감소"]'::jsonb, 5, NULL, NULL, '{"1": "약물의 흡수능력 증가: 노인에서는 약물 흡수가 평소보다 감소하는 경향이 있다.", "2": "심장의 수축력 증가: 노인에서는 심장 수축력이 감소하여 혈액순환이 불량해진다.", "3": "간의 대사능력 증가: 노인의 간 대사능력은 보통 감소하며, 이는 약물의 작용 지속시간을 늘릴 수 있다.\n[정답]", "5": "신장의 혈류량 감소: 노인의 경우 신장 기능이 저하되어 약물의 배설이 원활하지 못하고, 이로 인해 약물중독이 발생할 수 있다.", "4": "위장의 위산분비 증가: 노인은 위산 분비가 줄어드는 경향이 있다."}'::jsonb, '[{"term_ko": "약물", "term_vi": "중독", "def_ko": "약(한국어)/thuốc(베트남어)", "def_vi": "타락(한국어)/ngộ độc(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1054, '7', '뇌졸증 대상자가 성생활에 대해 고민할 때 요양보호사의 대처방법은?', '["\"성생활은 건강에 도움이 안 돼요.\"", "\"성생활로 뇌졸증이 악화되지 않아요.\"", "\"윤활제를 사용하면 성기능이 감소돼요.\"", "\"항고혈압제를 드시면 성기능이 좋아져요.\"", "\"체위변화를 위한 기구는 전혀 도움이 되지 않아요.\""]'::jsonb, 2, NULL, NULL, '{"1": "\"성생활은 건강에 도움이 안 돼요.\" - 성생활은 건강에 여러모로 긍정적인 영향을 줄 수 있습니다. 잘못된 정보입니다.\n[정답]", "2": "\"성생활로 뇌졸증이 악화되지 않아요.\" - 이 문장은 뇌졸증 환자가 성생활을 해도 건강에 나쁜 영향을 주지 않는다는 올바른 정보입니다.", "3": "\"윤활제를 사용하면 성기능이 감소돼요.\" - 윤활제는 오히려 도움이 되는 경우가 많습니다. 잘못된 정보입니다.", "4": "\"항고혈압제를 드시면 성기능이 좋아져요.\" - 항고혈압제가 모두 성기능에 긍정적인 영향을 주는 것은 아닙니다. 일반적인 진술이 아닙니다.", "5": "\"체위변화를 위한 기구는 전혀 도움이 되지 않아요.\" - 체위변화를 돕는 기구는 성생활에 도움이 될 수 있습니다. 잘못된 정보입니다."}'::jsonb, '[{"term_ko": "뇌졸증", "term_vi": "Đột quỵ", "def_ko": "뇌혈관이 막혀서 생기는 질병", "def_vi": "Bệnh do tắc nghẽn mạch máu não"}, {"term_ko": "성생활", "term_vi": "Đời sống tình dục", "def_ko": "성적 활동", "def_vi": "Hoạt động tình dục"}, {"term_ko": "윤활제", "term_vi": "Chất bôi trơn", "def_ko": "성적 활동을 돕기 위해 사용하는 용액", "def_vi": "Chất lỏng sử dụng để hỗ trợ hoạt động tình dục"}, {"term_ko": "항고혈압제", "term_vi": "Thuốc hạ huyết áp", "def_ko": "고혈압을 치료하는 약물", "def_vi": "Thuốc điều trị cao huyết áp"}, {"term_ko": "체위변화", "term_vi": "Thay đổi tư thế", "def_ko": "성적 활동 시 자세를 바꾸는 것", "def_vi": "Việc thay đổi tư thế trong hoạt động tình dục"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1053, '7', '노인의 성기능을 감소시키는 요인과 관계가 없는 대상자는?', '["이뇨제를 복용하는 대상자", "고혈압 약을 복용중인 대상자", "관절염을 치료중인 대상자", "전립선 절제술을 받은 대상자", "당뇨병이 있는 대상자"]'::jsonb, 4, NULL, NULL, '{"1": "이뇨제는 성기능에 영향을 미칠 수 있는 약물이다.\n[정답]", "4": "전립선 절제술은 성기능에 영향을 줄 수 있지만, 이 질문에서는 관계가 없는 것으로 간주된다.", "2": "고혈압 약물은 성기능에 부정적인 영향을 줄 수 있다.", "3": "관절염 치료를 위한 약물도 성기능에 영향을 미칠 수 있다.", "5": "당뇨병은 성기능 감소와 관련이 있다."}'::jsonb, '[{"term_ko": "성기능", "term_vi": "Chức năng tình dục", "def_ko": "성에 관련된 신체적 능력", "def_vi": "Khả năng liên quan đến cơ thể về tình dục"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1052, '7', '노인의 성적 변화에 대한 설명으로 옳은 것은?', '["항염즈성 약물을 복용하면 성적 욕구가 증가한다.", "과도한 알코올 섭취는 오르가슴을 빨리 느끼게 한다.", "유방절제술을 한 노인은 성기능이 감소한다.", "질 분비물이 증가하여 성교 시 통증이 없다.", "자궁척출술은 성기능에 영향을 주지 않는다."]'::jsonb, 5, NULL, NULL, '{"1": "항염증성 약물이 성적 욕구에 미치는 영향은 개별 차이가 크며 일반적으로 증가시키지 않습니다.", "2": "과도한 알코올 섭취는 성적 반응을 저하시킬 수 있습니다.\n[정답]", "3": "유방절제술을 한 노인은 성기능이 감소할 수 있습니다. 이는 심리적 요인과 생리적 요인 모두가 관련될 수 있습니다.", "4": "질 분비물의 양은 개인차가 있으며, 증가한다고 하더라도 성교 시 통증 없이 진행되기 어려울 수 있습니다.", "5": "자궁적출술을 한 경우에도 성기능이 영향을 받을 수 있습니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "고령자(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "성적 변화", "term_vi": "Sự thay đổi tình dục", "def_ko": "성적 상황이나 반응의 변화(한국어)", "def_vi": "Sự thay đổi về tình trạng tình dục hoặc phản ứng"}, {"term_ko": "성적 욕구", "term_vi": "Ham muốn tình dục", "def_ko": "성적 충동이나 욕망(한국어)", "def_vi": "Sự thèm muốn tình dục"}, {"term_ko": "유방절제술", "term_vi": "Phẫu thuật cắt bỏ vú", "def_ko": "유방을 제거하는 수술(한국어)", "def_vi": "Phẫu thuật loại bỏ ngực"}, {"term_ko": "자궁적출술", "term_vi": "Phẫu thuật cắt bỏ tử cung", "def_ko": "자궁을 제거하는 수술(한국어)", "def_vi": "Phẫu thuật loại bỏ tử cung"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1051, '7', '대상자의 질환이 성생활에 미치는 영향으로 올바르게 연결된 것은?', '["뇌졸증 - 성기능 감소", "당뇨병 - 발기부전", "심근경색- 성 욕구 감소", "알코올 중독 - 성기능 증가", "전립선 절제술 - 성 욕구 감소"]'::jsonb, 2, NULL, NULL, '{"1": "뇌졸증은 신경계에 영향을 주어 성기능을 감소시킬 수 있으나, 연결이 정확하지 않음.\n[정답]", "2": "당뇨병은 혈액순환 및 신경 손상으로 발기부전을 유발할 수 있어 올바른 연결이다.", "3": "심근경색은 심장 건강의 문제로 성욕에 영향을 줄 수 있으나 항상 감소한다고 할 수 없음.", "4": "알코올 중독은 성기능을 감소시킬 가능성이 높으며, 기능 증가와는 연결되지 않음.", "5": "전립선 절제술은 성욕 감소를 유발하는 경우가 일반적이지만, 전립선의 상태나 개인에 따라서 다를 수 있다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "질환", "def_ko": "환자, đối tượng", "def_vi": "병, bệnh lý"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1050, '7', '무더운 여름밤에 잠을 못 이루고 뒤척이는 치매 대상자를 돕는 방법은?', '["시원한 홍차를 제공한다.", "시원하고 얇은 이불을 덮어 준다.", "포만감을 느끼도록 간식을 제공한다.", "낮잠으로 수면을 보충하도록 돕는다.", "숙면을 위해 수면제를 복용하게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "시원한 홍차는 카페인이 포함되어 있어 수면에 도움을 주지 않는다.\n[정답]", "2": "시원하고 얇은 이불을 덮어 주면 열을 식히고 편안함을 제공하여 숙면을 돕는다.", "3": "포만감을 주는 간식은 오히려 불편함으로 이어질 수 있다.", "4": "낮잠을 잘 경우, 밤에 잠을 이루기 더욱 어려워질 수 있으므로 적절하지 않다.", "5": "수면제는 부작용이 있을 수 있어 치매 환자에게 사용하기 위험하다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh Alzheimer", "def_ko": "기억력과 사고 능력이 저하되는 질환", "def_vi": "Bệnh giảm sút trí nhớ và khả năng tư duy"}, {"term_ko": "숙면", "term_vi": "Giấc ngủ ngon", "def_ko": "깊고 편안한 잠", "def_vi": "Giấc ngủ sâu và thoải mái"}, {"term_ko": "이불", "term_vi": "Chăn", "def_ko": "침대 위에 덮는 천", "def_vi": "Vải phủ lên giường"}, {"term_ko": "포만감", "term_vi": "Cảm giác no", "def_ko": "배부른 느낌", "def_vi": "Cảm giác no bụng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1049, '7', '공복감으로 잠을 이루지 못하는 수면장애 대상자를 돕는 방법은?', '["따뜻한 홍차나 녹차를 제공한다.", "실내온도를 서늘하게 유지한다.", "수면제를 복용하게 한다.", "저녁 식사를 많이 권한다.", "따뜻한 우유를 제공한다."]'::jsonb, 5, NULL, NULL, '{"1": "따뜻한 홍차나 녹차는 카페인이 있어 수면에 방해가 될 수 있다.\n[정답]", "5": "따뜻한 우유는 수면 유도에 도움이 될 수 있는 효과가 있다.", "3": "수면제를 복용하게 하는 것은 만성적으로 의존성을 초래할 수 있다.", "2": "실내온도를 서늘하게 유지하는 것은 수면에 도움이 되나, 식사와 관련이 없다.", "4": "저녁 식사를 많이 권하는 것은 오히려 수면에 부정적인 영향을 미칠 수 있다."}'::jsonb, '[{"term_ko": "공복감", "term_vi": "Cảm giác đói", "def_ko": "허기가 느껴지는 상태", "def_vi": "trạng thái cảm thấy đói"}, {"term_ko": "수면장애", "term_vi": "Rối loạn giấc ngủ", "def_ko": "수면에 문제가 있는 상태", "def_vi": "trạng thái có vấn đề về giấc ngủ"}, {"term_ko": "제공하다", "term_vi": "Cung cấp", "def_ko": "어떤 것을 주거나 제공하는 것", "def_vi": "hành động đưa hoặc cung cấp một cái gì đó"}, {"term_ko": "저녁 식사", "term_vi": "Bữa tối", "def_ko": "저녁에 먹는 식사", "def_vi": "bữa ăn vào buổi tối"}, {"term_ko": "의존성", "term_vi": "Sự phụ thuộc", "def_ko": "사용이 반복되며 그에 따라 영향을 받는 상태", "def_vi": "trạng thái bị ảnh hưởng bởi việc sử dụng lặp đi lặp lại"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1048, '7', '공복감으로 잠을 이루지 못하는 수면장애 대상자를 돕는 방법은?', '["따뜻한 홍차나 녹차를 제공한다.", "실내온도를 서늘하게 유지한다.", "수면제를 복용하게 한다.", "저녁 식사를 많이 권한다.", "따뜻한 우유를 제공한다."]'::jsonb, 5, NULL, NULL, '{"1": "따뜻한 홍차나 녹차는 카페인을 포함할 수 있어 수면을 방해할 수 있습니다.\n[정답]", "5": "따뜻한 우유는 트립토판과 칼슘을 포함해 수면을 촉진시킬 수 있습니다.", "2": "실내온도를 서늘하게 유지하는 것도 도움이 될 수 있지만, 공복감 해결에는 직접적인 원인이 아닙니다.", "3": "수면제를 복용하게 하는 것은 의존성을 유발할 수 있어 장기적인 해결책이 아닙니다.", "4": "저녁 식사를 많이 권하는 것은 오히려 불편함을 초래하여 수면을 방해할 수 있습니다."}'::jsonb, '[{"term_ko": "공복감", "term_vi": "Cảm giác đói", "def_ko": "배가 고픈 느낌", "def_vi": "Cảm giác bụng đói"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1047, '7', '밤에 잠을 쉽게 이루지 못하는 대상자의 잘못된 생활 습관은?', '["낮잠을 자지 않는다.", "낮 시간에 산책이나 운동을 한다.", "저녁 운동 후 시원한 녹차를 마신다.", "침실의 온도를 적절하게 유지한다.", "매일 일정한 시간에 일어나고 일정한 시간에 잠을 잔다."]'::jsonb, 3, NULL, NULL, '{"1": "낮잠을 자지 않는 것은 밤에 잠을 이루는 데 도움이 됩니다.", "2": "낮 시간에 산책이나 운동을 하는 것은 자연스러운 피로를 유도하여 수면에 좋습니다.\n[정답]", "3": "저녁 운동 후 시원한 녹차를 마시는 것은 카페인의 영향을 줄 수 있어 수면에 방해가 될 수 있습니다.", "4": "침실의 온도를 적절하게 유지하는 것은 수면의 질을 높이는 데 중요합니다.", "5": "매일 일정한 시간에 일어나고 잠자리에 드는 것은 생체 리듬을 유지하는 데 도움이 됩니다."}'::jsonb, '[{"term_ko": "잠", "term_vi": "Giấc ngủ", "def_ko": "잠(한국어)", "def_vi": "ngủ"}, {"term_ko": "생활습관", "term_vi": "Thói quen sinh hoạt", "def_ko": "생활습관(한국어)", "def_vi": "thói quen sinh hoạt"}, {"term_ko": "온도", "term_vi": "Nhiệt độ", "def_ko": "온도(한국어)", "def_vi": "nhiệt độ"}, {"term_ko": "운동", "term_vi": "Tập thể dục", "def_ko": "운동(한국어)", "def_vi": "tập thể dục"}, {"term_ko": "녹차", "term_vi": "Trà xanh", "def_ko": "녹차(한국어)", "def_vi": "trà xanh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1046, '7', '잠들기 어려운 대상자의 수면을 돕는 방법으로 옳은 것은?', '["잠자기 전에 술을 마신다.", "매일 아침 일정한 시간에 일어난다.", "잠들기 전까지 텔레비전을 본다.", "취침 전 집중할 수 있는 일을 한다.", "공복감으로 잠이 안 오는 경우 따뜻한 녹차를 마신다."]'::jsonb, 2, NULL, NULL, '{"1": "술은 수면 유도에 도움이 될 수 있으나, 수면의 질을 저하시킬 수 있습니다.\n[정답]", "2": "일정한 시간에 일어나는 것은 생체리듬을 조절하는 데 유리합니다.", "3": "취침 전 텔레비전 시청은 수면을 방해할 수 있는 요소입니다.", "4": "취침 전 집중할 수 있는 일은 오히려 정신을 더 활발하게 해 수면을 방해합니다.", "5": "따뜻한 녹차는 이완에 도움이 되지만 카페인이 포함되어 있어 자극이 될 수 있습니다."}'::jsonb, '[{"term_ko": "수면", "term_vi": "Giấc ngủ", "def_ko": "잠(한국어)", "def_vi": "Ngủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1045, '7', '노화로 인한 수면 양상상의 변화로 옳은 것은?', '["수면시간이 늘어난다.", "쉽게 잠이 든다.", "수면 중에 자주 깬다.", "수면의 질이 향상된다.", "낮잠을 거의 자지 않는다."]'::jsonb, 3, NULL, NULL, '{"1": "노화가 진행됨에 따라 수면 시간은 보통 줄어드는 경향이 있습니다.", "2": "노인은 쉽게 잠이 드는 경향이 있지만, 이 역시 개인차가 클 수 있습니다.\n[정답]", "3": "노화로 인해 수면 중 자주 깰 확률이 높아지는 것이 일반적입니다.", "4": "노화에 따른 수면의 질은 보통 저하되는 경우가 많습니다.", "5": "낮잠을 자는 빈도는 개인마다 다르지만, 노인은 종종 낮잠을 자기도 합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많은 상태", "def_vi": "Tình trạng có tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1044, '7', '노인 대상자의 운동관리 방법으로 옳은 것은?', '["개인의 신체 능력에 맞는 운동을 한다.", "강도가 높은 운동으로 폐활량을 늘린다.", "준비 운동은 2~3분 이내로 짧게 한다.", "빠른 동작의 운동으로 관절이 굳는 것을 예방한다.", "운동효과를 높이기 위해 운동 중간에 휴식은 생략한다."]'::jsonb, 1, NULL, NULL, '{"1": "개인의 신체 능력에 맞는 운동을 한다. [정답] 이는 안전하고 효과적인 운동 관리 방법입니다.", "2": "강도가 높은 운동으로 폐활량을 늘린다. 이는 노인의 신체 상태에 무리가 될 수 있습니다.", "3": "준비 운동은 2~3분 이내로 짧게 한다. 준비 운동은 충분한 시간이 필요합니다.", "4": "빠른 동작의 운동으로 관절이 굳는 것을 예방한다. 이는 오히려 부상을 초래할 수 있습니다.", "5": "운동효과를 높이기 위해 운동 중간에 휴식은 생략한다. 이는 오히려 건강에 해롭습니다."}'::jsonb, '[{"term_ko": "운동관리", "term_vi": "노인", "def_ko": "관리 luyện tập", "def_vi": "người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1043, '7', '만성질환을 예방하기 위한 노인의 운동방법으로 옳은 것은?', '["최대 심박동수의 80% 수준으로 운동을 시작한다.", "이른 아침이나 밤시간 대에 운동을 한다.", "고강도로 시작하여 저강도 운동으로 마무리 한다.", "현재 복용 중인 약물을 확인한 후 운동하게 한다.", "운동을 모두 마친 후에 휴식시간을 갖는다."]'::jsonb, 4, NULL, NULL, '{"1": "최대 심박동수의 80% 수준으로 운동을 시작하는 것은 너무 강한 운동일 수 있어 노인에게 적절하지 않습니다.\n[정답]", "4": "현재 복용 중인 약물을 확인한 후 운동하도록 하는 것은 안전한 운동을 위해 필수적입니다.", "2": "이른 아침이나 밤시간 대에 운동하는 것은 개인의 상황에 따라 다를 수 있으나, 좋은 운동 시간은 아닐 수 있습니다.", "3": "고강도로 시작하여 저강도 운동으로 마무리하는 것은 잘못된 접근으로, 노인의 운동 강도는 천천히 조절해야 합니다.", "5": "운동 후에 휴식 시간을 가지는 것은 중요하지만, 운동 방법으로 보기에서는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "만성질환", "term_vi": "Bệnh mãn tính", "def_ko": "만성질환(한국어)", "def_vi": "Bệnh lâu dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1042, '7', '노인 대상자의 운동관리 방법으로 옳은 것은?', '["빠르게 방향을 바꾸는 운동으로 민첩성을 키운다.", "저강도 운동으로 시작하여 서서히 증가시킨다.", "땀복을 입어 운동효과를 높인다.", "마무리 운동은 생략한다.", "휴식ㅇ은 운동을 마친 후 갖는다."]'::jsonb, 2, NULL, NULL, '{"1": "빠르게 방향을 바꾸는 운동은 노인에게 부상의 위험이 높으므로 적합하지 않습니다.\n[정답]", "2": "저강도 운동으로 시작하여 서서히 증가시키는 방법이 가장 안전하고 효과적인 운동 관리 방법입니다.", "3": "땀복을 입는 것은 운동 효과를 높이지 않으며, 오히려 체온 조절에 문제를 일으킬 수 있습니다.", "4": "마무리 운동은 부상의 예방을 위해 반드시 필요합니다.", "5": "휴식은 운동 중에도 필요하며, 운동 후 적절한 휴식을 취하는 것이 중요합니다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1041, '7', '노인이 운동을 할 때 힘이 드는 이유는?', '["심장근육의 수축력 증가", "균형 및 조정 능력 증가", "폐활량의 감소", "심근의 두께 감소", "근육피로도 감소"]'::jsonb, 3, NULL, NULL, '{"1": "심장근육의 수축력이 증가하면 운동 시 더 많은 힘을 낼 수 있어야 한다. 그러나 노인의 경우 오히려 체력 저하가 나타날 수 있다.\n[정답]", "3": "폐활량의 감소는 노인이 운동할 때 힘이 드는 주된 원인 중 하나로, 노화에 따른 폐기능이 저하되기 때문이다.", "2": "균형 및 조정 능력의 증가가 아니라 감소가 나타나기 때문에 운동 시 힘이 더욱 들어지게 된다.", "4": "심근의 두께는 나이에 따라 감소할 수 있지만, 운동력이 줄어드는 주된 요인은 아니다.", "5": "근육 피로도는 노인에게서 증가하는 경향이 있으며, 운동이 더욱 힘들게 느껴지게 하는 요인이다."}'::jsonb, '[{"term_ko": "운동", "term_vi": "Vận động", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "폐활량", "term_vi": "Dung tích phổi", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "심장근육", "term_vi": "Cơ tim", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "근육", "term_vi": "Cơ bắp", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}, {"term_ko": "체력", "term_vi": "Thể lực", "def_ko": "뜻(한국어)", "def_vi": "Nghĩa(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1040, '7', '노인이 운동을 할 때 힘이 드는 이유는?', '["관절의 운동 범위 증가", "낙상에 대한 두려움 증가", "폐조직의 탄력성 증가", "골밀도 증가", "자극에 대한 반응 증가"]'::jsonb, 2, NULL, NULL, '{"1": "관절의 운동 범위가 증가했을 때 오히려 운동이 수월해질 수 있다.\n[정답]", "2": "낙상에 대한 두려움이 증가하면 운동을 할 때 힘이 들게 된다.", "3": "폐조직의 탄력성이 증가하는 것은 오히려 도움이 될 수 있다.", "4": "골밀도가 증가하면 힘이 들지 않을 수 있다.", "5": "자극에 대한 반응이 증가하는 것은 운동이 쉬워질 수 있는 요인이다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người già", "def_ko": "나이가 많은 사람", "def_vi": "Người lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1039, '7', '한국인을 위한 식생활 지침으로 옳은 것은?', '["수분섭취를 제한한다.", "간헐적으로 단식을 한다.", "많은 양의 음식을 한꺼번에 준비한다.", "신선한 채소와 과일을 매일 섭취한다.", "단순당이 많은 음식을 선택하여 섭취한다."]'::jsonb, 4, NULL, NULL, '{"1": "수분섭취를 제한하는 것은 건강에 좋지 않다.\n[정답]", "4": "신선한 채소와 과일을 매일 섭취하는 것은 균형 잡힌 영양을 위한 중요한 요소이다.", "2": "간헐적으로 단식을 하는 것은 개인의 삶의 방식에 따라 다르지만 일반적으로 권장되지 않는다.", "3": "많은 양의 음식을 한꺼번에 준비하는 것은 비효율적이며 균형 잡힌 식사를 방해할 수 있다.", "5": "단순당이 많은 음식을 선택하여 섭취하는 것은 건강에 해롭다."}'::jsonb, '[{"term_ko": "식생활", "term_vi": "지침", "def_ko": "식사의 방식, eating habits", "def_vi": "지시사항, guideline"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1038, '7', '노인에게 영양 문제가 발생하는 요인으로 옳은 것은?', '["나트륨은 기준 이하 부족하게 섭취한다.", "전체 섭취량 중 탄수화물의 비중이 높다.", "비타민 A, C, D를 필요량보다 많이 섭취한다.", "75세 이상 고령자 중 에너지 과다 섭취가 많다.", "소득 수준이 낮은 경우 영양소를 과다 섭취한다."]'::jsonb, 2, NULL, NULL, '{"1": "나트륨의 부족한 섭취는 영양 문제의 한 가지 요인이지만, 나트륨의 과다 섭취가 더 많이 문제될 수 있다.\n[정답]", "2": "노인의 경우 탄수화물의 비중이 높아 영양 불균형이 발생할 수 있다.", "3": "비타민 A, C, D를 과다 섭취하는 것은 잘못된 내용으로 영양 문제와는 무관하다.", "4": "75세 이상 고령자의 경우 에너지 과다 섭취는 일반적이지 않다.", "5": "소득 수준이 낮으면 영양소의 섭취가 부족해지는 경우가 많아서 과다 섭취는 잘못된 정보이다."}'::jsonb, '[{"term_ko": "영양", "term_vi": "Dinh dưỡng", "def_ko": "영양(한국어)", "def_vi": "dinh dưỡng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1037, '7', '노인에게 탈수 증상이 쉽게 나타나는 원인은?', '["갈증반응 감소", "타액분비 감소", "염분섭취 증가", "칼슘흡수 증가", "위 소화액 분비 감소"]'::jsonb, 1, NULL, NULL, '{"1": "갈증반응이 감소하여 노인이 탈수 증상이 안 나타나기 쉽다.\n[정답]", "2": "타액 분비 감소가 탈수와 관련이 있지만, 갈증 반응 감소가 더 직접적인 원인이다.", "3": "염분 섭취 증가는 탈수를 유발할 수 있으나, 노인에게 주로 발생하는 갈증 반응 감소가 더 큰 영향을 미친다.", "4": "칼슘 흡수 증가와 탈수의 직접적인 연관은 없다.", "5": "위 소화액 분비 감소는 소화 기능에 영향을 미치지만 탈수와의 직접적인 연관은 미미하다."}'::jsonb, '[{"term_ko": "탈수", "term_vi": "Mất nước", "def_ko": "수분 부족(한국어)", "def_vi": "Thiếu nước"}, {"term_ko": "갈증", "term_vi": "Khát", "def_ko": "물이 마르고 싶어지는 느낌(한국어)", "def_vi": "Cảm giác muốn uống nước"}, {"term_ko": "반응", "term_vi": "Phản ứng", "def_ko": "반응 또는 응답(한국어)", "def_vi": "Phản ứng hoặc phản hồi"}, {"term_ko": "타액", "term_vi": "Nước bọt", "def_ko": "입에서 나오는 침(한국어)", "def_vi": "Nước trong miệng"}, {"term_ko": "염분", "term_vi": "Muối", "def_ko": "소금과 같은 물질(한국어)", "def_vi": "Chất giống như muối"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈에 주요한 무기질(한국어)", "def_vi": "Khoáng chất quan trọng trong xương"}, {"term_ko": "소화액", "term_vi": "Dịch tiêu hóa", "def_ko": "음식을 소화하는 데 필요한 액체(한국어)", "def_vi": "Dịch cần thiết để tiêu hóa thức ăn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1036, '6', '영양 문제 발생 위험이 가장 높은 대상자는?', '["보청기를 사용하는 대상자", "배변 활동이 양호한 대상자", "인지기능이 저하된 대상자", "잇몸에 맞는 의치를 낀 대상자", "시력 교정용 안경을 쓴 대상자"]'::jsonb, 3, NULL, NULL, '{"1": "보청기를 사용하는 대상자는 영양 문제와 관련이 적습니다.\n[정답]", "3": "인지기능이 저하된 대상자는 식사에 대한 인식이 부족해 영양 문제 발생 위험이 높습니다.", "2": "배변 활동이 양호한 대상자는 영양 문제와 관련이 없습니다.", "4": "잇몸에 맞는 의치를 낀 대상자는 식사를 할 수 있어 영양 문제가 적습니다.", "5": "시력 교정용 안경을 쓴 대상자는 영양 문제와 관련이 적습니다."}'::jsonb, '[{"term_ko": "영양", "term_vi": "Dinh dưỡng", "def_ko": "음식과 그 성분에 대한 정보", "def_vi": "Thông tin về thực phẩm và thành phần của chúng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1035, '7', '노인에게 영양 관련 문제가 발생할 가능성이 높은 이유는?', '["위장 운동 증가", "미각과 후각기능 저하", "소화 및 흡수기능 증가", "인지기능의 증가", "칼슘의 섭취 및 흡수 증가"]'::jsonb, 2, NULL, NULL, '{"1": "위장 운동은 보통 저하되므로 영양 문제가 발생하기 쉬움.\n[정답]", "2": "미각과 후각 기능이 저하되면서 음식의 맛을 느끼지 못하고 식욕이 감소할 수 있음.", "3": "소화 및 흡수 기능은 대개 감소함.", "4": "인지 기능이 감소하면 식사 패턴도 변화하게 됨.", "5": "칼슘의 섭취 및 흡수는 나이가 들수록 감소하는 경향이 있음."}'::jsonb, '[{"term_ko": "영양", "term_vi": "Dinh dưỡng", "def_ko": "영양(한국어)", "def_vi": "Dinh dưỡng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1034, '6', '파킨슨병을 치료 및 관리하는 방법으로 옳은 것은?', '["근육 스트레칭을 삼간다.", "관절 운동을 삼간다.", "약물요법을 지속한다.", "단백질 섭취량을 줄인다.", "두뇌활동을 규칙적으로 한다."]'::jsonb, 3, NULL, NULL, '{"1": "근육 스트레칭을 삼간다: 근육 스트레칭은 긴장을 풀어주고 운동 기능을 개선하는 데 도움이 됩니다.", "2": "관절 운동을 삼간다: 관절 운동은 유연성을 유지하는 데 중요합니다.\n[정답]", "3": "약물요법을 지속한다: 약물요법은 파킨슨병 관리에 필수적입니다.", "4": "단백질 섭취량을 줄인다: 단백질 섭취는 뇌 건강에 필요합니다.", "5": "두뇌활동을 규칙적으로 한다: 두뇌 활동은 인지 기능 유지를 돕습니다."}'::jsonb, '[{"term_ko": "파킨슨병", "term_vi": "Bệnh Parkinson", "def_ko": "신경계 질환의 일종", "def_vi": "Một loại bệnh về hệ thần kinh"}, {"term_ko": "약물요법", "term_vi": "Liệu pháp thuốc", "def_ko": "약을 사용하는 치료법", "def_vi": "Phương pháp điều trị bằng thuốc"}, {"term_ko": "근육 스트레칭", "term_vi": "Kéo giãn cơ", "def_ko": "근육을 늘리기 위한 운동", "def_vi": "Bài tập để kéo dãn cơ"}, {"term_ko": "관절 운동", "term_vi": "Vận động khớp", "def_ko": "관절을 유연하게 하기 위한 운동", "def_vi": "Bài tập để duy trì độ linh hoạt của khớp"}, {"term_ko": "두뇌활동", "term_vi": "Hoạt động não bộ", "def_ko": "뇌의 기능을 사용하는 모든 활동", "def_vi": "Tất cả các hoạt động sử dụng chức năng của não"}, {"term_ko": "단백질", "term_vi": "Protein", "def_ko": "몸에 필요한 영양소의 일종", "def_vi": "Một loại dinh dưỡng cần thiết cho cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1033, '6', '파킨슨병의 증상으로 옳은 것은?', '["곧은 자세", "행동 빨라짐", "인지능력 증가", "자세 불안정", "얼굴 표정의 변화"]'::jsonb, 4, NULL, NULL, '{"1": "곧은 자세는 파킨슨병의 증상 중 하나가 아닙니다.\n[정답]", "4": "자세 불안정은 파킨슨병의 전형적인 증상입니다.", "2": "행동 빨라짐은 파킨슨병과 관련이 없습니다.", "3": "인지능력 증가도 파킨슨병의 증상이 아닙니다.", "5": "얼굴 표정의 변화는 발생할 수 있지만, 자세 불안정이 더 전형적입니다."}'::jsonb, '[{"term_ko": "파킨슨병", "term_vi": "Bệnh Parkinson", "def_ko": "신경계 질환으로 운동 기능에 영향을 주는 질병", "def_vi": "Bệnh liên quan đến hệ thần kinh ảnh hưởng đến chức năng vận động"}, {"term_ko": "자세", "term_vi": "Tư thế", "def_ko": "신체의 위치나 상태", "def_vi": "Vị trí hoặc trạng thái của cơ thể"}, {"term_ko": "불안정", "term_vi": "Không ổn định", "def_ko": "안정되지 않음, 불안정한 상태", "def_vi": "Trạng thái không ổn định"}, {"term_ko": "행동", "term_vi": "Hành động", "def_ko": "사람의 의도된 동작", "def_vi": "Hành vi hoặc động tác có ý định của một người"}, {"term_ko": "인지능력", "term_vi": "Khả năng nhận thức", "def_ko": "사고, 이해 및 학습하는 능력", "def_vi": "Khả năng suy nghĩ, hiểu và học hỏi"}, {"term_ko": "표정", "term_vi": "Biểu cảm", "def_ko": "얼굴의 감정을 나타내는 모습", "def_vi": "Diện mạo thể hiện cảm xúc trên khuôn mặt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1032, '6', '파킨슨병에 관한 설명으로 옳은 것은?', '["고혈압이 주된 발병 원인이다.", "도파민이 과잉 분비되어 발생한다.", "안정 시 떨림과 근육경직이 나타난다.", "손상된 쪽 뇌의 반대편 신체에 마비가 온다.", "뇌혈관이 좁아져 혈액의 흐름에 장애가 생겨 발생한다."]'::jsonb, 3, NULL, NULL, '{"1": "고혈압은 파킨슨병의 주된 발병 원인이 아닙니다.\n[정답]", "3": "파킨슨병은 안정 시 떨림과 근육경직이 나타나는 특징이 있습니다.", "2": "도파민은 부족해져서 발생하는 질병입니다.", "4": "마비는 손상된 쪽 뇌의 같은 편 신체에 주로 나타납니다.", "5": "뇌혈관의 질환은 다른 형태의 신경 질환을 유발할 수 있습니다."}'::jsonb, '[{"term_ko": "파킨슨병", "term_vi": "Bệnh Parkinson", "def_ko": "병의 이름(한국어)", "def_vi": "Tên của bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1031, '6', '도파민 부족으로 동작이 느려지고 안정 시 떨림이 발생하는 질병은?', '["섬망", "고혈압", "파킨슨병", "혈관성 치매", "알츠하이머병"]'::jsonb, 3, NULL, NULL, '{"1": "섬망은 주로 정신적인 혼란과 관련된 증상이다.", "2": "고혈압은 혈압 상승과 관련된 상태로 도파민과 직접적인 관련이 없다.\n[정답]", "3": "파킨슨병은 도파민 부족으로 인한 동작의 느려짐과 안정 시 떨림이 발생하는 질병이다.", "4": "혈관성 치매는 뇌혈관 문제로 인한 인지장애고 도파민 부족과는 관련이 적다.", "5": "알츠하이머병은 기억력과 인지 기능에 영향을 주지만 도파민 부족과는 연관성이 낮다."}'::jsonb, '[{"term_ko": "도파민", "term_vi": "Dopamine", "def_ko": "신경전달물질의 일종", "def_vi": "Một loại chất truyền dẫn thần kinh"}, {"term_ko": "동작", "term_vi": "Hành động", "def_ko": "행동을 취하는 것", "def_vi": "Hành động mà ai đó thực hiện"}, {"term_ko": "떨림", "term_vi": "Run", "def_ko": "손이나 몸이 불규칙하게 움직이는 것", "def_vi": "Di chuyển không đều của tay hoặc cơ thể"}, {"term_ko": "질병", "term_vi": "Căn bệnh", "def_ko": "건강에 문제가 있는 상태", "def_vi": "Tình trạng có vấn đề sức khỏe"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1030, '6', '다음과 같은 전구증상이 나타날 때 의심할 수 있는 질환은?• 두통 및 구토, 시각장애 (복시, 시야장애)가 발생한다.• 일어서려고 하면 자꾸 한쪽으로 넘어진다.• 한쪽 팔다리가 마비되거나 감각이 이상하다.•말할 때 발음이 분명치 않거나, 말을 잘 못한다.', '["난청", "빈혈", "고혈압", "뇌졸증", "폐렴"]'::jsonb, 4, NULL, NULL, '{"1": "난청: 주로 청각과 관련된 증상으로, 구토 및 시각장애와는 관련이 적다.", "2": "빈혈: 피로감이 주요 증상이며, 언어 장애와 관련성이 없다.\n[정답]", "3": "고혈압: 증상으로 보여진 두통과 관련이 있을 수 있으나, 다른 신경학적 증상은 포함되지 않는다.", "4": "뇌졸증: 뇌혈관에 문제가 생겨 발생하며, 제시된 모든 증상이 관련이 있다.", "5": "폐렴: 호흡기 관련 문제로 신경학적 증상과는 거리가 있다."}'::jsonb, '[{"term_ko": "전구증상", "term_vi": "Triệu chứng tiền triệu", "def_ko": "증상이 나타나기 전에 보이는 증상", "def_vi": "Những triệu chứng xuất hiện trước khi có triệu chứng chính"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1029, '6', '현기증, 팔다리 저림, 뒷ㅗㄹ 통증 등의 전구증상이 나타나는 질환은?', '["알츠하이머병", "뇌졸중", "파킨슨병", "섬망", "치매"]'::jsonb, 2, NULL, NULL, '{"1": "알츠하이머병은 주로 기억력 감소와 인지 기능 저하로 나타납니다.\n[정답]", "2": "뇌졸중은 현기증, 팔다리 저림, 통증 등의 전구증상이 나타날 수 있습니다.", "3": "파킨슨병은 운동 장애 및 경직 증상이 주를 이룹니다.", "4": "섬망은 급성 혼돈 상태로, 전구증상과는 다릅니다.", "5": "치매는 인지 기능 저하가 나타나나, 전구증상으로는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "현기증", "term_vi": "Chóng mặt", "def_ko": "어지럼증(한국어)", "def_vi": "Chóng mặt(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1028, '6', '대상자가 음식이나 물을 삼키기 힘들어 하는 증상은?', '["삼킴장애", "오심", "운동 실조증", "다뇨증", "다갈증"]'::jsonb, 1, NULL, NULL, '{"1": "삼킴장애: 음식이나 물을 삼키는 데 어려움을 겪는 증상입니다.\n[정답]", "2": "오심: 구역질이 나는 증상으로 삼키기와는 관련이 없습니다.", "3": "운동 실조증: 운동 조정의 문제가 있는 상태로 삼키기와 관계가 없습니다.", "4": "다뇨증: 소변을 많이 보는 상태로 삼킴과는 관련이 없습니다.", "5": "다갈증: 극심한 갈증을 느끼는 상태로 삼키기와는 관계가 없습니다."}'::jsonb, '[{"term_ko": "삼킴장애", "term_vi": "Rối loạn nuốt", "def_ko": "음식이나 물을 삼키는 데 어려움을 겪는 증상", "def_vi": "Triệu chứng gặp khó khăn khi nuốt thức ăn hoặc nước"}, {"term_ko": "오심", "term_vi": "Buồn nôn", "def_ko": "구역질이 나는 증상", "def_vi": "Triệu chứng cảm thấy buồn nôn"}, {"term_ko": "운동 실조증", "term_vi": "Rối loạn phối hợp vận động", "def_ko": "운동 조정의 문제가 있는 상태", "def_vi": "Tình trạng không phối hợp trong vận động"}, {"term_ko": "다뇨증", "term_vi": "Tiểu nhiều", "def_ko": "소변을 많이 보는 상태", "def_vi": "Trạng thái đi tiểu nhiều"}, {"term_ko": "다갈증", "term_vi": "Khát nước dữ dội", "def_ko": "극심한 갈증을 느끼는 상태", "def_vi": "Trạng thái cảm thấy khát nước dữ dội"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1027, '6', '뇌에 혈액을 공급하는 혈관이 막히거나 터졌을 때 나타나는 질환의 증상은?', '["허리 통증", "기침과 객담", "언어장애, 삼킴장애,", "가려움증", "피부 발적"]'::jsonb, 3, NULL, NULL, '{"1": "허리 통증은 뇌와 관련이 없다.\n[정답]", "3": "언어장애와 삼킴장애는 뇌에 혈액이 공급되지 않아 발생할 수 있는 증상이다.", "2": "기침과 객담은 호흡기 관련 증상이다.", "4": "가려움증은 피부 관련 문제로 뇌와 직접적인 관련이 없다.", "5": "피부 발적도 피부 문제로 뇌와는 관련이 없다."}'::jsonb, '[{"term_ko": "뇌", "term_vi": "혈액", "def_ko": "뇌(한국어) / Não: não", "def_vi": "혈액(한국어) / Máu: máu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1026, '6', '뇌졸중에 대한 설명으로 옳은 것은?', '["도파민의 부족으로 발생한다.", "좌뇌가 손상되면 좌측마비가 발생한다.", "측두엽이 손사되면 술 취한 사람처럼 비틀거린다.", "안정 시 떨림, 무표정한 얼굴이 특징적으로 나타난다.", "한 개의 무렟가 둘로 보이는 전구 증상이 나타난다."]'::jsonb, 5, NULL, NULL, '{"1": "도파민의 부족은 파킨슨병과 관련이 있으며, 뇌졸중과는 관계가 없습니다.\n[정답]", "5": "한 개의 물체가 둘로 보이는 전구 증상은 뇌졸중의 일부 증상으로 나타날 수 있습니다.", "2": "좌뇌가 손상되면 우측마비가 발생합니다. 좌뇌는 신체 오른쪽을 관장합니다.", "3": "측두엽 손상은 비틀거림을 일으킬 수 있지만, 주로 발음이나 기억력에 영향을 미칩니다.", "4": "안정 시 떨림과 무표정한 얼굴은 파킨슨병의 증상입니다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 차단되는 상태", "def_vi": "Tình trạng mất cung cấp máu đến não"}, {"term_ko": "좌뇌", "term_vi": "Bán cầu não trái", "def_ko": "뇌의 왼쪽 반구", "def_vi": "Bán cầu bên trái của não"}, {"term_ko": "마비", "term_vi": "Liệt", "def_ko": "신체의 일부가 움직이지 않는 상태", "def_vi": "Tình trạng không thể vận động một phần cơ thể"}, {"term_ko": "전구", "term_vi": "Đèn báo", "def_ko": "물체의 모양을 왜곡하게 만드는 증상", "def_vi": "Triệu chứng làm biến dạng hình dạng của vật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1025, '6', '뇌졸중 증상 중 운동 실조증에 대한 설명으로 옳은 것은?', '["복시 (한 개의 물체를 보는데 두 개로 보임)", "물건을 잡으려고 할 때 정확하게 잡을 수는 있음", "발음이 어눌해 짐", "음식이나 물을 삼키기 힘들어짐", "술 취한 사람처럼 비틀거리고 한쪽으로 자꾸 쓰러지려함"]'::jsonb, 5, NULL, NULL, '{"1": "복시는 운동 실조증의 증상이 아닙니다.\n[정답]", "5": "운동 실조증은 비틀거림과 쓰러짐이 특징입니다.", "2": "물건을 정확히 잡지 못하는 것이 운동 실조증의 증상입니다.", "3": "발음이 어눌해지는 것은 언어 장애와 관련됩니다.", "4": "음식이나 물을 삼키기 힘든 것은 연하곤란과 관련됩니다."}'::jsonb, '[{"term_ko": "운동 실조증", "term_vi": "Rối loạn phối hợp vận động", "def_ko": "몸의 움직임을 조절하지 못하는 증상", "def_vi": "triệu chứng không thể điều chỉnh chuyển động của cơ thể"}, {"term_ko": "복시", "term_vi": "Đôi thị", "def_ko": "한 개의 물체를 두 개로 보이는 것", "def_vi": "nhìn thấy một vật thể thành hai"}, {"term_ko": "발음", "term_vi": "Phát âm", "def_ko": "말을 하는 방법", "def_vi": "phương pháp nói"}, {"term_ko": "음식", "term_vi": "Thức ăn", "def_ko": "먹는 것", "def_vi": "món ăn"}, {"term_ko": "삼키기", "term_vi": "Nuốt", "def_ko": "입으로 물리적 물체를 목으로 넘기는 행위", "def_vi": "hành động đưa vật thể vào cổ họng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1024, '6', '소뇌가 손상되어 뇌졸중이 발생했을 때 나타나는 특징적인 증상은?', '["묽은 혈변", "전신성 수포", "관절 부위 통증", "몸의 균형감각 상실", "가슴이 조이는 흉통"]'::jsonb, 4, NULL, NULL, '{"1": "묽은 혈변은 소화기 계통의 문제로 발생하며, 소뇌와는 관련이 없습니다.", "2": "전신성 수포는 피부 질환과 관련된 증상입니다.", "3": "관절 부위 통증은 소뇌 손상과는 무관합니다.\n[정답]", "4": "몸의 균형감각 상실은 소뇌의 주요 기능 중 하나이며, 손상 시 나타납니다.", "5": "가슴이 조이는 흉통은 심혈관계의 문제로 소뇌와는 직접적인 연관이 없습니다."}'::jsonb, '[{"term_ko": "소뇌", "term_vi": "Tiểu não", "def_ko": "뇌의 일부로 운동协调과 균형을 담당하는 부분", "def_vi": "Phần của não chịu trách nhiệm điều phối vận động và cân bằng"}, {"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈류가 막혀 발생하는 질병", "def_vi": "Bệnh xảy ra khi lưu lượng máu đến não bị tắc nghẽn"}, {"term_ko": "균형감각", "term_vi": "Cảm giác cân bằng", "def_ko": "몸의 균형을 유지하는 감각", "def_vi": "Cảm giác duy trì sự cân bằng của cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1023, '6', '뇌졸중으로 오른쪽 뇌가 손상되었을 때 나타날 수 있는 증상은?', '["왼쪽 팔의 소양증", "왼쪽 다리의 마비", "오른쪽 팔의 감각 저하", "오른쪽 다리의 얼얼한 느낌", "전신마비와 함께 의식 저하"]'::jsonb, 2, NULL, NULL, '{"1": "왼쪽 팔이 간지럽거나 소양증이 나타날 수 있지만 이는 뇌졸중의 전형적인 증상은 아니다.\n[정답]", "2": "뇌졸중으로 오른쪽 뇌가 손상되면 왼쪽 몸의 마비가 나타날 수 있다.", "3": "오른쪽 팔의 감각 저하는 오른쪽 뇌 손상과 관련이 없고 왼쪽 몸의 증상과 관련이 있다.", "4": "오른쪽 다리의 얼얼한 느낌은 오른쪽 뇌 손상과는 관련없다.", "5": "전신마비와 의식 저하는 일반적인 증상이지만, 이는 뇌졸중의 구체적인 증상으로는 적합하지 않다."}'::jsonb, '[{"term_ko": "뇌졸중", "term_vi": "Đột quỵ", "def_ko": "뇌의 혈액 공급이 차단되어 생기는 질병", "def_vi": "Bệnh xảy ra khi cung cấp máu cho não bị ngăn chặn"}, {"term_ko": "손상", "term_vi": "Tổn thương", "def_ko": "피해를 입거나 해를 입음", "def_vi": "Bị thiệt hại hoặc bị hại"}, {"term_ko": "마비", "term_vi": "Liệt", "def_ko": "신체의 일부 기능을 잃는 것", "def_vi": "Mất chức năng của một phần cơ thể"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 상태에 따라 나타나는 질병의 특징", "def_vi": "Đặc điểm của bệnh hoặc tình trạng theo bệnh tật"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "깨어 있는 능력", "def_vi": "Khả năng tỉnh táo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1022, '6', '다음의 지시에 따른 대상자의 반응으로 예측할 수 있는 질환은?• "말해 보세요." - 발음이 정확한지 확인한다.• "웃어 보세요." - 입의 좌우 모양이 대칭인지 확인한다.• "걸어 보세요." - 비틀거리고 한쪽으로 쓰러지는지 확인한다.', '["고혈압", "심부전", "뇌졸중", "동맥경화증", "기립성 저혈압"]'::jsonb, 3, NULL, NULL, '{"1": "고혈압은 주로 혈압과 관련된 증상으로 이 문제와 직접적 연관이 없다.", "2": "심부전은 호흡곤란, 부종 등의 증상이 주로 나타나며, 이 지시와는 관련이 없다.\n[정답]", "3": "뇌졸중은 발음, 얼굴의 비대칭, 균형 감각 저하와 같은 증상이 나타나며, 문제의 지시에 가장 적합하다.", "4": "동맥경화증은 주요 심혈관계 질환으로서 이 문제와 관련된 증상과는 차이가 있다.", "5": "기립성 저혈압은 서 있을 때 발생하는 혈압 강하와 주로 관련된 증상으로, 제시된 지시와 일치하지 않는다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "환자 또는 검사를 받는 사람", "def_vi": "Người bệnh hoặc người được kiểm tra"}, {"term_ko": "발음", "term_vi": "Phát âm", "def_ko": "소리를 내는 방식", "def_vi": "Cách phát ra âm thanh"}, {"term_ko": "모양", "term_vi": "Hình dạng", "def_ko": "형태", "def_vi": "Hình thức"}, {"term_ko": "비대칭", "term_vi": "Không đối xứng", "def_ko": "대칭이 아닐 때", "def_vi": "Khi không đối xứng"}, {"term_ko": "비틀거리다", "term_vi": "Chao đảo", "def_ko": "엉망으로 걷다", "def_vi": "Đi lạc thường"}, {"term_ko": "쓰러지다", "term_vi": "Ngã", "def_ko": "넘어지다", "def_vi": "Bị ngã"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1021, '6', '치매 대상자에게 발생할 수 있는 다음과 같은 증상의 질환은?', '["요실금", "섬망", "변실금", "영양실조", "경련"]'::jsonb, 2, NULL, NULL, '{"1": "요실금은 노인성 질환으로 발생할 수 있지만 치매와는 직접적인 관련이 적다.\n[정답]", "2": "섬망은 치매 환자에게 자주 발생하는 상태로, 인지 기능의 급격한 변화가 특징이다.", "3": "변실금은 일부 치매 환자에게 나타날 수 있으나 일반적으로 섬망과 관련된 증상이다.", "4": "영양실조는 다양한 원인으로 발생하지만, 치매 환자에 의해 간접적으로 영향받을 수 있다.", "5": "경련은 갑작스러운 신경학적 상태로, 일시적인 문제일 수 있지만 치매와는 직접적인 연관이 없다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh sa sút trí tuệ", "def_ko": "기억과 사고 기능에 문제가 생기는 질환", "def_vi": "Bệnh có vấn đề với trí nhớ và tư duy"}, {"term_ko": "섬망", "term_vi": "Rối loạn ý thức", "def_ko": "급성 혼란 상태", "def_vi": "Trạng thái rối loạn cấp tính"}, {"term_ko": "요실금", "term_vi": "Tiểu không kiểm soát", "def_ko": "소변을 제어하지 못하는 상태", "def_vi": "Tình trạng không kiểm soát được tiểu tiện"}, {"term_ko": "영양실조", "term_vi": "Suy dinh dưỡng", "def_ko": "영양소 부족으로 인한 상태", "def_vi": "Tình trạng thiếu chất dinh dưỡng"}, {"term_ko": "경련", "term_vi": "Co giật", "def_ko": "비정상적인 근육 수축", "def_vi": "Co thắt cơ bất thường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1020, '6', '치매의 말기 증상으로 옳은 것은?', '["배회와 같은 정신행동증상이 심해진다.", "시간 이외에 공간도 헷갈리기 시작한다.", "새로 외우는 것이 거의 불가능하다.", "남의 말을 이해하는데 어려움이 생긴다.", "가족의 얼굴을 알아보지 못한다."]'::jsonb, 5, NULL, NULL, '{"1": "배회와 같은 정신행동증상이 심해질 수 있으나, 이는 말기의 전반적인 특징이 아닐 수 있습니다.\n[정답]", "5": "가족의 얼굴을 알아보지 못하는 것은 치매의 말기 증상 중 하나입니다.", "2": "시간 이외에 공간도 헷갈리는 증상은 중기 증상일 수 있습니다.", "3": "새로 외우는 것이 거의 불가능한 것은 전반적으로 나타나지만 말기 증상으로 한정할 수 없습니다.", "4": "남의 말을 이해하는 데 어려움이 생기는 것은 초기와 중기의 특징일 수 있습니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력이 저하되는 질환", "def_vi": "Bệnh giảm khả năng nhớ và suy nghĩ"}, {"term_ko": "배회", "term_vi": "Đi lang thang", "def_ko": "일정한 경로 없이 돌아다니는 행동", "def_vi": "Hành động đi không theo lộ trình nhất định"}, {"term_ko": "정신행동증상", "term_vi": "Triệu chứng hành vi tinh thần", "def_ko": "정신적 행동의 변화", "def_vi": "Thay đổi hành vi tâm lý"}, {"term_ko": "가족", "term_vi": "Gia đình", "def_ko": "혈연으로 연결된 사람들", "def_vi": "Những người có mối liên hệ huyết thống"}, {"term_ko": "얼굴", "term_vi": "Khuôn mặt", "def_ko": "사람의 얼굴", "def_vi": "Khuôn mặt của con người"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1019, '6', '중기 치매 증상으로 옳은 것은?', '["새로운 것을 외우는 것이 어렵다.", "환각, 망상 등의 정신행동증상이 심해진다.", "우울이나 짜증의 증상이 나타나기 시작한다.", "말을 할 때 적절한 단어가 떠오르지 않는다.", "간혹 시간이 헷갈릴 때가 있다."]'::jsonb, 2, NULL, NULL, '{"1": "새로운 것을 외우는 것이 어렵다. 중기 치매의 초기 증상일 수 있으나, 명확한 특징은 아닙니다.\n[정답]", "2": "환각, 망상 등의 정신행동증상이 심해진다. 이 증상은 중기 치매에서 흔히 나타나는 증상입니다.", "3": "우울이나 짜증의 증상이 나타나기 시작한다. 이 역시 초기 단계에서 흔히 나타날 수 있습니다.", "4": "말을 할 때 적절한 단어가 떠오르지 않는다. 이는 진행되는 중기나 말기 치매에서 흔하게 나타나는 증상입니다.", "5": "간혹 시간이 헷갈릴 때가 있다. 일반적인 노화 과정에서도 있을 수 있는 증상입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Chứng mất trí nhớ", "def_ko": "기억 또는 사고 능력을 잃어가는 상태(한국어)", "def_vi": "Trạng thái mất khả năng ghi nhớ hoặc tư duy"}, {"term_ko": "중기", "term_vi": "Giai đoạn giữa", "def_ko": "진행 중인 상태(한국어)", "def_vi": "Trạng thái đang diễn ra"}, {"term_ko": "환각", "term_vi": "Ảo giác", "def_ko": "현실과 다른 감각 인식(한국어)", "def_vi": "Nhận thức giác quan khác với thực tế"}, {"term_ko": "망상", "term_vi": "Hoang tưởng", "def_ko": "사실과 다른 믿음이나 생각(한국어)", "def_vi": "Niềm tin hoặc suy nghĩ khác với sự thật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1018, '6', '치매의 초기 증상으로 옳은 것은?', '["시간과 공간이 헷갈린다.", "과거의 기억을 떠올리기 어렵다.", "남의 말을 이해하는데 어려움이 있다.", "간혹 시간이 헷갈릴 때가 있다.", "의사소통이 거의 불가능하다."]'::jsonb, 4, NULL, NULL, '{"1": "치매 초기에도 시간과 공간 혼동은 나타날 수 있지만, 일부 환자에서만 발생합니다.\n[정답]", "4": "간혹 시간이 헷갈릴 때가 있다는 것은 치매 초기의 일반적인 증상으로, 다양한 사람에게 일어날 수 있습니다.", "2": "과거의 기억을 떠올리기 어렵다는 것은 치매가 어느 정도 진행된 후 나타나는 증상입니다.", "3": "남의 말을 이해하는 능력이 감소하는 것은 치매의 중기 이상의 증상으로 주로 나타납니다.", "5": "의사소통이 거의 불가능하다는 것은 치매의 말기 증상으로, 초기와는 거리가 멉니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "기억력과 사고 능력의 감소로 일상 생활에 지장을 주는 신경 퇴행성 질환", "def_vi": "Bệnh thoái hóa thần kinh gây ra sự suy giảm trí nhớ và khả năng suy nghĩ, ảnh hưởng đến cuộc sống hàng ngày"}, {"term_ko": "초기", "term_vi": "Giai đoạn đầu", "def_ko": "사건이 발생하는 시점", "def_vi": "Thời điểm xảy ra sự kiện"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 이상이 나타나는 징후", "def_vi": "Dấu hiệu của bệnh tật hoặc tình trạng bất thường"}, {"term_ko": "기억", "term_vi": "Ký ức", "def_ko": "정보나 경험을 저장하고 회상하는 능력", "def_vi": "Khả năng lưu trữ và hồi tưởng thông tin hoặc kinh nghiệm"}, {"term_ko": "이해", "term_vi": "Hiểu", "def_ko": "상황이나 의미를 명확히 알다", "def_vi": "Biết rõ bối cảnh hoặc ý nghĩa"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "소통하는 행위", "def_vi": "Hành động giao tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1017, '6', '치매에 관한 설명으로 옳은 것은?', '["시공간을 파악하는 능력은 정상이다.", "뇌의 정상적인 노화 현상이다.", "혈관성 치매 비율이 가장 높다.", "최근 일보다 먼 과거의 일을 잘 기억해 내지 못한다.", "감각 및 운동기관은 정상인데 실행능력기능이 저하된다."]'::jsonb, 5, NULL, NULL, '{"1": "시공간을 파악하는 능력은 치매 환자들에게 종종 저하됩니다. 따라서 잘못된 설명입니다.", "2": "치매는 단순한 노화 현상이 아닙니다. 퇴행성 및 비퇴행성 뇌 질환입니다. 따라서 잘못된 설명입니다.\n[정답]", "3": "여러 유형의 치매 중 혈관성 치매 비율은 많지만, 알츠하이머형 치매의 비율이 가장 높습니다. 따라서 잘못된 설명입니다.", "4": "치매 환자들은 최근의 일을 기억하기 어려워하고 먼 과거의 일을 더 잘 기억하는 경향이 있습니다. 따라서 잘못된 설명입니다.", "5": "감각 및 운동기관은 정상일 수 있으나, 실행 능력은 저하되는 것이 치매의 주요 증상 중 하나입니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí nhớ", "def_ko": "일종의 퇴행성 뇌 질환이자 기억력과 사고력을 저하시키는 상태", "def_vi": "Một loại bệnh thoái hóa não làm suy giảm trí nhớ và khả năng suy nghĩ"}, {"term_ko": "시공간", "term_vi": null, "def_ko": "시간과 공간", "def_vi": null}, {"term_ko": "혈관성", "term_vi": null, "def_ko": "혈관과 관련된", "def_vi": null}, {"term_ko": "실행능력", "term_vi": null, "def_ko": "일을 계획하고 수행하는 능력", "def_vi": null}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1016, '6', '치매 대상자의 지남력 저하로 인해 나타나는 증상은?', '["물건을 둔 장소를 기억하지 못한다.", "전화 통화 내용을 기억하지 못한다.", "날짜, 요일, 시간을 착각한다.", "대화 중 적절한 단어가 떠오르지 않는다.", "시간이 지나 곰곰이 생각하면 기억이 난다."]'::jsonb, 3, NULL, NULL, '{"1": "물건을 둔 장소를 기억하지 못한다는 것은 주의력, 기억력의 문제를 나타내지만 지남력 저하와는 다소 차이가 있습니다.\n[정답]", "2": "날짜, 요일, 시간을 착각한다는 것은 지남력 저하의 대표적인 증상입니다.", "3": "전화 통화 내용을 기억하지 못하는 것은 단기 기억의 문제로, 지남력과는 다른 증상입니다.", "4": "대화 중 적절한 단어가 떠오르지 않는 것은 언어적 표현의 저하로, 지남력 저하와는 관련이 없습니다.", "5": "시간이 지나 곰곰이 생각하면 기억이 난다는 것은 치매와 관련된 일반적인 기억상실과는 다릅니다."}'::jsonb, '[{"term_ko": "치매", "term_vi": "Bệnh mất trí", "def_ko": "기억력과 판단력의 저하로 인해 발생하는 질병", "def_vi": "Bệnh lý do suy giảm trí nhớ và khả năng phán đoán"}, {"term_ko": "지남력", "term_vi": "Khả năng định hướng", "def_ko": "시간, 장소, 자기를 인식하는 능력", "def_vi": "Khả năng nhận biết thời gian, địa điểm và bản thân"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "특정 질병이나 상태의 징후", "def_vi": "Dấu hiệu của một bệnh hoặc tình trạng cụ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1015, '6', '정상적으로 생활하던 사람이 다양한 원인에 의한 인지기능 장애로, 일상생활을 수행할 수 없게 되는 질환은?', '["뇌졸증", "치매", "고혈압", "당뇨병", "동맥경화"]'::jsonb, 2, NULL, NULL, '{"1": "뇌졸증은 뇌에 혈액 공급이 중단되어 발생하며, 후유증으로 인지기능 장애가 올 수 있지만 반드시 일상생활을 수행하지 못하게 하지는 않는다.\n[정답]", "2": "치매는 인지기능의 전반적인 저하로 인해 일상생활 수행이 어려워지는 질환이다.", "3": "고혈압은 혈압 상승으로 심혈관계에 영향을 미치나, 인지기능 자체를 직접적으로 제한하지 않는다.", "4": "당뇨병은 주로 혈당 조절과 관련된 질환이며 인지기능 저하와는 직접적으로 관련이 없다.", "5": "동맥경화는 혈관의 경화로 심혈관계 질환의 원인이 될 수 있지만, 인지기능 장애를 유발하는 주된 원인은 아니다."}'::jsonb, '[{"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "정신적 기능(한국어)", "def_vi": "Chức năng tinh thần"}, {"term_ko": "장애", "term_vi": "Khuyết tật", "def_ko": "기능의 제한(한국어)", "def_vi": "Sự hạn chế chức năng"}, {"term_ko": "일상생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "일상적인 활동(한국어)", "def_vi": "Hoạt động hàng ngày"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병, 질병(한국어)", "def_vi": "Bệnh tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1014, '5', '다음 설명에 해당하는 질환으로 옳은 것은?종아리 둘레 길이를 재어 간단히 측정할 수 있다. 근력 감소, 보행 능력의 감소를 나타내는 노쇠의 핵심 증상이다.', '["욕창", "낙상", "식욕부진", "근감소증", "수면장애"]'::jsonb, 4, NULL, NULL, '{"1": "욕창: 피부의 상처로, 종아리 둘레와는 관련이 없습니다.", "2": "낙상: 넘어지는 사고로, 근력 감소와 보행 능력의 감소는 관련이 있으나 주된 증상은 아닙니다.", "3": "식욕부진: 식욕의 감소로, 종아리 둘레와는 관련이 없습니다.\n[정답]", "4": "근감소증: 근력 감소, 보행 능력의 감소와 직접 관련이 있습니다.", "5": "수면장애: 수면의 질 문제로, 종아리 둘레와는 관련이 없습니다."}'::jsonb, '[{"term_ko": "종아리", "term_vi": "Bắp chân", "def_ko": "종아리(한국어)", "def_vi": "Bắp chân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1013, '5', '노인증후군의 특징으로 옳은 것은?', '["면역력이 강한 노인들에게 많이 생긴다.", "노인증후군은 노쇠의 과정을 거쳐 회복된다.", "질병의 다발성으로 인한 기능 저하로 발생한다.", "기존의 질병으로 주된 증상을 특정할 수 있다.", "노인의 식욕부진, 변비 등의 증상과는 관계없다."]'::jsonb, 3, NULL, NULL, '{"1": "면역력과는 관련이 적으며, 오히려 면역력이 약한 노인에게 많이 나타납니다.\n[정답]", "3": "질병의 다발성이 기능 저하를 초래하여 노인증후군을 발생시킵니다.", "2": "노인증후군은 회복이 빠르지 않으며, 오히려 증상이 지속되는 경우가 많습니다.", "4": "기존 질병이 있는 경우가 많지만 주된 증상을 특정할 수 없는 경우가 많습니다.", "5": "노인의 식욕부진, 변비 등은 노인증후군의 주요 증상과 밀접한 관계가 있습니다."}'::jsonb, '[{"term_ko": "노인증후군", "term_vi": "Hội chứng người già", "def_ko": "노인에서 나타나는 다양한 증상들의 집합", "def_vi": "Tập hợp các triệu chứng khác nhau xuất hiện ở người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1012, '5', '노인증후군에 대한 설명으로 옳은 것은?', '["의학적 요인에 의해서만 발현된다.", "서로 연관성이 있는 기관에만 발생한다.", "주된 증상이 특정한 병적 상태로 설명된다.", "건강한 노인들에게서 흔히 나타나는 문제이다.", "다약제 복용으로 인한 약물-약물 상호작용이 원인이다."]'::jsonb, 5, NULL, NULL, '{"1": "노인증후군은 다양한 요인에 의해 발생하므로 의학적 요인만으로 발현되지 않습니다.", "2": "여러 기관의 상호작용으로 발생할 수 있으며, 특정 기관에만 국한되지 않습니다.", "3": "증상은 특정한 병적 상태와 관련이 없을 수 있습니다.\n[정답]", "4": "건강한 노인들에게는 노인증후군이 통상적이지 않으며, 여러 위험 요소가 있지만 건강한 노인에게 자주 나타나지는 않습니다.", "5": "다약제 복용은 노인에서 흔한 문제이며, 약물-약물 상호작용이 노인증후군의 원인 중 하나입니다."}'::jsonb, '[{"term_ko": "노인증후군", "term_vi": "Hội chứng người già", "def_ko": "노인에서 여러 증상이 동시에 나타나는 상태", "def_vi": "Tình trạng có nhiều triệu chứng đồng thời ở người già"}, {"term_ko": "의학적", "term_vi": "Y tế", "def_ko": "의료에 관련된", "def_vi": "Liên quan đến y tế"}, {"term_ko": "병적 상태", "term_vi": "Tình trạng bệnh lý", "def_ko": "특정 병으로 인한 상태", "def_vi": "Tình trạng do bệnh cụ thể gây ra"}, {"term_ko": "건강한", "term_vi": "Khỏe mạnh", "def_ko": "질병이나 문제가 없는 상태", "def_vi": "Tình trạng không có bệnh hoặc vấn đề"}, {"term_ko": "다약제", "term_vi": "Đa dược", "def_ko": "여러 가지 약을 동시에 복용하는 것", "def_vi": "Sử dụng nhiều loại thuốc cùng lúc"}, {"term_ko": "약물-약물 상호작용", "term_vi": "Tương tác thuốc-thuốc", "def_ko": "두 가지 이상의 약물이 서로 영향을 미치는 것", "def_vi": "Ảnh hưởng của hai hoặc nhiều loại thuốc lẫn nhau"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1011, '5', '섬망이 있는 치매 대상자가 늦은 밤에 흥부나여 소리 지르며 난동을 피울 때 돕기 방법은?', '["방을 밝고 따뜻하게 해준다.", "흥분이 가라앉을 때까지 그냥 둔다.", "왜 그러는지 이유를 물어본다.", "다른 대상자들 앞에서 야단을 친다.", "진정제를 투약하여 잠을 재운다."]'::jsonb, 1, NULL, NULL, '{"1": "방을 밝고 따뜻하게 해주는 것은 안정감을 주어 환자의 상태를 개선하는 데 효과적입니다.\n[정답]", "2": "흥분이 가라앉을 때까지 그냥 두는 것은 오히려 문제를 악화시킬 수 있습니다.", "3": "왜 그러는지 이유를 물어보는 것은 환자가 정서적으로 불안정할 수 있어 도움이 되지 않습니다.", "4": "다른 대상자들 앞에서 야단을 치는 것은 환자에게 부정적인 영향을 미치고 더욱 혼란을 초래할 수 있습니다.", "5": "진정제를 투약하는 것은 의사의 지시에 따라 필요할 수 있지만, 상시적으로 사용하는 것은 권장되지 않습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Mê sảng", "def_ko": "정신 혼란 상태", "def_vi": "Tình trạng rối loạn tâm thần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1010, '5', '섬망 대상자가 초조해 하는 경우 돕는 방법은?', '["가족사진을 치운다.", "가족 방문 횟수를 줄인다.", "대상자의 물건을 다른 곳으로 치운다.", "단호하고 부드러운 목소리로 말한다.", "대상자와 시선을 마주치지 않는다."]'::jsonb, 4, NULL, NULL, '{"1": "가족사진을 치우는 것은 대상자의 안정을 도울 수 없으며 오히려 불안감을 증가시킬 수 있습니다.", "2": "가족의 방문 횟수를 줄이는 것은 대상자의 외로움을 느끼게 할 수 있습니다.", "3": "대상자의 물건을 다른 곳으로 치우는 것은 대상자의 혼란을 가중시킬 수 있습니다.\n[정답]", "4": "단호하고 부드러운 목소리로 말하면 대상자에게 안정감을 줄 수 있습니다.", "5": "대상자와 시선을 마주치지 않는 것은 소통을 방해하고 불안감을 증대시킬 수 있습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Delirium", "def_ko": "의식트래블 및 인지 기능 장애", "def_vi": "Rối loạn ý thức và chức năng nhận thức"}, {"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "요양 서비스의 제공을 받는 사람", "def_vi": "Người nhận dịch vụ chăm sóc"}, {"term_ko": "초조하다", "term_vi": "Lo lắng", "def_ko": "불안감이나 긴장 상태에 있다", "def_vi": "Ở trong trạng thái lo âu hoặc căng thẳng"}, {"term_ko": "단호하다", "term_vi": "Kiên quyết", "def_ko": "의견이 확고하다", "def_vi": "Có ý kiến vững vàng"}, {"term_ko": "부드럽다", "term_vi": "Mềm mại", "def_ko": "말이나 행동이 부드럽고 온화하다", "def_vi": "Nói hoặc hành động nhẹ nhàng và hòa nhã"}, {"term_ko": "목소리", "term_vi": "Giọng nói", "def_ko": "사람의 목소리", "def_vi": "Giọng nói của con người"}, {"term_ko": "시선", "term_vi": "Ánh nhìn", "def_ko": "눈의 방향", "def_vi": "Hướng nhìn của đôi mắt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1009, '5', '섬망 치료를 위한 비약물요법 중 개인의 정체성을 유지하는 방법은?', '["혼자 있게 한다.", "새로운 친구를 사귀게 한다.", "가족이 자주 방문하게 한다.", "밤에는 불을 끄고 어둡게 한다.", "많은 사람들을 접촉하게 한다."]'::jsonb, 3, NULL, NULL, '{"1": "혼자 있게 한다는 것은 오히려 개인의 정체성을 상실하게 할 수 있습니다.\n[정답]", "3": "가족이 자주 방문하게 하는 것은 개인의 정체성을 유지하는 데 긍정적인 영향을 미칩니다.", "2": "새로운 친구를 사귀는 것은 도움이 될 수 있으나, 개인의 정체성을 중요시하는 데 있어 가족의 역할이 더 큽니다.", "4": "밤에 불을 끄고 어둡게 하는 것은 섬망 증상을 악화시킬 수 있습니다.", "5": "많은 사람들과 접촉하게 하는 것은 혼란을 초래할 수 있으므로 개인의 정체성을 저해할 수 있습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Rối loạn", "def_ko": "혼란 상태(한국어)", "def_vi": "Tình trạng lẫn lộn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1008, '5', '섬망 증상이 있는 대상자의 지남력을 유지하는 방법은?', '["환경에 변화를 준다.", "달력, 시계 등을 없앤다.", "텔레비전을 크게 틀어 놓는다.", "낮 동안 커튼을 쳐서 빛을 차단한다.", "식사를 제공할 때 시간을 알려준다."]'::jsonb, 5, NULL, NULL, '{"1": "환경에 변화를 주는 것은 오히려 혼란을 초래할 수 있습니다.\n[정답]", "5": "식사 제공 시 시간을 알려주는 것은 지남력 향상에 도움이 됩니다.", "3": "텔레비전을 크게 틀어 놓는 것은 집중을 방해할 수 있습니다.", "4": "낮 동안 커튼을 쳐서 빛을 차단하는 것은 불규칙한 환경을 만들 수 있습니다.", "2": "달력, 시계 등을 없애는 것은 지남력 유지에 도움이 되지 않습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Sảng khoái", "def_ko": "혼란 또는 인지 기능의 장애", "def_vi": "Sự nhầm lẫn hoặc rối loạn chức năng nhận thức"}, {"term_ko": "지남력", "term_vi": "Phương hướng", "def_ko": "사람이나 장소에 대한 인식과 기억", "def_vi": "Nhận thức và ghi nhớ về người hoặc địa điểm"}, {"term_ko": "달력", "term_vi": "Lịch", "def_ko": "날짜를 표시하는 도구", "def_vi": "Công cụ đánh dấu ngày"}, {"term_ko": "식사", "term_vi": "Bữa ăn", "def_ko": "음식 섭취", "def_vi": "Tiêu thụ thực phẩm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1007, '5', '섬망 증상이 있는 대상자의 지남력을 유지하는 방법은?', '["환경에 변화를 준다.", "달력, 시계 등을 없앤다.", "텔레비전을 크게 틀어 놓는다.", "낮 동안 커튼을 쳐서 빛을 차단한다.", "식사를 제공할 때 시간을 알려준다."]'::jsonb, 5, NULL, NULL, '{"1": "환경을 변화시키면 혼란을 가중시킬 수 있어 오히려 지남력 유지에 도움이 되지 않는다.\n[정답]", "5": "식사를 제공할 때 시간을 알려주면 대상자가 시간이 이해되고 지남력을 유지하는 데 도움이 된다.", "2": "달력과 시계는 시간을 알려주는 도구로 지남력 유지에 필요하다.", "3": "텔레비전 소음은 혼란을 초래할 수 있으며 도움이 되지 않는다.", "4": "낮 동안의 빛을 차단하면 일주기 리듬에 문제가 생겨 지남력 유지에 방해가 된다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Mê sảng", "def_ko": "정신 혼란 상태", "def_vi": "Trạng thái rối loạn tinh thần"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1006, '5', '섬망에 대한 설명으로 옳은 것은?', '["만성질환이다.", "신체 생리적 변화는 적다.", "주의력이 감소한다.", "증상의 기복이 약하다.", "수면양상이 규칙적이다."]'::jsonb, 3, NULL, NULL, '{"1": "섬망은 급성 질환으로 만성질환이 아닙니다.\n[정답]", "3": "섬망은 주의력이 감소하는 특징을 가지고 있습니다.", "2": "섬망에서는 신체 생리적 변화가 뚜렷하게 나타날 수 있습니다.", "4": "섬망의 증상은 기복이 심합니다.", "5": "섬망 환자의 수면양상은 불규칙적입니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Delirium", "def_ko": "혼란스러운 정신 상태", "def_vi": "Trạng thái tinh thần hỗn loạn"}, {"term_ko": "주의력", "term_vi": "Sự chú ý", "def_ko": "주의를 기울이는 능력", "def_vi": "Khả năng tập trung"}, {"term_ko": "만성질환", "term_vi": "Bệnh mãn tính", "def_ko": "장기적인 질환", "def_vi": "Bệnh kéo dài"}, {"term_ko": "생리적", "term_vi": "Sinh lý", "def_ko": "생리와 관련된", "def_vi": "Liên quan đến sinh lý"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 상태의 외부적인 표시", "def_vi": "Dấu hiệu bên ngoài của bệnh hoặc trạng thái"}, {"term_ko": "기복", "term_vi": "Biến động", "def_ko": "변동이 심함", "def_vi": "Biến đổi lớn"}, {"term_ko": "수면양상", "term_vi": "Mô hình giấc ngủ", "def_ko": "수면의 패턴", "def_vi": "Mô thức giấc ngủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1005, '5', '섬망의 증상에 대한 설명으로 옳은 것은?', '["서서히 나타난다.", "회복이 불가능하다.", "의식에 변화가 없다.", "단독으로만 발생한다.", "호전과 악화가 반복된다."]'::jsonb, 5, NULL, NULL, '{"1": "섬망의 증상은 급작스럽게 나타날 수 있습니다.\n[정답]", "5": "섬망은 증상이 호전과 악화를 반복하는 특징이 있습니다.", "2": "섬망은 회복이 가능할 수 있습니다.", "3": "섬망은 의식 변화가 있으므로 이 보기의 설명은 틀립니다.", "4": "섬망은 다양한 원인으로 발생할 수 있으며, 단독으로 발생하지 않습니다."}'::jsonb, '[{"term_ko": "섬망", "term_vi": "Mê sảng", "def_ko": "의식의 변화가 있는 상태", "def_vi": "Trạng thái có sự thay đổi ý thức"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병의 징후", "def_vi": "Dấu hiệu của bệnh"}, {"term_ko": "호전", "term_vi": "Cải thiện", "def_ko": "증상이 나아짐", "def_vi": "Sự phục hồi triệu chứng"}, {"term_ko": "악화", "term_vi": "Xấu đi", "def_ko": "증상이 나빠짐", "def_vi": "Sự xấu đi của triệu chứng"}, {"term_ko": "회복", "term_vi": "Hồi phục", "def_ko": "건강이 회복되는 것", "def_vi": "Việc phục hồi sức khỏe"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1004, '5', '의식장애로 인해 수 시간 내지 수일에 걸쳐 급격하게 발생하여, 증상의 기복이 심하고 인지장애, 정서불안 증세를 보이는 질환은?', '["섬망", "치매", "뇌졸증", "우울증", "파킨슨병"]'::jsonb, 1, NULL, NULL, '{"1": "섬망은 의식장애가 급격하게 발생하며 증상의 기복이 심한 특징이 있습니다.\n[정답]", "2": "치매는 일반적으로 진행성이며 급격하게 발생하지 않습니다.", "3": "뇌졸증은 급성 질환이지만, 증상의 기복이 섬망에 비해 덜 심합니다.", "4": "우울증은 정서적 불안을 동伴하지만, 의식장애와는 다릅니다.", "5": "파킨슨병은 주로 운동장애와 관련된 질환입니다."}'::jsonb, '[{"term_ko": "의식장애", "term_vi": "Rối loạn ý thức", "def_ko": "의식을 잃거나 변형된 상태", "def_vi": "Trạng thái thay đổi hoặc mất ý thức"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1003, '5', '우울증 대상자를 돕는 방법으로 옳은 것은?', '["곧 괜찮아질 것이라고 위로한다.", "햇볕을 쬐며 걷기운동을 하게 한다.", "사회적 활동을 줄이고 혼자 있게 한다.", "항우울제 용량을 늘려야 한다고 말한다.", "감정 표현을 자제시키고 스스로 극복하게 한다."]'::jsonb, 2, NULL, NULL, '{"1": "곧 괜찮아질 것이라는 위로는 실제 환자의 상태를 무시하는 것으로 도움이 되지 않습니다.\n[정답]", "2": "햇볕을 쬐며 걷기 운동은 기분을 좋게 하고 우울증을 완화하는 데 도움이 됩니다.", "3": "사회적 활동을 줄이고 혼자 있게 하는 것은 우울증을 악화시킬 수 있습니다.", "4": "항우울제 용량을 늘려야 한다는 권장은 의료 전문가가 해야 할 일입니다.", "5": "감정 표현을 자제시키고 스스로 극복하게 하는 것은 환자에게 부정적인 영향을 미칠 수 있습니다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "정신적 질병의 일종으로 기분 저하가 주 증상", "def_vi": "Một loại bệnh tâm thần với triệu chứng chính là tâm trạng xuống."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1002, '5', '우울증 발생 가능성이 높은 대상자의 상황은?', '["가족과 함께 살고 이다.", "타인에 대한 관심이 증가한다.", "낮에 햇빛을 쐬며 운동을 한다.", "최근 갑상샘기능저하증을 진단받았다.", "식욕과 체중이 변화 없이 유지되고 있다."]'::jsonb, 4, NULL, NULL, '{"1": "가족과 함께 사는 것은 정서적 지지로 우울증 발생 가능성을 낮춘다.", "2": "타인에 대한 관심 증가도 긍정적인 변화로 우울증 위험을 낮춘다.", "3": "햇빛을 쬐고 운동을 하는 것은 정신 건강에 긍정적 영향을 미쳐 우울증 발생 가능성을 줄인다.\n[정답]", "4": "갑상샘기능저하증은 우울증과 관련이 있는 신체적 요인으로, 우울증 발생 가능성을 높인다.", "5": "식욕과 체중 변화가 없다는 것은 우울증의 증상이 아닐 수도 있다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "갑상샘기능저하증", "def_ko": "우울증(Trầm cảm)", "def_vi": "갑상선의 기능 저하( Suy giáp)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1001, '5', '노인에게 나타나는 우울증 특성은?', '["인지기능은 그대로 유지된다.", "무기력과 흥분이 교대로 나타난다.", "본인 스스로 우울증을 자각하기 쉽다.", "주변 사람들이 우울증임을 쉽게 발견한다.", "두통, 소화불량 등 신체 증상을 호소한다."]'::jsonb, 5, NULL, NULL, '{"1": "인지기능은 유지되지만, 우울증을 앓고 있는 경우 인지능력에 영향을 줄 수 있습니다.\n[정답]", "5": "두통, 소화불량 등 신체 증상을 호소하는 것은 노인 우울증의 일반적인 증상입니다.", "2": "무기력과 흥분이 함께 나타나는 것도 있지만, 이는 일반적인 양상은 아닙니다.", "3": "본인 스스로 자각하기 어려운 경우가 많습니다.", "4": "주변 사람들이 발견하기 어려울 수 있습니다."}'::jsonb, '[{"term_ko": "우울증", "term_vi": "Trầm cảm", "def_ko": "기분이 낮아지며, 흥미나 즐거움이 감소하는 상태", "def_vi": "Tình trạng cảm xúc giảm sút, mất hứng thú hoặc niềm vui"}, {"term_ko": "인지기능", "term_vi": "Chức năng nhận thức", "def_ko": "사고, 기억, 인식의 능력", "def_vi": "Khả năng suy nghĩ, ghi nhớ và nhận thức"}, {"term_ko": "신체 증상", "term_vi": "Triệu chứng cơ thể", "def_ko": "병이나 고통으로 인해 나타나는 신체적 징후", "def_vi": "Dấu hiệu vật lý do bệnh tật hoặc đau đớn gây ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (1000, '5', '대상자가 말수가 줄고 매사에 관심이 없으며, 식욕부진과 함게 수면양상이 변할 때 의심되는 질환은?', '["섬망", "우울증", "치매", "환각", "망상"]'::jsonb, 2, NULL, NULL, '{"1": "섬망은 주로 혼란과 인지 장애를 동반하므로 이 상황과는 다르다.\n[정답]", "2": "우울증은 말수가 줄고, 관심이 없으며, 식욕부진과 수면 양상 변화가 있는 전형적인 증상이다.", "3": "치매는 인지 기능 저하가 중심이며, 이 경우와는 다르게 진행된다.", "4": "환각은 현실과 다른 감각적 경험을 의미하며, 여기서만의 증상으로는 우울증이라고 보기 어렵다.", "5": "망상은 비현실적인 믿음을 포함하나, 대상자의 증상이 구체적으로 우울증 쪽으로 기울어진다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Đối tượng", "def_ko": "어떤 사건의 피해자나 관찰자의 사람", "def_vi": "Người chịu ảnh hưởng của sự kiện hoặc quan sát"}, {"term_ko": "말수", "term_vi": "Lượng lời nói", "def_ko": "대화의 양이나 빈도", "def_vi": "Số lượng hoặc tần suất nói"}, {"term_ko": "관심", "term_vi": "Sự quan tâm", "def_ko": "어떤 일에 대한 주의나 흥미", "def_vi": "Sự chú ý hoặc hứng thú với một điều gì đó"}, {"term_ko": "식욕부진", "term_vi": "Giảm cảm giác thèm ăn", "def_ko": "음식에 대한 욕구 감소", "def_vi": "Giảm nhu cầu ăn uống"}, {"term_ko": "수면양상", "term_vi": "Mô hình giấc ngủ", "def_ko": "수면의 특징이나 패턴", "def_vi": "Đặc điểm hoặc cách thức của giấc ngủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (999, '5', '당뇨병 관리에 관한 설명으로 옳은 것은?', '["격렬한 운동으로 열량을 소비한다.", "혈당 조절을 위해 공복 시에만 운동한다.", "발의 상처 유무를 주의 깊게 관찰한다.", "혈당 조절을 위해 탄수화물 섭취를 금한다.", "운동량이 많은 날은 인슐린 투여량을 늘린다."]'::jsonb, 3, NULL, NULL, '{"1": "격렬한 운동은 당뇨병 환자에게 위험할 수 있으며, 적절한 운동을 권장합니다.\n[정답]", "3": "당뇨병 환자는 발에 상처가 생기기 쉬우므로 정기적으로 관찰하고 관리해야 합니다.", "2": "공복 시에만 운동하는 것은 혈당 조절에 도움이 되지 않습니다.", "4": "탄수화물은 에너지 공급원으로 필요하며, 적절한 섭취가 중요합니다.", "5": "운동량이 많은 날은 인슐린 투여량 조절이 필요하지만 무조건 늘리는 것은 아닙니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "당을 제대로 조절하지 못해 발생하는 질병", "def_vi": "Bệnh do không kiểm soát được lượng đường"}, {"term_ko": "격렬한 운동", "term_vi": "Tập thể dục mạnh", "def_ko": "신체적으로 힘든 활동", "def_vi": "Hoạt động thể chất căng thẳng"}, {"term_ko": "혈당", "term_vi": "Lượng đường trong máu", "def_ko": "혈액 속에 있는 포도당의 양", "def_vi": "Lượng glucose trong máu"}, {"term_ko": "탄수화물", "term_vi": "Carbohydrate", "def_ko": "질병을 예방하고 치료하는 데 중요한 영양소", "def_vi": "Chất dinh dưỡng quan trọng trong việc phòng ngừa và điều trị bệnh"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "혈당을 조절하는 호르몬", "def_vi": "Hormone điều chỉnh lượng đường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (998, '5', '당뇨병 대상자의 발 관리 방법으로 옳은 것은?', '["발톱의 양 끝을 둥글게 자른다.", "뜨거운 물로 발을 자주 씻게 한다.", "손톱깎이로 굳은살과 티눈을 잘라낸다.", "발가락이 노출되지 않게 양말을 신는다.", "발을 씻은 후에 물기는 남겨 습기를 유지한다."]'::jsonb, 4, NULL, NULL, '{"1": "발톱의 양 끝을 둥글게 자르는 것은 권장되지 않습니다. 발톱은 일자로 자르는 것이 안전합니다.\n[정답]", "4": "발가락이 노출되지 않게 양말을 신는 것은 발을 보호하고 체온을 유지하는데 도움이 됩니다.", "2": "뜨거운 물로 발을 씻는 것은 피부에 손상을 줄 수 있어 바람직하지 않습니다.", "3": "굳은살과 티눈을 손톱깎이로 자르는 것은 감염의 위험이 있으며 전문가에게 맡기는 것이 안전합니다.", "5": "발을 씻은 후 습기를 남기는 것은 세균의 성장에 기여할 수 있어 피해야 합니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병적 상태로 혈당 조절이 어려운 질환", "def_vi": "Tình trạng bệnh viện không kiểm soát được đường huyết"}, {"term_ko": "발 관리", "term_vi": "Chăm sóc chân", "def_ko": "발의 건강과 위생을 유지하는 방법", "def_vi": "Cách duy trì sức khỏe và vệ sinh của bàn chân"}, {"term_ko": "발톱", "term_vi": "Móng chân", "def_ko": "발끝에 위치한 단단한 표면", "def_vi": "Bề mặt cứng nằm ở đầu ngón chân"}, {"term_ko": "양말", "term_vi": "Tất", "def_ko": "발을 감싸는 의류", "def_vi": "Thời trang bao bọc bàn chân"}, {"term_ko": "굳은살", "term_vi": "Da chết", "def_ko": "피부가 두꺼워진 부분", "def_vi": "Vùng da dày lên"}, {"term_ko": "티눈", "term_vi": "Mụn nước", "def_ko": "발에 생기는 고통스러운 감염", "def_vi": "Nhiễm trùng gây đau ở chân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (997, '5', '당뇨병 대상자에게 권장하는 운동요법으로 옳은 것은?', '["하루에 10분 이내로 운동한다.", "식사 후 30분~60분 경에 운동을 시작한다.", "공복에 운동할 때는 혈당강하제를 갖고 다닌다.", "혈당이 300mg/dl 이상 시 바로 운동을 시작한다.", "약물복용 중에는 치료효과를 얻기 위해 운동을 삼간다."]'::jsonb, 2, NULL, NULL, '{"1": "하루에 10분 이내로 운동하는 것은 권장되지 않습니다. 운동은 최소 30분 이상이 효과적입니다.\n[정답]", "2": "식사 후 30분~60분 경에 운동을 시작하는 것이 혈당 조절에 좋습니다.", "3": "공복에 운동할 때는 혈당강하제를 갖고 다녀야 하지만, 항상 복용하는 것이 아니라 필요시 사용해야 합니다.", "4": "혈당이 300mg/dl 이상일 때는 운동을 피해야 합니다.", "5": "약물복용 중에도 적절한 운동은 치료효과에 긍정적 영향을 미칩니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병명(한국어)", "def_vi": "Tên bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (996, '5', '저혈당 증상이 보이는 대상자에게 응급처치를 하지 않았을 때 발생할 수 있는 합병증은?', '["위염", "간 손상", "뇌 손상", "요도염", "방광염"]'::jsonb, 3, NULL, NULL, '{"1": "위염: 저혈당과 직접적인 관계가 없는 질환이다.\n[정답]", "3": "뇌 손상: 저혈당 상태가 지속되면 뇌에 필요한 포도당이 부족해져 뇌 손상이 발생할 수 있다.", "2": "간 손상: 저혈당과는 관련이 적으며, 주로 간의 대사 기능과 관련이 있다.", "4": "요도염: 저혈당과는 직접적인 연관성이 없다.", "5": "방광염: 방광의 염증으로 저혈당과는 관련이 없다."}'::jsonb, '[{"term_ko": "저혈당", "term_vi": "Hạ đường huyết", "def_ko": "혈당이 정상보다 낮은 상태", "def_vi": "Trạng thái đường huyết thấp hơn bình thường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (995, '5', '당뇨병을 관리하는 방법으로 옳은 것은?', '["맨발로 운동화를 신고 운동한다.", "인슐린주사약을 입으로 복용한다.", "감염이 이는 경우 저혈당에 대비한다.", "일주일에 1회, 최소 30분 이상 운동한다.", "활동량이 증가할 경우 저혈당에 대비한다."]'::jsonb, 5, NULL, NULL, '{"1": "맨발로 운동하면 발에 상처가 생길 위험이 증가합니다.\n[정답]", "5": "활동량이 증가할 경우 저혈당에 대비하는 것은 매우 중요합니다.", "2": "인슐린 주사는 반드시 주사 형태로 투여해야 하며, 입으로 복용할 수 없습니다.", "3": "감염 발생 시 저혈당 대비는 중요하지만, 처음부터 저혈당에 대비하기보다는 상황에 따라 대처해야 합니다.", "4": "운동은 중요하지만 주 1회는 부족하며, 적어도 매일 또는 주 3회 이상 권장됩니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병명(한국어)", "def_vi": "bệnh lý liên quan đến việc cao đường huyết"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "호르몬(한국어)", "def_vi": "hormone điều tiết đường huyết"}, {"term_ko": "저혈당", "term_vi": "Hạ đường huyết", "def_ko": "혈당이 낮은 상태(한국어)", "def_vi": "tình trạng đường huyết thấp"}, {"term_ko": "운동", "term_vi": "Tập thể dục", "def_ko": "신체활동(한국어)", "def_vi": "hoạt động thể chất"}, {"term_ko": "감염", "term_vi": "Nhiễm trùng", "def_ko": "질병의 원인(한국어)", "def_vi": "nguyên nhân gây bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (994, '5', '인슐린 주사를 맞고 식사를 하지 않은 당뇨병 대상자에게 나타날 수 있는 증상은?', '["식은땀", "소화불량", "체온 상승", "식욕 증가", "소변량 증가"]'::jsonb, 1, NULL, NULL, '{"1": "식은땀: 저혈당 시 나타나는 일반적인 증상 중 하나입니다.\n[정답]", "2": "소화불량: 저혈당과는 관련이 적은 증상입니다.", "3": "체온 상승: 저혈당과는 관련이 없습니다.", "4": "식욕 증가: 저혈당 시 보통 반대되는 증상입니다.", "5": "소변량 증가: 당뇨병의 증상 중 하나이나, 저혈당과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "혈당 조절 호르몬", "def_vi": "Hormone điều tiết đường huyết"}, {"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "혈당 조절에 문제가 있는 질환", "def_vi": "Bệnh có vấn đề trong việc điều chỉnh đường huyết"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 상태의 표시", "def_vi": "Những điều hiển thị của bệnh tật hoặc tình trạng"}, {"term_ko": "저혈당", "term_vi": "Hạ đường huyết", "def_ko": "혈당이 비정상적으로 낮은 상태", "def_vi": "Tình trạng đường huyết bất thường thấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (993, '5', '당뇨병의 원인으로 옳은 것은?', '["규칙적인 식사", "고섬유질 음식섭취", "규칙적인 운동", "표준체중", "유전적 요인"]'::jsonb, 5, NULL, NULL, '{"1": "규칙적인 식사는 건강에 좋지만, 당뇨병의 직접적인 원인은 아닙니다.", "2": "고섬유질 음식섭취는 당뇨병 관리에 도움이 되지만, 원인은 아닙니다.", "3": "규칙적인 운동은 당뇨병 예방에 중요하지만, 원인은 아닙니다.", "4": "표준체중 또한 당뇨병 예방에 중요하나, 직접적인 원인은 아닙니다.\n[정답]", "5": "유전적 요인은 당뇨병 발생에 중요한 역할을 하는 원인 중 하나입니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "병의 상태", "def_vi": "Tình trạng bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (992, '5', '당뇨병의 대표적인 증상으로 옳은 것은?', '["수분 섭취량 감소", "식사량 감소", "질 감염의 감소", "말초 부종 증가", "소변 배설량 증가"]'::jsonb, 5, NULL, NULL, '{"1": "수분 섭취량 감소는 당뇨병의 증상과 관련이 없습니다.", "2": "식사량 감소는 일반적으로 당뇨병의 증상으로 나타나지 않습니다.", "3": "질 감염의 감소는 당뇨병과는 반대되는 내용입니다.", "4": "말초 부종 증가도 당뇨병의 대표적인 증상이 아닙니다.\n[정답]", "5": "소변 배설량 증가는 당뇨병의 대표적인 증상 중 하나입니다."}'::jsonb, '[{"term_ko": "당뇨병", "term_vi": "증상", "def_ko": "뜻(한국어) - Bệnh tiểu đường: 뜻(베트남어)", "def_vi": "뜻(한국어) - Triệu chứng: 뜻(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (991, '5', '인슐린이 분비되지 않거나 부족할 경우에 나타나는 질환의 증상으로 옳은 것은?', '["체중 증가", "질 분비물 감소", "식욕 감소", "상처 치유 지연", "성기능 증가"]'::jsonb, 4, NULL, NULL, '{"1": "체중 증가는 인슐린 저항성과 관련이 있을 수 있지만, 인슐린 분비 부족의 직접적인 증상은 아닙니다.", "2": "질 분비물 감소는 일반적으로 인슐린과 관계가 없는 증상입니다.", "3": "식욕 감소는 인슐린의 부족으로는 보통 나타나지 않습니다.\n[정답]", "4": "상처 치유 지연은 인슐린 부족으로 인해 발생할 수 있는 증상입니다.", "5": "성기능 증가는 인슐린 부족과 관련이 없습니다."}'::jsonb, '[{"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "호르몬의 일종, 혈당을 조절하는 역할", "def_vi": "Một loại hormone, có vai trò điều chỉnh lượng đường trong máu"}, {"term_ko": "체중 증가", "term_vi": "Tăng cân", "def_ko": "몸의 무게가 늘어나는 것", "def_vi": "Sự tăng trọng lượng cơ thể"}, {"term_ko": "상처 치유", "term_vi": "Lành vết thương", "def_ko": "부상이 회복되는 과정", "def_vi": "Quá trình phục hồi vết thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (990, '5', '노화로 인한 내분비계 특성 중 인슐린이 부족한 대상자에게 나타나는 증상으로 옳은 것은?', '["공복혈당 상승", "시력 향상", "체중 증가", "갈증 감소", "성 욕구 증가"]'::jsonb, 1, NULL, NULL, '{"1": "공복혈당이 상승하는 것은 인슐린 부족으로 인해 당 대사가 제대로 이루어지지 않아 발생한다.\n[정답]", "2": "시력 향상은 인슐린 부족과 관련이 없다.", "3": "체중 증가는 인슐린 부족 시 발생할 수 있으나, 일반적으로 감소가 더 흔하다.", "4": "갈증 감소는 일반적으로 인슐린 부족과 맞지 않으며 오히려 갈증이 증가할 수 있다.", "5": "성 욕구 증가는 인슐린 부족과 관련이 없다."}'::jsonb, '[{"term_ko": "내분비계", "term_vi": "Hệ nội tiết", "def_ko": "내분비 시스템", "def_vi": "Hệ thống tiết hormone"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (989, '5', '노화에 따른 내분비계 특성으로 옳은 것은?', '["포도당 대사능력이 감소된다.", "인슐린에 대한 민감성 증가로 저혈당이 된다.", "갑상선의 크기가 커진다.", "갑상선 호르몬의 분비량이 증가한다.", "기초대사율이 증가한다."]'::jsonb, 1, NULL, NULL, '{"1": "노화 과정에서 포도당 대사능력이 감소하는 것은 일반적으로 맞는 사실입니다.\n[정답]", "2": "노화와 관련하여 인슐린에 대한 민감성은 감소하는 경향이 있습니다.", "3": "노화가 진행됨에 따라 갑상선의 크기가 줄어드는 경향이 더 많이 관찰됩니다.", "4": "노화에 따라 갑상선 호르몬의 분비량은 보통 감소하는 경향이 있습니다.", "5": "기초대사율은 노화 과정에서 감소하는 경향이 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노화(한국어)", "def_vi": "lão hóa"}, {"term_ko": "내분비계", "term_vi": "Hệ nội tiết", "def_ko": "내분비계(한국어)", "def_vi": "hệ thống tiết hormone"}, {"term_ko": "포도당", "term_vi": "Glucose", "def_ko": "포도당(한국어)", "def_vi": "glucose"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "인슐린(한국어)", "def_vi": "insulin"}, {"term_ko": "민감성", "term_vi": "Độ nhạy", "def_ko": "민감성(한국어)", "def_vi": "độ nhạy"}, {"term_ko": "갑상선", "term_vi": "Tuyến giáp", "def_ko": "갑상선(한국어)", "def_vi": "tuyến giáp"}, {"term_ko": "호르몬", "term_vi": "Hormone", "def_ko": "호르몬(한국어)", "def_vi": "hormone"}, {"term_ko": "기초대사율", "term_vi": "Tỷ lệ trao đổi cơ bản", "def_ko": "기초대사율(한국어)", "def_vi": "tỷ lệ trao đổi cơ bản"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (988, '5', '노화로 인한 내분비계 변화로 옳은 것은?', '["뇌하수체가 커진다.", "인슐린 분비량이 늘어난다.", "에스트로겐 분비가 감소한다.", "포도당 대사능력이 좋아진다.", "콜레스테롤 수치가 감소한다."]'::jsonb, 3, NULL, NULL, '{"1": "뇌하수체의 크기 변화는 노화에 따라 고정적이지 않으며, 반드시 커지는 것은 아닙니다.\n[정답]", "3": "노화가 진행됨에 따라 에스트로겐의 분비는 감소하게 됩니다.", "2": "인슐린 분비량은 노화와 함께 감소하거나 일정하게 유지되는 경향이 있습니다.", "4": "노화에 따라 포도당 대사능력은 저하되는 경우가 많습니다.", "5": "콜레스테롤 수치는 노화에 따라 증가할 수 있으며, 반드시 감소하는 것은 아닙니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들어감", "def_vi": "Sự già đi"}, {"term_ko": "내분비계", "term_vi": "Hệ nội tiết", "def_ko": "호르몬을 분비하는 기관의 집합", "def_vi": "Tập hợp các cơ quan tiết hormone"}, {"term_ko": "에스트로겐", "term_vi": "Estrogen", "def_ko": "여성의 성호르몬", "def_vi": "Hormone giới tính nữ"}, {"term_ko": "인슐린", "term_vi": "Insulin", "def_ko": "혈당 조절 호르몬", "def_vi": "Hormone điều chỉnh đường huyết"}, {"term_ko": "콜레스테롤", "term_vi": "Cholesterol", "def_ko": "지방의 일종", "def_vi": "Một loại chất béo"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (987, '5', '노인성 난청이 있는 대상자와 의사소통하는 방법 중 옳은 것은?', '["옆에서 귀에 대고 큰 소리로 말한다.", "소음이 있는 곳에서 대화한다.", "얼굴을 보면서 천천히 또박또박 말한다.", "보청기를 사용 시 고음의 큰 소리가 효과적이다.", "청력을 복구시키기 위해 약물치료를 한다."]'::jsonb, 3, NULL, NULL, '{"1": "옆에서 귀에 대고 큰 소리로 말하는 것은 불필요한 소음을 유발할 수 있다.\n[정답]", "3": "얼굴을 보면서 천천히 또박또박 말하면 환자가 입 모양을 보고 이해하기 쉽다.", "2": "소음이 있는 곳에서 대화하면 의사소통이 어려워진다.", "4": "보청기를 사용할 때 고음의 큰 소리는 오히려 역효과를 줄 수 있다.", "5": "청력을 복구하기 위한 약물치료는 일반적으로 가능하지 않다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Điếc tuổi già", "def_ko": "나이가 들어서 발생하는 청각 손실", "def_vi": "Mất thính giác do tuổi cao"}, {"term_ko": "의사소통", "term_vi": "Giao tiếp", "def_ko": "정보를 주고받는 방법", "def_vi": "Cách truyền đạt thông tin"}, {"term_ko": "보청기", "term_vi": "Máy trợ thính", "def_ko": "청각 보조 기구", "def_vi": "Thiết bị hỗ trợ nghe"}, {"term_ko": "소음", "term_vi": "Tiếng ồn", "def_ko": "방해가 되는 소리", "def_vi": "Âm thanh gây cản trở"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (986, '5', '노인성 난청의 중심으로 옳은 것은?', '["고음에서의 난청", "음의 전달 능력 증가", "평형감각의 증가", "언어 구분능력 증가", "소리에 대한 민감성 증가"]'::jsonb, 1, NULL, NULL, '{"1": "고음에서의 난청은 노인성 난청에서 일반적으로 나타나는 특징이다.\n[정답]", "2": "음의 전달 능력이 감소하기 때문에 소리의 전달 능력은 증가하지 않는다.", "3": "노인성 난청은 평형감각의 감소를 동반하는 경우가 많다.", "4": "언어 구분 능력은 저하되며, 노인들은 소리의 구분이 어려운 경우가 많다.", "5": "노인성 난청에서는 소리에 대한 민감성이 감소한다."}'::jsonb, '[{"term_ko": "노인성 난청", "term_vi": "Khiếm thính người già", "def_ko": "노인에서 발생하는 청각 장애", "def_vi": "Khiếm thính xảy ra ở người cao tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (985, '5', '노화에 따른 고막, 내이의 퇴행성 변화에 의해 청력이 감소되는 질환은?', '["이석증", "중이염", "노인성 난청", "내이염", "이명"]'::jsonb, 3, NULL, NULL, '{"1": "이석증은 귀의 균형 문제와 관련된 질환으로 청력 저하와는 관련이 적다.\n[정답]", "3": "노인성 난청은 노화로 인한 청력 감소를 의미하며, 가장 일반적인 노인들의 청력 장애이다.", "2": "중이염은 주로 염증으로 인한 청력 저하와 관련이 있다.", "4": "내이염은 내이에 염증이 생겨 청력에 영향을 줄 수 있으나 노화와의 직접적인 연관은 적다.", "5": "이명은 소리가 없는데도 귓속에서 소리가 나는 증상으로, 주로 소음 등의 여러 원인으로 발생한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 들어감(한국어)", "def_vi": "Sự tăng tuổi"}, {"term_ko": "고막", "term_vi": "Màng nhĩ", "def_ko": "귀 내부의 막(한국어)", "def_vi": "Màng trong tai"}, {"term_ko": "퇴행성", "term_vi": "Thoái hóa", "def_ko": "점진적으로 나빠지는(한국어)", "def_vi": "Xấu đi dần dần"}, {"term_ko": "청력", "term_vi": "Thính lực", "def_ko": "소리를 듣는 능력(한국어)", "def_vi": "Khả năng nghe"}, {"term_ko": "난청", "term_vi": "Điếc", "def_ko": "듣는 능력이 떨어지는 상태(한국어)", "def_vi": "Tình trạng mà khả năng nghe giảm"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (984, '5', '고혈압이나 당뇨병 등의 합병증으로 올 수 있는 안과질환은?', '["녹내장", "백내장", "결막염", "망막염", "각막염"]'::jsonb, 2, NULL, NULL, '{"1": "녹내장은 고혈압에 의해 악화될 수 있지만, 직접적인 합병증으로 보기 어렵습니다.\n[정답]", "2": "백내장은 당뇨병과 관련하여 발생할 수 있는 합병증 중 하나입니다.", "3": "결막염은 일반적인 안과 질환으로 만성 질환과 직접적인 연관이 적습니다.", "4": "망막염은 여러 원인으로 발생하지만 고혈압이나 당뇨병의 직접적인 합병증으로 보기 어렵습니다.", "5": "각막염 또한 일반적인 염증으로 만성 질환과의 관련성이 낮습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Huyết áp cao", "def_ko": "혈압이 비정상적으로 높은 상태", "def_vi": "Trạng thái áp lực máu bất thường cao"}, {"term_ko": "당뇨병", "term_vi": "Bệnh tiểu đường", "def_ko": "인슐린의 문제로 발생하는 만성 질환", "def_vi": "Bệnh mãn tính do vấn đề về insulin"}, {"term_ko": "합병증", "term_vi": "Biến chứng", "def_ko": "주 질병에서 발생하는 추가적인 문제", "def_vi": "Vấn đề thêm phát sinh từ bệnh chính"}, {"term_ko": "안과질환", "term_vi": "Bệnh mắt", "def_ko": "눈에 관련된 질병", "def_vi": "Bệnh liên quan đến mắt"}, {"term_ko": "녹내장", "term_vi": "Glaucoma", "def_ko": "시신경이 손상되는 질환", "def_vi": "Bệnh tổn thương dây thần kinh thị giác"}, {"term_ko": "백내장", "term_vi": "Đục thủy tinh thể", "def_ko": "수정체가 혼탁해지는 질환", "def_vi": "Bệnh làm mờ thủy tinh thể"}, {"term_ko": "결막염", "term_vi": "Viêm kết mạc", "def_ko": "눈의 결막에 염증이 생긴 상태", "def_vi": "Tình trạng viêm kết mạc mắt"}, {"term_ko": "망막염", "term_vi": "Viêm võng mạc", "def_ko": "망막에 염증이 생기는 질환", "def_vi": "Bệnh gây viêm võng mạc"}, {"term_ko": "각막염", "term_vi": "Viêm giác mạc", "def_ko": "각막에 염증이 생기는 질환", "def_vi": "Bệnh gây viêm giác mạc"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (983, '5', '백내장 진단을 받은 대상자에게 나타나는 증상은?', '["좁은 시야", "안구 통증", "어두움 적응장애", "색깔변화 인식장애", "동공의 백색 혼탁"]'::jsonb, 5, NULL, NULL, '{"1": "좁은 시야는 일반적으로 녹내장 등의 다른 시각 질환에서 나타나는 증상입니다.", "2": "안구 통증은 백내장과 직접적으로 연결되지 않은 증상입니다.", "3": "어두움 적응장애는 백내장의 증상 중 하나일 수 있지만, 주된 증상은 아닙니다.", "4": "색깔변화 인식장애도 백내장의 증상 중 하나이지만, 주로 백내장으로 인해 가장 두드러지게 나타나는 증상은 아닙니다.\n[정답]", "5": "동공의 백색 혼탁은 백내장을 정확하게 나타내는 주요 증상입니다."}'::jsonb, '[{"term_ko": "백내장", "term_vi": "Đục thủy tinh thể", "def_ko": "안구의 수정체가 혼탁해져 시력이 저하되는 질환", "def_vi": "Bệnh làm mờ mắt do thủy tinh thể bị đục"}, {"term_ko": "동공", "term_vi": "Đồng tử", "def_ko": "안구의 중심부로 빛이 들어오는 구멍", "def_vi": "Lỗ ở giữa mắt cho phép ánh sáng đi vào"}, {"term_ko": "혼탁", "term_vi": "Mờ đục", "def_ko": "명확하지 않거나 흐린 상태", "def_vi": "Trạng thái không rõ ràng hoặc mờ"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병이나 상태가 나타나는 신체적 또는 심리적 이상", "def_vi": "Sự bất thường về thể chất hoặc tinh thần thể hiện cho bệnh hoặc tình trạng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (982, '5', '수정체가 혼탁해져서 뿌옇게 보일 때 나타나는 증상은?', '["두통, 구역질", "눈 이물감", "안구통증", "밝은 불빛에서의 눈부심", "실명"]'::jsonb, 4, NULL, NULL, '{"1": "두통과 구역질은 일반적인 증상이 아닌 혼탁한 수정체와 직접적인 연관이 없음.\n[정답]", "4": "밝은 불빛에서의 눈부심은 수정체 혼탁의 대표적인 증상이다.", "3": "안구통증은 따라올 수 있지만 혼탁과 직접적인 관련은 적다.", "2": "눈 이물감은 증상 중 하나이나 혼탁한 수정체와 명확히 연결되지 않는다.", "5": "실명은 최악의 결과로 추가 증상이 동반되어야 한다."}'::jsonb, '[{"term_ko": "수정체", "term_vi": "Thủy tinh thể", "def_ko": "렌즈(한국어)", "def_vi": "Thấu kính trong mắt"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (981, '5', '눈동자에 하얗게 백태가 껴서 잘 안보이게 되는 백내장의 발생 부위는?', '["공막", "각막", "홍채", "황반", "수정체"]'::jsonb, 5, NULL, NULL, '{"1": "공막: 눈의 흰자위를 형성하는 구조로, 백내장이 발생하지 않습니다.\n[정답]", "2": "수정체: 백내장은 수정체에 발생하여 시력을 저하시킵니다.", "3": "홍채: 눈의 색깔을 결정하는 부분이며, 백내장과 직접적인 관련이 없습니다.", "4": "황반: 망막의 중심 부분으로, 백내장과는 관계가 없습니다.", "5": "각막: 눈의 전면에 위치한 투명한 막으로, 백내장과는 관련이 없습니다."}'::jsonb, '[{"term_ko": "백내장", "term_vi": "Đục thủy tinh thể", "def_ko": "수정체가 혼탁해져 시력이 저하되는 질환", "def_vi": "Bệnh làm đục thủy tinh thể gây giảm thị lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (980, '5', '수정체가 혼탁해져서 빛이 들어가지 못하여 뿌옇게 보이는 질환은?', '["녹내장", "백내장", "결막염", "망막증", "황반변성"]'::jsonb, 2, NULL, NULL, '{"1": "녹내장은 시신경에 손상을 주는 질환으로, 수정체 혼탁과는 관련이 없습니다.\n[정답]", "2": "백내장은 수정체가 혼탁해져서 빛이 통과하지 못해 뿌옇게 보이는 질환입니다.", "3": "결막염은 눈의 결막에 염증이 생기는 질환으로, 수정체와는 관계가 없습니다.", "4": "망막증은 망막에 문제가 생기는 질환으로, 수정체의 혼탁과는 무관합니다.", "5": "황반변성은 망막의 중심부에 영향을 미치는 질환이지 수정체와는 관계가 없습니다."}'::jsonb, '[{"term_ko": "수정체", "term_vi": "Thể thủy tinh", "def_ko": "렌즈(한국어)", "def_vi": "Thủy tinh thể"}, {"term_ko": "혼탁", "term_vi": "Đục", "def_ko": "흐리다(한국어)", "def_vi": "Mờ"}, {"term_ko": "빛", "term_vi": "Ánh sáng", "def_ko": "빛(한국어)", "def_vi": "Ánh sáng"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "질병(한국어)", "def_vi": "Bệnh"}, {"term_ko": "뿌옇게", "term_vi": "Mờ", "def_ko": "흐림(한국어)", "def_vi": "Mờ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (979, '5', '녹내장 대상자의 일상생활 습관으로 옳은 것은?', '["낮 시간에 일광욕을 한다.", "무거운 물건 드는 것을 피한다.", "매일 윗몸일으키기 운동을 한다.", "장시간 고개를 숙이고 책을 본다.", "목이 꽉 조이도록 넥타이를 세게 맨다."]'::jsonb, 2, NULL, NULL, '{"1": "낮 시간에 일광욕을 한다. - 녹내장 환자는 햇빛이 직접 눈에 들어오는 것을 피하는 것이 좋습니다.\n[정답]", "2": "무거운 물건 드는 것을 피한다. - 무거운 물건을 들면 안압이 상승할 수 있으므로 피하는 것이 바람직합니다.", "3": "매일 윗몸일으키기 운동을 한다. - 윗몸일으키기는 안압을 상승시킬 수 있어 주의해야 합니다.", "4": "장시간 고개를 숙이고 책을 본다. - 고개를 숙이면 안압이 높아질 수 있습니다.", "5": "목이 꽉 조이도록 넥타이를 세게 맨다. - 목을 조이면 혈류 순환에 영향을 줄 수 있습니다."}'::jsonb, '[{"term_ko": "녹내장", "term_vi": "Glaucoma", "def_ko": "안압이 상승하여 시신경 손상으로 이어지는 질환", "def_vi": "Bệnh tăng áp lực mắt"}, {"term_ko": "일상생활", "term_vi": "Sinh hoạt hàng ngày", "def_ko": "매일 반복되는 생활 습관", "def_vi": "Thói quen lặp đi lặp lại hàng ngày"}, {"term_ko": "안압", "term_vi": "Áp lực mắt", "def_ko": "눈 안의 압력", "def_vi": "Áp lực trong mắt"}, {"term_ko": "무거운", "term_vi": "Nặng", "def_ko": "많은 무게를 가진", "def_vi": "Có trọng lượng lớn"}, {"term_ko": "운동", "term_vi": "Tập thể dục", "def_ko": "신체를 움직여 활동하는 것", "def_vi": "Hoạt động cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (978, '5', '다음과 같은 질환을 진단받은 대상자에게 나타나는 증상은?안압의 상승으로 시신경이 손상되어 시력이 점차 약해진다.', '["좁은 시야", "동공의 백색 혼탁", "밝은 불빛에서의 눈부심", "통증 없이 흐린 시력", "불빛 주위에 무지개가 보임"]'::jsonb, 1, NULL, NULL, '{"1": "좁은 시야는 시신경 손상으로 나타날 수 있는 증상입니다.\n[정답]", "2": "동공의 백색 혼탁은 시신경 손상과는 관련이 적습니다.", "3": "밝은 불빛에서의 눈부심은 일반적으로 시신경 손상과 관계가 없습니다.", "4": "통증 없이 흐린 시력은 특정 질환에서 나타날 수 있지만, 이 경우 시신경 손상과는 연결되지 않습니다.", "5": "불빛 주위에 무지개가 보이는 증상은 다른 시각 질환과 관련이 있습니다."}'::jsonb, '[{"term_ko": "안압", "term_vi": "Áp lực nội nhãn", "def_ko": "눈 안의 압력", "def_vi": "Áp lực bên trong mắt"}, {"term_ko": "시신경", "term_vi": "Dây thần kinh thị giác", "def_ko": "눈의 신경", "def_vi": "Dây thần kinh của mắt"}, {"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "질병에서 나타나는 표시", "def_vi": "Dấu hiệu xuất hiện trong bệnh tật"}, {"term_ko": "좁은 시야", "term_vi": "Tầm nhìn hẹp", "def_ko": "시야가 제한적인 상태", "def_vi": "Tình trạng nhìn hạn chế"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Cảm giác khó chịu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (977, '5', '다음 증상은 어떠한 질환에 대한 설명인가?좁은 시야, 눈 이물감 뿌옇게 혼탁한 각막, 안구통증, 두통', '["백내장", "녹내장", "결막염", "안구건조증", "다래끼"]'::jsonb, 2, NULL, NULL, '{"1": "백내장은 시야가 뿌옇게 보이는 증상을 포함하지만, 주로 시야의 포착과는 관련이 없습니다.\n[정답]", "2": "녹내장은 좁은 시야와 함께 안구통증 등의 증상으로 설명되며, 문제에서 언급된 모든 증상과 잘 연관됩니다.", "3": "결막염은 주로 눈의 충혈과 가려움증과 관련이 있으며, 제시된 증상과는 관련이 적습니다.", "4": "안구건조증은 통증과 불편함은 있지만, 좁은 시야와 관련이 없습니다.", "5": "다래끼는 눈꺼풀에 생기는 염증으로, 위의 증상들과 맞지 않습니다."}'::jsonb, '[{"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증세(한국어)", "def_vi": "triệu chứng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (976, '5', '다음은 노화에 따른 후각, 촉각의 특성이다. 옳은 것은?', '["후각세포가 증가한다.", "후각의 변화가 없다.", "촉각에 의한 접촉감을 쉽게 느낀다.", "통증을 호소하는 정도는 감소한다.", "통증에 둔감한 반응을 보인다."]'::jsonb, 5, NULL, NULL, '{"1": "후각세포는 노화와 함께 감소합니다.\n[정답]", "5": "노화가 진행되면 통증에 둔감해지는 경향이 있습니다.", "2": "노화로 인해 후각의 변화가 발생합니다.", "3": "촉각에 의한 접촉감이 둔화됩니다.", "4": "통증을 호소하는 정도는 오히려 증가할 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아지는 과정", "def_vi": "Quá trình trở nên lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (975, '5', '노화에 따른 미각의 변화로 옳은 것은?', '["혀의 미뢰개수 증가", "맛의 감지능력 증가", "구강건조 증상 증가", "단맛 감지기능 증가", "구강 점막의 재생 능력 증가"]'::jsonb, 3, NULL, NULL, '{"1": "혀의 미뢰 개수는 노화와 함께 감소한다.\n[정답]", "3": "구강 건조 증상은 노화와 함께 흔히 발생하는 증상이다.", "2": "맛의 감지 능력은 나이가 들면서 감소하는 경향이 있다.", "4": "노화에 따라 단맛 감지 기능은 감소하는 것이 일반적이다.", "5": "구강 점막의 재생 능력도 노화에 따라 감소한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "미각", "def_ko": "늙음; tuổi tác", "def_vi": "vị giác; vị giác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (974, '5', '노화에 따른 청각의 변화로 옳은 것은?', '["귓바퀴의 연골이 위축된다.", "외이도의 건조증이 감소한다.", "이관이 내측으로 커진다.", "고막이 두꺼워지고 음의 전달 능력이 감소된다.", "노인성 난청은 여성에게 흔하게 나타난다."]'::jsonb, 4, NULL, NULL, '{"1": "귓바퀴의 연골은 노화에 따라 위축되지만 이는 전반적인 변화 중 하나임.\n[정답]", "4": "고막은 노화와 관련하여 두꺼워지고 음의 전달 능력이 감소하는 경향이 있음.", "2": "외이도의 건조증은 노화에 따라 증가하는 경향이 있음.", "3": "이관이 내측으로 커지지 않음.", "5": "노인성 난청은 남성에게 더 흔하게 나타남."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이로 인한 변화", "def_vi": "sự thay đổi do tuổi tác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (973, '5', '노화에 따른 감각기계 변화로 옳은 것은?', '["평형감각이 향상된다.", "통증에 대한 민감성이 증가한다.", "같은 계열의 여러 색을 잘 구별한다.", "노인성 난청이 발생하여 고음을 잘 들을 수 있다.", "동공 지름 감소로 빛을 받아들이지 못해 밝은 곳을 좋아한다."]'::jsonb, 5, NULL, NULL, '{"1": "평형감각이 향상된다: 노화로 인해 평형감각은 오히려 감소한다.\n[정답]", "5": "동공 지름 감소로 빛을 받아들이지 못해 밝은 곳을 좋아한다: 노화에 따라 동공의 반응이 감소하여 밝은 곳을 선호하게 된다.", "2": "통증에 대한 민감성이 증가한다: 일반적으로 노화로 인해 통증에 대한 민감성이 감소한다.", "3": "같은 계열의 여러 색을 잘 구별한다: 노화로 인해 색 채도가 떨어지며 구별하기 어려운 경우가 많다.", "4": "노인성 난청이 발생하여 고음을 잘 들을 수 있다: 노화에 따라 고음이 잘 들리지 않는 경우가 많다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙어가는 과정", "def_vi": "Quá trình trở nên già"}, {"term_ko": "감각기계", "term_vi": "Hệ thống cảm giác", "def_ko": "감각을 담당하는 기관들", "def_vi": "Các cơ quan chịu trách nhiệm cảm giác"}, {"term_ko": "평형감각", "term_vi": "Cảm giác thăng bằng", "def_ko": "몸의 균형을 감지하는 능력", "def_vi": "Khả năng cảm nhận sự cân bằng của cơ thể"}, {"term_ko": "동공", "term_vi": "Đồng tử", "def_ko": "눈의 중앙에 있는 구멍", "def_vi": "Lỗ ở giữa mắt"}, {"term_ko": "고음", "term_vi": "Âm cao", "def_ko": "높은 주파수의 소리", "def_vi": "Âm thanh có tần số cao"}, {"term_ko": "밝은 곳", "term_vi": "Nơi sáng", "def_ko": "빛이 많이 있는 장소", "def_vi": "Nơi có nhiều ánh sáng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (972, '5', '수정체의 황화현상으로 색의 식별 능력이 떨어진 노인이 구별하기 어려운 색은?', '["빨간색, 노란색", "보라색, 남색", "빨간색, 초록색", "노란색, 남색", "흰색, 회색"]'::jsonb, 2, NULL, NULL, '{"1": "빨간색과 노란색은 일반적으로 인식하기 비교적 쉬운 색상입니다.\n[정답]", "2": "보라색과 남색은 특히 노인에게는 인식이 더 어려운 색상입니다.", "3": "빨간색과 초록색은 많은 경우 구별 능력이 유지됩니다.", "4": "노란색과 남색은 평균적으로 잘 구별됩니다.", "5": "흰색과 회색은 밝은 톤이어서 인식에 어려움이 덜합니다."}'::jsonb, '[{"term_ko": "수정체", "term_vi": "Thể thủy tinh", "def_ko": "눈 속의투명한 부분이자 초점을 맞추는 역할을 하는 부분", "def_vi": "Phần trong suốt của mắt có chức năng điều chỉnh tiêu cự."}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (971, '5', '노화에 따른 시각의 특성으로 옳은 것은?', '["각막반사의 증가", "눈부심의 감소", "빛 순응의 어려움 증가", "눈물의 양 증가", "가까운 물체에 초점을 맞추는 능력 증가"]'::jsonb, 3, NULL, NULL, '{"1": "각막반사는 노화와 관계없이 유지되므로 옳지 않습니다.", "2": "눈부심은 노화가 진행됨에 따라 증가하므로 옳지 않습니다.\n[정답]", "3": "노화에 따라 빛 순응의 어려움이 증가하는 것이 맞습니다.", "4": "나이가 들면서 눈물의 양은 보통 줄어들어 옳지 않습니다.", "5": "가까운 물체에 초점을 맞추는 능력은 감소하므로 옳지 않습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 많아지는 현상", "def_vi": "Hiện tượng già đi"}, {"term_ko": "시각", "term_vi": "Thị giác", "def_ko": "눈으로 사물을 보는 능력", "def_vi": "Khả năng nhìn thấy sự vật bằng mắt"}, {"term_ko": "각막", "term_vi": "Giác mạc", "def_ko": "눈의 가장 바깥층", "def_vi": "Lớp ngoài cùng của mắt"}, {"term_ko": "눈부심", "term_vi": "Ánh sáng chói", "def_ko": "밝은 빛에 의해 불편함을 느끼는 상태", "def_vi": "Tình trạng cảm thấy khó chịu do ánh sáng chói"}, {"term_ko": "빛 순응", "term_vi": "Thích nghi với ánh sáng", "def_ko": "밝은 환경과 어두운 환경 간의 시각적 적응", "def_vi": "Khả năng thích ứng giữa môi trường sáng và tối"}, {"term_ko": "눈물", "term_vi": "Nước mắt", "def_ko": "눈에서 나오는 액체", "def_vi": "Dịch tiết ra từ mắt"}, {"term_ko": "초점", "term_vi": "Tiêu điểm", "def_ko": "이미지가 맺히는 지점", "def_vi": "Điểm mà hình ảnh được hình thành"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (970, '5', '노화에 따른 신경계의 특성으로 옳은 것은?', '["감각이 예민해진다.", "정서조절이 안정된다.", "균형을 유지하는 능력이 증가한다.", "신경세포의 기능이 증가한다.", "단기 기억이 감퇴한다."]'::jsonb, 5, NULL, NULL, '{"1": "감각이 예민해진다. - 노화에 따라 감각 기능은 일반적으로 감소합니다.", "2": "정서조절이 안정된다. - 노화로 인해 정서 표현이나 조절이 다소 변화할 수 있습니다.", "3": "균형을 유지하는 능력이 증가한다. - 노화에 따라 균형 능력은 오히려 감소하는 경향이 있습니다.", "4": "신경세포의 기능이 증가한다. - 노화에 따라 신경세포의 기능은 감소합니다.\n[정답]", "5": "단기 기억이 감퇴한다. - 노화의 일반적인 특성 중 하나로, 단기 기억력이 감퇴하는 것이 사실입니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이가 들어감", "def_vi": "Quy trình già đi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (969, '5', '장기간의 자외선 노출과 강력한 스테로이드 연고 도포에 의해 출혈이 생기며, 노인학대로 올해받을 수 있는 피부계 질환은?', '["간찰진", "우정문신", "노인성 자반", "지루성 피부염", "기저귀 피부염"]'::jsonb, 3, NULL, NULL, '{"1": "간찰진: 주로 마찰에 의해 발생하는 피부질환이지만, 문제의 원인과 관련성이 약합니다.\n[정답]", "3": "노인성 자반: 노인에게 흔히 발생하며 장기간의 자외선 노출과 스테로이드 연고 사용으로 출혈이 생길 수 있습니다.", "2": "우정문신: 이와 직접적인 연관성이 없는 것으로 고려됩니다.", "4": "지루성 피부염: 주로 지루선 분비물과 관련된 피부질환으로, 문제의 의도와는 거리가 있습니다.", "5": "기저귀 피부염: 주로 아기에게 나타나는 피부질환으로 노인과는 연관성이 없습니다."}'::jsonb, '[{"term_ko": "장기간", "term_vi": "Thời gian dài", "def_ko": "오랜 시간", "def_vi": "Thời gian kéo dài"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (968, '5', '피부가 접히는 부분에 발생하는 붉은 변화로 마찰, 열, 습윤, 짓무름, 공기순환 부족에 의하여 발생하는 피부계 질환은?', '["간찰진", "우정문신", "노인성 자반", "기저귀 피부염", "지루성 피부염"]'::jsonb, 1, NULL, NULL, '{"1": "간찰진: 피부가 접히는 부분에서 마찰로 인해 발생하는 피부질환이다.\n[정답]", "2": "우정문신: 피부에 문신을 하는 것으로, 피부 질환과 관련이 없다.", "3": "노인성 자반: 노인에게 발생하는 자반으로, 피부 접힘과는 관련 없다.", "4": "기저귀 피부염: 기저귀 착용으로 인해 발생하는 염증으로 특정한 구간에서만 발생한다.", "5": "지루성 피부염: 피지선의 활동과 관련된 피부질환으로 접히는 부분과는 다른 원인이다."}'::jsonb, '[{"term_ko": "간찰진", "term_vi": "간찰 진", "def_ko": "접히는 피부에서 발생하는 질환(한국어)", "def_vi": "Bệnh lý da xuất hiện ở phần tiếp giáp do ma sát"}, {"term_ko": "염증", "term_vi": "Viêm", "def_ko": "염증의 상태(한국어)", "def_vi": "Trạng thái viêm"}, {"term_ko": "자반", "term_vi": "Bầm tím", "def_ko": "피부에 발생하는 자반 증세(한국어)", "def_vi": "Triệu chứng bầm tím xuất hiện trên da"}, {"term_ko": "지루성", "term_vi": "Bã nhờn", "def_ko": "피지선과 관련된(한국어)", "def_vi": "Liên quan đến tuyến bã nhờn"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (967, '5', '피부질환에 대한 설명이 올바르게 연결된 것은?', '["우정문신 - 과도한 자극, 자외선 노출 등에 주의한다.", "간찰진 - 피부가 접히는 부위에 발생하며 감염에 의해 악화된다.", "노인성 자반 - 통풍을 시키고 항진균제나 스테로이드 연고를 바른다.", "지루성 피부염 - 마찰, 열, 습윤에 의하며 통풍과 국소항생제를 바른다.", "피지선의 활동이 많은 부위에 발생하며 흰색 인설이 동반된다."]'::jsonb, 2, NULL, NULL, '{"1": "우정문신 - 과도한 자극, 자외선 노출 등에 주의한다. 이 설명은 우정문신의 관리에 대한 설명이나, 피부질환의 정의와 관련이 없다.\n[정답]", "2": "간찰진 - 피부가 접히는 부위에 발생하며 감염에 의해 악화된다. 간찰진은 발병 부위와 원인을 잘 설명하고 있다.", "3": "노인성 자반 - 통풍을 시키고 항진균제나 스테로이드 연고를 바른다. 노인성 자반에 대한 잘못된 치료 방법으로 설명이 부적절하다.", "4": "지루성 피부염 - 마찰, 열, 습윤에 의하며 통풍과 국소항생제를 바른다. 지루성 피부염에 대한 올바른 설명이 아니다.", "5": "피지선의 활동이 많은 부위에 발생하며 흰색 인설이 동반된다. 이 설명은 정확하지 않다."}'::jsonb, '[{"term_ko": "피부질환", "term_vi": "Bệnh da", "def_ko": "병 về da", "def_vi": "Bệnh về da"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (966, '5', '머릿니에 대한 설명으로 옳은 것은?', '["피부 속에 굴을 뚫어 피부병을 유발한다.", "다른 사람에게 옮기지 않는다.", "빗과 브러쉬는 흐르는 물에 씻어 사용한다.", "모자, 수건 등을 함께 사용해도 된다.", "침구와 옷을 뜨거운 물로 세탁하고 말린다."]'::jsonb, 5, NULL, NULL, '{"1": "피부 속에 굴을 뚫어 피부병을 유발한다. - 머릿니는 피부를 뚫고 들어가지는 않지만 가려움증을 유발할 수 있습니다.\n[정답]", "5": "침구와 옷을 뜨거운 물로 세탁하고 말린다. - 머릿니의 전파를 막기 위해서는 이러한 소독이 필요합니다.", "3": "빗과 브러쉬는 흐르는 물에 씻어 사용한다. - 흐르는 물에 씻는 것만으로는 머릿니 완전히 제거할 수 없습니다.", "4": "모자, 수건 등을 함께 사용해도 된다. - 머릿니는 전염성이 있으므로 함께 사용하면 안 됩니다.", "2": "다른 사람에게 옮기지 않는다. - 머릿니는 접촉을 통해 감염될 수 있습니다."}'::jsonb, '[{"term_ko": "머릿니", "term_vi": "Chấy", "def_ko": "두피에 기생하는 작은 곤충", "def_vi": "Côn trùng nhỏ sống trên da đầu"}, {"term_ko": "침구", "term_vi": "Ga trải giường", "def_ko": "잠을 잘 때 사용하는 이불이나 시트", "def_vi": "Vải bọc giường"}, {"term_ko": "세탁", "term_vi": "Giặt", "def_ko": "더러움을 없애기 위해 세척하는 것", "def_vi": "Làm sạch để loại bỏ bụi bẩn"}, {"term_ko": "전파", "term_vi": "Lây lan", "def_ko": "한 곳에서 다른 곳으로 이동하는 것", "def_vi": "Di chuyển từ nơi này sang nơi khác"}, {"term_ko": "소독", "term_vi": "Khử trùng", "def_ko": "세균이나 병원균을 죽이는 것", "def_vi": "Giết vi khuẩn hoặc virus"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (965, '5', '다음의 방법으로 관리해야 하는 감염성 질환은?• 처방받은 연고를 밤에 바르고 다음 날 아침에 씻어 낸다.• 사용한 침구류는 뜨거운 물에 세탁 후 3일 이상 사용하지 않는다.• 대상자는 물론 동거 가족이나 요양보호사도 동시에 치료를 받는다.', '["옴", "대상포진", "두드러기", "피부건조증", "알레르기성 피부염"]'::jsonb, 1, NULL, NULL, '{"1": "옴은 피부에 기생하는 진드기로 인해 발생하며, 감염된 사람과의 접촉이나 오염된 침구류를 통해 전파됩니다. 따라서 관리 방법으로 처방받은 연고를 바르고, 침구를 세탁하며, 동거 가족과 함께 치료받는 것이 필수적입니다.\n[정답]", "2": "대상포진은 바이러스에 의해 발생하지만, 위의 관리 방법과는 맞지 않습니다.", "3": "두드러기는 알레르기 반응으로 발생하며, 위의 관리 방법과 관련이 없습니다.", "4": "피부건조증은 일반적인 피부 상태로 특별한 감염성 관리가 필요하지 않습니다.", "5": "알레르기성 피부염은 알레르기로 인해 발생되는 것이며, 감염성 질환이 아닙니다."}'::jsonb, '[{"term_ko": "감염성 질환", "term_vi": "Bệnh truyền nhiễm", "def_ko": "전염 bệnh", "def_vi": "Bệnh lây lan"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (964, '5', '밤에 가려움증이 심해지고 알레르기 증세와 비슷하며 사람에서 사람으로 직접 감염되는 피부계 질환은?', '["옴", "수두", "건조증", "대상포진", "아토피 피부염"]'::jsonb, 1, NULL, NULL, '{"1": "옴: 가려움증이 심하며 사람 간 전염되는 피부 질환.\n[정답]", "2": "수두: 가려움증이 있으나 전염 경로가 사람 간 직적 전염이 아닌 공기를 통한 감염이다.", "3": "건조증: 가려움증이 있을 수 있으나 전염성이 없다.", "4": "대상포진: 신경과 관련된 피부 질환으로 감염성이 있으나 나이 든 사람에게 주로 발병한다.", "5": "아토피 피부염: 알레르기 증세를 동반하나 직접적인 감염 전파는 없다."}'::jsonb, '[{"term_ko": "가려움증", "term_vi": "Ngứa", "def_ko": "가려움(한국어)", "def_vi": "Cảm giác ngứa"}, {"term_ko": "알레르기", "term_vi": "Dị ứng", "def_ko": "알레르기(한국어)", "def_vi": "Dị ứng"}, {"term_ko": "피부계", "term_vi": "Hệ da", "def_ko": "피부 관련(한국어)", "def_vi": "Hệ thống liên quan đến da"}, {"term_ko": "감염", "term_vi": "Lây nhiễm", "def_ko": "전염(한국어)", "def_vi": "Lây truyền"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병(한국어)", "def_vi": "Bệnh tật"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (963, '5', '다음 중 대상포진에 대한 설명으로 옳은 것은?', '["세균에 의해 감염되는 질환이다.", "가려움이 없는 수포가 발생한다.", "치료 후 신경통이 사라질 때까지 격리한다.", "과거 풍진을 앓았던 사람에게 주로 발생한다.", "작열감을 동반한 수포가 띠 모양으로 나타난다."]'::jsonb, 5, NULL, NULL, '{"1": "세균에 의해 감염되는 질환이 아니다. 대상포진은 바이러스에 의해 발생한다.\n[정답]", "5": "작열감을 동반한 수포가 띠 모양으로 나타나는 것이 특징이다.", "2": "대상포진에 가려움이 없는 수포가 발생하는 것이 아니다. 일반적으로 통증이 동반된다.", "3": "치료 후 신경통이 사라질 때까지 격리할 필요는 없다. 일반적으로 증상이 가벼운 경우 격리할 필요가 없다.", "4": "대상포진은 과거 수두를 앓았던 사람에게 주로 발생한다."}'::jsonb, '[{"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "질병 이름(한국어)", "def_vi": "tên bệnh"}, {"term_ko": "가려움", "term_vi": "Ngứa", "def_ko": "가렵다(한국어)", "def_vi": "ngứa"}, {"term_ko": "수포", "term_vi": "Bọng nước", "def_ko": "물집(한국어)", "def_vi": "bọng nước"}, {"term_ko": "작열감", "term_vi": "Cảm giác nóng rát", "def_ko": "열감(한국어)", "def_vi": "cảm giác nóng rát"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (962, '5', '대상포진에 관한 설명으로 옳은 것은?', '["1~2주면 통증이 없어진다.", "수포가 건조되지 않게 관리한다.", "장기간 스테로이드를 복용해야 한다.", "가려움증이 있는 부위에 온찜질을 적용한다.", "과거에 수두를 앓았던 사람에게서 주로 발생한다."]'::jsonb, 5, NULL, NULL, '{"1": "대상포진의 통증은 개인에 따라 다르며, 1~2주 만에 완전히 없어지지 않을 수 있습니다.\n[정답]", "5": "과거에 수두를 앓았던 사람에게서 주로 발생하는 질환입니다.", "2": "수포가 건조되지 않게 관리하는 것은 필요하지 않습니다. 오히려 자연히 건조되도록 하는 것이 중요합니다.", "3": "장기간 스테로이드를 복용하는 것은 대상포진 치료에 적합하지 않습니다.", "4": "가려움증이 있는 부위에 온찜질을 적용하는 것은 오히려 더 자극할 수 있으므로 적절하지 않습니다."}'::jsonb, '[{"term_ko": "대상포진", "term_vi": "Bệnh zona", "def_ko": "수두 바이러스가 재활성화되어 나타나는 질환", "def_vi": "Bệnh xảy ra do virus thủy đậu tái hoạt động"}, {"term_ko": "부위", "term_vi": "Vùng", "def_ko": "특정한 장소", "def_vi": "Địa điểm cụ thể"}, {"term_ko": "수포", "term_vi": "Mụn nước", "def_ko": "물집", "def_vi": "Bọng nước"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔", "def_vi": "Cảm giác đau"}, {"term_ko": "스테로이드", "term_vi": "Steroid", "def_ko": "스테로이드 약물", "def_vi": "Thuốc steroid"}, {"term_ko": "가려움증", "term_vi": "Ngứa", "def_ko": "가려운 느낌", "def_vi": "Cảm giác ngứa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (961, '5', '노인 대상자가 대상포진에 걸릴 위험성이 높은 원인은?', '["과체중", "피부 건조", "면역력 저하", "혈액순환 장애", "신장기능 저하"]'::jsonb, 3, NULL, NULL, '{"1": "과체중은 여러 건강 문제를 일으킬 수 있지만, 대상포진과의 직접적인 관계는 부족하다.", "2": "피부 건조는 노인에게 흔한 문제이나, 대상포진의 발생 위험과는 무관하다.\n[정답]", "3": "면역력 저하는 노인의 주요 문제이며, 이는 대상포진 발생과 밀접한 관련이 있다.", "4": "혈액순환 장애는 여러 문제를 초래할 수 있지만, 대상포진과의 직접적인 관련은 적다.", "5": "신장기능 저하 역시 노인에게 흔하지만, 대상포진 발생 위험과는 관련이 적다."}'::jsonb, '[{"term_ko": "대상포진", "term_vi": "Bệnh zona", "def_ko": "질병 이름(한국어)", "def_vi": "tên bệnh(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (960, '5', '다음과 같은 증상이 나타나는 질환은?피부와 점막에 있는 감각신경말단 부위의 수포, 통증, 작열감, 가려움', '["욕창", "습진", "건조증", "대상포진", "아토피 피부염"]'::jsonb, 4, NULL, NULL, '{"1": "욕창: 피부가 눌려서 혈액순환이 나빠져 생기는 손상으로, 수포나 작열감과는 차이가 있습니다.", "2": "습진: 가려움증을 동반하지만, 특정 감각신경말단 부위의 수포는 나타나지 않습니다.", "3": "건조증: 수분 부족으로 인한 증상으로, 통증이나 작열감이 동반되기 어려운 경우가 많습니다.\n[정답]", "4": "대상포진: 수포와 함께 통증, 작열감, 가려움이 특징으로, 감각신경 말단에 영향을 미칩니다.", "5": "아토피 피부염: 두드러기처럼 보일 수 있으나, 통증과 작열감이 주된 증상이 아닙니다."}'::jsonb, '[{"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증후(한국어)", "def_vi": "triệu chứng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (959, '5', '피부 건조증이 있는 대상자의 목욕을 돕는 방법으로 옳은 것은?', '["뜨거운 물로 깨끗이 씻어준다.", "때를 불린 뒤 밀어준다.", "자극이 강한 비누를 사용한다.", "목욕 후 수건으로 문지르듯 물기를 닦는다.", "목욕 후 물기가 완전히 마르기 전에 보습제를 바른다."]'::jsonb, 5, NULL, NULL, '{"1": "뜨거운 물은 피부를 더욱 건조하게 만들 수 있습니다.", "2": "때를 불린 뒤 밀어주는 것은 피부 자극을 줄 수 있는 방법이 아닙니다.", "3": "자극이 강한 비누는 피부 건조증에 도움이 되지 않습니다.", "4": "물기를 문지르듯 닦는 것은 피부에 추가적인 자극을 줄 수 있습니다.\n[정답]", "5": "목욕 후 물기가 완전히 마르기 전에 보습제를 바르는 것은 피부 건조증 관리에 효과적입니다."}'::jsonb, '[{"term_ko": "피부", "term_vi": "Da", "def_ko": "피부(한국어)", "def_vi": "Da(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (958, '5', '노인에게 흔한 피부건조증을 예방하는 방법으로 옳은 것은?', '["수분섭취를 제한한다.", "목욕 후 물기는 그대로 둔다.", "실내습도는 30~40%를 유지한다.", "수시로 때를 문질러 닦는다.", "순한 비누와 보습제를 사용한다."]'::jsonb, 5, NULL, NULL, '{"1": "수분 섭취를 제한하는 것은 피부건조증을 악화시킬 수 있습니다.\n[정답]", "5": "순한 비누와 보습제를 사용하면 피부 보호막이 유지되어 피부건조증 예방에 효과적입니다.", "2": "목욕 후 물기를 그대로 두는 것은 피부를 더욱 건조하게 만들 수 있습니다.", "3": "실내습도를 30~40%로 유지하면 다소 도움이 될 수 있지만, 적정 습도는 40~60%가 이상적입니다.", "4": "수시로 때를 문질러 닦는 것은 피부를 손상시킬 수 있습니다."}'::jsonb, '[{"term_ko": "피부건조증", "term_vi": "Bệnh khô da", "def_ko": "피부가 건조해지는 증상", "def_vi": "Triệu chứng da trở nên khô"}, {"term_ko": "목욕", "term_vi": "Tắm", "def_ko": "몸을 씻는 행위", "def_vi": "Hành động rửa cơ thể"}, {"term_ko": "수분섭취", "term_vi": "Sự tiêu thụ nước", "def_ko": "물을 섭취하는 것", "def_vi": "Việc uống nước"}, {"term_ko": "보습제", "term_vi": "Kem dưỡng ẩm", "def_ko": "피부에 수분을 공급하는 제품", "def_vi": "Sản phẩm cung cấp độ ẩm cho da"}, {"term_ko": "실내습도", "term_vi": "Độ ẩm trong nhà", "def_ko": "실내의 습기 정도", "def_vi": "Mức độ ẩm trong nhà"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (957, '5', '노인 대상자의 피부 건조를 예방하는 방법으로 옳은 것은?', '["겨울철에 제습기를 사용한다.", "알코올이 함유된 피부 보습제를 사용한다.", "뜨거운 물로 매일 샤워한다.", "때를 밀어 피부를 청결하게 한다.", "목욕 후 문지르지 않고 두드려 말린다."]'::jsonb, 5, NULL, NULL, '{"1": "겨울철에 제습기를 사용하면 오히려 습도가 낮아져 피부 건조를 악화시킬 수 있다.\n[정답]", "5": "목욕 후 문지르지 않고 두드려 말리면 피부가 수분을 유지하면서도 자극을 최소화할 수 있다.", "2": "알코올이 함유된 피부 보습제는 피부를 더 건조하게 만들 수 있으므로 사용해서는 안 된다.", "3": "뜨거운 물로 매일 샤워하는 것은 피부의 자연 유분을 제거하여 피부 건조를 초래할 수 있다.", "4": "때를 밀어 피부를 청결하게 할 경우 피부 장벽이 손상될 위험이 있다."}'::jsonb, '[{"term_ko": "노인", "term_vi": "Người cao tuổi", "def_ko": "노인(한국어)", "def_vi": "Người lớn tuổi"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "피부(한국어)", "def_vi": "Da"}, {"term_ko": "건조", "term_vi": "Khô", "def_ko": "건조하다(한국어)", "def_vi": "Khô"}, {"term_ko": "보습제", "term_vi": "Sản phẩm dưỡng ẩm", "def_ko": "보습제(한국어)", "def_vi": "Sản phẩm dưỡng ẩm"}, {"term_ko": "문지르다", "term_vi": "Chà", "def_ko": "문지르다(한국어)", "def_vi": "Chà"}, {"term_ko": "두드리다", "term_vi": "Vỗ", "def_ko": "두드리다(한국어)", "def_vi": "Vỗ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (956, '5', '습도가 낮은 겨울에 피부가 건조해지며 거칠어지고 손과 다리에 가려움증이 발생하는 질환은?', '["옴", "욕창", "건조증", "대상포진", "수두"]'::jsonb, 3, NULL, NULL, '{"1": "옴은 기생충에 의한 피부염으로 가려움증이 발생하지만, 주로 전염병의 성격이 강합니다.\n[정답]", "3": "건조증은 겨울철 습도가 낮을 때 피부가 건조해지고 거칠어지는 것을 설명합니다.", "2": "욕창은 장기간 압력이 가해져 피부나 조직이 손상된 상태입니다.", "4": "대상포진은 수두 바이러스에 의해 발생하는 피부 발진이며 주로 신경과 관련이 있습니다.", "5": "수두는 바이러스 감염으로 발생하는 질환으로 가려움증을 동반한 수포가 생깁니다."}'::jsonb, '[{"term_ko": "습도", "term_vi": "Độ ẩm", "def_ko": "습기(수분) 상태", "def_vi": "Trạng thái độ ẩm"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "인체의 외부 층", "def_vi": "Lớp bên ngoài của cơ thể"}, {"term_ko": "건조증", "term_vi": "Khô da", "def_ko": "수분이 부족하여 피부가 건조한 상태", "def_vi": "Tình trạng da khô do thiếu nước"}, {"term_ko": "가려움증", "term_vi": "Ngứa", "def_ko": "피부가 가렵도록 느끼는 증상", "def_vi": "Triệu chứng cảm thấy ngứa da"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (955, '5', '욕창의 치료 및 예방을 위해 우선적으로 공급해야 하는 영양소는?', '["칼슘", "욕창", "건조증", "대상포진", "수두"]'::jsonb, 3, NULL, NULL, '{"1": "칼슘은 뼈 건강에 중요한 미네랄이지만 욕창 예방과는 직접적인 연관이 없습니다.\n[정답]", "2": "욕창 자체는 질병명이며 영양소가 아닙니다.", "3": "건조증은 피부 상태를 나타내지만 욕창 예방에 필요한 영양소는 아닙니다.", "4": "대상포진은 신경계의 바이러스 감염으로, 욕창 예방과는 관련이 없습니다.", "5": "수두는 바이러스 질환으로, 욕창과는 상관이 없습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부의 손상을 초래하는 상태", "def_vi": "Tình trạng gây tổn thương cho da"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈 건강에 필요한 미네랄", "def_vi": "Khoáng chất cần thiết cho sức khỏe xương"}, {"term_ko": "건조증", "term_vi": "Khô da", "def_ko": "피부가 마르고 갈라지는 상태", "def_vi": "Trạng thái da khô và nứt nẻ"}, {"term_ko": "대상포진", "term_vi": "Zona", "def_ko": "신경계의 바이러스 감염", "def_vi": "Nhiễm virus ảnh hưởng đến hệ thần kinh"}, {"term_ko": "수두", "term_vi": "Thủy đậu", "def_ko": "바이러스 질환", "def_vi": "Bệnh nhiễm virus"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (954, '5', '요양보호사의 다음 행동 중 대상자에게 욕창 발생이 우려되는 경우는?', '["천골 부위에 도넛모양의 베개를 대어준다.", "기저귀가 뭉치지 않게 펴서 채워준다.", "목욕 후에 피부를 완전히 말려준다.", "무릎 사이에 베개를 끼운다.", "체위를 자주 변경해준다."]'::jsonb, 1, NULL, NULL, '{"1": "천골 부위에 도넛모양의 베개를 대어주는 것은 압력을 분산시켜 욕창을 유발할 수 있습니다. 이는 오히려 욕창 발생 위험을 높입니다.\n[정답]", "2": "기저귀가 뭉치지 않게 펴서 채워주는 것은 피부 마찰을 줄여 욕창을 예방할 수 있는 행동입니다.", "3": "목욕 후에 피부를 완전히 말려주는 것은 피부를 건강하게 유지하는 좋은 방법입니다.", "4": "무릎 사이에 베개를 끼우는 것은 압력을 줄이는 데 도움을 줄 수 있습니다.", "5": "체위를 자주 변경해주는 것은 욕창 예방의 핵심적인 방법입니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "압력이나 마찰로 인해 피부가 상처나는 것", "def_vi": "Vết thương trên da do áp lực hoặc ma sát"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (953, '5', '욕창 예방 방법으로 천골부위에 도넛 모양의 베개를 사용하지 않는 이유는?', '["옷 갈아 입히기가 어렵다.", "천골 부위에 혈액순환이 저하된다.", "피부가 건조해진다.", "체위변경이 어렵다.", "배설물 처리가 어렵다."]'::jsonb, 2, NULL, NULL, '{"1": "옷 갈아 입히기가 어려운 것은 주요 원인이 아닙니다.\n[정답]", "2": "천골 부위에 혈액순환이 저하되어 욕창을 유발할 수 있습니다.", "3": "피부가 건조해지는 것과 직접적인 연관은 없습니다.", "4": "체위변경이 어렵다는 것은 맞지만, 혈액순환 문제보다 덜 중요한 이유입니다.", "5": "배설물 처리가 어려운 것은 이 문제와 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét do tì đè", "def_ko": "상처가 생기기 쉬운 부위의 피부가 손상되는 상태", "def_vi": "Tình trạng tổn thương da ở vùng dễ bị thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (952, '5', '장기간 누워 있는 대상자의 욕창 예방으로 옳은 ㅓㅅ은?', '["두꺼운 이불을 덮어준다.", "피부를 주무르듯이 마사지 한다.", "침대 시트의 주름을 펴준다.", "특정부위에 압력이 가해지도록 눕혀 둔다.", "의자보다는 침대에서 자주 자세를 바꾸어준다."]'::jsonb, 3, NULL, NULL, '{"1": "두꺼운 이불을 덮어주는 것은 오히려 압력을 증가시켜 욕창 예방에 도움이 되지 않는다.\n[정답]", "3": "침대 시트의 주름을 펴주는 것은 피부에 가해지는 압력을 줄여 욕창 예방에 효과적이다.", "2": "피부를 주무르듯이 마사지하는 것은 피부를 자극할 수 있어 권장되지 않는다.", "4": "특정부위에 압력이 가해지도록 눕혀 두는 것은 욕창을 유발할 수 있다.", "5": "의자보다는 침대에서 자주 자세를 바꾸어 주는 것이 아니라 의자에서 자주 자세를 바꾸어 주는 것이 좋다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부에 상처가 생기는 것(한국어)", "def_vi": "Vết thương hình thành trên da(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (951, '5', '욕창을 예방하는 방법으로 옳은 것은?', '["뜨거운 물주머니를 대준다.", "격일로 피부 상태를 점검한다.", "파우더를 사용하여 피부를 건조하게 한다.", "피부 건조시 찬바람과 뜨거운 바람을 번갈아 사용한다.", "무릎 사이에는 베개를 끼워준다."]'::jsonb, 5, NULL, NULL, '{"1": "뜨거운 물주머니를 대주는 것은 피부에 화상을 입힐 수 있어 위험합니다.\n[정답]", "5": "무릎 사이에 베개를 끼워줌으로써 압력을 분산시켜 욕창을 예방할 수 있습니다.", "2": "격일로 피부 상태를 점검하는 것은 바람직하지만, 빈도가 낮아 효과적인 예방이 어려울 수 있습니다.", "3": "파우더를 사용하여 피부를 건조하게 하는 것은 오히려 피부를 더욱 손상시킬 수 있습니다.", "4": "피부 건조시 차가운 바람과 뜨거운 바람을 번갈아 사용하는 것은 피부에 자극이 될 수 있습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Vết loét", "def_ko": "피부에 생긴 궤양(상처)", "def_vi": "Vết thương trên da"}, {"term_ko": "예방", "term_vi": "Ngăn ngừa", "def_ko": "미리 방지하는 것", "def_vi": "Phòng ngừa"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "인체의 보호 외피", "def_vi": "Lớp bọc bảo vệ cơ thể"}, {"term_ko": "압력", "term_vi": "Áp lực", "def_ko": "물체가 다른 물체에 가하는 힘", "def_vi": "Lực mà một vật tác động lên vật khác"}, {"term_ko": "상태", "term_vi": "Tình trạng", "def_ko": "어떤 형편이나 상황", "def_vi": "Tình huống hay trạng thái"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (950, '5', '욕창이 있는 대상자를 돌보는 방법으로 옳은 것은?', '["얼음 주머니를 대준다.", "천골부위에 도넛 모양의 베개를 사용한다.", "젖은 침대 시트는 바로 교체한다.", "오염물질이 묻은 경우 찬물로 씻고 건조시킨다.", "의자에서는 두 시간마다 자세를 바꾸어준다."]'::jsonb, 3, NULL, NULL, '{"1": "얼음 주머니를 대주는 것은 혈류를 줄여서 조직 손상을 초래할 수 있습니다.\n[정답]", "2": "천골부위에 도넛 모양의 베개를 사용하면 압력을 분산시켜 욕창 예방에 도움이 됩니다.", "3": "젖은 침대 시트는 바로 교체해야 합니다.", "4": "오염물질이 묻은 경우 찬물로 씻고 건조시키는 것보다는 미지근한 물로 씻는 것이 좋습니다.", "5": "의자에서는 두 시간마다 자세를 바꿔주는 것이 맞습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "상처 질환(한국어)", "def_vi": "Bệnh lý vết thương(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (949, '5', '욕창이 있는 대상자를 돕는 방법으로 옳은 것은?', '["대상자가 원하지 않으면 체위변경을 하지 않는다.", "침대에서는 두 시간 마다 체위변경을 한다.", "매트리스와 베개는 딱딱한 것이 좋다.", "지서용 비누로 깨끗이 씻겨준다.", "단추가 달린 바지를 입힌다."]'::jsonb, 2, NULL, NULL, '{"1": "대상자가 원하지 않더라도 체위변경은 필수적입니다. 체위변경은 욕창 예방을 위한 중요한 방법입니다.\n[정답]", "2": "욕창을 예방하기 위해 두 시간마다 체위를 변경하는 것이 바람직합니다.", "3": "매트리스와 베개는 부드러운 것이 좋습니다. 딱딱한 것은 오히려 욕창을 유발할 수 있습니다.", "4": "지서용 비누는 피부에 자극을 줄 수 있으므로 부드러운 비누를 사용하는 것이 좋습니다.", "5": "통증을 유발할 수 있는 의복은 피하는 것이 좋습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Vết loét", "def_ko": "피부에 생기는 궤양", "def_vi": "Vết thương xuất hiện trên da"}, {"term_ko": "체위변경", "term_vi": "Thay đổi tư thế", "def_ko": "환자의 자세를 바꾸는 것", "def_vi": "Thay đổi vị trí của bệnh nhân"}, {"term_ko": "매트리스", "term_vi": "Nệm", "def_ko": "침대에 사용하는 쿠션", "def_vi": "Đệm sử dụng trên giường"}, {"term_ko": "부드러운", "term_vi": "Mềm mại", "def_ko": "단단하지 않은, 유연한", "def_vi": "Không cứng, linh hoạt"}, {"term_ko": "지서용 비누", "term_vi": "Xà phòng dùng cho da", "def_ko": "피부에 사용되는 비누", "def_vi": "Xà phòng sử dụng cho da"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (948, '5', '거동이 불편한 대상자의 체위변경을 돕는 방법은?', '["욕창이 있으면 체위변경 횟수를 늘린다.", "딱딱하고 표면이 거친 쿠션을 받쳐 준다.", "파우더를 사용하여 피부가 습하지 않게 한다.", "대상자의 옷을 잡아당겨 체위를 변경한다.", "의자에서는 2시간마다 체위를 바꾸어 준다."]'::jsonb, 1, NULL, NULL, '{"1": "욕창이 있으면 체위변경 횟수를 늘린다. [정답] 욕창 예방을 위해 체위를 자주 변경하는 것이 중요합니다.", "2": "딱딱하고 표면이 거친 쿠션을 받쳐 준다. 체위변경 시 부드러운 쿠션이 필요합니다.", "3": "파우더를 사용하여 피부가 습하지 않게 한다. 피부를 건조하게 유지하는 것은 중요하지만 바르는 방법에 대한 지식이 필요합니다.", "4": "대상자의 옷을 잡아당겨 체위를 변경한다. 대상자의 피부에 자극을 줄 수 있습니다.", "5": "의자에서는 2시간마다 체위를 바꾸어 준다. 의자에서의 체위변경은 자주 필요하지만, 2시간이라는 시간은 기계적일 수 있습니다."}'::jsonb, '[{"term_ko": "체위변경", "term_vi": "Thay đổi tư thế", "def_ko": "몸의 자세를 바꾸는 것", "def_vi": "Thay đổi vị trí của cơ thể"}, {"term_ko": "욕창", "term_vi": "Loét tì đè", "def_ko": "피부에 생기는 상처", "def_vi": "Vết thương trên da"}, {"term_ko": "쿠션", "term_vi": "Đệm", "def_ko": "편안함을 제공하는 물질", "def_vi": "Vật liệu tạo cảm giác thoải mái"}, {"term_ko": "의자", "term_vi": "Ghế", "def_ko": "앉는 가구", "def_vi": "Đồ nội thất dành để ngồi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (947, '5', '대상자의 기저귀를 교환할 때 둔부를 가볍게 두드려 마사지하는 이유는?', '["변의 자극", "욕창 예방", "근육 이완", "장운동 촉진", "심리적 안정"]'::jsonb, 2, NULL, NULL, '{"1": "변의 자극: 마사지를 하는 주요 목적이 아닙니다.\n[정답]", "2": "욕창 예방: 마사지가 혈액순환을 촉진하여 욕창 예방에 도움을 줍니다.", "3": "근육 이완: 마사지로 인해 근육이 이완될 수 있으나, 주된 목적은 아닙니다.", "4": "장운동 촉진: 마사지가 장운동에 도움을 줄 수 있지만 이 경우는 우선순위가 아닙니다.", "5": "심리적 안정: 마사지를 통해 심리적 안정감을 줄 수는 있지만, 질문의 주제와는 관련성이 적습니다."}'::jsonb, '[{"term_ko": "기저귀", "term_vi": "Tã", "def_ko": "기저귀(한국어)", "def_vi": "Tã"}, {"term_ko": "둔부", "term_vi": "Mông", "def_ko": "엉덩이(한국어)", "def_vi": "Mông"}, {"term_ko": "마사지", "term_vi": "Xoa bóp", "def_ko": "마사지(한국어)", "def_vi": "Xoa bóp"}, {"term_ko": "욕창", "term_vi": "Loét tì đè", "def_ko": "욕창(한국어)", "def_vi": "Loét tì đè"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (946, '5', '욕창으로 인해 대상자에게 피부 발적과 수포가 생겼을 경우 돕는 방법으로 옳은 것은?', '["피부를 주무르며 마사지한다.", "발적 부위를 미지근한 물로 닦아주고 건조시킨다.", "하루에 두 번 체위변경을 한다.", "몸에 꽉 끼는 옷을 입힌다.", "욕창 예방을 위해 도넛 모양의 베개를 대준다."]'::jsonb, 2, NULL, NULL, '{"1": "피부를 주무르며 마사지하는 것은 오히려 피부 손상을 초래할 수 있다.\n[정답]", "2": "발적 부위를 미지근한 물로 닦아주고 건조시키는 것은 피부 상태를 개선하고, 감염 예방에 도움이 된다.", "3": "하루에 두 번 체위변경을 하는 것은 욕창 예방에는 중요하지만, 대상자의 상태에 따라 빈도가 달라질 수 있다.", "4": "몸에 꽉 끼는 옷은 혈액 순환을 저해할 수 있어 피해야 한다.", "5": "도넛 모양의 베개는 도와줄 수 있지만, 상황에 따라 적절하지 않을 수 있다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét do tỳ đè", "def_ko": "피부가 손상되어 생기는 상처", "def_vi": "Vết thương do tổn thương da"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (945, '5', '와상 상태에 있는 대상자의 피부가 약간 붉게 변하였을 때 대처방법으로 옳은 것은?', '["욕창 주위를 마사지하고 가볍게 두드린다.", "뜨거운 물수건으로 찜질한다.", "차가운 바람으로 건조시킨다.", "춥지 않으면 1~2시간 햇볕을 쪼인다.", "물티슈로 수시로 닦아준다."]'::jsonb, 1, NULL, NULL, '{"1": "욕창 주위를 마사지하고 가볍게 두드린다. - 피부의 혈액 순환을 도와 피부 상태를 개선할 수 있습니다.\n[정답]", "2": "뜨거운 물수건으로 찜질한다. - 화상의 위험이 있어 적절하지 않은 방법입니다.", "3": "차가운 바람으로 건조시킨다. - 피부를 더욱 손상시킬 수 있으므로 피해야 합니다.", "4": "춥지 않으면 1~2시간 햇볕을 쪼인다. - 피부에 부담을 주어 상태를 악화시킬 수 있습니다.", "5": "물티슈로 수시로 닦아준다. - 피부에 자극을 줄 수 있으므로 주의해야 합니다."}'::jsonb, '[{"term_ko": "와상 상태", "term_vi": "Trạng thái nằm liệt", "def_ko": "누워 있는 상태(한국어)", "def_vi": "Tình trạng nằm không di chuyển"}, {"term_ko": "욕창", "term_vi": "Loét do tì đè", "def_ko": "피부가 눌려서 상처가 생기는 질환(한국어)", "def_vi": "Bệnh xảy ra khi da bị ép"}, {"term_ko": "마사지", "term_vi": "Mát xa", "def_ko": "눌러서 혈액 순환을 촉진하는 방법(한국어)", "def_vi": "Phương pháp thúc đẩy tuần hoàn máu bằng cách ấn"}, {"term_ko": "자극", "term_vi": "Kích thích", "def_ko": "반응을 일으키는 것(한국어)", "def_vi": "Điều gây ra phản ứng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (944, '5', '욕창의 단계별 증상 중 다음 내용에 해당하는 것은?피하조직과 근막, 근육, 뼈나 관절을 포함한 심부조직에 손상이 있다.', '["1단계", "2단계", "3단계", "4단계", "5단계"]'::jsonb, 4, NULL, NULL, '{"1": "1단계: 피부의 발적, 통증 등의 증상이 나타나는 경미한 단계입니다.", "2": "2단계: 표피와 진피 손상이 나타나며, 통증이 있습니다.\n[정답]", "3": "3단계: 피하조직 손상이 있고, 단단한 껍질이 형성되며, 외부가 드러날 수 있습니다.", "4": "4단계: 심부조직 손상이 있으며, 피하조직과 근막, 근육, 뼈나 관절 등까지 포함됩니다.", "5": "5단계: 이러한 정의는 없으며, 최대 4단계까지만 존재합니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부의 손상(한국어)", "def_vi": "Tổn thương da"}, {"term_ko": "단계", "term_vi": "Giai đoạn", "def_ko": "수준(한국어)", "def_vi": "Cấp độ"}, {"term_ko": "피하조직", "term_vi": "Mô dưới da", "def_ko": "조직(한국어)", "def_vi": "Mô"}, {"term_ko": "근막", "term_vi": "Vải cơ", "def_ko": "근육을 싸고 있는 막(한국어)", "def_vi": "Màng cơ"}, {"term_ko": "근육", "term_vi": "Cơ", "def_ko": "신체의 근력 조직(한국어)", "def_vi": "Cơ"}, {"term_ko": "뼈", "term_vi": "Xương", "def_ko": "신체를 구성하는 단단한 조직(한국어)", "def_vi": "Xương"}, {"term_ko": "관절", "term_vi": "Khớp", "def_ko": "뼈가 만나서 이루는 부분(한국어)", "def_vi": "Khớp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (943, '5', '욕창 발생 위험이 가장 높은 대상자는?', '["산책을 즐기는 과체중 대상자", "체중부하운동이 어려운 관절염 대상자", "지팡이를 짚고 걷는 파킨슨병 대상자", "체위 변겨이 어려운 척수 장애 대상자", "보조기구를 이용하여 산책하는 편마비 대상자"]'::jsonb, 4, NULL, NULL, '{"1": "산책을 즐기는 과체중 대상자는 활동량이 많아 욕창 발생 위험이 상대적으로 낮습니다.\n[정답]", "4": "체위 변겨이 어려운 척수 장애 대상자는 움직임이 제한되어 욕창이 발생할 위험이 가장 높습니다.", "2": "체중부하운동이 어려운 관절염 대상자는 활동이 제한되지만 상태에 따라 다릅니다.", "3": "지팡이를 짚고 걷는 파킨슨병 대상자는 어느 정도 움직일 수 있어 욕창 위험이 낮을 수 있습니다.", "5": "보조기구를 이용하여 산책하는 편마비 대상자는 이동이 가능하여 욕창 위험이 상대적으로 적습니다."}'::jsonb, '[{"term_ko": "욕창", "term_vi": "Đau đớn", "def_ko": "피부와 조직의 손상으로 인한 통증 및 궤양", "def_vi": "Đau và loét do tổn thương da và mô"}, {"term_ko": "체중부하운동", "term_vi": "Vận động tải trọng", "def_ko": "움직임을 위한 체중을 지지하는 운동", "def_vi": "Bài tập hỗ trợ trọng lượng cho chuyển động"}, {"term_ko": "체위", "term_vi": "Tư thế", "def_ko": "자세, 위치", "def_vi": "Tư thế, vị trí"}, {"term_ko": "척수 장애", "term_vi": "Khuyết tật cột sống", "def_ko": "척수와 관련된 신경 기능 문제", "def_vi": "Vấn đề chức năng thần kinh liên quan đến cột sống"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (942, '5', '거동이 불편한 대상자에게 욕창이 발생할 가능성이 가장 높은 경우는?', '["충분한 영양섭취를 하고 있다.", "낮잠을 자지 않는다.", "요실금 및 변실금이 있다.", "취침 시 자주 뒤척인다.", "변비가 이어 물을 많이 마신다."]'::jsonb, 3, NULL, NULL, '{"1": "충분한 영양섭취를 하고 있다: 영양 섭취가 좋으면께 욕창 발생 위험이 감소합니다.\n[정답]", "3": "요실금 및 변실금이 있다: 이러한 상태는 체중이 같은 부위에 지속적으로 압력이 가해져 욕창이 발생할 가능성을 높입니다.", "2": "낮잠을 자지 않는다: 낮잠과 욕창 발생은 직접적인 연관이 없습니다.", "4": "취침 시 자주 뒤척인다: 자주 자세를 변화시키면 욕창 발생 위험이 낮아집니다.", "5": "변비가 이어 물을 많이 마신다: 변비와 물 섭취는 욕창 발생과 직접적인 관련이 없습니다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직이다(한국어)", "def_vi": "Di chuyển"}, {"term_ko": "불편", "term_vi": "Không thoải mái", "def_ko": "불편하다(한국어)", "def_vi": "Không thuận tiện"}, {"term_ko": "욕창", "term_vi": "Loét", "def_ko": "피부에 생기는 상처(한국어)", "def_vi": "Vết thương trên da"}, {"term_ko": "요실금", "term_vi": "Tiểu són", "def_ko": "소변을 잘 못 가리는 상태(한국어)", "def_vi": "Tình trạng không kiểm soát được tiểu tiện"}, {"term_ko": "변실금", "term_vi": "Tiêu chảy", "def_ko": "대변을 잘 못 가리는 상태(한국어)", "def_vi": "Tình trạng không kiểm soát được đại tiện"}, {"term_ko": "취침", "term_vi": "Ngủ", "def_ko": "잠을 자는 것(한국어)", "def_vi": "Thời gian ngủ"}, {"term_ko": "뒤척이다", "term_vi": "Lăn lộn", "def_ko": "자는 중에 몸을 움직이다(한국어)", "def_vi": "Di chuyển trong khi ngủ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (941, '5', '거동이 불편한 대상자에게 욕창이 발생할 가능성이 가장 높은 경우는?', '["피하지방이 많은 대상자", "부적절한 영양으로 근육이 위축된 대상자", "정상 체중을 유지하고 있는 대상자", "변비가 있는 대상자", "요의, 변의가 있는 대상자"]'::jsonb, 2, NULL, NULL, '{"1": "피하지방이 많은 대상자는 피부가 보호되는 경향이 있어 욕창 발생 가능성이 낮다.\n[정답]", "2": "부적절한 영양으로 근육이 위축된 대상자는 피부 보호 기능이 약화되어 욕창 발생 가능성이 높다.", "3": "정상 체중을 유지하는 대상자는 욕창 발생 가능성이 낮다.", "4": "변비가 있는 대상자는 욕창과 직접적인 관계가 적다.", "5": "요의, 변의가 있는 대상자는 욕창 발생에 큰 영향을 미치지 않다."}'::jsonb, '[{"term_ko": "거동", "term_vi": "Hành động", "def_ko": "움직임(한국어)", "def_vi": "hành động(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (940, '5', '병상에 오랫동안 누워 있는 ㅐ상자의 피부가 혈액을 공급받지 못해서 괴사되는 질환은?', '["건조증", "욕창", "수두", "대상포진", "아토피 피부염"]'::jsonb, 2, NULL, NULL, '{"1": "건조증: 피부가 건조해지는 상태로, 혈액 공급 부족과는 관련이 없습니다.\n[정답]", "2": "욕창: 병상에 오래 누워 있을 때 피부가 괴사되는 질환으로, 혈액 공급이 부족하여 발생합니다.", "3": "수두: 바이러스성 질환으로 피부 괴사와는 다른 문제입니다.", "4": "대상포진: 신경계 질환과 관련이 있는 피부 질환입니다.", "5": "아토피 피부염: 알레르기 반응으로 인해 발생하는 피부 질환입니다."}'::jsonb, '[{"term_ko": "병상", "term_vi": "Giường bệnh", "def_ko": "침대(한국어)", "def_vi": "Giường mà bệnh nhân nằm"}, {"term_ko": "피부", "term_vi": "Da", "def_ko": "피부(한국어)", "def_vi": "Da của cơ thể"}, {"term_ko": "괴사", "term_vi": "Hoại tử", "def_ko": "죽어 있는 세포(한국어)", "def_vi": "Tình trạng tế bào chết do thiếu máu"}, {"term_ko": "혈액", "term_vi": "Máu", "def_ko": "피(한국어)", "def_vi": "Chất lỏng trong cơ thể"}, {"term_ko": "공급", "term_vi": "Cung cấp", "def_ko": "제공하다(한국어)", "def_vi": "Vận chuyển hoặc gửi đến"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (939, '5', '노화에 따른 피부의 특성으로 옳은 것은?', '["표피가 두꺼워진다.", "각질층의 수분함량이 증가한다.", "피하지방의 증가로 기온에 둔감해진다.", "모근의 멜라닌생성 세포가 증가한다.", "상처가 잘 낫지 않으면 궤양이 생기기 쉽다."]'::jsonb, 5, NULL, NULL, '{"1": "표피는 일반적으로 노화에 따라 얇아집니다.\n[정답]", "5": "노화로 인해 피부의 치유 능력이 감소하여 상처가 잘 낫지 않으면 궤양이 생기기 쉽습니다.", "2": "각질층의 수분함량은 노화로 인해 감소합니다.", "3": "피하지방은 노화로 인해 감소하며, 기온에 둔감해지는 것은 피하지방의 감소 때문입니다.", "4": "모근의 멜라닌 생성 세포는 노화와 함께 감소합니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "노인(한국어)", "def_vi": "người già(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (938, '5', '대상자에게 관찰되는 피부계 변화 중 보고해야 하는 상황은?', '["머리카락이 가늘어졌다.", "손등에 노인성 반점이 생겼다.", "피부에 발적과 가려움증이 있다.", "손톱, 발톱이 딱딱하고 두꺼워졌다.", "눈가에 주름이 생기고, 피부의 탄력성이 떨어졌다."]'::jsonb, 3, NULL, NULL, '{"1": "머리카락이 가늘어지는 것은 일반적인 노화 과정으로, 보고할 필요가 없다.", "2": "손등에 노인성 반점이 생기는 것은 노화의 일환으로, 보고하지 않아도 된다.\n[정답]", "3": "피부에 발적과 가려움증이 있는 경우는 염증이나 알레르기 반응의 가능성이 있어 즉시 보고해야 한다.", "4": "손톱, 발톱이 딱딱하고 두꺼워지는 것은 일반적인 노화 현상으로, 특별한 문제가 없으면 보고할 필요가 없다.", "5": "눈가에 주름이 생기고 피부의 탄력성이 떨어지는 것은 노화로 인한 자연스러운 변화로, 보고할 필요가 없다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người được chăm sóc", "def_ko": "환자 또는 돌보는 사람", "def_vi": "Bệnh nhân hoặc người được chăm sóc"}, {"term_ko": "피부계", "term_vi": "Hệ thống da", "def_ko": "피부 및 그 기능에 관계된 시스템", "def_vi": "Hệ thống liên quan đến da và chức năng của nó"}, {"term_ko": "변화", "term_vi": "Biến đổi", "def_ko": "변화", "def_vi": "Sự thay đổi"}, {"term_ko": "발적", "term_vi": "Đỏ da", "def_ko": "피부의 붉은 반점", "def_vi": "Vết đỏ trên da"}, {"term_ko": "가려움증", "term_vi": "Ngứa", "def_ko": "피부가 간질거리는 느낌", "def_vi": "Cảm giác da bị ngứa"}, {"term_ko": "노인성 반점", "term_vi": "Đốm tuổi", "def_ko": "나이가 들어서 생기는 피부의 색소 변화", "def_vi": "Sự thay đổi sắc tố trên da do tuổi tác"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (937, '5', '전립선비대증 대상자의 방광염 예방을 돕는 방법로 옳은 것은?', '["유치도뇨관을 삽입한다.", "골반근육강화운동을 하게 한다.", "소변을 참을 수 있을 때까지 참는다.", "낮에는 시간을 정해 규칙적으로 배뇨하게 한다.", "식이섬유가 풍부한 음식을 섭취하게 한다."]'::jsonb, 4, NULL, NULL, '{"1": "유치도뇨관을 삽입하는 것은 일반적으로 방광염 예방이 아닌 치료적인 방법이다.\n[정답]", "2": "골반근육강화운동은 방광의 기능을 개선할 수 있지만 직접적인 예방 방법은 아니다.", "3": "소변을 참는 것은 방광에 부담을 줄 수 있어 예방에 도움이 되지 않는다.", "4": "낮에는 시간을 정해 규칙적으로 배뇨하게 하는 것이 방광염 예방에 효과적이다.", "5": "식이섬유가 풍부한 음식은 장 건강에는 좋은 영향을 미치겠지만 방광염 예방과 직접적인 관련은 적다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Bệnh phì đại tiền liệt tuyến", "def_ko": "전립선이 비대해져서 발생하는 질환", "def_vi": "Bệnh lý gia tăng kích thước tuyến tiền liệt"}, {"term_ko": "방광염", "term_vi": "Viêm bàng quang", "def_ko": "방광의 염증", "def_vi": "Viêm nhiễm của bàng quang"}, {"term_ko": "유치도뇨관", "term_vi": "Ống thông tiểu", "def_ko": "소변을 배출하는 도구", "def_vi": "Thiết bị để dẫn lưu nước tiểu"}, {"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 행위", "def_vi": "Hành động đi tiểu"}, {"term_ko": "식이섬유", "term_vi": "Chất xơ", "def_ko": "소화관에서 게르마에 기여하는 식품 성분", "def_vi": "Thành phần thực phẩm giúp tiêu hóa"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (936, '5', '전립선비대증을 치료하는 방법으로 옳은 것은?', '["도뇨관을 이용하여 정기적으로 소변을 빼준다.", "고지방과 고콜레스테롤 음식을 섭취한다.", "약화된 근육을 강화하기 위해 체중을 늘린다.", "소변량을 증가시키기 위해 맥주를 마신다.", "심하면 약물 치료와 방사선 치료를 시작한다."]'::jsonb, 1, NULL, NULL, '{"1": "도뇨관을 이용하여 정기적으로 소변을 빼주는 것은 전립선비대증의 일반적인 치료 방법 중 하나입니다.\n[정답]", "2": "고지방과 고콜레스테롤 음식은 오히려 건강에 좋지 않으므로 치료 방법이 아닙니다.", "3": "약화된 근육을 강화하기 위해 체중을 늘리는 것은 전립선비대증과 관련된 방법이 아닙니다.", "4": "소변량을 증가시키기 위해 맥주를 마시는 것은 전립선비대증에 도움이 되지 않습니다.", "5": "심하면 약물 치료와 방사선 치료를 고려할 수 있으나, 이 방법은 일반적인 치료 방법이 아닙니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Bệnh phì đại tuyến tiền liệt", "def_ko": "과도한 전립선 성장으로 인한 증상", "def_vi": "Tình trạng tăng trưởng quá mức của tuyến tiền liệt"}, {"term_ko": "도뇨관", "term_vi": "Ống thông", "def_ko": "소변을 빼내기 위해 사용하는 관", "def_vi": "Ống sử dụng để xả nước tiểu"}, {"term_ko": "약물 치료", "term_vi": "Điều trị bằng thuốc", "def_ko": "의약품을 사용하여 질병을 치료하는 것", "def_vi": "Sử dụng thuốc để điều trị bệnh"}, {"term_ko": "방사선 치료", "term_vi": "Điều trị bằng xạ trị", "def_ko": "방사선을 이용하여 질병을 치료하는 것", "def_vi": "Sử dụng tia xạ để điều trị bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (935, '5', '전립선비대증이 있는 대상자에게 나타나는 증상으로 옳은 것은?', '["소변량이 많아졌어요.", "소변에서 냄새가 나요.", "소변 줄기가 굵어졌어요.", "소변에 거품이 섞여 나와요.", "소변을 보았는데도 시원하지가 않아요."]'::jsonb, 5, NULL, NULL, '{"1": "전립선비대증에서는 소변량이 많아지지 않는 경우가 많습니다.", "2": "소변에서 냄새가 나는 것은 비대증과 관련이 없습니다.", "3": "소변 줄기가 굵어지지 않으며 오히려 약해질 수 있습니다.\n[정답]", "5": "소변을 보았는데도 시원하지가 않은 느낌은 전립선비대증의 대표적인 증상입니다.", "4": "소변에 거품이 섞여 나오는 것은 다른 문제로 여겨질 수 있습니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "소변", "def_ko": "전립선이 비대해지는 질환 (Phì đại tuyến tiền liệt)", "def_vi": "체내에서 배출되는 액체 (Nước tiểu)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (934, '5', '전립선비대증 증상으로 옳은 것은?', '["단백뇨가 있다.", "배뇨 후 시원하다.", "소변에서 피가 섞여 나온다.", "요도가 넓어져서 소변을 자주 본다.", "배뇨 후 2시간 이내에 다시 소변이 마렵다."]'::jsonb, 5, NULL, NULL, '{"1": "단백뇨는 전립선비대증의 증상이 아닙니다.\n[정답]", "5": "배뇨 후 2시간 이내에 다시 소변이 마렵다는 전립선비대증의 전형적인 증상입니다.", "2": "배뇨 후 시원하다는 증상은 일반적으로 전립선비대증과 관련이 없습니다.", "3": "소변에서 피가 섞여 나오는 것은 다른 비뇨기계 질환과 관련이 있을 수 있습니다.", "4": "요도가 넓어져서 소변을 자주 본다는 것은 전립선비대증의 증상과는 반대 개념입니다."}'::jsonb, '[{"term_ko": "전립선비대증", "term_vi": "Phì đại tuyến tiền liệt", "def_ko": "전립선이 비대해져서 생기는 증상", "def_vi": "Triệu chứng do tuyến tiền liệt phình to gây ra"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (933, '5', '배뇨 후 잔뇨감이 있고 소변 줄기가 가늘어지며 힘을 주어야 소변이 나오는 질환은?', '["요실금", "요도염", "요로결석", "신장염", "전립선비대증"]'::jsonb, 5, NULL, NULL, '{"1": "요실금: 소변을 의도하지 않게 흘리는 상태로, 본 문제와 관련이 없습니다.\n[정답]", "5": "전립선비대증: 배뇨 후 잔뇨감과 소변 줄기가 가늘어지는 증상이 보이며, 힘을 주어야 소변이 나옵니다.", "2": "요도염: 요도에 염증이 생겨 소변에 통증이 있을 수 있지만, 본 문제의 증상과는 다릅니다.", "3": "요로결석: 통증을 동반할 수 있는 질환이지만 잔뇨감과 줄기가 가늘어지는 증상과는 차이가 있습니다.", "4": "신장염: 신장의 염증으로, 배뇨 문제와는 다른 증상이 주로 나타납니다."}'::jsonb, '[{"term_ko": "배뇨", "term_vi": "Đi tiểu", "def_ko": "소변을 보는 행위", "def_vi": "Hành động đi tiểu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (932, '5', '전립성비대증 발생과 관련된 요인으로 옳은 것은?', '["요로감염", "복압상승", "남성호르몬 불균형", "방광의 저장능력 감소", "골반 근육 조절능력의 약화"]'::jsonb, 3, NULL, NULL, '{"1": "요로감염은 전립성비대증의 직접적인 원인이 아닙니다.\n[정답]", "2": "복압상승은 전립선에 압력을 가할 수 있지만, 전립성 비대증의 주요 원인은 아닙니다.", "3": "남성호르몬 불균형은 전립성비대증의 발생과 밀접한 관련이 있습니다.", "4": "방광의 저장능력 감소는 전립성비대증의 증상으로 나타날 수 있지만, 발생 원인은 아닙니다.", "5": "골반 근육 조절능력의 약화는 비대증의 결과일 수 있으나, 발생 원인은 아닙니다."}'::jsonb, '[{"term_ko": "전립선", "term_vi": "비대증", "def_ko": "남성의 생식기관 중 하나 - Tuyến tiền liệt: Một trong những cơ quan sinh sản của nam giới", "def_vi": "비정상적으로 커지는 상태 - Phì đại: Tình trạng lớn một cách bất thường"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (931, '5', '복압성 요실금이 있는 대상자를 돕는 방법은?', '["복부를 꽉 조이는 옷을 입힌다.", "매시간 화장실을 가도록 한다.", "비만 관리를 한다.", "규칙적으로 줄넘기를 하게 한다.", "식이섬유소가 적은 음식을 제공한다."]'::jsonb, 3, NULL, NULL, '{"1": "복부를 꽉 조이는 옷을 입히면 요실금 증상이 악화될 수 있습니다.\n[정답]", "3": "비만 관리는 복압성 요실금 증상을 경감시킬 수 있는 방법입니다.", "2": "매시간 화장실에 가도록 하는 것은 효과적일 수 있지만 장기적인 관리 방법으로는 적절하지 않을 수 있습니다.", "4": "규칙적으로 줄넘기를 하는 것은 오히려 증상을 악화시킬 수 있습니다.", "5": "식이섬유소가 적은 음식은 변비를 유발할 수 있어 요실금에 좋지 않습니다."}'::jsonb, '[{"term_ko": "복압성", "term_vi": "Áp lực", "def_ko": "압력에 의해 발생하는", "def_vi": "chịu đựng một cái gì đó"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (920, '5', '절박성 요실금이 있는 대상자를 돕는 방법으로 옳은 것은?', '["수분 섭취를 제한한다.", "낮에는 기저귀를 채워 준다.", "웃음치료에 참여하게 한다.", "따뜻한 커피를 자주 마시게 한다.", "골반근육강화 운동을 하게한다."]'::jsonb, 5, NULL, NULL, '{"1": "온열요법은 골절 예방과 관련이 없습니다.\n[정답]", "2": "체중부하운동은 뼈를 강화하고 골절 예방에 도움이 됩니다.", "3": "자외선 차단제는 골다공증과 무관합니다.", "4": "혈전예방 약물은 골절 예방과 관련이 없습니다.", "5": "에스트로겐 섭취 제한은 필요하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 낮아져 약해지는 상태", "def_vi": "Tình trạng xương trở nên yếu do mật độ thấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (929, '5', '복압성 요실금 대상자를 돕는 방법으로 옳은 것은?', '["체중을 늘린다.", "변비를 예방한다.", "유치도뇨관을 삽입한다.", "야간에는 수분 섭취를 금지한다.", "장기간 소변을 참았다가 배뇨하도록 한다."]'::jsonb, 2, NULL, NULL, '{"1": "체중을 늘리는 것은 복압성 요실금을 악화시킬 수 있습니다.\n[정답]", "2": "변비 예방은 복압성 요실금 환자에게 중요한 관리 방법입니다.", "3": "유치도뇨관은 필요하지 않은 경우에는 삽입하지 않아야 합니다.", "4": "야간에 수분 섭취를 제한하는 것은 수분 부족을 초래할 수 있습니다.", "5": "장기간 소변을 참는 것은 방광 기능에 문제를 일으킬 수 있습니다."}'::jsonb, '[{"term_ko": "복압성", "term_vi": "Tiểu không kiểm soát do áp lực", "def_ko": "압력이 가해지는 상태", "def_vi": "Tình trạng không kiểm soát tiểu tiện do áp lực"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (928, '5', '노화로 인한 요실금의 원인이 되는 것은?', '["잔뇨량 감소", "신장 기능의 향상", "요도 기능 향상", "방광의 저장능력 감소", "골반 근육 조절능력의 향상"]'::jsonb, 4, NULL, NULL, '{"1": "잔뇨량 감소는 요실금을 유발하는 요인이 아닙니다.\n[정답]", "4": "방광의 저장능력 감소는 노화에 따라 발생하는 일반적인 증상으로 요실금을 유발할 수 있습니다.", "2": "신장 기능의 향상은 요실금과 관련이 없습니다.", "3": "요도 기능 향상은 요실금으로 이어지지 않습니다.", "5": "골반 근육 조절능력의 향상은 오히려 요실금 예방에 도움이 됩니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không kiểm soát", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "방광", "term_vi": "Bàng quang", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "저장능력", "term_vi": "Khả năng chứa", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "골반", "term_vi": "Khung chậu", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "근육", "term_vi": "Cơ", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (927, '5', '대상자가 기침, 웃음, 재채기를 할 때 복부 내 압려그이 증가로 인해 소변이 배출되는 증상이 나타나는 것은?', '["혼합성 요실금", "복압성 요실금", "절박성 요실금", "역류성 요실금", "반사성 요실금"]'::jsonb, 2, NULL, NULL, '{"1": "혼합성 요실금은 여러 요인으로 발생하는 요실금을 의미합니다.\n[정답]", "2": "복압성 요실금은 기침, 웃음, 재채기 등으로 복압이 증가해 소변이 배출되는 현상을 말합니다.", "3": "절박성 요실금은 갑작스러운 배뇨 욕구로 인해 발생하는 요실금을 의미합니다.", "4": "역류성 요실금은 방광의 기능 저하로 인해 발생하는 요실금입니다.", "5": "반사성 요실금은 신경 손상으로 인해 배뇨의 반사가 제대로 이루어지지 않아 발생합니다."}'::jsonb, '[{"term_ko": "대상자", "term_vi": "Người bệnh", "def_ko": "환자", "def_vi": "Bệnh nhân"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (926, '5', '자신의 의지와 상관없이 소변이 밖으로 흘러나오는 증상을 무엇이라 하는가?', '["변실금", "요실금", "요도염", "방광염", "신장염"]'::jsonb, 2, NULL, NULL, '{"1": "변실금: 대변이 의사와 관계없이 흘러나오는 증상입니다.\n[정답]", "2": "요실금: 자신의 의지와 상관없이 소변이 흘러나오는 증상입니다.", "3": "요도염: 요도의 염증으로, 소변을 흘리는 증상은 포함되지 않습니다.", "4": "방광염: 방광의 염증이지만, 소변이 흘러나오는 직접적인 증상은 아닙니다.", "5": "신장염: 신장의 염증이지만, 요실금과는 다른 증상입니다."}'::jsonb, '[{"term_ko": "요실금", "term_vi": "Tiểu không tự chủ", "def_ko": "의사와 상관없이 소변이 흘러나오는 증상", "def_vi": "Triệu chứng mà nước tiểu chảy ra ngoài mà không theo ý muốn"}, {"term_ko": "변실금", "term_vi": "Biểu hiện đi ngoài", "def_ko": "대변이 의사와 관계없이 흘러나오는 증상", "def_vi": "Thành phần của đại tiện chảy ra ngoài mà không theo ý muốn"}, {"term_ko": "요도염", "term_vi": "Viêm niệu đạo", "def_ko": "요도의 염증", "def_vi": "Tình trạng viêm niệu đạo"}, {"term_ko": "방광염", "term_vi": "Viêm bàng quang", "def_ko": "방광의 염증", "def_vi": "Tình trạng viêm bàng quang"}, {"term_ko": "신장염", "term_vi": "Viêm thận", "def_ko": "신장의 염증", "def_vi": "Tình trạng viêm thận"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (925, '5', '여성노인의 생식기계 변화로 옳은 것은?', '["성적 욕구 감소", "성교 시 통증 감소", "에스트로겐 분비 증가", "질의 수축력 증가", "질의 윤활작용 감소"]'::jsonb, 5, NULL, NULL, '{"1": "성적 욕구 감소는 일반적으로 나타나는 현상입니다.\n[정답]", "5": "질의 윤활작용 감소는 노화 과정에서 흔히 발생하는 문제입니다.", "2": "성교 시 통증 감소는 반대의 경우가 일반적입니다.", "3": "에스트로겐 분비는 감소하는 경향이 있습니다.", "4": "질의 수축력은 나이가 들면서 감소하는 경향이 있습니다."}'::jsonb, '[{"term_ko": "여성노인", "term_vi": "Phụ nữ già", "def_ko": "나이가 많은 여성", "def_vi": "Phụ nữ lớn tuổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (924, '5', '노화에 따른 여성 노인의 생식기계 변화는?', '["난소 크기 감소", "질염 발생 감소", "질의 길이 증가", "질벽의 두께 증가", "여성호르몬 분비 증가"]'::jsonb, 1, NULL, NULL, '{"1": "노화에 따라 난소의 크기가 감소하는 것이 일반적이다.\n[정답]", "2": "질염 발생은 오히려 증가하는 경향이 있다.", "3": "질의 길이는 노화에 따라 감소하는 경향이 있다.", "4": "질벽의 두께는 감소할 수 있다.", "5": "여성호르몬 분비는 일반적으로 감소한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙어감(한국어)", "def_vi": "Sự già đi(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (923, '5', '골다공증으로 고관절 골절의 위험이 높은 대상자의 잘못된 행동은?', '["거실에 널려 있는 물건을 모두 치운다.", "규칙적으로 하지근력 강화운동을 한다.", "연어, 고등어, 달걀을 자주 섭취한다.", "저체중 상태를 유지하기 위해 다이어트를 한다.", "안경 도수가 맞지 않아 안경을 새로 맞춘다."]'::jsonb, 4, NULL, NULL, '{"1": "거실에 있는 물건을 치우는 것은 안전사고를 예방하므로 좋은 행동입니다.\n[정답]", "4": "저체중 상태를 유지하기 위한 다이어트는 영양 섭취 부족을 초래할 수 있어 위험합니다.", "2": "하지근력 강화운동은 골절 예방에 도움이 되는 좋은 행동입니다.", "3": "연어, 고등어, 달걀은 칼슘과 비타민D의 섭취에 도움이 되어 건강에 좋습니다.", "5": "안경 도수를 맞춰 시력을 개선하는 것은 안전에 도움을 줍니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈가 약해지는 질병", "def_vi": "Bệnh làm xương yếu đi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (922, '5', '다음 중 고관절 골절을 유발하는 질환은?', '["퇴행성 관절염", "류마티스 관절염", "추간판 탈출증", "골다공증", "척추관 협착증"]'::jsonb, 4, NULL, NULL, '{"1": "퇴행성 관절염은 관절의 마모와 노화를 초래하지만 고관절 골절과는 직접적인 관계가 없다.\n[정답]", "4": "골다공증은 뼈의 밀도가 감소하여 골절 위험이 증가하며, 고관절 골절의 주 원인 중 하나이다.", "2": "류마티스 관절염은 주로 관절의 염증을 유발하여 관절 기능 장애를 초래하지만 고관절 골절을 직접적으로 유발하지는 않는다.", "3": "추간판 탈출증은 주로 허리와 관련된 문제로, 고관절 골절을 유발하는 것과는 관련이 없다.", "5": "척추관 협착증은 주로 척추에서 발생하는 질환으로 고관절 골절과는 직접적인 관계가 없다."}'::jsonb, '[{"term_ko": "고관절", "term_vi": "Khớp háng", "def_ko": "엉덩이 관절", "def_vi": "Khớp giữa xương chậu và xương đùi"}, {"term_ko": "골절", "term_vi": "Gãy xương", "def_ko": "뼈가 부러지는 것", "def_vi": "Hiện tượng xương bị gãy"}, {"term_ko": "퇴행성", "term_vi": "Thoái hóa", "def_ko": "나이가 들어감에 따라 퇴화하는 것", "def_vi": "Quá trình mất chức năng hoặc giảm hiệu suất theo thời gian"}, {"term_ko": "관절염", "term_vi": "Viêm khớp", "def_ko": "관절에 발생하는 염증 또는 질환", "def_vi": "Bệnh viêm ở khớp"}, {"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 감소하는 질환", "def_vi": "Bệnh làm giảm mật độ xương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (921, '5', '낙상으로 인해 서혜부와 대퇴부에 통증이 있고 움직임에 제한이 있는 질환은?', '["퇴행성 관절염", "류마티스 관절염", "고관절 골절", "골다공증", "외상성 관절염"]'::jsonb, 3, NULL, NULL, '{"1": "퇴행성 관절염은 노화나 반복적인 사용으로 인해 관절이 퇴화되면서 발생하는 질환입니다.", "2": "류마티스 관절염은 주로 면역계의 이상으로 인해 발생하는 염증성 질환입니다.\n[정답]", "3": "고관절 골절은 사고나 낙상 등에 의해 고관절이 부러진 상태로, 서혜부와 대퇴부에 통증 및 움직임에 제한이 발생합니다.", "4": "골다공증은 뼈의 밀도가 감소하여 쉽게 골절되는 상태를 나타내지만, 직접적인 통증이나 움직임 제한을 유발하지 않습니다.", "5": "외상성 관절염은 외부의 충격으로 인해 발생하는 관절의 염증을 의미하지만, 고관절 골절 경우와는 다릅니다."}'::jsonb, '[{"term_ko": "낙상", "term_vi": "Ngã", "def_ko": "넘어지다(한국어)", "def_vi": "Ngã"}, {"term_ko": "서혜부", "term_vi": "Vùng bẹn", "def_ko": "서혜부(한국어)", "def_vi": "Vùng bẹn"}, {"term_ko": "대퇴부", "term_vi": "Đùi", "def_ko": "허벅지(한국어)", "def_vi": "Đùi"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "아픔(한국어)", "def_vi": "Đau"}, {"term_ko": "움직임", "term_vi": "Vận động", "def_ko": "운동(한국어)", "def_vi": "Vận động"}, {"term_ko": "제한", "term_vi": "Hạn chế", "def_ko": "제한하다(한국어)", "def_vi": "Hạn chế"}, {"term_ko": "질환", "term_vi": "Bệnh", "def_ko": "병(한국어)", "def_vi": "Bệnh"}, {"term_ko": "골절", "term_vi": "Gãy", "def_ko": "부러지다(한국어)", "def_vi": "Gãy"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (920, '5', '골다공증으로 인한 골절을 예방할 수 있는 방법은?', '["온열요법을 실시한다.", "체중부하운동을 한다.", "자외선 차단제를 바른다.", "혈전예방 약물을 복용한다.", "에스트로겐 섭취를 제한한다."]'::jsonb, 2, NULL, NULL, '{"1": "온열요법은 골절 예방과 관련이 없습니다.\n[정답]", "2": "체중부하운동은 뼈를 강화하고 골절 예방에 도움이 됩니다.", "3": "자외선 차단제는 골다공증과 무관합니다.", "4": "혈전예방 약물은 골절 예방과 관련이 없습니다.", "5": "에스트로겐 섭취 제한은 필요하지 않을 수 있습니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 낮아져 약해지는 상태", "def_vi": "Tình trạng xương trở nên yếu do mật độ thấp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (919, '5', '골다공증 예방에 도움을 주는 영양소는?', '["비타민A", "비타민B", "비타민C", "비타민D", "비타민E"]'::jsonb, 4, NULL, NULL, '{"1": "비타민A는 주로 시력과 면역기능에 도움을 줍니다.", "2": "비타민B는 에너지 대사와 관련된 비타민 그룹입니다.", "3": "비타민C는 항산화 작용과 면역력 강화에 중요합니다.\n[정답]", "4": "비타민D는 칼슘 흡수를 도와 골다공증 예방에 중요합니다.", "5": "비타민E는 항산화 작용을 하는 비타민입니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈의 밀도가 낮아지는 질병(한국어)", "def_vi": "Bệnh giảm mật độ xương"}, {"term_ko": "영양소", "term_vi": "Dưỡng chất", "def_ko": "신체에 필요한 영양 성분(한국어)", "def_vi": "Thành phần dinh dưỡng cần thiết cho cơ thể"}, {"term_ko": "비타민", "term_vi": "Vitamin", "def_ko": "인체에 필수적인 유기 화합물(한국어)", "def_vi": "Hợp chất hữu cơ cần thiết cho cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (918, '5', '골다공증 예방을 위한 비타민 D의 섭취에 도움이 되는 것은?', '["매일 30분씩 햇볕을 쬐며 걷는다.", "충분한 숙면을 취한다.", "비타민A를 섭취한다.", "카페인이 많은 커피를 섭취한다.", "실외 운동보다는 실내 운동을 강화한다."]'::jsonb, 1, NULL, NULL, '{"1": "햇볕을 쬐는 것은 비타민 D의 자연 생성에 도움을 줍니다.\n[정답]", "2": "충분한 숙면은 건강에 필요하지만 비타민 D와는 직접적인 연관이 없습니다.", "3": "비타민 A는 비타민 D와는 다른 역할을 하며, 비타민 D의 섭취에 도움을 주지 않습니다.", "4": "카페인이 많은 커피는 칼슘 흡수를 방해할 수 있어 골다공증 예방에 부정적입니다.", "5": "실내 운동보다 실외 운동이 비타민 D 합성에 더 효과적입니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Bệnh loãng xương", "def_ko": "뼈의 밀도가 낮아져 약해지는 질환", "def_vi": "Một căn bệnh mà mật độ xương giảm và làm xương trở nên yếu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (917, '5', '골다공증과 관련된 설명으로 옳은 것은?', '["뼈세포가 증가하여 골밀도가 높아진다.", "서혜부와 대퇴부에 통증이 온다", "칼슘섭취를 제한한다.", "햇볕에 노출되는 것을 피한다.", "비타민 D가 함유된 음식을 섭취한다."]'::jsonb, 5, NULL, NULL, '{"1": "뼈세포가 증가하면 오히려 골밀도가 낮아질 수 있습니다. \n[정답]", "5": "비타민 D는 칼슘 흡수에 중요한 역할을 하므로, 이를 포함한 식사를 하는 것이 중요합니다.", "2": "서혜부와 대퇴부의 통증은 골다공증의 직접적인 증상이 아닙니다.", "3": "칼슘 섭취는 골다공증 예방에 중요하므로 제한해서는 안 됩니다.", "4": "햇볕에 노출되는 것은 비타민 D 합성에 필요하므로 피해야 합니다."}'::jsonb, '[{"term_ko": "골다공증", "term_vi": "Loãng xương", "def_ko": "뼈가 약해지고 쉽게 부러지는 병", "def_vi": "Bệnh làm xương yếu và dễ gãy"}, {"term_ko": "골밀도", "term_vi": "Mật độ xương", "def_ko": "뼈의 밀도", "def_vi": "Độ dày của xương"}, {"term_ko": "비타민 D", "term_vi": "Vitamin D", "def_ko": "칼슘 흡수에 중요한 비타민", "def_vi": "Vitamin quan trọng cho sự hấp thụ canxi"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈를 형성하는 중요한 미네랄", "def_vi": "Khoáng chất quan trọng cho sự hình thành xương"}, {"term_ko": "햇볕", "term_vi": "Ánh nắng mặt trời", "def_ko": "태양의 빛", "def_vi": "Ánh sáng mặt trời"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (916, '5', '뼈세포가 상실되고 골밀도가 낮아져 골절이 발생하기 쉬운 질환은?', '["고관절 골절", "골다공증", "퇴행성 관절염", "대퇴골 골절", "척추 디스크"]'::jsonb, 2, NULL, NULL, '{"1": "고관절 골절: 골절에 대한 내용으로 관련성을 찾기 어려움.\n[정답]", "2": "골다공증: 뼈의 밀도가 감소하고 골절의 위험을 증가시키는 질환.", "3": "퇴행성 관절염: 관절의 연골이 닳아 없어지는 질환으로 골밀도와 관계 없음.", "4": "대퇴골 골절: 특정 부위의 골절로, 골밀도 문제의 직접적인 언급 없음.", "5": "척추 디스크: 디스크 문제로 골밀도와는 관계가 없음."}'::jsonb, '[{"term_ko": "뼈세포", "term_vi": "Tế bào xương", "def_ko": "뼈를 구성하는 세포", "def_vi": "Các tế bào cấu thành xương"}, {"term_ko": "골밀도", "term_vi": "Mật độ xương", "def_ko": "뼈의 밀도", "def_vi": "Độ đặc của xương"}, {"term_ko": "골절", "term_vi": "Gãy xương", "def_ko": "뼈가 부서짐", "def_vi": "Sự gãy của xương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (915, '5', '퇴행성 관절염이 있는 대상자에게 적합한 운동으로 옳은 것은?', '["등산", "수영", "배드민턴", "계단 오르내리기", "장거리 걷기"]'::jsonb, 2, NULL, NULL, '{"1": "등산은 무릅에 부담이 되어 좋지 않습니다.\n[정답]", "2": "수영은 관절의 부담을 덜어주면서 전신 운동이 가능하여 좋습니다.", "3": "배드민턴은 빠른 움직임이 필요해 관절에 무리가 갈 수 있습니다.", "4": "계단 오르내리기는 관절에 큰 부담을 준다.", "5": "장거리 걷기는 무릎에 부담이 커질 수 있습니다."}'::jsonb, '[{"term_ko": "퇴행성 관절염", "term_vi": "Viêm khớp thoái hóa", "def_ko": "관절의 소모성 질환", "def_vi": "Bệnh lý hao mòn khớp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (914, '5', '퇴행성 관절염을 예방하는 방법으로 옳은 것은?', '["체중 줄이기", "계단 오르내리기", "무거운 것 들기", "등산 하기", "장거리 걷기"]'::jsonb, 1, NULL, NULL, '{"1": "체중을 줄이면 관절에 가해지는 부담을 줄어들게 하여 퇴행성 관절염을 예방할 수 있다.\n[정답]", "2": "계단 오르내리기는 무릎 관절에 부담을 심하게 주어 퇴행성 관절염을 유발할 수 있다.", "3": "무거운 것을 드는 것은 관절에 부하를 주어 위험하다.", "4": "등산은 무릎에 부담을 주어 관절염을 악화시킬 수 있다.", "5": "장거리 걷기는 관절에 과도한 스트레스를 줄 수 있어 주의가 필요하다."}'::jsonb, '[{"term_ko": "퇴행성", "term_vi": "Thoái hóa", "def_ko": "노화나 외상 등으로 인하여 나타나는 질병", "def_vi": "Bệnh xuất hiện do lão hóa hoặc chấn thương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (913, '5', '다음과 같은 증상이 나타나는 노인성 질환으로 옳은 것은?• 연골이 닳아서 없어지는 상태이다.• 아침에 일어나면 관절이 뻣뻣해진다.• 운동 시 악화되고 안정 시 호전된다.', '["퇴행성 관절염", "류마티스 관절염", "골다공증", "고관절 골절", "골연화증"]'::jsonb, 1, NULL, NULL, '{"1": "퇴행성 관절염은 연골이 닳아 없어지는 상태로 아침에 뻣뻣함과 운동 시 악화되는 증상이 나타난다.\n[정답]", "2": "류마티스 관절염은 관절의 염증으로 전신 증상이 동반되며, 증상 양상이 다르다.", "3": "골다공증은 뼈의 밀도가 감소하여 쉽게 골절되는 병으로 관절의 증상과는 다르다.", "4": "고관절 골절은 외부의 힘에 의해 발생하는 손상으로 노인에서 흔히 발생하지만 위의 증상과는 관련이 없다.", "5": "골연화증은 뼈의 질감이 부드러워지는 병으로, 관절 문제와는 관련이 없다."}'::jsonb, '[{"term_ko": "노인성 질환", "term_vi": "Bệnh tuổi già", "def_ko": "노인에서 발생하는 질병", "def_vi": "Bệnh lý phát sinh ở người già"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (912, '5', '노화에 따른 근골격계 변화로 옳은 것은?', '["추간판이 얇아진다.", "항가골이 단단해진다.", "근육의 피로도가 감소한다.", "인대의 탄력성이 증가한다.", "팔, 다리의 지방이 증가한다."]'::jsonb, 1, NULL, NULL, '{"1": "노화로 인해 추간판이 얇아지는 것은 일반적인 변화입니다. \n[정답]", "2": "항가골이 단단해지는 것은 사실이 아닙니다. 노화에 따라 항가골의 밀도가 감소할 수 있습니다.", "3": "근육의 피로도는 오히려 증가하는 경향이 있습니다.", "4": "인대의 탄력성은 노화와 함께 감소합니다.", "5": "팔, 다리의 지방은 노화에 따라 증가할 수 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "근골격계", "def_ko": "늙음, Lão hóa", "def_vi": "근육과 뼈로 이루어진 계통, Hệ cơ xương"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (911, '5', '노화에 따른 근골격계 변화로 옳은 것은?', '["뼈의 질량 증가", "근긴장도 증가", "관절운동의 제한", "어깨가 넓어지고 골반이 작아짐", "엉덩이와 허리의 피하지방 감소"]'::jsonb, 3, NULL, NULL, '{"1": "뼈의 질량은 보통 노화에 따라 감소합니다.", "2": "근긴장도는 노화와 함께 감소하는 경향이 있습니다.\n[정답]", "3": "노화가 진행됨에 따라 관절의 운동 범위가 줄어드는 현상이 관찰됩니다.", "4": "어깨가 넓어지기보다는 노화로 인해 수축하는 경향이 있습니다.", "5": "엉덩이와 허리의 피하지방은 대개 증가하는 경향이 있습니다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "늙어가는 것", "def_vi": "Quá trình già đi"}, {"term_ko": "근골격계", "term_vi": "Hệ cơ xương", "def_ko": "근육과 뼈의 시스템", "def_vi": "Hệ thống cơ và xương"}, {"term_ko": "관절", "term_vi": "Khớp", "def_ko": "두 개 이상의 뼈가 만나는 곳", "def_vi": "Nơi hai hoặc nhiều xương gặp nhau"}, {"term_ko": "운동", "term_vi": "Vận động", "def_ko": "신체의 움직임", "def_vi": "Sự di chuyển của cơ thể"}, {"term_ko": "근긴장도", "term_vi": "Độ căng cơ", "def_ko": "근육의 긴장감", "def_vi": "Độ căng của cơ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (910, '5', '심장질환 대상자가 복도를 걷다가 갑자기 어지럼증을 호소할 때 우선적으로 해야 할 행동은?', '["따뜻한 설탕물을 준다.", "식사를 했는지 확인한다.", "바로 그 자리에 주저앉힌다.", "스트레스받은 일이 있는지 물어본다.", "즉시 도움을 요청하러 시설장에게 간다."]'::jsonb, 3, NULL, NULL, '{"1": "따뜻한 설탕물을 주는 것은 저혈당을 의심할 때 도움이 될 수 있으나, 이 경우에는 즉각적인 대처가 필요합니다.\n[정답]", "3": "바로 그 자리에 주저앉히는 것이 안전하며, 이는 어지럼증으로 인해 넘어질 위험을 줄입니다.", "2": "식사를 했는지 확인하는 것은 중요하지만, 즉각적인 응급조치가 필요합니다.", "4": "스트레스를 물어보는 것도 중요하지만, 어지럼증의 즉각적인 원인 파악보다 우선하여 안전하게 대처해야 합니다.", "5": "도움을 요청하러 가는 것은 적절한 행동이지만, 환자의 안전이 우선시되어야 하므로 즉시 도움을 요청하기 전에 환자를 안전하게 해야 합니다."}'::jsonb, '[{"term_ko": "심장질환", "term_vi": "Bệnh tim", "def_ko": "심장과 관련된 질병", "def_vi": "Bệnh liên quan đến tim"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (909, '5', '노인 대상자에게 흔히 나타나는 빈혈의 원인은?', '["칼슘 부족", "비타민A 부족", "비타민 D 부족", "철분 부족", "단백질 부족"]'::jsonb, 4, NULL, NULL, '{"1": "칼슘이 부족해도 빈혈은 발생할 수 있지만, 주원인은 아님.\n[정답]", "4": "철분 부족은 빈혈의 가장 일반적인 원인 중 하나로, 특히 노인에게서 흔히 나타남.", "2": "비타민 A 부족은 시력 저하 등의 문제를 일으킬 수 있으나 빈혈과는 직접적인 관계가 적음.", "3": "비타민 D 부족은 뼈 건강에 중요한 요소이나 빈혈과는 관련이 없음.", "5": "단백질 부족은 여러 건강 문제를 초래할 수 있으나 빈혈의 직접적인 원인은 아님."}'::jsonb, '[{"term_ko": "빈혈", "term_vi": "Thiếu máu", "def_ko": "혈액 내 헤모글로빈 농도가 낮아지는 상태", "def_vi": "Tình trạng giảm mức độ hemoglobin trong máu"}, {"term_ko": "철분", "term_vi": "Sắt", "def_ko": "혈액 생성에 중요한 미네랄", "def_vi": "Khoáng chất quan trọng cho sự tạo máu"}, {"term_ko": "칼슘", "term_vi": "Canxi", "def_ko": "뼈 건강에 필요한 미네랄", "def_vi": "Khoáng chất cần thiết cho sức khỏe xương"}, {"term_ko": "비타민", "term_vi": "Vitamin", "def_ko": "신체 기능을 지원하는 유기 화합물", "def_vi": "Hợp chất hữu cơ hỗ trợ chức năng cơ thể"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (908, '5', '빈혈로 철분제를 복용하고 있는 대상자가 어지럼증을 호소할 때 우선적으로 해야 할 일은?', '["영양주사를 맞힌다.", "햇볕을 쬐며 산책을 한다.", "낮잠을 자도록 돕는다.", "처방된 철분제를 복용했는지 확인한다.", "고지방식이로 영양을 공급한다."]'::jsonb, 4, NULL, NULL, '{"1": "영양주사를 맞히는 것은 필요하지 않습니다.", "2": "햇볕을 쬐며 산책하는 것은 어지럼증에 도움이 되지 않을 수 있습니다.", "3": "낮잠을 자도록 돕는 것은 일시적인 해결책이 될 수 있습니다.\n[정답]", "4": "처방된 철분제를 복용했는지 확인하는 것이 가장 중요합니다.", "5": "고지방식이로 영양을 공급하는 것은 비효율적입니다."}'::jsonb, '[{"term_ko": "빈혈", "term_vi": "Thiếu máu", "def_ko": "적혈구 또는 헤모글로빈 부족으로 인한 상태", "def_vi": "Tình trạng thiếu hồng cầu hoặc hemoglobin"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (907, '5', '심부전증 대상자를 돕는 방법으로 옳은 것은?', '["매일 체중을 측정한다.", "식사량을 늘려 제공한다.", "탄력스타킹을 항상 신게 한다.", "온, 냉탕을 오가며 목욕하게 한다.", "계단오르기 운동을 규칙적으로 하게 한다."]'::jsonb, 1, NULL, NULL, '{"1": "심부전증 환자는 체중의 변화를 지속적으로 관찰해야 합니다. 체중 증가가 부종의 지표가 될 수 있기 때문입니다.\n[정답]", "2": "심부전증 환자는 식사량을 늘리는 것이 아니라 적절한 양의 식사를 하여 나트륨 섭취를 줄여야 합니다.", "3": "탄력스타킹을 착용하는 것은 부종을 방지하는 데 도움이 되지만, 항상 신게 할 필요는 없습니다.", "4": "온, 냉탕을 오가며 목욕하는 것은 심부전 환자에게 위험할 수 있습니다.", "5": "계단오르기 운동은 심부전증 관리에는 적합하지 않습니다."}'::jsonb, '[{"term_ko": "심부전증", "term_vi": "対象者", "def_ko": "질병의 일종 - 心衰", "def_vi": "환자 - Đối tượng"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (906, '5', '혈액 내에 적혈구나 헤모글로빈이 부족하여 몸에 필요한 산소를 충분히 공급하지 못하는 질병은?', '["기흉", "빈혈", "심부전", "협심증", "혈전색전증"]'::jsonb, 2, NULL, NULL, '{"1": "기흉: 폐와 흉막 사이에 공기가 찬 상태로 호흡곤란을 일으킬 수 있다.\n[정답]", "2": "빈혈: 적혈구나 헤모글로빈이 부족하여 몸에 필요한 산소를 충분히 공급하지 못하는 질병이다.", "3": "심부전: 심장이 제대로 기능하지 못해 몸의 여러 기관에 산소 공급이 부족할 수 있다.", "4": "협심증: 심장에 혈액이 충분히 공급되지 않아 가슴 통증이 발생하는 질환이다.", "5": "혈전색전증: 혈전에 의해 혈관이 막히는 현상으로, 특정 부위의 혈액 공급을 차단한다."}'::jsonb, '[{"term_ko": "혈액", "term_vi": "Máu", "def_ko": "피(한국어)", "def_vi": "máu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (905, '5', '심부전증을 예방하는 방법으로 옳은 것은?', '["고혈압을 치료한다.", "흡연을 한다.", "고염식이를 섭취한다.", "물을 많이 마신다.", "과식을 한다."]'::jsonb, 1, NULL, NULL, '{"1": "고혈압은 심부전증의 위험 요소 중 하나이므로 치료는 예방에 도움이 됩니다.\n[정답]", "2": "흡연은 심혈관 질환의 위험을 증가시켜 심부전증 예방에 도움이 되지 않습니다.", "3": "고염식이는 고혈압 및 심부전에 악영향을 미치므로 피해야 합니다.", "4": "물을 많이 마시는 것이 심부전 예방에 직접적으로 도움이 되지는 않습니다.", "5": "과식은 비만과 관련되어 심부전증 위험을 증가시킵니다."}'::jsonb, '[{"term_ko": "심부전증", "term_vi": "Suy tim", "def_ko": "심장이 혈액을 충분히 펌프질하지 못하는 상태(한국어)", "def_vi": "Tình trạng tim không bơm đủ máu(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (904, '5', '다음 증상과 관련이 깊은 질환은?심장의 수축력 저하로 신체에 적절한 산소와 영양분을 공급받지 못하여 허약감, 피로, 호흡곤란을 느끼게 되며 걷기, 계단 오르기, 쇼핑하기 등 일상 생활에 어려움이 나타난다.', '["관절염", "고혈압", "심부전", "폐결핵", "동맥경화증"]'::jsonb, 3, NULL, NULL, '{"1": "관절염은 주로 관절에 염증이 생기는 질환으로, 해당 증상과는 관련이 없습니다.\n[정답]", "3": "심부전은 심장의 수축력이 저하되어 적절한 혈액 공급이 이루어지지 않아 허약감, 피로, 호흡곤란 등의 증상을 유발합니다.", "2": "고혈압은 혈압 상승으로 인한 문제로, 직접적인 수축력 저하와는 관련이 없습니다.", "4": "폐결흉은 폐 관련 질환으로 호흡기 증상이 주로 나타나며, 심부전과는 차이가 있습니다.", "5": "동맥경화증은 혈관의 경화로 여러 가지 심혈관계에 영향을 미칠 수 있지만, 주된 증상은 아닙니다."}'::jsonb, '[{"term_ko": "심장", "term_vi": "Tim", "def_ko": "심장(한국어)", "def_vi": "trái tim"}, {"term_ko": "수축력", "term_vi": "Sức co bóp", "def_ko": "혈액을 내보내는 힘(한국어)", "def_vi": "sức mạnh bơm máu"}, {"term_ko": "허약감", "term_vi": "Cảm giác yếu đuối", "def_ko": "힘이 없음(한국어)", "def_vi": "cảm giác không có sức"}, {"term_ko": "호흡곤란", "term_vi": "Khó thở", "def_ko": "숨쉬기 힘든 상태(한국어)", "def_vi": "tình trạng khó thở"}, {"term_ko": "일상 생활", "term_vi": "Cuộc sống hàng ngày", "def_ko": "매일 하는 활동(한국어)", "def_vi": "hoạt động hàng ngày"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (903, '5', '심부전의 증상으로 옳은 것은?가. 좌식호흡 나. 식욕상실 다. 의식혼돈, 현기증 라. 언어장애', '["가,라", "가, 나, 라", "나, 라", "가, 다, 라", "가, 나, 다"]'::jsonb, 5, NULL, NULL, '{"1": "가: 좌식호흡은 심부전의 증상으로 보지 않으며, 라: 언어장애는 일반적으로 심부전과는 관련이 없습니다.", "2": "가: 좌식호흡은 심부전의 증상이 아니고, 나: 식욕상실은 심부전의 일반적인 증상입니다.\n[정답]", "5": "가: 좌식호흡은 심부전의 증상이 아니며, 나: 식욕상실과 다: 의식혼돈, 현기증은 심부전의 중요한 증상으로 포함됩니다.", "3": "나: 식욕상실은 맞지만, 라: 언어장애는 심부전과 관계가 없습니다.", "4": "가: 좌식호흡은 심부전 증상이 아니므로 틀립니다."}'::jsonb, '[{"term_ko": "심부전", "term_vi": "Suy tim", "def_ko": "심장이 제 기능을 하지 못하는 상태", "def_vi": "Tình trạng tim không hoạt động bình thường"}, {"term_ko": "좌식호흡", "term_vi": "Thở ngồi", "def_ko": "앉아서 호흡을 하는 것", "def_vi": "Thở trong tư thế ngồi"}, {"term_ko": "식욕상실", "term_vi": "Mất cảm giác thèm ăn", "def_ko": "음식에 대한 욕구가 줄어드는 것", "def_vi": "Giảm sự thèm ăn"}, {"term_ko": "의식혼돈", "term_vi": "Rối loạn ý thức", "def_ko": "인지 기능의 장애", "def_vi": "Sự rối loạn về nhận thức"}, {"term_ko": "현기증", "term_vi": "Chóng mặt", "def_ko": "어지럼증을 느끼는 것", "def_vi": "Cảm giác choáng váng"}, {"term_ko": "언어장애", "term_vi": "Rối loạn ngôn ngữ", "def_ko": "말하는 데 어려움이 있는 것", "def_vi": "Khó khăn trong giao tiếp"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (902, '5', '심장의 수축력이 저하되어 저산소증이 올 때 나타나는 증상은?', '["의식혼돈", "부종", "흉객혈통", "객혈", "언어장애"]'::jsonb, 1, NULL, NULL, '{"1": "의식혼돈: 저산소증으로 인해 뇌에 충분한 산소 공급이 이루어지지 않아 혼돈 상태를 유발할 수 있습니다.\n[정답]", "2": "부종: 심장 기능 저하로 수분이 체내에 축적되며 부종이 발생할 수 있으나 주된 증상과는 거리가 있습니다.", "3": "흉객혈통: Кордиум 관상동맥의 질환으로 인한 통증이지만 저산소증과 직접적 연관은 없습니다.", "4": "객혈: 폐혈관의 문제일 가능성이 있지만 저산소증과는 명확하게 연결되지 않습니다.", "5": "언어장애: 뇌의 산소 부족으로 언어에 문제가 생길 수 있으나 이는 다른 요인과의 관련성이 크기 때문에 주된 증상으로 보기 어렵습니다."}'::jsonb, '[{"term_ko": "심장", "term_vi": "Trái tim", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "수축력", "term_vi": "Sức co bóp", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "저산소증", "term_vi": "Thiếu oxy", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "의식", "term_vi": "Ý thức", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}, {"term_ko": "혼돈", "term_vi": "Lẫn lộn", "def_ko": "뜻(한국어)", "def_vi": "뜻(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (901, '5', '동맥경화증이 있는 대상자에게 적합한 음식은?', '["새우튀김", "제육볶음", "토마토", "부대찌개", "오징어 젓갈"]'::jsonb, 3, NULL, NULL, '{"1": "새우튀김은 기름에 튀겨져 있는 고열량 음식으로 적합하지 않습니다.", "2": "제육볶음은 지방이 많아 동맥경화증 환자에게 좋지 않습니다.\n[정답]", "3": "토마토는 항산화 물질이 풍부하고 심혈관 건강에 도움을 줍니다.", "4": "부대찌개는 여러 재료가 들어가고 기름기가 많아 부적합합니다.", "5": "오징어 젓갈은 나트륨 함량이 높아 좋지 않은 선택입니다."}'::jsonb, '[{"term_ko": "동맥경화증", "term_vi": "Xơ vữa động mạch", "def_ko": "혈관의 벽에 지방, 콜레스테롤 등이 쌓이는 병증", "def_vi": "Bệnh lý tích tụ chất béo, cholesterol vào thành mạch"}, {"term_ko": "적합한", "term_vi": "Phù hợp", "def_ko": "적절한, 맞는", "def_vi": "Thích hợp, đúng"}, {"term_ko": "음식", "term_vi": "Thực phẩm", "def_ko": "식사나 간식으로 먹는 것", "def_vi": "Món ăn, món ngon"}, {"term_ko": "토마토", "term_vi": "Cà chua", "def_ko": "한 종류의 채소, 붉은색", "def_vi": "Một loại rau củ, màu đỏ"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (900, '5', '동맥경화증의 원인으로 옳은 것은?', '["저염식이 섭취", "규칙적인 운동", "저지방식이 섭취", "당뇨병, 고지혈증, 고혈압", "가족적 소인은 없다."]'::jsonb, 4, NULL, NULL, '{"1": "저염식이 섭취는 동맥경화증을 예방하는데 도움이 될 수 있습니다.", "2": "규칙적인 운동도 심혈관 건강에 좋습니다.\n[정답]", "4": "당뇨병, 고지혈증, 고혈압은 동맥경화증의 주요한 위험 인자입니다.", "3": "저지방식이 섭취는 동맥경화증을 예방하는데 기여할 수 있습니다.", "5": "가족적 소인은 동맥경화증에 영향을 미칠 수 있습니다."}'::jsonb, '[{"term_ko": "동맥경화증", "term_vi": "Xơ vữa động mạch", "def_ko": "혈관 벽에 지방, 콜레스테롤 등이 축적되어 혈관이 좁아지는 질환", "def_vi": "Bệnh mà ở thành mạch máu tích tụ mỡ, cholesterol làm hẹp lòng mạch"}, {"term_ko": "원인", "term_vi": "Nguyên nhân", "def_ko": "어떤 일이 일어나는 이유", "def_vi": "Lý do xảy ra một sự việc"}, {"term_ko": "당뇨병", "term_vi": "Bệnh đái tháo đường", "def_ko": "인체의 혈당 수치 조절이 어려운 질병", "def_vi": "Bệnh mà cơ thể khó kiểm soát mức đường huyết"}, {"term_ko": "고지혈증", "term_vi": "Rối loạn lipid máu", "def_ko": "혈액 중의 지질 성분이 비정상적으로 높은 상태", "def_vi": "Tình trạng lipid trong máu quá cao bất thường"}, {"term_ko": "고혈압", "term_vi": "Tăng huyết áp", "def_ko": "혈압이 비정상적으로 높은 상태", "def_vi": "Tình trạng huyết áp cao bất thường"}, {"term_ko": "가족적", "term_vi": "Di truyền", "def_ko": "가족과 관련된", "def_vi": "Liên quan đến gia đình"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (899, '5', '관상동맥이 동맥경화로 좁아져 심장근육에 충분한 산소공급을 하지 못할 때 발생하는 통증은?', '["복통", "요통", "흉통", "관절통", "신경통"]'::jsonb, 3, NULL, NULL, '{"1": "복통은 위장관 계통의 문제로 발생하는 통증입니다.", "2": "요통은 허리나 주변 부위의 통증으로, 심장과 관련이 없습니다.\n[정답]", "3": "흉통은 심장에 공급되는 혈액이나 산소의 부족으로 인해 발생하는 통증입니다.", "4": "관절통은 관절에서 발생하는 통증으로 심장과 관련이 없습니다.", "5": "신경통은 신경의 손상이나 자극으로 인해 발생하는 통증입니다."}'::jsonb, '[{"term_ko": "관상동맥", "term_vi": "Động mạch vành", "def_ko": "심장의 혈액을 공급하는 동맥", "def_vi": "Động mạch cung cấp máu cho tim"}, {"term_ko": "동맥경화", "term_vi": "Xơ vữa động mạch", "def_ko": "동맥에 지방, 콜레스테롤이 쌓이는 상태", "def_vi": "Tình trạng tích tụ mỡ, cholesterol trong động mạch"}, {"term_ko": "산소", "term_vi": "Oxy", "def_ko": "생명 유지에 필수적인 기체", "def_vi": "Khí thiết yếu cho sự sống"}, {"term_ko": "심장근육", "term_vi": "Cơ tim", "def_ko": "심장 벽을 구성하여 심장의 수축을 담당하는 근육", "def_vi": "Cơ cấu tạo nên thành tim, chịu trách nhiệm co bóp của tim"}, {"term_ko": "통증", "term_vi": "Đau", "def_ko": "불쾌한 감각이나 느낌", "def_vi": "Cảm giác hay cảm xúc khó chịu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (898, '5', '고혈압 대상자의 관리 방법으로 옳은 것은?', '["체중을 서서히 늘린다.", "복부 비만이라도 표준체중이면 정상이다.", "일주일에 3~5회, 30분 이상 땀이 날 정도로 운동한다.", "포화지방이 많은 음식을 섭취하여 혈압을 조절한다.", "혈압을 낮추기 위해 하루 15g 이상 염분을 섭취한다."]'::jsonb, 3, NULL, NULL, '{"1": "체중을 서서히 늘리는 것은 고혈압 관리에 도움이 되지 않습니다.\n[정답]", "3": "일주일에 3~5회, 30분 이상 땀이 날 정도로 운동하는 것은 고혈압 관리에 효과적입니다.", "2": "복부 비만이라도 표준체중이면 정상이라는 것은 잘못된 정보입니다.", "4": "포화지방이 많은 음식을 섭취하여 혈압을 조절한다는 것은 사실과 다릅니다.", "5": "날마다 15g 이상의 염분 섭취는 혈압을 높일 수 있으므로 피해야 합니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "운동", "def_ko": "높은 혈압(압 suất máu cao)", "def_vi": "신체 활동(hoạt động thể chất)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (897, '5', '뒷머리가 뻐근하게 아프고 어지럽거나 흐리게 보이며 이른 아침에 두통 증상이 나타나는 질환은?', '["동맥경화증", "고혈압", "심부전", "빈혈", "뇌졸증"]'::jsonb, 2, NULL, NULL, '{"1": "동맥경화증은 혈관의 경직과 관련된 질환으로 두통과는 직접적으로 연관이 없습니다.\n[정답]", "2": "고혈압은 두통의 일반적인 원인 중 하나로 이른 아침에 나타나는 경우가 많습니다.", "3": "심부전은 심장과 관련된 문제로 두통이 주요 증상이지 않습니다.", "4": "빈혈은 일반적으로 졸림, 피로감 등의 증세가 더 두드러집니다.", "5": "뇌졸증은 심각한 신경학적 증상으로 두통은 나타날 수 있지만, 문제에서 설명한 증상과는 걸맞지 않습니다."}'::jsonb, '[{"term_ko": "두통", "term_vi": "Đau đầu", "def_ko": "통증(한국어)", "def_vi": "Đau trong đầu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (896, '5', '고혈압 대상자의 혈압약 복용 방법으로 옳은 것은?', '["혈압이 조절되면 약 복용을 중단한다.", "체중이 감소하면 복용량을 줄인다.", "혈압이 높아지면 복용량을 늘린다.", "투약 후에도 고혈압이 지속되면 의사와 상의한다.", "몸이 약해지므로 장기간 투약하지 않는다."]'::jsonb, 4, NULL, NULL, '{"1": "혈압이 조절되었다고 해서 약 복용을 중단해서는 안 됩니다. 약물은 지속적으로 복용해야 합니다.\n[정답]", "4": "고혈압이 지속될 경우 반드시 의사와 상의해야 하며, 이는 안전한 치료를 위해 중요합니다.", "2": "체중 감소가 약물 복용량에 직접적인 영향을 주는 것은 아닙니다.", "3": "혈압이 높아졌다고 해서 복용량을 즉시 늘리는 것은 불필요할 수 있으며, 의사의 지시에 따라야 합니다.", "5": "고혈압 관리에 있어 장기간 투약은 필수적이며, 환자의 상태에 따라 의사가 결정합니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "Tăng huyết áp", "def_ko": "고혈압(한국어)", "def_vi": "Huyết áp cao"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (895, '5', '고혈압 대상자가 장기간 약물 복용 후 정상적인 혈압을 유지할 때 돕는 방법은?', '["운동으로만 관리한다.", "증상이 없으면 약 복용을 중단한다.", "금식인 경우에는 혈압약을 먹지 않는다.", "두통이 있을 때만 약을 복용한다.", "혈압이 조절되어도 처방된 혈압약은 계속 복용한다."]'::jsonb, 5, NULL, NULL, '{"1": "운동으로만 관리한다: 고혈압 관리에는 운동이 중요하지만, 약물 치료도 필요하다.\n[정답]", "5": "혈압이 조절되어도 처방된 혈압약은 계속 복용한다: 약물의 지속적인 복용은 혈압 조절에 필수적이다.", "2": "증상이 없으면 약 복용을 중단한다: 증상이 없어도 혈압 조절을 위해 약물 복용이 필요하다.", "3": "금식인 경우에는 혈압약을 먹지 않는다: 금식 중에도 의료진의 지시에 따라 약을 복용해야 할 수 있다.", "4": "두통이 있을 때만 약을 복용한다: 두통 외에도 약물을 정기적으로 복용하는 것이 중요하다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "약물", "def_ko": "높은 혈압(압 suất của máu)", "def_vi": "약 또는 thuốc chữa bệnh"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (894, '5', '다음 중 고혈압에 관련된 설명으로 옳은 것은?', '["혈관이 좁아지면 혈압은 낮아진다.", "혈압은 측정 시간과 자세에 따라 다르다.", "이완기 혈압은 심장이 혈액을 내보낼 때의 압력이다.", "본태성 고혈압은 원인 질병이 치료되면 정상화된다.", "대부분의 고혈압은 다른 질병의 합병증으로 발생한다."]'::jsonb, 2, NULL, NULL, '{"1": "혈관이 좁아지면 혈압이 높아지는 것이 일반적입니다. 이는 혈액이 흐르는 경로가 좁아지기 때문에 압력이 증가하는 원리입니다.\n[정답]", "2": "혈압은 측정 시간과 자세에 따라 변동할 수 있으며, 이는 정상적인 생리적 현상입니다.", "3": "이완기 혈압은 심장이 이완될 때 혈관 내 압력을 의미합니다. 따라서 심장이 혈액을 내보낼 때의 압력은 수축기 혈압입니다.", "4": "본태성 고혈압은 원인질환이 없는 고혈압으로, 원인 치료에 따라 항상 정상으로 돌아오지 않습니다.", "5": "대부분의 고혈압은 본태성 고혈압이며, 안타깝게도 다른 질병의 합병증으로 발생하기보다는 독립적으로 존재하는 경우가 많습니다."}'::jsonb, '[{"term_ko": "고혈압", "term_vi": "혈관", "def_ko": "높은 혈압(압 suất máu cao)", "def_vi": "몸의 혈액을 전달하는 구조(mạch máu)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (893, '5', '오랫동안 심혈관 질환을 앓고 있는 대상자에게 발생할 수 있는 문제는?', '["우울증으로 인한 자해", "감각이상으로 인한 괴사", "골격이상으로 인한 골절", "청각이상으로 인한 교통사고", "기립성 저혈압으로 인한 낙상"]'::jsonb, 5, NULL, NULL, '{"1": "우울증은 심혈관 질환 환자에게 흔하게 발생할 수 있으나, 자해와는 직접적인 관련이 적습니다.\n[정답]", "5": "기립성 저혈압은 심혈관 질환 환자에게 자주 나타나는 문제로, 이는 낙상의 위험을 증가시킵니다.", "2": "감각이상으로 인한 괴사는 심혈관 질환의 직접적인 합병증은 아닙니다.", "3": "골격이상은 일반적인 심혈관 질환과는 관련이 적습니다.", "4": "청각이상은 심혈관과 직접적인 관련성이 적으며, 교통사고와의 연관성도 낮습니다."}'::jsonb, '[{"term_ko": "심혈관 질환", "term_vi": "Bệnh tim mạch", "def_ko": "심장과 혈관의 질환", "def_vi": "Bệnh liên quan đến tim và mạch máu"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (892, '5', '노화에 따른 심혈관계 특성으로 옳은 것은?', '["최대 심박출량 증가", "최대 심박동수 증가", "심장의 탄력성 감소", "심장으로의 혈액순환 증가", "정맥의 탄력 증가"]'::jsonb, 5, NULL, NULL, '{"1": "최대 심박출량은 보통 감소한다.", "2": "최대 심박동수는 나이가 들면서 감소한다.\n[정답]", "3": "심장의 탄력성은 감소한다.", "4": "심장으로의 혈액순환은 일반적으로 감소한다.", "5": "정맥의 탄력은 보통 감소한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이 들다", "def_vi": "Trở nên già"}, {"term_ko": "심혈관계", "term_vi": "Hệ tim mạch", "def_ko": "심장과 혈관으로 이루어진 계통", "def_vi": "Hệ thống bao gồm tim và mạch máu"}, {"term_ko": "심박출량", "term_vi": "Lưu lượng bơm máu", "def_ko": "심장에서 혈액이 흘러나오는 양", "def_vi": "Lượng máu chảy ra từ tim"}, {"term_ko": "심박동수", "term_vi": "Tần số nhịp tim", "def_ko": "심장이 뛰는 횟수", "def_vi": "Số lần tim đập"}, {"term_ko": "탄력성", "term_vi": "Độ đàn hồi", "def_ko": "늘어나는 성질", "def_vi": "Đặc tính co dãn"}, {"term_ko": "혈액순환", "term_vi": "Tuần hoàn máu", "def_ko": "심장과 혈관을 통해 혈액이 흐르는 과정", "def_vi": "Quá trình máu chảy qua tim và mạch máu"}, {"term_ko": "정맥", "term_vi": "Tĩnh mạch", "def_ko": "심장으로 혈액을 가져오는 혈관", "def_vi": "Mạch máu đưa máu về tim"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (891, '5', '노화에 따른 심혈관계 특성으로 옳은 것은?', '["말초혈관의 저항 감소", "하지정맥류 발생 감소", "기립성 저혈압 발생 감소", "심장 근육의 탄력성 증가", "정맥의 약화로 하지 부종 발생"]'::jsonb, 5, NULL, NULL, '{"1": "말초혈관의 저항은 노화로 인해 증가한다.\n[정답]", "5": "정맥의 약화로 인해 하지 부종이 발생할 수 있다.", "2": "하지정맥류의 발생은 오히려 증가한다.", "3": "기립성 저혈압의 발생도 증가한다.", "4": "심장 근육의 탄력성은 감소한다."}'::jsonb, '[{"term_ko": "노화", "term_vi": "Lão hóa", "def_ko": "나이의 증가(한국어)", "def_vi": "Sự gia tăng tuổi tác(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (890, '5', '폐결핵 의심 대상자와 접촉했을 때 요양보호사의 대처 방법으로 옳은 것은?', '["결핵약을 즉시 복용한다.", "2~3일간 요양보호 서비스를 중단한다.", "사용하는 침구류는 강한 산이나 알칼리로 소독한다.", "2주~1개월 이후 반드시 X-ray 검진을 받아본다.", "대상자는 물론 가족과 요양보호사도 동시에 치료 받는다."]'::jsonb, 4, NULL, NULL, '{"1": "결핵약은 의사의 처방에 따라 복용해야 하므로 즉시 복용하는 것은 옳지 않습니다.\n[정답]", "4": "폐결핵 접촉 후 2주에서 1개월 이내에 X-ray 검사로 확인하는 것이 필요합니다.", "2": "요양보호 서비스 중단은 필요하지 않습니다.", "3": "침구류 소독은 필요하지만 적절한 방법이 아닙니다.", "5": "가족과 요양보호사도 치료받는 것은 권장되지만 반드시 동시에 치료를 받을 필요는 없습니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에서 발생하는 결핵", "def_vi": "Lao xảy ra trong phổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (889, '5', '다음 중 폐결핵에 대한 설명으로 옳은 것은?', '["바이러스성 만성질환이다.", "약물 복용이 끝ㅌ날 때까지 격리치료한다.", "약물 투여로 인한 위장장애, 피부 발진 등 부작용이 생긴다.", "대체로 오전에 열이 오르고, 오후에 열이 내린다.", "치료기간 중 증상이 없으면 약 복용을 중단한다"]'::jsonb, 3, NULL, NULL, '{"1": "폐결핵은 세균성 질환으로, 바이러스성 만성질환이 아닙니다.\n[정답]", "3": "약물 투여로 인해 위장장애와 피부 발진 등의 부작용이 발생할 수 있습니다.", "2": "약물 복용이 끝날 때까지 격리 치료가 필요하지만, 일반적으로 격리 치료의 규정은 치료 단계에 따라 다릅니다.", "4": "폐결핵로 인한 열은 대개 오후에 더 심해지는 경향이 있습니다.", "5": "치료기간 중 증상이 없더라도 의사 지시에 따라 약 복용을 지속해야 합니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에서 발생하는 결핵 질환", "def_vi": "Bệnh lao xảy ra ở phổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (888, '5', '폐결핵에 대한 설명으로 옳은 것은?', '["항결핵제 중 한 가지 약물만 복용한다.", "주기적으로 간 기능 검사와 객담 검사를 실시한다.", "치료기간은 1주일이다.", "증상이 좋아지면 약의 양을 줄인다.", "결핵은 감염성이 매우 낮다."]'::jsonb, 2, NULL, NULL, '{"1": "항결핵제는 여러 가지 약물을 조합하여 복용해야 합니다.\n[정답]", "2": "주기적으로 간 기능 검사와 객담 검사를 실시하는 것이 중요합니다.", "3": "치료기간은 보통 6개월 이상 걸립니다.", "4": "증상이 좋아지더라도 약을 조기 중단하면 효과가 떨어질 수 있으므로 주의해야 합니다.", "5": "결핵은 전염성이 높은 질병입니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에 생기는 결핵균 감염", "def_vi": "Nhiễm trùng do vi khuẩn lao ở phổi"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (887, '5', '다음 증상이 나타나는 질환은?• 오후에 고열이 있다가 늦은 밤에 식은땀과 함께 열이 내린다.• 피로감, 식욕부진, 체중감소• 호흡곤란과 흉막염이 나타난다.', '["폐렴", "천식", "폐결핵", "간염", "만성기관지염"]'::jsonb, 3, NULL, NULL, '{"1": "폐렴: 주로 고열과 기침 등의 증상이 나타나지만 식은땀과 체중 감소가 주 증상이 아님.\n[정답]", "3": "폐결핵: 오후에 고열과 식은땀, 체중 감소 등 전형적인 증상을 나타내며, 흉막염이 동반될 수 있음.", "2": "천식: 호흡곤란이 나타나지만 열과 체중 감소는 일반적이지 않음.", "4": "간염: 일반적으로 식욕부진과 피로가 있으나 고열과 식은땀은 주 증상이 아님.", "5": "만성기관지염: 호흡곤란이 있으나 고열과 함께 식은땀, 체중 감소는 동반되지 않음."}'::jsonb, '[{"term_ko": "증상", "term_vi": "Triệu chứng", "def_ko": "증상(한국어)", "def_vi": "triệu chứng(베트남어)"}]'::jsonb) on conflict (id) do nothing;
insert into public.cbt_questions (id, chapter, question, choices, answer_index, intent_ko, intent_vi, choice_explanations, key_terms) values (886, '5', '폐결핵 발병 원인으로 옳은 것은?', '["결핵균의 호흡기 감염", "영양상태 양호", "면역력 증가", "혈액을 통한 감염", "미생물에 의한 피부 감염"]'::jsonb, 1, NULL, NULL, '{"1": "결핵균인 Mycobacterium tuberculosis가 호흡기를 통해 감염되며, 폐결핵의 주요 원인입니다.\n[정답]", "2": "영양상태가 양호하면 면역력이 높아져 결핵 발병 위험이 낮아집니다.", "3": "면역력 증가는 결핵 발병에 영향을 미치는 요인이 아니므로 옳지 않습니다.", "4": "혈액을 통한 감염은 폐결핵의 일반적인 전파 경로가 아닙니다.", "5": "미생물에 의한 피부 감염은 폐결핵과 관련이 없습니다."}'::jsonb, '[{"term_ko": "폐결핵", "term_vi": "Bệnh lao phổi", "def_ko": "폐에 발생하는 결핵", "def_vi": "Lao xảy ra ở phổi"}]'::jsonb) on conflict (id) do nothing;
